  service: { price: number; title: string } | null;
  barber: { name: string } | null;
  appointment_payments?: { amount: number; payment_method: string }[];
}

interface Barber {
  id: string;
  name: string;
}

interface Service {
  id: string;
  title: string;
}

interface Product {
  id: string;
  name: string;
  price?: number;
}

interface ProductSale {
