}

const COLORS = ['hsl(var(--primary))', 'hsl(var(--secondary))', '#22c55e', '#3b82f6', '#f59e0b', '#ef4444'];

const FinancialDashboard = () => {
  const { role } = useAuth();
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [productSales, setProductSales] = useState<ProductSale[]>([]);
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [period, setPeriod] = useState<'day' | 'week' | 'month' | 'year' | 'custom'>('week');
  const [dateFrom, setDateFrom] = useState<string>(() => format(startOfMonth(new Date()), 'yyyy-MM-dd'));
  const [dateTo, setDateTo] = useState<string>(() => format(endOfMonth(new Date()), 'yyyy-MM-dd'));
  const [filterType, setFilterType] = useState<'all' | 'local' | 'online' | 'manual'>('all');
  const [filterBarber, setFilterBarber] = useState<string>('all');
  const [filterService, setFilterService] = useState<string>('all');
  const [filterProduct, setFilterProduct] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<'all' | 'completed' | 'confirmed' | 'cancelled'>('all');
  const [activeTab, setActiveTab] = useState<'overview' | 'commissions' | 'advances' | 'expenses' | 'reports'>('overview');
  const [showFilters, setShowFilters] = useState(false);
  const [recentTab, setRecentTab] = useState<'appointments' | 'products'>('appointments');
  const [manualDialogOpen, setManualDialogOpen] = useState(false);
  const [manualType, setManualType] = useState<'service' | 'product'>('service');
  const [manualBarberId, setManualBarberId] = useState<string>('');
  const [manualServiceId, setManualServiceId] = useState<string>('');
  const [manualProductId, setManualProductId] = useState<string>('');
  const [manualQuantity, setManualQuantity] = useState<number>(1);
  const [manualDate, setManualDate] = useState<string>(() => format(new Date(), 'yyyy-MM-dd'));
  const [manualTime, setManualTime] = useState<string>(() => format(new Date(), 'HH:mm'));
  const [manualClientName, setManualClientName] = useState<string>('');
  const [manualSaving, setManualSaving] = useState(false);
  
  const isManager = role === 'admin' || role === 'gestor';

  const { 
    calculateCommission: calculateIndividualCommission,
    loadAllCommissions: loadAllIndividualCommissions,
  } = useBarberCommissions(null);

  const {
    calculateServiceCommission: calculateFixedServiceCommission,
    loadAllCommissions: loadAllFixedCommissions,
    getProductCommissionPercentage: getFixedProductCommissionPercentage,
  } = useBarberFixedCommissions(null);

  const {
    loadAllCommissions: loadAllProductCommissions,
    getCommissionPercentage: getIndividualProductCommissionPercentage,
  } = useBarberProductCommissions(null);

  useEffect(() => {
    loadBarbers();
    loadServices();
    loadProducts();
  }, []);

  useEffect(() => {
    if (isManager) {
      loadAllIndividualCommissions();
      loadAllFixedCommissions();
      loadAllProductCommissions();
    }
  }, [isManager, loadAllIndividualCommissions, loadAllFixedCommissions, loadAllProductCommissions]);

  useEffect(() => {
    loadAppointments();
    loadProductSales();
  }, [period, dateFrom, dateTo, filterType, filterBarber, filterService, filterProduct, filterStatus]);

  // Subscriptions Realtime separadas — criadas apenas uma vez
  useEffect(() => {
    let apptRemoved = false;
    const appointmentsChannel = supabase
      .channel('financial-appointments')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'appointments' },
        () => { loadAppointments(); }
      )
      .subscribe((status: string) => {
        if ((status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') && !apptRemoved) {
          apptRemoved = true;
          setTimeout(() => { try { supabase.removeChannel(appointmentsChannel); } catch { /* ignore */ } }, 0);
        }
      });

    let salesRemoved = false;
    const productSalesChannel = supabase
      .channel('financial-product-sales')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'product_sales' },
        () => { loadProductSales(); }
      )
      .subscribe((status: string) => {
        if ((status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') && !salesRemoved) {
          salesRemoved = true;
          setTimeout(() => { try { supabase.removeChannel(productSalesChannel); } catch { /* ignore */ } }, 0);
        }
      });

    return () => {
      apptRemoved = true;
      salesRemoved = true;
      try { supabase.removeChannel(appointmentsChannel); } catch { /* ignore */ }
      try { supabase.removeChannel(productSalesChannel); } catch { /* ignore */ }
    };
  }, []);

  const loadBarbers = async () => {
    const { data } = await supabase
      .from('barbers')
      .select('id, name')
      .eq('visible', true);
    setBarbers(data || []);
  };

  const loadServices = async () => {
    const { data } = await supabase
      .from('services')
      .select('id, title, price')
      .eq('visible', true);
    setServices(data || []);
  };

  const loadProducts = async () => {
    const { data } = await supabase
      .from('products')
      .select('id, name, price')
      .eq('visible', true);
    setProducts(data || []);
  };

  const getDateRange = () => {
    const today = new Date();
    if (period === 'custom' && dateFrom && dateTo) {
      const startParsed = startOfDay(parse(dateFrom, 'yyyy-MM-dd', new Date()));
      const endParsed = endOfDay(parse(dateTo, 'yyyy-MM-dd', new Date()));
      return { start: startParsed, end: endParsed };
    }
    switch (period) {
      case 'day':
        return { start: startOfDay(today), end: endOfDay(today) };
      case 'week':
        return { start: startOfWeek(today, { weekStartsOn: 0 }), end: today };
      case 'month':
        return { start: startOfMonth(today), end: today };
      case 'year':
        return { start: startOfYear(today), end: today };
      default:
        return { start: startOfWeek(today, { weekStartsOn: 0 }), end: today };
    }
  };

  const loadAppointments = async () => {
    const { start, end } = getDateRange();
    
    let query = supabase
      .from('appointments')
      .select(`
        id,
        appointment_date,
        appointment_time,
        booking_type,
        status,
        created_at,
        payment_method,
        barber_id,
        service_id,
        service:services(price, title),
        barber:barbers(name),
        appointment_payments(amount, payment_method)
      `)
      .gte('appointment_date', format(start, 'yyyy-MM-dd'))
      .lte('appointment_date', format(end, 'yyyy-MM-dd'));

    if (filterType !== 'all') {
      query = query.eq('booking_type', filterType);
    }
    if (filterBarber !== 'all') {
      query = query.eq('barber_id', filterBarber);
    }
    if (filterService !== 'all') {
      query = query.eq('service_id', filterService);
    }
    if (filterStatus !== 'all') {
      query = query.eq('status', filterStatus);
    }

    const { data, error } = await query.order('appointment_date', { ascending: false });

    if (error) {
      console.error('Error loading appointments:', error);
      return;
    }

    setAppointments((data as any) || []);
  };

  const loadProductSales = async () => {
    const { start, end } = getDateRange();
    
    let query = (supabase as any)
      .from('product_sales')
      .select(`
        id,
        sale_date,
        sale_time,
        total_price,
        commission_value,
        barber_id,
        product_id,
        barber:barbers(name),
        product:products(name)
      `)
      .eq('status', 'confirmed')
      .gte('sale_date', format(start, 'yyyy-MM-dd'))
      .lte('sale_date', format(end, 'yyyy-MM-dd'));

    if (filterBarber !== 'all') {
      query = query.eq('barber_id', filterBarber);
    }
    if (filterProduct !== 'all') {
      query = query.eq('product_id', filterProduct);
    }

    const { data, error } = await query.order('sale_date', { ascending: false });

    if (error) {
      console.error('Error loading product sales:', error);
      return;
    }

    setProductSales((data as any) || []);
  };

  const handleOpenManualDialog = (type: 'service' | 'product') => {};

  const handleSaveManualSale = async () => {};

  // Helper to calculate appointment revenue considering split payments
  const getAppointmentRevenue = (apt: Appointment) => {
    const paymentsTotal = apt.appointment_payments?.reduce((pSum, p) => pSum + Number(p.amount), 0) || 0;
    return paymentsTotal > 0 ? paymentsTotal : ((apt.service as any)?.price || 0);
  };

  const getServiceCommissionValue = (apt: Appointment): number => {
    if (!apt.service || !apt.service_id || !apt.barber_id) return 0;
    const paymentsTotal = apt.appointment_payments?.reduce((sum, p) => sum + Number(p.amount), 0) || 0;
    const servicePrice = paymentsTotal > 0 ? paymentsTotal : (apt.service.price || 0);
    const individual = calculateIndividualCommission(apt.barber_id, apt.service_id, servicePrice);
    if (individual > 0) return individual;
    return calculateFixedServiceCommission(apt.barber_id, servicePrice);
  };

  // Calculate stats
  const completedAndConfirmed = appointments.filter(
    apt => apt.status === 'completed' || apt.status === 'confirmed'
  );

  const totalRevenue = completedAndConfirmed.reduce(
    (sum, apt) => sum + getAppointmentRevenue(apt),
    0
  );

  const totalServiceCommission = completedAndConfirmed.reduce(
    (sum, apt) => sum + getServiceCommissionValue(apt),
    0
  );
  
  const totalProductRevenue = productSales.reduce((sum, sale) => sum + sale.total_price, 0);
  const totalProductCommission = productSales.reduce((sum, sale) => sum + sale.commission_value, 0);
  const totalRevenueWithProducts = totalRevenue + totalProductRevenue;
  const totalCommission = totalServiceCommission + totalProductCommission;
  const serviceTicketBase = completedAndConfirmed.length;
  const averageServiceTicket =
    serviceTicketBase > 0 ? totalRevenue / serviceTicketBase : 0;
  
  const totalAppointments = appointments.length;
  const completedCount = appointments.filter(apt => apt.status === 'completed').length;
  const confirmedCount = appointments.filter(apt => apt.status === 'confirmed').length;
  const cancelledCount = appointments.filter(apt => apt.status === 'cancelled').length;
  const localCount = appointments.filter(apt => apt.booking_type === 'local').length;
  const onlineCount = appointments.filter(apt => apt.booking_type === 'online').length;
  const manualCount = appointments.filter(apt => apt.booking_type === 'manual').length;

  // Chart data by date
  const chartDataByDate = () => {
    const grouped: Record<string, { date: string; receita: number; agendamentos: number }> = {};
    
    appointments
      .filter(apt => apt.status === 'completed' || apt.status === 'confirmed')
      .forEach((apt) => {
        const dateKey = period === 'day' 
          ? apt.appointment_time.slice(0, 2) + 'h'
          : format(new Date(apt.appointment_date + 'T00:00:00'), 'dd/MM');
        
        if (!grouped[dateKey]) {
          grouped[dateKey] = { date: dateKey, receita: 0, agendamentos: 0 };
        }
        grouped[dateKey].receita += getAppointmentRevenue(apt);
        grouped[dateKey].agendamentos += 1;
      });

    return Object.values(grouped).sort((a, b) => a.date.localeCompare(b.date));
  };

  // Chart data by booking type
  const chartDataByType = [
    { name: 'Local', value: localCount, color: COLORS[0] },
    { name: 'Online', value: onlineCount, color: COLORS[1] },
  ].filter(d => d.value > 0);

  // Chart data by status
  const chartDataByStatus = [
    { name: 'Confirmados', value: confirmedCount, color: '#22c55e' },
    { name: 'Concluídos', value: completedCount, color: COLORS[0] },
    { name: 'Cancelados', value: cancelledCount, color: '#ef4444' },
  ].filter(d => d.value > 0);

  // Revenue by barber (including products)
  const revenueByBarber = () => {
    const grouped: Record<string, number> = {};
    appointments
      .filter(apt => apt.status === 'completed' || apt.status === 'confirmed')
      .forEach((apt) => {
        const barberName = (apt.barber as any)?.name || 'Desconhecido';
        grouped[barberName] = (grouped[barberName] || 0) + getAppointmentRevenue(apt);
      });
    productSales.forEach((sale) => {
      const barberName = (sale.barber as any)?.name || 'Desconhecido';
      grouped[barberName] = (grouped[barberName] || 0) + sale.total_price;
    });
    return Object.entries(grouped).map(([name, value]) => ({ name, value }));
  };

  // Revenue by service
  const revenueByService = () => {
    const grouped: Record<string, { count: number; revenue: number }> = {};
    appointments
      .filter(apt => apt.status === 'completed' || apt.status === 'confirmed')
      .forEach((apt) => {
        const serviceName = (apt.service as any)?.title || 'Desconhecido';
        if (!grouped[serviceName]) {
          grouped[serviceName] = { count: 0, revenue: 0 };
        }
        grouped[serviceName].count += 1;
        grouped[serviceName].revenue += getAppointmentRevenue(apt);
      });
    return Object.entries(grouped).map(([name, data]) => ({ 
      name, 
      quantidade: data.count,
      receita: data.revenue 
    }));
  };

  // Revenue by product
  const revenueByProduct = () => {
    const grouped: Record<string, { count: number; revenue: number; commission: number }> = {};
    productSales.forEach((sale) => {
      const productName = (sale.product as any)?.name || 'Desconhecido';
      if (!grouped[productName]) {
        grouped[productName] = { count: 0, revenue: 0, commission: 0 };
      }
      grouped[productName].count += 1;
      grouped[productName].revenue += sale.total_price;
      grouped[productName].commission += sale.commission_value;
    });
    return Object.entries(grouped).map(([name, data]) => ({ 
      name, 
      quantidade: data.count,
      receita: data.revenue,
      comissao: data.commission
    }));
  };

  // Revenue by payment method
  const revenueByPaymentMethod = () => {
    const grouped: Record<string, number> = {};
    
    appointments
      .filter(apt => apt.status === 'completed' || apt.status === 'confirmed')
      .forEach((apt) => {
        if (apt.appointment_payments && apt.appointment_payments.length > 0) {
            apt.appointment_payments.forEach(p => {
                let method = p.payment_method || 'Outros';
                // Capitalize
                method = method.charAt(0).toUpperCase() + method.slice(1);
                if (method === 'Cartao') method = 'Cartão';
                
                grouped[method] = (grouped[method] || 0) + Number(p.amount);
            });
        } else {
            // Fallback
            const price = getAppointmentRevenue(apt);
            if (price > 0) {
                let method = apt.payment_method || 'Não definido';
                method = method.charAt(0).toUpperCase() + method.slice(1);
                if (method === 'Cartao') method = 'Cartão';
                
                grouped[method] = (grouped[method] || 0) + price;
            }
        }
      });
      
    return Object.entries(grouped)
        .map(([name, value]) => ({ name, value }))
        .sort((a, b) => b.value - a.value);
  };

  // Chart data by date (including products)
  const chartDataByDateWithProducts = () => {
    const grouped: Record<string, { date: string; receita: number; receitaProdutos: number; agendamentos: number }> = {};
    
    appointments
      .filter(apt => apt.status === 'completed' || apt.status === 'confirmed')
      .forEach((apt) => {
        const dateKey = period === 'day' 
          ? apt.appointment_time.slice(0, 2) + 'h'
          : format(new Date(apt.appointment_date + 'T00:00:00'), 'dd/MM');
        
        if (!grouped[dateKey]) {
          grouped[dateKey] = { date: dateKey, receita: 0, receitaProdutos: 0, agendamentos: 0 };
        }
        grouped[dateKey].receita += getAppointmentRevenue(apt);
        grouped[dateKey].agendamentos += 1;
      });

    productSales.forEach((sale) => {
      const dateKey = period === 'day' 
        ? sale.sale_time.slice(0, 2) + 'h'
        : format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM');
      
      if (!grouped[dateKey]) {
        grouped[dateKey] = { date: dateKey, receita: 0, receitaProdutos: 0, agendamentos: 0 };
      }
      grouped[dateKey].receitaProdutos += sale.total_price;
    });

    return Object.values(grouped).sort((a, b) => a.date.localeCompare(b.date));
  };

  const getPeriodLabel = () => {
    if (period === 'custom' && dateFrom && dateTo) {
      const startLabel = format(parse(dateFrom, 'yyyy-MM-dd', new Date()), 'dd/MM/yyyy', { locale: ptBR });
      const endLabel = format(parse(dateTo, 'yyyy-MM-dd', new Date()), 'dd/MM/yyyy', { locale: ptBR });
      return `${startLabel} até ${endLabel}`;
    }
    switch (period) {
      case 'day': return 'Hoje';
      case 'week': return 'Esta Semana';
      case 'month': return 'Este Mês';
      case 'year': return 'Este Ano';
      default: return 'Período';
    }
  };

  const renderContent = () => (
    <>
      {/* Filters */}
      <div className="flex justify-end">
        <Button
          size="sm"
          variant="outline"
          className="h-8 px-2 text-xs"
          onClick={() => setShowFilters((v) => !v)}
        >
          <Filter className="h-3 w-3 mr-1" />
          {showFilters ? 'Ocultar filtros' : 'Mostrar filtros'}
        </Button>
      </div>
      <Card className={`bg-card border-border ${showFilters ? '' : 'hidden'}`}>
        <CardHeader className="pb-3">
          <CardTitle className="text-lg flex items-center gap-2">
            <Filter className="h-5 w-5" />
            Filtros
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 gap-2">
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <Calendar className="h-3 w-3 mr-1" />
                  Período: {period === 'day' ? 'Diário' : period === 'week' ? 'Semanal' : period === 'month' ? 'Mensal' : period === 'year' ? 'Anual' : 'Personalizado'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Período</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={period} onValueChange={(v) => setPeriod(v as any)}>
                  <DropdownMenuRadioItem value="day">Diário</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="week">Semanal</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="month">Mensal</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="year">Anual</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="custom">Personalizado</DropdownMenuRadioItem>
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>
            {period === 'custom' && (
              <>
                <div className="min-w-[160px]">
                  <label className="text-xs text-muted-foreground mb-1 block">Data inicial</label>
                  <Input
                    type="date"
                    value={dateFrom}
                    onChange={(e) => setDateFrom(e.target.value)}
                  />
                </div>
                <div className="min-w-[160px]">
                  <label className="text-xs text-muted-foreground mb-1 block">Data final</label>
                  <Input
                    type="date"
                    value={dateTo}
                    onChange={(e) => setDateTo(e.target.value)}
                  />
                </div>
              </>
            )}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <Users className="h-3 w-3 mr-1" />
                  Tipo: {filterType === 'all' ? 'Todos' : filterType === 'local' ? 'Local' : filterType === 'online' ? 'Online' : 'Manual'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Tipo</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={filterType} onValueChange={(v) => setFilterType(v as any)}>
                  <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="local">Local</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="online">Online</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="manual">Manual (Retroativo)</DropdownMenuRadioItem>
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <Users className="h-3 w-3 mr-1" />
                  Barbeiro: {barbers.find(b => b.id === filterBarber)?.name || 'Todos'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Barbeiro</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={filterBarber} onValueChange={setFilterBarber}>
                  <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                  {barbers.map((b) => (
                    <DropdownMenuRadioItem key={b.id} value={b.id}>{b.name}</DropdownMenuRadioItem>
                  ))}
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <TrendingUp className="h-3 w-3 mr-1" />
                  Serviço: {services.find(s => s.id === filterService)?.title || 'Todos'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Serviço</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={filterService} onValueChange={setFilterService}>
                  <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                  {services.map((s) => (
                    <DropdownMenuRadioItem key={s.id} value={s.id}>{s.title}</DropdownMenuRadioItem>
                  ))}
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <DollarSign className="h-3 w-3 mr-1" />
                  Produto: {products.find(p => p.id === filterProduct)?.name || 'Todos'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Produto</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={filterProduct} onValueChange={setFilterProduct}>
                  <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                  {products.map((p) => (
                    <DropdownMenuRadioItem key={p.id} value={p.id}>{p.name}</DropdownMenuRadioItem>
                  ))}
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                  <Filter className="h-3 w-3 mr-1" />
                  Status: {filterStatus === 'all' ? 'Todos' : filterStatus === 'confirmed' ? 'Confirmados' : filterStatus === 'completed' ? 'Concluídos' : 'Cancelados'}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent>
                <DropdownMenuLabel className="text-xs">Status</DropdownMenuLabel>
                <DropdownMenuRadioGroup value={filterStatus} onValueChange={(v) => setFilterStatus(v as any)}>
                  <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="confirmed">Confirmados</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="completed">Concluídos</DropdownMenuRadioItem>
                  <DropdownMenuRadioItem value="cancelled">Cancelados</DropdownMenuRadioItem>
                </DropdownMenuRadioGroup>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </CardContent>
      </Card>

      {/* Stats Cards */}
      <div className="space-y-3 sm:space-y-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4">
          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Receita do Período ({getPeriodLabel()})</CardTitle>
              <DollarSign className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalRevenueWithProducts.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                {confirmedCount + completedCount} serviços + {productSales.length} produtos
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Receita de Produtos</CardTitle>
              <DollarSign className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalProductRevenue.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                {productSales.length} vendas realizadas
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Receita de Serviços</CardTitle>
              <DollarSign className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalRevenue.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                Apenas serviços concluídos/confirmados
              </p>
            </CardContent>
          </Card>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4">
          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Comissão do Período</CardTitle>
              <TrendingUp className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalCommission.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                Serviços e produtos no período
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Comissão de Produtos</CardTitle>
              <TrendingUp className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalProductCommission.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                Comissões de produtos vendidos no período
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Comissão de Serviços</CardTitle>
              <TrendingUp className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {totalServiceCommission.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">
                Total de comissões de serviços no período
              </p>
            </CardContent>
          </Card>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Total Agendamentos</CardTitle>
              <Calendar className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">{totalAppointments}</div>
              <p className="text-xs text-muted-foreground">
                {localCount} local • {onlineCount} online{manualCount > 0 && ` • ${manualCount} manual`}
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Taxa de Conclusão</CardTitle>
              <TrendingUp className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                {totalAppointments > 0
                  ? Math.round(((confirmedCount + completedCount) / totalAppointments) * 100)
                  : 0}
                %
              </div>
              <p className="text-xs text-muted-foreground">
                {cancelledCount} cancelamentos
              </p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Ticket Médio Produtos</CardTitle>
              <Users className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {productSales.length > 0
                  ? (totalProductRevenue / productSales.length).toFixed(2)
                  : '0.00'}
              </div>
              <p className="text-xs text-muted-foreground">por venda</p>
            </CardContent>
          </Card>

          <Card className="bg-card border-border">
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <CardTitle className="text-sm font-medium">Ticket Médio Serviços</CardTitle>
              <Users className="h-4 w-4 text-primary" />
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-primary">
                R$ {averageServiceTicket.toFixed(2)}
              </div>
              <p className="text-xs text-muted-foreground">por atendimento de serviço</p>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6">
        {/* Revenue over time (including products) */}
        <Card className="bg-card border-border">
          <CardHeader>
            <CardTitle>Receita e Agendamentos</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={chartDataByDateWithProducts()}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis dataKey="date" stroke="hsl(var(--muted-foreground))" />
                <YAxis yAxisId="left" stroke="hsl(var(--muted-foreground))" />
                <YAxis yAxisId="right" orientation="right" stroke="hsl(var(--muted-foreground))" />
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'hsl(var(--card))', 
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }} 
                />
                <Legend />
                <Bar yAxisId="left" dataKey="receita" fill="hsl(var(--primary))" name="Receita Serviços (R$)" radius={[4, 4, 0, 0]} />
                <Bar yAxisId="left" dataKey="receitaProdutos" fill="#22c55e" name="Receita Produtos (R$)" radius={[4, 4, 0, 0]} />
                <Bar yAxisId="right" dataKey="agendamentos" fill="hsl(var(--secondary))" name="Agendamentos" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Distribution by type */}
        <Card className="bg-card border-border">
          <CardHeader>
            <CardTitle>Distribuição por Tipo</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <PieChart>
                <Pie
                  data={chartDataByType}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                >
                  {chartDataByType.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'hsl(var(--card))', 
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }} 
                />
              </PieChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Revenue by payment method */}
        <Card className="bg-card border-border">
          <CardHeader>
            <CardTitle>Receita por Método</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={revenueByPaymentMethod()} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis type="number" stroke="hsl(var(--muted-foreground))" />
                <YAxis dataKey="name" type="category" stroke="hsl(var(--muted-foreground))" width={100} />
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'hsl(var(--card))', 
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }}
                  formatter={(value: number) => [`R$ ${value.toFixed(2)}`, 'Receita']}
                />
                <Bar dataKey="value" fill="#8b5cf6" radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Revenue by barber */}
        <Card className="bg-card border-border">
          <CardHeader>
            <CardTitle>Receita por Barbeiro</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={revenueByBarber()} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis type="number" stroke="hsl(var(--muted-foreground))" />
                <YAxis dataKey="name" type="category" stroke="hsl(var(--muted-foreground))" width={100} />
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'hsl(var(--card))', 
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }}
                  formatter={(value: number) => [`R$ ${value.toFixed(2)}`, 'Receita']}
                />
                <Bar dataKey="value" fill="hsl(var(--primary))" radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Revenue by service */}
        <Card className="bg-card border-border">
          <CardHeader>
            <CardTitle>Receita por Serviço</CardTitle>
          </CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={revenueByService()} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis type="number" stroke="hsl(var(--muted-foreground))" />
                <YAxis dataKey="name" type="category" stroke="hsl(var(--muted-foreground))" width={120} />
                <Tooltip 
                  contentStyle={{ 
                    backgroundColor: 'hsl(var(--card))', 
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }}
                  formatter={(value: number, name: string) => [
                    name === 'receita' ? `R$ ${value.toFixed(2)}` : value,
                    name === 'receita' ? 'Receita' : 'Quantidade'
                  ]}
                />
                <Legend />
                <Bar dataKey="quantidade" fill="hsl(var(--secondary))" name="Quantidade" radius={[0, 4, 4, 0]} />
                <Bar dataKey="receita" fill="hsl(var(--primary))" name="Receita (R$)" radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>

        {/* Revenue by product */}
        {revenueByProduct().length > 0 && (
          <Card className="bg-card border-border">
            <CardHeader>
              <CardTitle>Receita por Produto</CardTitle>
            </CardHeader>
            <CardContent>
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={revenueByProduct()} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                  <XAxis type="number" stroke="hsl(var(--muted-foreground))" />
                  <YAxis dataKey="name" type="category" stroke="hsl(var(--muted-foreground))" width={120} />
                  <Tooltip 
                    contentStyle={{ 
                      backgroundColor: 'hsl(var(--card))', 
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                    formatter={(value: number, name: string) => [
                      name === 'receita' || name === 'comissao' ? `R$ ${value.toFixed(2)}` : value,
                      name === 'receita' ? 'Receita' : name === 'comissao' ? 'Comissão' : 'Quantidade'
                    ]}
                  />
                  <Legend />
                  <Bar dataKey="quantidade" fill="hsl(var(--secondary))" name="Quantidade" radius={[0, 4, 4, 0]} />
                  <Bar dataKey="receita" fill="#22c55e" name="Receita (R$)" radius={[0, 4, 4, 0]} />
                  <Bar dataKey="comissao" fill="#f59e0b" name="Comissão (R$)" radius={[0, 4, 4, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Recent records table */}
      <Card className="bg-card border-border">
        <CardHeader>
          <CardTitle>Registros Recentes</CardTitle>
        </CardHeader>
        <CardContent className="p-2 sm:p-3 md:p-4 lg:p-6">
          <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
            <Tabs value={recentTab} onValueChange={(v) => setRecentTab(v as 'appointments' | 'products')} className="w-full">
              <TabsList className="mb-4">
                <TabsTrigger value="appointments" className="text-xs sm:text-sm">Agendamentos</TabsTrigger>
                <TabsTrigger value="products" className="text-xs sm:text-sm">Produtos</TabsTrigger>
              </TabsList>
              <TabsContent value="appointments">
                <div className="overflow-x-auto">
                  <table className="w-full text-sm" style={{ tableLayout: 'fixed', minWidth: '600px' }}>
                    <thead>
                      <tr className="border-b border-border">
                        <th className="text-left py-3 px-2">Data</th>
                        <th className="text-left py-3 px-2">Horário</th>
                        <th className="text-left py-3 px-2">Serviço</th>
                        <th className="text-left py-3 px-2">Barbeiro</th>
                        <th className="text-left py-3 px-2">Tipo</th>
                        <th className="text-left py-3 px-2">Pagamento</th>
                        <th className="text-left py-3 px-2">Status</th>
                        <th className="text-right py-3 px-2">Valor</th>
                      </tr>
                    </thead>
                    <tbody>
                      {appointments.slice(0, 10).map((apt) => (
                        <tr key={apt.id} className="border-b border-border/50 hover:bg-muted/50">
                          <td className="py-3 px-2">
                            {format(new Date(apt.appointment_date + 'T00:00:00'), 'dd/MM/yyyy')}
                          </td>
                          <td className="py-3 px-2">{apt.appointment_time}</td>
                          <td className="py-3 px-2">{(apt.service as any)?.title || '-'}</td>
                          <td className="py-3 px-2">{(apt.barber as any)?.name || '-'}</td>
                          <td className="py-3 px-2">
                            <span
                              className={`px-2 py-1 rounded text-xs font-medium ${
                                apt.booking_type === 'local'
                                  ? 'bg-primary/20 text-primary'
                                  : apt.booking_type === 'manual'
                                  ? 'bg-orange-500/20 text-orange-400 border border-orange-500/30'
                                  : 'bg-blue-500/20 text-blue-400'
                              }`}
                              title={
                                apt.booking_type === 'manual'
                                  ? 'Agendamento criado manualmente pelo barbeiro (retroativo)'
                                  : ''
                              }
                            >
                              {apt.booking_type === 'local'
                                ? 'Local'
                                : apt.booking_type === 'manual'
                                ? '📝 Manual'
                                : 'Online'}
                            </span>
                          </td>
                          <td className="py-3 px-2">
                            {apt.appointment_payments && apt.appointment_payments.length > 0 ? (
                              <div className="flex flex-col gap-1">
                                {apt.appointment_payments.map((p, idx) => (
                                  <span key={idx} className="text-xs text-muted-foreground whitespace-nowrap">
                                    {p.payment_method === 'pix'
                                      ? 'Pix'
                                      : p.payment_method === 'cartao'
                                      ? 'Cartão'
                                      : p.payment_method === 'dinheiro'
                                      ? 'Dinheiro'
                                      : 'Outro'}
                                    : R$ {Number(p.amount).toFixed(2)}
                                  </span>
                                ))}
                              </div>
                            ) : (
                              <span className="text-xs text-muted-foreground">
                                {apt.payment_method ? (
                                  <>
                                    {apt.payment_method === 'pix'
                                      ? 'Pix'
                                      : apt.payment_method === 'cartao'
                                      ? 'Cartão'
                                      : apt.payment_method === 'dinheiro'
                                      ? 'Dinheiro'
                                      : apt.payment_method}
                                  </>
                                ) : (
                                  '-'
                                )}
                              </span>
                            )}
                          </td>
                          <td className="py-3 px-2">
                            <span
                              className={`px-2 py-1 rounded text-xs font-medium ${
                                apt.status === 'confirmed'
                                  ? 'bg-green-500/20 text-green-400'
                                  : apt.status === 'completed'
                                  ? 'bg-primary/20 text-primary'
                                  : apt.status === 'cancelled'
                                  ? 'bg-red-500/20 text-red-400'
                                  : 'bg-yellow-500/20 text-yellow-400'
                              }`}
                            >
                              {apt.status === 'confirmed'
                                ? 'Confirmado'
                                : apt.status === 'completed'
                                ? 'Concluído'
                                : apt.status === 'cancelled'
                                ? 'Cancelado'
                                : 'Pendente'}
                            </span>
                          </td>
                          <td className="py-3 px-2 text-right font-medium text-primary">
                            R$ {((apt.service as any)?.price || 0).toFixed(2)}
                          </td>
                        </tr>
                      ))}
                      {appointments.length === 0 && (
                        <tr>
                          <td colSpan={8} className="py-8 text-center text-muted-foreground">
                            Nenhum agendamento encontrado
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </TabsContent>
              <TabsContent value="products">
                <div className="overflow-x-auto">
                  <table className="w-full text-sm" style={{ tableLayout: 'fixed', minWidth: '600px' }}>
                    <thead>
                      <tr className="border-b border-border">
                        <th className="text-left py-3 px-2">Data</th>
                        <th className="text-left py-3 px-2">Hora</th>
                        <th className="text-left py-3 px-2">Produto</th>
                        <th className="text-left py-3 px-2">Barbeiro</th>
                        <th className="text-right py-3 px-2">Total</th>
                        <th className="text-right py-3 px-2">Comissão</th>
                      </tr>
                    </thead>
                    <tbody>
                      {productSales.slice(0, 10).map((sale) => (
                        <tr key={sale.id} className="border-b border-border/50 hover:bg-muted/50">
                          <td className="py-3 px-2">
                            {format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM/yyyy')}
                          </td>
                          <td className="py-3 px-2">{sale.sale_time}</td>
                          <td className="py-3 px-2">{(sale.product as any)?.name || '-'}</td>
                          <td className="py-3 px-2">{(sale.barber as any)?.name || '-'}</td>
                          <td className="py-3 px-2 text-right">
                            R$ {Number(sale.total_price || 0).toFixed(2)}
                          </td>
                          <td className="py-3 px-2 text-right">
                            R$ {Number(sale.commission_value || 0).toFixed(2)}
                          </td>
                        </tr>
                      ))}
                      {productSales.length === 0 && (
                        <tr>
                          <td colSpan={6} className="py-8 text-center text-muted-foreground">
                            Nenhuma venda de produto encontrada
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </TabsContent>
            </Tabs>
          </div>
        </CardContent>
      </Card>
      <Dialog open={manualDialogOpen} onOpenChange={setManualDialogOpen}>
        <DialogContent className="max-w-md w-[95vw]">
          <DialogHeader>
            <DialogTitle>
              {manualType === 'service' ? 'Lançar venda de serviço' : 'Lançar venda de produto'}
            </DialogTitle>
            <DialogDescription>
              Lançamento manual vinculado ao barbeiro selecionado.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div>
              <label className="text-xs text-muted-foreground mb-1 block">Barbeiro</label>
              <Input
                value={barbers.find(b => b.id === manualBarberId)?.name || ''}
                readOnly
                className="h-9 text-sm"
              />
            </div>
            {manualType === 'service' ? (
              <>
                <div>
                  <label className="text-xs text-muted-foreground mb-1 block">Serviço</label>
                  <Select value={manualServiceId} onValueChange={setManualServiceId}>
                    <SelectTrigger className="h-9 text-sm">
                      <SelectValue placeholder="Selecione um serviço" />
                    </SelectTrigger>
                    <SelectContent>
                      {services.map((s) => (
                        <SelectItem key={s.id} value={s.id}>
                          {s.title}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-xs text-muted-foreground mb-1 block">Nome do cliente (opcional)</label>
                  <Input
                    value={manualClientName}
                    onChange={(e) => setManualClientName(e.target.value)}
                    placeholder="Ex: Cliente local"
                    className="h-9 text-sm"
                  />
                </div>
              </>
            ) : (
              <>
                <div>
                  <label className="text-xs text-muted-foreground mb-1 block">Produto</label>
                  <Select value={manualProductId} onValueChange={setManualProductId}>
                    <SelectTrigger className="h-9 text-sm">
                      <SelectValue placeholder="Selecione um produto" />
                    </SelectTrigger>
                    <SelectContent>
                      {products.map((p) => (
                        <SelectItem key={p.id} value={p.id}>
                          {p.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-xs text-muted-foreground mb-1 block">Quantidade</label>
                  <Input
                    type="number"
                    min={1}
                    value={manualQuantity}
                    onChange={(e) => setManualQuantity(parseInt(e.target.value) || 1)}
                    className="h-9 text-sm"
                  />
                </div>
              </>
            )}
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="text-xs text-muted-foreground mb-1 block">Data</label>
                <Input
                  type="date"
                  value={manualDate}
                  onChange={(e) => setManualDate(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>
              <div>
                <label className="text-xs text-muted-foreground mb-1 block">Hora</label>
                <Input
                  type="time"
                  value={manualTime}
                  onChange={(e) => setManualTime(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setManualDialogOpen(false)} disabled={manualSaving}>
              Cancelar
            </Button>
            <Button onClick={handleSaveManualSale} disabled={manualSaving}>
              {manualSaving ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  Salvando...
                </>
              ) : (
                'Salvar lançamento'
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );

  return (
    <div className="space-y-4 sm:space-y-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
      {isManager ? (
        <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as 'overview' | 'commissions' | 'advances' | 'expenses' | 'reports')} className="w-full" style={{ maxWidth: '100%' }}>
          <TabsList className="grid w-full max-w-full grid-cols-5">
            <TabsTrigger value="overview" className="text-xs sm:text-sm">Visão Geral</TabsTrigger>
            <TabsTrigger value="commissions" className="text-xs sm:text-sm">Comissões</TabsTrigger>
            <TabsTrigger value="advances" className="text-xs sm:text-sm">Vales</TabsTrigger>
            <TabsTrigger value="expenses" className="text-xs sm:text-sm">Despesas</TabsTrigger>
            <TabsTrigger value="reports" className="text-xs sm:text-sm">Relatórios</TabsTrigger>
          </TabsList>
          
          <TabsContent value="overview" className="space-y-4 sm:space-y-6 mt-4 sm:mt-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
            {renderContent()}
          </TabsContent>
          
          <TabsContent value="commissions" className="space-y-4 sm:space-y-6 mt-4 sm:mt-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
            <IndividualCommissionManager />
          </TabsContent>
          
          <TabsContent value="advances" className="space-y-4 sm:space-y-6 mt-4 sm:mt-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
            <BarberAdvancesManager />
          </TabsContent>

          <TabsContent value="expenses" className="space-y-4 sm:space-y-6 mt-4 sm:mt-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
            <OperationalExpensesManager />
          </TabsContent>
          
          <TabsContent value="reports" className="space-y-4 sm:space-y-6 mt-4 sm:mt-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
            <ReportsManager />
          </TabsContent>
        </Tabs>
      ) : (
        <div className="space-y-4 sm:space-y-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
          {renderContent()}
        </div>
      )}
    </div>
  );
};

export default FinancialDashboard;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useBarberCommissions } from '@/hooks/useBarberCommissions';
import { useBarberProductCommissions } from '@/hooks/useBarberProductCommissions';
import { toast } from 'sonner';
import { Save, DollarSign, Loader2, Scissors, ShoppingBag, Plus } from 'lucide-react';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

interface Barber {
  id: string;
  name: string;
}

interface Service {
  id: string;
  title: string;
  price: number;
}

interface Product {
  id: string;
  name: string;
  price: number;
}

export const IndividualCommissionManager = () => {
  const { 
    commissions: serviceCommissions, 
    loading: serviceCommissionsLoading, 
    loadAllCommissions: loadAllServiceCommissions,
    updateCommission: updateServiceCommission
  } = useBarberCommissions(null);

  const { 
    commissions: productCommissions, 
    loading: productCommissionsLoading, 
    loadAllCommissions: loadAllProductCommissions,
    updateCommission: updateProductCommission
  } = useBarberProductCommissions(null);
  
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);

  // Local state for commission values (for editing)
  // Format: { "barberId-serviceId": percentage }
  const [serviceCommissionValues, setServiceCommissionValues] = useState<Record<string, number>>({});
  const [productCommissionValues, setProductCommissionValues] = useState<Record<string, number>>({});

  useEffect(() => {
    loadData();
    loadAllServiceCommissions();
    loadAllProductCommissions();
  }, []);

  // Realtime subscriptions
  useEffect(() => {
    const makeGuard = (ch: ReturnType<typeof supabase.channel>) => {
      let removed = false;
      ch.subscribe((status: string) => {
        if ((status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') && !removed) {
          removed = true;
          setTimeout(() => { try { supabase.removeChannel(ch); } catch { /* ignore */ } }, 0);
        }
      });
      return { ch, setRemoved: () => { removed = true; } };
    };

    const { ch: barbersChannel, setRemoved: r1 } = makeGuard(
      supabase.channel('individual-commission-manager-barbers')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'barbers' }, () => { loadData(); })
    );
    const { ch: servicesChannel, setRemoved: r2 } = makeGuard(
      supabase.channel('individual-commission-manager-services')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'services' }, () => { loadData(); })
    );
    const { ch: productsChannel, setRemoved: r3 } = makeGuard(
      supabase.channel('individual-commission-manager-products')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => { loadData(); })
    );
    const { ch: serviceCommissionsChannel, setRemoved: r4 } = makeGuard(
      supabase.channel('individual-commission-manager-service-commissions')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'barber_commissions' }, () => { loadAllServiceCommissions(); })
    );
    const { ch: productCommissionsChannel, setRemoved: r5 } = makeGuard(
      supabase.channel('individual-commission-manager-product-commissions')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'barber_product_commissions' }, () => { loadAllProductCommissions(); })
    );

    return () => {
      [r1, r2, r3, r4, r5].forEach(r => r());
      [barbersChannel, servicesChannel, productsChannel, serviceCommissionsChannel, productCommissionsChannel]
        .forEach(ch => { try { supabase.removeChannel(ch); } catch { /* ignore */ } });
    };
  }, []);

  // Initialize commission values from loaded commissions
  useEffect(() => {
    if (barbers.length === 0 || services.length === 0) return;
    
    setServiceCommissionValues(prev => {
      const updated = { ...prev };
      barbers.forEach(barber => {
        services.forEach(service => {
          const key = `${barber.id}-${service.id}`;
          if (!(key in updated)) {
            const commission = serviceCommissions.find(
              c => c.barber_id === barber.id && c.service_id === service.id
            );
            updated[key] = commission?.commission_percentage ?? 0;
          }
        });
      });
      return updated;
    });
  }, [serviceCommissions, barbers, services]);

  useEffect(() => {
    if (barbers.length === 0 || products.length === 0) return;
    
    setProductCommissionValues(prev => {
      const updated = { ...prev };
      barbers.forEach(barber => {
        products.forEach(product => {
          const key = `${barber.id}-${product.id}`;
          if (!(key in updated)) {
            const commission = productCommissions.find(
              c => c.barber_id === barber.id && c.product_id === product.id
            );
            updated[key] = commission?.commission_percentage ?? 0;
          }
        });
      });
      return updated;
    });
  }, [productCommissions, barbers, products]);

  const loadData = async () => {
    setLoading(true);
    
    try {
      // Load barbers
      const { data: barbersData } = await supabase
        .from('barbers')
        .select('id, name')
        .eq('visible', true)
        .order('order_index');

      setBarbers(barbersData || []);

      // Load services
      const { data: servicesData } = await supabase
        .from('services')
        .select('id, title, price')
        .eq('visible', true)
        .order('order_index');

      setServices(servicesData || []);

      // Load products
      const { data: productsData } = await supabase
        .from('products')
        .select('id, name, price')
        .eq('visible', true)
        .order('name');

      setProducts(productsData || []);
    } catch (error) {
      console.error('Error loading data:', error);
      toast.error('Erro ao carregar dados');
    } finally {
      setLoading(false);
    }
  };

  const handleServiceCommissionChange = (barberId: string, serviceId: string, value: string) => {
    const numValue = parseFloat(value) || 0;
    if (numValue < 0 || numValue > 100) {
      toast.error('Percentual deve estar entre 0 e 100');
      return;
    }

    const key = `${barberId}-${serviceId}`;
    setServiceCommissionValues(prev => ({
      ...prev,
      [key]: numValue,
    }));
  };

  const handleProductCommissionChange = (barberId: string, productId: string, value: string) => {
    const numValue = parseFloat(value) || 0;
    if (numValue < 0 || numValue > 100) {
      toast.error('Percentual deve estar entre 0 e 100');
      return;
    }

    const key = `${barberId}-${productId}`;
    setProductCommissionValues(prev => ({
      ...prev,
      [key]: numValue,
    }));
  };

  const handleSaveServiceCommission = async (barberId: string, serviceId: string) => {
    const key = `${barberId}-${serviceId}`;
    const percentage = serviceCommissionValues[key] ?? 0;

    if (percentage < 0 || percentage > 100) {
      toast.error('Percentual deve estar entre 0 e 100');
      return;
    }

    setSaving(key);
    const { error } = await updateServiceCommission(barberId, serviceId, percentage);

    if (error) {
      toast.error(error.message || 'Erro ao salvar comissão');
    } else {
      toast.success('Comissão salva com sucesso!');
    }

    setSaving(null);
  };

  const handleSaveProductCommission = async (barberId: string, productId: string) => {
    const key = `${barberId}-${productId}`;
    const percentage = productCommissionValues[key] ?? 0;

    if (percentage < 0 || percentage > 100) {
      toast.error('Percentual deve estar entre 0 e 100');
      return;
    }

    setSaving(key);
    const { error } = await updateProductCommission(barberId, productId, percentage);

    if (error) {
      toast.error(error.message || 'Erro ao salvar comissão');
    } else {
      toast.success('Comissão salva com sucesso!');
    }

    setSaving(null);
  };

  if (loading || serviceCommissionsLoading || productCommissionsLoading) {
    return (
      <Card className="bg-card border-border">
        <CardContent className="p-6">
          <div className="flex items-center justify-center">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
            <span className="ml-2 text-muted-foreground">Carregando comissões...</span>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (barbers.length === 0) {
    return (
      <Card className="bg-card border-border">
        <CardContent className="p-6">
          <p className="text-muted-foreground text-center">
            Nenhum barbeiro encontrado. Configure barbeiros primeiro.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="bg-card border-border w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
      <CardHeader className="w-full" style={{ maxWidth: '100%' }}>
        <CardTitle className="flex items-center gap-2 text-lg sm:text-xl">
          <DollarSign className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
          <span className="truncate">Configurar Comissões Individuais</span>
        </CardTitle>
        <CardDescription className="text-xs sm:text-sm break-words">
          Defina o percentual de comissão individualmente para cada barbeiro em cada serviço e produto.
          Exemplo: Corte de cabelo (R$ 25) pode ter 50% para um barbeiro e 40% para outro.
        </CardDescription>
      </CardHeader>
      <CardContent className="w-full p-3 sm:p-4 md:p-6" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
        <Tabs defaultValue="services" className="w-full" style={{ maxWidth: '100%' }}>
          <TabsList className="grid w-full max-w-full grid-cols-2 mb-4 sm:mb-6">
            <TabsTrigger value="services" className="flex items-center gap-1 sm:gap-2 text-xs sm:text-sm">
              <Scissors className="h-3 w-3 sm:h-4 sm:w-4" />
              <span className="hidden sm:inline">Comissão por Serviço</span>
              <span className="sm:hidden">Serviço</span>
            </TabsTrigger>
            <TabsTrigger value="products" className="flex items-center gap-1 sm:gap-2 text-xs sm:text-sm">
              <ShoppingBag className="h-3 w-3 sm:h-4 sm:w-4" />
              <span className="hidden sm:inline">Comissão por Produto</span>
              <span className="sm:hidden">Produto</span>
            </TabsTrigger>
          </TabsList>

          <TabsContent value="services" className="space-y-4">
            {services.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                Nenhum serviço encontrado. Configure serviços primeiro.
              </div>
            ) : (
              services.map(service => (
                <div key={service.id} className="rounded-lg border border-border p-2 sm:p-3 md:p-4 bg-secondary/20 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
                  <div className="flex items-center justify-between mb-3 sm:mb-4">
                    <div className="min-w-0 flex-1">
                      <h3 className="font-semibold text-base sm:text-lg truncate">{service.title}</h3>
                      <p className="text-xs sm:text-sm text-muted-foreground">
                        Preço: R$ {service.price.toFixed(2)}
                      </p>
                    </div>
                  </div>
                  <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                    <div className="relative w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                      <table className="w-full caption-bottom text-sm" style={{ tableLayout: 'fixed', width: '100%', maxWidth: '100%' }}>
                        <TableHeader>
                          <TableRow>
                            <TableHead className="px-1 sm:px-2" style={{ width: '30%' }}>Barbeiro</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '25%' }}>Comissão (%)</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '25%' }}>Valor</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '20%' }}>Ações</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {barbers.map(barber => {
                            const key = `${barber.id}-${service.id}`;
                            const isSaving = saving === key;
                            const percentage = serviceCommissionValues[key] ?? 
                              serviceCommissions.find(
                                c => c.barber_id === barber.id && c.service_id === service.id
                              )?.commission_percentage ?? 0;
                            const commissionValue = (service.price * percentage) / 100;

                            return (
                              <TableRow key={barber.id}>
                                <TableCell className="font-semibold px-1 sm:px-2">
                                  <span className="truncate block" title={barber.name}>{barber.name}</span>
                                </TableCell>
                                <TableCell className="px-1 sm:px-2">
                                  <div className="flex gap-1 sm:gap-2 items-center justify-center">
                                    <Input
                                      type="number"
                                      min="0"
                                      max="100"
                                      step="0.01"
                                      value={percentage}
                                      onChange={(e) => handleServiceCommissionChange(barber.id, service.id, e.target.value)}
                                      className="w-16 sm:w-20 text-center text-xs sm:text-sm h-8 sm:h-10"
                                      disabled={isSaving}
                                      placeholder="0"
                                    />
                                    <span className="text-xs sm:text-sm text-muted-foreground">%</span>
                                  </div>
                                </TableCell>
                                <TableCell className="text-center px-1 sm:px-2">
                                  <span className="font-semibold text-green-600 text-xs sm:text-sm">
                                    R$ {commissionValue.toFixed(2)}
                                  </span>
                                </TableCell>
                                <TableCell className="px-1 sm:px-2">
                                  <Button
                                    size="sm"
                                    onClick={() => handleSaveServiceCommission(barber.id, service.id)}
                                    disabled={isSaving}
                                    className="w-full h-8 sm:h-9 text-xs sm:text-sm"
                                  >
                                    {isSaving ? (
                                      <>
                                        <Loader2 className="h-3 w-3 animate-spin mr-1" />
                                        <span className="hidden sm:inline">Salvando...</span>
                                        <span className="sm:hidden">...</span>
                                      </>
                                    ) : (
                                      <>
                                        <Save className="h-3 w-3 mr-1" />
                                        <span className="hidden sm:inline">Salvar</span>
                                        <span className="sm:hidden">Salvar</span>
                                      </>
                                    )}
                                  </Button>
                                </TableCell>
                              </TableRow>
                            );
                          })}
                        </TableBody>
                      </table>
                    </div>
                  </div>
                </div>
              ))
            )}
          </TabsContent>

          <TabsContent value="products" className="space-y-4">
            {products.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                Nenhum produto encontrado. Configure produtos primeiro.
              </div>
            ) : (
              products.map(product => (
                <div key={product.id} className="rounded-lg border border-border p-2 sm:p-3 md:p-4 bg-secondary/20 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
                  <div className="flex items-center justify-between mb-3 sm:mb-4">
                    <div className="min-w-0 flex-1">
                      <h3 className="font-semibold text-base sm:text-lg truncate">{product.name}</h3>
                      <p className="text-xs sm:text-sm text-muted-foreground">
                        Preço: R$ {product.price.toFixed(2)}
                      </p>
                    </div>
                  </div>
                  <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                    <div className="relative w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                      <table className="w-full caption-bottom text-sm" style={{ tableLayout: 'fixed', width: '100%', maxWidth: '100%' }}>
                        <TableHeader>
                          <TableRow>
                            <TableHead className="px-1 sm:px-2" style={{ width: '30%' }}>Barbeiro</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '25%' }}>Comissão (%)</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '25%' }}>Valor</TableHead>
                            <TableHead className="text-center px-1 sm:px-2" style={{ width: '20%' }}>Ações</TableHead>
                          </TableRow>
                        </TableHeader>
                        <TableBody>
                          {barbers.map(barber => {
                            const key = `${barber.id}-${product.id}`;
                            const isSaving = saving === key;
                            const percentage = productCommissionValues[key] ?? 
                              productCommissions.find(
                                c => c.barber_id === barber.id && c.product_id === product.id
                              )?.commission_percentage ?? 0;
                            const commissionValue = (product.price * percentage) / 100;

                            return (
                              <TableRow key={barber.id}>
                                <TableCell className="font-semibold px-1 sm:px-2">
                                  <span className="truncate block" title={barber.name}>{barber.name}</span>
                                </TableCell>
                                <TableCell className="px-1 sm:px-2">
                                  <div className="flex gap-1 sm:gap-2 items-center justify-center">
                                    <Input
                                      type="number"
                                      min="0"
                                      max="100"
                                      step="0.01"
                                      value={percentage}
                                      onChange={(e) => handleProductCommissionChange(barber.id, product.id, e.target.value)}
                                      className="w-16 sm:w-20 text-center text-xs sm:text-sm h-8 sm:h-10"
                                      disabled={isSaving}
                                      placeholder="0"
                                    />
                                    <span className="text-xs sm:text-sm text-muted-foreground">%</span>
                                  </div>
                                </TableCell>
                                <TableCell className="text-center px-1 sm:px-2">
                                  <span className="font-semibold text-green-600 text-xs sm:text-sm">
                                    R$ {commissionValue.toFixed(2)}
                                  </span>
                                </TableCell>
                                <TableCell className="px-1 sm:px-2">
                                  <Button
                                    size="sm"
                                    onClick={() => handleSaveProductCommission(barber.id, product.id)}
                                    disabled={isSaving}
                                    className="w-full h-8 sm:h-9 text-xs sm:text-sm"
                                  >
                                    {isSaving ? (
                                      <>
                                        <Loader2 className="h-3 w-3 animate-spin mr-1" />
                                        <span className="hidden sm:inline">Salvando...</span>
                                        <span className="sm:hidden">...</span>
                                      </>
                                    ) : (
                                      <>
                                        <Save className="h-3 w-3 mr-1" />
                                        <span className="hidden sm:inline">Salvar</span>
                                        <span className="sm:hidden">Salvar</span>
                                      </>
                                    )}
                                  </Button>
                                </TableCell>
                              </TableRow>
                            );
                          })}
                        </TableBody>
                      </table>
                    </div>
                  </div>
                </div>
              ))
            )}
          </TabsContent>
        </Tabs>
      </CardContent>
    </Card>
  );
};

import { useState, useEffect } from "react";
import { getSiteConfig } from '@/lib/siteConfigCache';
import { Button } from "@/components/ui/button";
import { Scissors, Menu, X, LogOut, Home, ShoppingBag, Users, Calendar, Wifi, Star, Instagram, Facebook, QrCode, Copy, Smartphone } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useAuth } from "@/contexts/AuthContext";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { useNavigate } from "react-router-dom";
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import { useIsMobile } from "@/hooks/use-mobile";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [socialMenuOpen, setSocialMenuOpen] = useState(false);
  const [wifiCredentials, setWifiCredentials] = useState({ username: '', password: '' });
  const [socialLinks, setSocialLinks] = useState({ google: '', instagram: '', facebook: '' });
  const [wifiDialogOpen, setWifiDialogOpen] = useState(false);
  const [qrCodeDataUrl, setQrCodeDataUrl] = useState<string>('');
  const [userProfile, setUserProfile] = useState<{ name: string; photo_url: string | null } | null>(null);
  const { user, role, signOut } = useAuth();
  const navigate = useNavigate();
  const isMobile = useIsMobile();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    loadSocialConfig();
  }, []);

  useEffect(() => {
    if (user) {
      loadUserProfile();
    } else {
      setUserProfile(null);
    }
  }, [user, role]);

  useEffect(() => {
    const handleProfileUpdated = () => {
      if (user) {
        loadUserProfile();
      }
    };
    window.addEventListener("profile-updated", handleProfileUpdated);
    return () => {
      window.removeEventListener("profile-updated", handleProfileUpdated);
    };
  }, [user, role]);

  const loadSocialConfig = async () => {
    const config = await getSiteConfig('footer_info');
    if (config) {
      setWifiCredentials({
        username: config?.wifi?.username || '',
        password: config?.wifi?.password || '',
      });
      setSocialLinks({
        google: config?.social?.google_reviews || '',
        instagram: config?.social?.instagram || '',
        facebook: config?.social?.facebook || '',
      });
    }
  };

  const loadUserProfile = async () => {
    if (!user) return;
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("name, cpf, photo_url")
        .eq("id", user.id)
        .maybeSingle();

      const nameFromProfile = profile?.name?.trim() || "";
      const cpfFromProfile = profile?.cpf || "";
      const nameFromMeta = (user as any)?.user_metadata?.name?.trim() || "";
      const fallbackName = user.email?.split("@")[0] || "Usuário";
      const nameLooksLikeCpf =
        nameFromProfile && nameFromProfile.replace(/\D/g, "") === cpfFromProfile;

      let name = nameLooksLikeCpf
        ? (nameFromMeta || fallbackName)
        : (nameFromProfile || nameFromMeta || fallbackName);
      let photoUrl = profile?.photo_url || null;

      if (role === "barbeiro") {
        const { data: barber } = await supabase
          .from("barbers")
          .select("name, image_url")
          .eq("user_id", user.id)
          .maybeSingle();

        if (barber) {
          name = barber.name || name;
          photoUrl = barber.image_url || photoUrl;
        }
      }

      setUserProfile({ name, photo_url: photoUrl });
    } catch (error) {
      console.error("Error loading user profile:", error);
      setUserProfile({ name: user.email?.split("@")[0] || "Usuário", photo_url: null });
    }
  };

  const handleWifiClick = async () => {
    setSocialMenuOpen(false);
    
    // Verificar se tem credenciais configuradas
    if (!wifiCredentials.username || !wifiCredentials.password) {
      toast.error('Credenciais WiFi não configuradas pelo gestor');
      return;
    }

    // Gerar QR Code
    await generateWifiQRCode();
    setWifiDialogOpen(true);
  };

  // Escape special chars per WiFi QR Code spec: \ ; , " :
  const escapeWifi = (s: string) => s.replace(/([\\;,":'])/g, '\\$1');

  const generateWifiQRCode = async () => {
    try {
      // Formato padrão WiFi para QR Code (funciona em Android e iOS)
      const wifiString = `WIFI:T:WPA;S:${escapeWifi(wifiCredentials.username)};P:${escapeWifi(wifiCredentials.password)};H:;;`;
      
      // Gerar QR Code usando API pública (alternativa simples)
      const qrApiUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(wifiString)}`;
      setQrCodeDataUrl(qrApiUrl);
    } catch (error) {
      console.error('Erro ao gerar QR Code:', error);
      toast.error('Erro ao gerar QR Code WiFi');
    }
  };

  const copyWifiCredentials = async () => {
    try {
      const wifiString = `WIFI:T:WPA;S:${escapeWifi(wifiCredentials.username)};P:${escapeWifi(wifiCredentials.password)};H:;;`;
      await navigator.clipboard.writeText(wifiString);
      
      toast.success('✅ Credenciais copiadas!', {
        description: 'Cole em um leitor de QR Code ou configurações WiFi',
        duration: 3000,
      });
    } catch (error) {
      // Fallback para dispositivos que não suportam clipboard
      toast.info('📋 Credenciais WiFi', {
        description: `Rede: ${wifiCredentials.username}`,
        duration: 5000,
      });
    }
  };

  const connectToWifi = async () => {
    const wifiString = `WIFI:T:WPA;S:${escapeWifi(wifiCredentials.username)};P:${escapeWifi(wifiCredentials.password)};H:;;`;
    
    // Detectar dispositivo
    const isAndroid = navigator.userAgent.match(/Android/i);
    const isIOS = navigator.userAgent.match(/iPhone|iPad|iPod/i);
    
    try {
      // Copiar para clipboard primeiro
      await navigator.clipboard.writeText(wifiString);
      
      if (isAndroid) {
        // Android: Tentar abrir configurações WiFi (funciona em alguns navegadores)
        try {
          // Tentar abrir configurações WiFi diretamente
          window.open('intent://wifi#Intent;scheme=android.settings;package=com.android.settings;end');
        } catch (error) {
          // Fallback: Instruções
        }
        
        toast.success('📱 Android - Próximos Passos:', {
          description: '1. Abra Configurações > WiFi\n2. Cole os dados copiados\n3. Ou escaneie o QR Code com a câmera',
          duration: 6000,
        });
        
      } else if (isIOS) {
        // iOS: Tentar abrir configurações WiFi
        try {
          window.open('App-Prefs:root=WIFI');
        } catch (error) {
          // Fallback: Instruções
        }
        
        toast.success('📱 iPhone - Próximos Passos:', {
          description: '1. Abra Configurações > WiFi\n2. Ou escaneie o QR Code com a câmera (mais fácil)',
          duration: 6000,
        });
        
      } else {
        // Desktop
        toast.info('💻 Desktop - Use seu celular:', {
          description: 'Escaneie o QR Code com a câmera do seu celular para conectar automaticamente',
          duration: 5000,
        });
      }
      
      // Mostrar toast adicional sobre QR Code
      setTimeout(() => {
        toast.info('💡 Dica:', {
          description: 'Escanear o QR Code é mais rápido e conecta automaticamente!',
          duration: 4000,
        });
      }, 2000);
      
    } catch (error) {
      // Se não conseguir copiar, mostrar credenciais
      toast.info('📶 Credenciais WiFi:', {
        description: `Rede: ${wifiCredentials.username}\nEscaneie o QR Code para conectar automaticamente`,
        duration: 8000,
      });
    }
  };


  const handleSocialClick = (type: 'google' | 'instagram' | 'facebook') => {
    let url = '';
    
    if (type === 'google') {
      url = socialLinks.google;
    } else if (type === 'instagram') {
      url = socialLinks.instagram;
    } else if (type === 'facebook') {
      url = socialLinks.facebook;
    }

    if (url) {
      window.open(url, '_blank');
    } else {
      toast.error('Link não configurado');
    }
    setSocialMenuOpen(false);
  };

  const scrollToSection = (id: string) => {
    const currentPath = window.location.pathname;
    
    // Se não estiver na página inicial, navegue primeiro para lá
    if (currentPath !== '/') {
      navigate(`/#${id}`);
      setIsMobileMenuOpen(false);
      return;
    }
    
    // Se estiver na página inicial, apenas faça scroll
    setTimeout(() => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
    setIsMobileMenuOpen(false);
  };

  const handleDashboardClick = () => {
    // Cada tipo de usuário vai para seu próprio painel
    if (role === 'admin' || role === 'gestor') navigate('/admin');
    else if (role === 'barbeiro') navigate('/barbeiro');
    else navigate('/cliente');
  };

  return (
    <nav 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        isScrolled ? 'bg-background/95 backdrop-blur-md border-b border-border shadow-elegant' : 'bg-transparent'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4">
        <div className="flex items-center justify-between h-20">
          {/* Logo with Social Menu and Home Button */}
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              {(socialLinks.google || socialLinks.instagram || socialLinks.facebook || (wifiCredentials.username && wifiCredentials.password)) && (
                <Popover open={socialMenuOpen} onOpenChange={setSocialMenuOpen}>
                  <PopoverTrigger asChild>
                    <button className="flex items-center gap-2 hover:opacity-80 transition-opacity">
                      <div className="w-10 h-10 rounded-full bg-gradient-gold flex items-center justify-center cursor-pointer">
                        <Scissors className="w-5 h-5 text-primary-foreground" />
                      </div>
                    </button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-2 bg-card border-border" align="start">
                    <div className="flex flex-col gap-2">
                      {socialLinks.google && (
                        <button
                          onClick={() => handleSocialClick('google')}
                          className="flex items-center justify-center w-12 h-12 rounded-full border-2 border-primary/30 hover:border-primary hover:bg-primary/10 transition-all"
                          title="Google Avaliações"
                        >
                          <Star className="w-6 h-6 text-primary" />
                        </button>
                      )}
                      {socialLinks.instagram && (
                        <button
                          onClick={() => handleSocialClick('instagram')}
                          className="flex items-center justify-center w-12 h-12 rounded-full border-2 border-primary/30 hover:border-primary hover:bg-primary/10 transition-all"
                          title="Instagram"
                        >
                          <Instagram className="w-6 h-6 text-primary" />
                        </button>
                      )}
                      {socialLinks.facebook && (
                        <button
                          onClick={() => handleSocialClick('facebook')}
                          className="flex items-center justify-center w-12 h-12 rounded-full border-2 border-primary/30 hover:border-primary hover:bg-primary/10 transition-all"
                          title="Facebook"
                        >
                          <Facebook className="w-6 h-6 text-primary" />
                        </button>
                      )}
                      {(wifiCredentials.username && wifiCredentials.password) && (
                        <button
                          onClick={handleWifiClick}
                          className="flex items-center justify-center w-12 h-12 rounded-full border-2 border-primary/30 hover:border-primary hover:bg-primary/10 transition-all"
                          title="WiFi"
                        >
                          <Wifi className="w-6 h-6 text-primary" />
                        </button>
                      )}
                    </div>
                  </PopoverContent>
                </Popover>
              )}
              <span className="text-xl font-bold cursor-pointer" onClick={() => navigate('/')}>Barbearia Raimundos</span>
            </div>
            
            {/* Dashboard Button (replace Home) */}
            <Button
              onClick={handleDashboardClick}
              variant="outline"
              size="sm"
              className="flex items-center gap-2 border-primary/30 hover:border-primary hover:bg-primary/10 text-primary hover:text-primary transition-all duration-300"
            >
              <Users className="w-4 h-4" />
              <span className="font-medium">Meu Painel</span>
            </Button>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center gap-8">
            <button onClick={() => navigate('/servicos')} className="text-muted-foreground hover:text-primary transition-colors">
              Nossos Serviços
            </button>
            <button onClick={() => navigate('/fila')} className="text-muted-foreground hover:text-primary transition-colors flex items-center gap-1">
              <Scissors className="w-4 h-4" />
              Fila
            </button>
            <button onClick={() => navigate('/shop')} className="text-muted-foreground hover:text-primary transition-colors">
              Shop
            </button>
            <button onClick={() => navigate('/equipe')} className="text-muted-foreground hover:text-primary transition-colors">
              Equipe
            </button>
            {user ? (
              <>
                <Button 
                  onClick={handleDashboardClick}
                  className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-gold transition-all duration-300 hover:scale-105"
                >
                  Meu Painel
                </Button>
                {userProfile && (
                  <div className="flex items-center gap-2 px-3 py-2 rounded-lg bg-secondary/30 border border-border/50">
                    <Avatar className="h-8 w-8">
                      {userProfile.photo_url ? (
                        <AvatarImage src={userProfile.photo_url} alt={userProfile.name} />
                      ) : null}
                      <AvatarFallback className="bg-primary/20 text-primary text-xs font-semibold">
                        {userProfile.name.charAt(0).toUpperCase()}
                      </AvatarFallback>
                    </Avatar>
                    {!isMobile && (
                      <span className="text-sm font-medium text-foreground max-w-[120px] truncate">
                        {userProfile.name}
                      </span>
                    )}
                  </div>
                )}
                <Button 
                  onClick={signOut}
                  variant="outline"
                  className="transition-all duration-300 hover:scale-105"
                >
                  <LogOut className="mr-2 h-4 w-4" />
                  Sair
                </Button>
              </>
            ) : (
              <>
                <Button 
                  onClick={() => scrollToSection('agendamento')}
                  className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-gold transition-all duration-300 hover:scale-105"
                >
                  Agendar
                </Button>
                <Button 
                  onClick={() => navigate('/auth')}
                  variant="outline"
                  className="transition-all duration-300 hover:scale-105"
                >
                  Entrar
                </Button>
              </>
            )}
          </div>

          {/* Mobile/Tablet User + Menu */}
          <div className="md:hidden flex items-center gap-2">
            {userProfile && (
              <Avatar className="h-9 w-9">
                {userProfile.photo_url ? (
                  <AvatarImage src={userProfile.photo_url} alt={userProfile.name} />
                ) : null}
                <AvatarFallback className="bg-primary/20 text-primary text-xs font-semibold">
                  {userProfile.name.charAt(0).toUpperCase()}
                </AvatarFallback>
              </Avatar>
            )}
            <button 
              className="text-foreground hover:text-primary transition-colors p-2 rounded-lg hover:bg-primary/10"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-label="Menu"
            >
              <Menu className="w-6 h-6" />
            </button>
          </div>
        </div>

        {/* Mobile/Tablet Sidebar Menu */}
        <Sheet open={isMobileMenuOpen} onOpenChange={setIsMobileMenuOpen}>
          <SheetContent 
            side="left" 
            className="w-[85vw] max-w-sm bg-gradient-to-br from-background via-background to-background/95 backdrop-blur-xl border-r border-border/50 overflow-y-auto flex flex-col p-0"
            style={{
              boxShadow: '0 0 0 1px rgba(255, 215, 0, 0.1), 0 25px 50px -12px rgba(0, 0, 0, 0.5), 0 0 100px rgba(255, 215, 0, 0.05)',
            }}
          >
            <div className="flex-1 overflow-y-auto px-6 py-6">
            <SheetHeader className="mb-6 pb-6 border-b border-border/50">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-full bg-gradient-gold flex items-center justify-center shadow-gold">
                  <Scissors className="w-6 h-6 text-primary-foreground" />
                </div>
                <div>
                  <SheetTitle className="text-xl font-bold text-foreground">Barbearia Raimundos</SheetTitle>
                </div>
              </div>
            </SheetHeader>

            <div className="flex flex-col gap-2">
              {/* Navigation Items */}
              <button 
                onClick={() => {
                  handleDashboardClick();
                  setIsMobileMenuOpen(false);
                }}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
              >
                <Users className="w-5 h-5 group-hover:scale-110 transition-transform" />
                <span className="font-medium">Meu Painel</span>
              </button>

              <button 
                onClick={() => {
                  navigate('/servicos');
                  setIsMobileMenuOpen(false);
                }}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
              >
                <Scissors className="w-5 h-5 group-hover:scale-110 transition-transform" />
                <span className="font-medium">Nossos Serviços</span>
              </button>

              <button 
                onClick={() => {
                  navigate('/fila');
                  setIsMobileMenuOpen(false);
                }}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
              >
                <Scissors className="w-5 h-5 group-hover:scale-110 transition-transform" />
                <span className="font-medium">Fila da Barbearia</span>
              </button>

              <button 
                onClick={() => {
                  navigate('/shop');
                  setIsMobileMenuOpen(false);
                }}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
              >
                <ShoppingBag className="w-5 h-5 group-hover:scale-110 transition-transform" />
                <span className="font-medium">Shop</span>
              </button>

              <button 
                onClick={() => {
                  navigate('/equipe');
                  setIsMobileMenuOpen(false);
                }}
                className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
              >
                <Users className="w-5 h-5 group-hover:scale-110 transition-transform" />
                <span className="font-medium">Equipe</span>
              </button>

              {user && (
                <button 
                  onClick={() => {
                    scrollToSection('agendamento');
                    setIsMobileMenuOpen(false);
                  }}
                  className="flex items-center gap-3 px-4 py-3 rounded-lg text-left text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 group"
                >
                  <Calendar className="w-5 h-5 group-hover:scale-110 transition-transform" />
                  <span className="font-medium">Agendar</span>
                </button>
              )}

              {/* Divider */}
              <div className="my-4 border-t border-border/50"></div>

              {/* User Actions */}
              {user ? (
                <>
                  {userProfile && (
                    <div className="flex items-center gap-3 px-4 py-3 rounded-lg bg-secondary/30 border border-border/50 mb-2">
                      <Avatar className="h-9 w-9">
                        {userProfile.photo_url ? (
                          <AvatarImage src={userProfile.photo_url} alt={userProfile.name} />
                        ) : null}
                        <AvatarFallback className="bg-primary/20 text-primary text-xs font-semibold">
                          {userProfile.name.charAt(0).toUpperCase()}
                        </AvatarFallback>
                      </Avatar>
                      <div className="min-w-0">
                        <div className="text-sm font-medium text-foreground truncate">
                          {userProfile.name}
                        </div>
                      </div>
                    </div>
                  )}
                  <Button 
                    onClick={() => {
                      handleDashboardClick();
                      setIsMobileMenuOpen(false);
                    }}
                    className="w-full bg-primary hover:bg-primary/90 text-primary-foreground shadow-gold transition-all duration-300 hover:scale-[1.02] justify-start gap-3 h-auto py-3"
                  >
                    <div className="w-5 h-5 rounded-full bg-primary-foreground/20 flex items-center justify-center">
                      <span className="text-xs">👤</span>
                    </div>
                    <span className="font-semibold">Meu Painel</span>
                  </Button>
                  <Button 
                    onClick={() => {
                      signOut();
                      setIsMobileMenuOpen(false);
                    }}
                    variant="outline"
                    className="w-full justify-start gap-3 h-auto py-3 border-border hover:bg-destructive/10 hover:text-destructive hover:border-destructive/50 transition-all duration-300"
                  >
                    <LogOut className="w-5 h-5" />
                    <span className="font-medium">Sair</span>
                  </Button>
                </>
              ) : (
                <>
                  <Button 
                    onClick={() => {
                      scrollToSection('agendamento');
                      setIsMobileMenuOpen(false);
                    }}
                    className="w-full bg-primary hover:bg-primary/90 text-primary-foreground shadow-gold transition-all duration-300 hover:scale-[1.02] justify-start gap-3 h-auto py-3"
                  >
                    <Calendar className="w-5 h-5" />
                    <span className="font-semibold">Agendar</span>
                  </Button>
                  <Button 
                    onClick={() => {
                      navigate('/auth');
                      setIsMobileMenuOpen(false);
                    }}
                    variant="outline"
                    className="w-full justify-start gap-3 h-auto py-3 border-border hover:bg-primary/10 hover:text-primary hover:border-primary transition-all duration-300"
                  >
                    <span className="font-medium">Entrar</span>
                  </Button>
                </>
              )}
            </div>

            </div>

            {/* Footer */}
            <div className="px-6 py-4 border-t border-border/50 bg-background/50">
              <p className="text-xs text-center text-muted-foreground">
                © {new Date().getFullYear()} Barbearia Raimundos
              </p>
          </div>
          </SheetContent>
        </Sheet>
      </div>

      {/* Modal WiFi */}
      <Dialog open={wifiDialogOpen} onOpenChange={setWifiDialogOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Wifi className="w-5 h-5 text-primary" />
              Conectar ao WiFi
            </DialogTitle>
            <DialogDescription>
              Escaneie o QR Code ou use as instruções abaixo para conectar à rede.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-6 py-4">
            {/* QR Code */}
            <div className="flex flex-col items-center space-y-4">
              <div className="p-4 bg-white rounded-lg border-2 border-border">
                {qrCodeDataUrl ? (
                  <img 
                    src={qrCodeDataUrl} 
                    alt="QR Code WiFi" 
                    className="w-48 h-48"
                  />
                ) : (
                  <div className="w-48 h-48 flex items-center justify-center bg-secondary rounded">
                    <QrCode className="w-12 h-12 text-muted-foreground" />
                  </div>
                )}
              </div>
              
              <div className="text-center space-y-2">
                <h3 className="font-semibold text-lg">Escaneie para Conectar</h3>
                <p className="text-sm text-muted-foreground">
                  Use a câmera do seu celular para escanear o QR Code
                </p>
              </div>
            </div>

            {/* Instruções por dispositivo */}
            <div className="space-y-3">
              <div className="flex items-start gap-3 p-3 bg-green-500/10 rounded-lg border border-green-500/20">
                <Smartphone className="w-5 h-5 text-green-500 mt-0.5 flex-shrink-0" />
                <div>
                  <p className="font-medium text-green-700 dark:text-green-400">Android</p>
                  <p className="text-sm text-green-600 dark:text-green-300">
                    Abra a câmera e aponte para o QR Code. Toque na notificação para conectar automaticamente.
                  </p>
                </div>
              </div>
              
              <div className="flex items-start gap-3 p-3 bg-blue-500/10 rounded-lg border border-blue-500/20">
                <Smartphone className="w-5 h-5 text-blue-500 mt-0.5 flex-shrink-0" />
                <div>
                  <p className="font-medium text-blue-700 dark:text-blue-400">iPhone/iPad</p>
                  <p className="text-sm text-blue-600 dark:text-blue-300">
                    Abra a câmera e aponte para o QR Code. Toque no banner que aparece para conectar.
                  </p>
                </div>
              </div>
            </div>

            {/* Botões de ação */}
            <div className="flex flex-col gap-2">
              <a
                href={`WIFI:T:WPA;S:${escapeWifi(wifiCredentials.username)};P:${escapeWifi(wifiCredentials.password)};H:;;`}
                className="flex items-center justify-center gap-2 w-full py-2.5 px-4 rounded-md bg-primary text-primary-foreground font-semibold text-sm hover:bg-primary/90 transition-colors"
              >
                <Wifi className="w-4 h-4" />
                Conectar ao WiFi
              </a>
              <div className="flex gap-2">
                <Button
                  onClick={async () => {
                    await navigator.clipboard.writeText(wifiCredentials.password);
                    toast.success('Senha copiada!', { duration: 2000 });
                  }}
                  variant="outline"
                  className="flex-1"
                >
                  <Copy className="w-4 h-4 mr-2" />
                  Copiar Senha
                </Button>
                <Button
                  onClick={copyWifiCredentials}
                  variant="outline"
                  className="flex-1"
                >
                  <Copy className="w-4 h-4 mr-2" />
                  Copiar Dados
                </Button>
              </div>
            </div>

            {/* Destaque para QR Code */}
            <div className="text-center p-4 bg-primary/10 rounded-lg border border-primary/20">
              <div className="flex items-center justify-center gap-2 mb-2">
                <QrCode className="w-5 h-5 text-primary" />
                <span className="font-semibold text-primary">Conexão Automática</span>
              </div>
              <p className="text-sm text-muted-foreground">
                <strong>Mais fácil:</strong> Escaneie o QR Code com a câmera do celular para conectar automaticamente sem digitar senha!
              </p>
            </div>

            {/* Informações da rede */}
            <div className="text-center p-3 bg-secondary/50 rounded-lg">
              <p className="text-sm text-muted-foreground">
                Rede: <span className="font-medium text-foreground">{wifiCredentials.username}</span>
              </p>
              <p className="text-xs text-muted-foreground mt-1">
                Conexão segura WPA/WPA2
              </p>
            </div>
          </div>
        </DialogContent>
      </Dialog>

    </nav>
  );
};

export default Navbar;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { toast } from 'sonner';
import { ShoppingBag, Plus, Loader2, DollarSign, Calendar, CheckCircle, XCircle, AlertCircle, Filter } from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { useBarberProductCommissions } from '@/hooks/useBarberProductCommissions';
import { useBarberFixedCommissions } from '@/hooks/useBarberFixedCommissions';
import { Badge } from '@/components/ui/badge';

interface Product {
  id: string;
  name: string;
  price: number;
  stock: number | null;
}

interface ProductSale {
  id: string;
  product_id: string;
  quantity: number;
  unit_price: number;
  total_price: number;
  commission_percentage: number;
  commission_value: number;
  sale_date: string;
  sale_time: string;
  product?: Product;
  status: 'pending' | 'confirmed' | 'cancelled';
  notes?: string;
}

interface ProductSalesManagerProps {
  barberId: string;
}

export const ProductSalesManager = ({ barberId }: ProductSalesManagerProps) => {
  const { getCommissionPercentage: getIndividualCommissionPercentage } = useBarberProductCommissions(barberId);
  const { getProductCommissionPercentage: getFixedCommissionPercentage } = useBarberFixedCommissions(barberId);
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<ProductSale[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const [dateFrom, setDateFrom] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [dateTo, setDateTo] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [statusFilter, setStatusFilter] = useState<'all' | 'confirmed' | 'pending' | 'cancelled'>('all');
  const [selectedProduct, setSelectedProduct] = useState<string>('');
  const [quantity, setQuantity] = useState<number>(1);
  const [saleDate, setSaleDate] = useState<string>(format(new Date(), 'yyyy-MM-dd'));
  const [saleTime, setSaleTime] = useState<string>(format(new Date(), 'HH:mm'));
  const [notes, setNotes] = useState<string>('');

  useEffect(() => {
    loadProducts();
    loadSales();
    
    // Subscribe to realtime changes
    let removed = false;
    const channel = supabase
      .channel('product_sales_changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'product_sales',
          filter: `barber_id=eq.${barberId}`,
        },
        () => { loadSales(); }
      )
      .subscribe((status: string) => {
        if ((status === 'CHANNEL_ERROR' || status === 'TIMED_OUT' || status === 'CLOSED') && !removed) {
          removed = true;
          setTimeout(() => { try { supabase.removeChannel(channel); } catch { /* ignore */ } }, 0);
        }
      });

    return () => {
      removed = true;
      try { supabase.removeChannel(channel); } catch { /* ignore */ }
    };
  }, [barberId]);

  const loadProducts = async () => {
    const { data, error } = await supabase
      .from('products')
      .select('id, name, price, stock')
      .eq('visible', true)
      .order('name');

    if (error) {
      console.error('Error loading products:', error);
      toast.error('Erro ao carregar produtos');
    } else {
      setProducts(data || []);
    }
  };

  const loadSales = async () => {
    setLoading(true);
    let query = supabase
      .from('product_sales')
      .select(`
        id,
        product_id,
        quantity,
        unit_price,
        total_price,
        commission_percentage,
        commission_value,
        sale_date,
        sale_time,
        notes,
        status,
        product:products(id, name, price, stock)
      `)
      .eq('barber_id', barberId);
    if (dateFrom && dateTo) {
      query = query.gte('sale_date', dateFrom).lte('sale_date', dateTo);
    }
    if (statusFilter !== 'all') {
      query = query.eq('status', statusFilter);
    }
    const { data, error } = await query
      .order('sale_date', { ascending: false })
      .order('sale_time', { ascending: false })
      .limit(50);

    if (error) {
      console.error('Error loading sales:', error);
      toast.error('Erro ao carregar vendas');
    } else {
      setSales((data as any) || []);
    }
    setLoading(false);
  };

  const handleUpdateStatus = async (saleId: string, newStatus: 'confirmed' | 'cancelled') => {
    try {
      let updateData: any = { status: newStatus };

      // Se estiver confirmando, recalcula a comissão com as taxas atuais
      if (newStatus === 'confirmed') {
        const sale = sales.find(s => s.id === saleId);
        if (sale) {
          const individualCommission = getIndividualCommissionPercentage(barberId, sale.product_id);
          const fixedCommission = getFixedCommissionPercentage(barberId);
          const commissionPercentage = individualCommission > 0 ? individualCommission : fixedCommission;
          const commissionValue = (sale.total_price * commissionPercentage) / 100;

          updateData = {
            ...updateData,
            commission_percentage: commissionPercentage,
            commission_value: commissionValue
          };
        }
      }

      const { error } = await supabase
        .from('product_sales')
        .update(updateData)
        .eq('id', saleId);

      if (error) throw error;

      toast.success(`Venda ${newStatus === 'confirmed' ? 'confirmada' : 'cancelada'} com sucesso!`);
      // No need to manually update stock here as the DB trigger handles it for confirmed sales
      
      loadSales();
    } catch (error) {
      console.error('Error updating status:', error);
      toast.error('Erro ao atualizar status da venda');
    }
  };

  const handleSaveSale = async () => {
    if (!selectedProduct) {
      toast.error('Selecione um produto');
      return;
    }

    if (quantity <= 0) {
      toast.error('Quantidade deve ser maior que zero');
      return;
    }

    const product = products.find(p => p.id === selectedProduct);
    if (!product) {
      toast.error('Produto não encontrado');
      return;
    }

    // Verificar estoque
    if (product.stock !== null && product.stock < quantity) {
      toast.error(`Estoque insuficiente. Disponível: ${product.stock}`);
      return;
    }

    setSaving(true);

    try {
      const unitPrice = product.price;
      const totalPrice = unitPrice * quantity;
      // Tenta usar comissão individual, se não houver usa comissão fixa
      const individualCommission = getIndividualCommissionPercentage(barberId, selectedProduct);
      const fixedCommission = getFixedCommissionPercentage(barberId);
      const commissionPercentage = individualCommission > 0 ? individualCommission : fixedCommission;
      const commissionValue = (totalPrice * commissionPercentage) / 100;

      const { error } = await supabase
        .from('product_sales')
        .insert({
          barber_id: barberId,
          product_id: selectedProduct,
          quantity,
          unit_price: unitPrice,
          total_price: totalPrice,
          commission_percentage: commissionPercentage,
          commission_value: commissionValue,
          sale_date: saleDate,
          sale_time: saleTime,
          notes: notes.trim() || null,
          status: 'confirmed', // Manual sales are auto-confirmed
        });

      if (error) throw error;

      // Stock update is handled by DB trigger when status is 'confirmed'

      toast.success('Venda registrada com sucesso!');
      setDialogOpen(false);
      resetForm();
      // loadSales will be triggered by realtime subscription, but we call it anyway for immediate feedback
      loadSales();
      loadProducts(); 
    } catch (error: any) {
      console.error('Error saving sale:', error);
      toast.error(error.message || 'Erro ao registrar venda');
    } finally {
      setSaving(false);
    }
  };

  const resetForm = () => {
    setSelectedProduct('');
    setQuantity(1);
    setSaleDate(format(new Date(), 'yyyy-MM-dd'));
    setSaleTime(format(new Date(), 'HH:mm'));
    setNotes('');
  };

  const selectedProductData = products.find(p => p.id === selectedProduct);
  const estimatedTotal = selectedProductData ? selectedProductData.price * quantity : 0;
  const estimatedCommission = selectedProductData ? (() => {
    const individualCommission = getIndividualCommissionPercentage(barberId, selectedProduct);
    const fixedCommission = getFixedCommissionPercentage(barberId);
    const commissionPercentage = individualCommission > 0 ? individualCommission : fixedCommission;
    return (estimatedTotal * commissionPercentage) / 100;
  })() : 0;
  
  const estimatedCommissionPercentage = selectedProductData ? (() => {
    const individualCommission = getIndividualCommissionPercentage(barberId, selectedProduct);
    const fixedCommission = getFixedCommissionPercentage(barberId);
    return individualCommission > 0 ? individualCommission : fixedCommission;
  })() : 0;

  return (
    <Card className="bg-card border-border w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
      <CardHeader className="w-full" style={{ maxWidth: '100%' }}>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="flex items-center gap-2 text-lg sm:text-xl">
              <ShoppingBag className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
              Vendas de Produtos
            </CardTitle>
            <CardDescription className="text-xs sm:text-sm">
              Registre vendas de produtos do shop e acompanhe suas comissões
            </CardDescription>
          </div>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              className="h-8 px-2 text-xs"
              onClick={() => setShowFilters(v => !v)}
            >
              <Filter className="h-3 w-3 mr-1" />
              {showFilters ? 'Ocultar filtros' : 'Mostrar filtros'}
            </Button>
            <Button onClick={() => setDialogOpen(true)} size="sm" className="flex-shrink-0">
            <Plus className="h-4 w-4 mr-2" />
            <span className="hidden sm:inline">Nova Venda</span>
            <span className="sm:hidden">Venda</span>
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent className="w-full p-3 sm:p-4 md:p-6" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
        <div className={`${showFilters ? '' : 'hidden'} mb-4 pb-3 border-b border-border`}>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <div>
              <Label className="text-xs text-muted-foreground mb-1 block">Data Inicial</Label>
              <Input type="date" value={dateFrom} onChange={(e) => setDateFrom(e.target.value)} />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground mb-1 block">Data Final</Label>
              <Input type="date" value={dateTo} onChange={(e) => setDateTo(e.target.value)} />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground mb-1 block">Status</Label>
              <Select value={statusFilter} onValueChange={(v) => setStatusFilter(v as any)}>
                <SelectTrigger className="h-9 text-xs">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="confirmed">Confirmado</SelectItem>
                  <SelectItem value="pending">Pendente</SelectItem>
                  <SelectItem value="cancelled">Cancelado</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>
          <div className="mt-3">
            <Button size="sm" variant="outline" onClick={loadSales}>Aplicar filtros</Button>
          </div>
        </div>
        {loading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
            <span className="ml-2 text-muted-foreground">Carregando vendas...</span>
          </div>
        ) : sales.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <ShoppingBag className="h-12 w-12 mx-auto mb-4 opacity-50" />
            <p>Nenhuma venda registrada ainda.</p>
            <p className="text-sm mt-2">Clique em "Nova Venda" para começar.</p>
          </div>
        ) : (
          <>
            {/* Desktop/Tablet */}
            <div className="hidden sm:block w-full overflow-hidden" style={{ maxWidth: '100%' }}>
              <div className="relative w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                <table className="w-full caption-bottom text-sm" style={{ tableLayout: 'fixed', width: '100%', maxWidth: '100%' }}>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="px-2" style={{ width: '15%' }}>Data</TableHead>
                      <TableHead className="px-2" style={{ width: '25%' }}>Produto</TableHead>
                      <TableHead className="text-center px-2" style={{ width: '10%' }}>Qtd</TableHead>
                      <TableHead className="text-right px-2" style={{ width: '15%' }}>Total</TableHead>
                      <TableHead className="text-right px-2" style={{ width: '15%' }}>Comissão</TableHead>
                      <TableHead className="text-center px-2" style={{ width: '10%' }}>Status</TableHead>
                      <TableHead className="text-center px-2" style={{ width: '10%' }}>Ações</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {sales.map((sale) => {
                      const product = sale.product as Product | undefined;
                      return (
                        <TableRow key={sale.id}>
                          <TableCell className="px-2">
                            <div className="text-sm">
                              <div>{format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}</div>
                              <div className="text-muted-foreground">{sale.sale_time}</div>
                            </div>
                          </TableCell>
                          <TableCell className="px-2">
                            <span className="truncate block text-sm" title={product?.name || 'Produto desconhecido'}>
                              {product?.name || 'Produto desconhecido'}
                            </span>
                            {sale.notes && (
                              <div className="text-xs text-muted-foreground truncate" title={sale.notes}>{sale.notes}</div>
                            )}
                          </TableCell>
                          <TableCell className="text-center px-2">
                            {sale.quantity}
                          </TableCell>
                          <TableCell className="text-right px-2">
                            <span className="font-semibold">
                              R$ {sale.total_price.toFixed(2)}
                            </span>
                          </TableCell>
                          <TableCell className="text-right px-2">
                            <span className="font-semibold text-green-600">
                              R$ {sale.commission_value.toFixed(2)}
                            </span>
                            <div className="text-xs text-muted-foreground">
                              ({sale.commission_percentage.toFixed(1)}%)
                            </div>
                          </TableCell>
                          <TableCell className="text-center px-2">
                            {sale.status === 'confirmed' && (
                              <Badge variant="default" className="bg-green-600 hover:bg-green-700 text-xs">Confirmado</Badge>
                            )}
                            {sale.status === 'pending' && (
                              <Badge variant="outline" className="border-yellow-500 text-yellow-600 bg-yellow-50 text-xs">Pendente</Badge>
                            )}
                            {sale.status === 'cancelled' && (
                              <Badge variant="destructive" className="text-xs">Cancelado</Badge>
                            )}
                          </TableCell>
                          <TableCell className="text-center px-2">
                            {sale.status === 'pending' && (
                              <div className="flex gap-1 justify-center">
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-8 w-8 text-green-600 hover:text-green-700 hover:bg-green-50"
                                  onClick={() => handleUpdateStatus(sale.id, 'confirmed')}
                                  title="Confirmar Venda"
                                >
                                  <CheckCircle className="h-4 w-4" />
                                </Button>
                                <Button
                                  size="icon"
                                  variant="ghost"
                                  className="h-8 w-8 text-red-600 hover:text-red-700 hover:bg-red-50"
                                  onClick={() => handleUpdateStatus(sale.id, 'cancelled')}
                                  title="Cancelar Venda"
                                >
                                  <XCircle className="h-4 w-4" />
                                </Button>
                              </div>
                            )}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </table>
              </div>
            </div>

            {/* Mobile cards */}
            <div className="sm:hidden space-y-3">
              {sales.map((sale) => {
                const product = sale.product as Product | undefined;
                return (
                  <div key={sale.id} className="rounded-lg border border-border p-3 bg-secondary/20">
                    <div className="flex items-start gap-3">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <p className="font-semibold text-sm truncate" title={product?.name || 'Produto desconhecido'}>
                            {product?.name || 'Produto desconhecido'}
                          </p>
                          <span className="text-xs text-muted-foreground">
                            {format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM', { locale: ptBR })} • {sale.sale_time}
                          </span>
                        </div>
                        {sale.notes && (
                          <p className="text-xs text-muted-foreground mt-1 truncate">{sale.notes}</p>
                        )}
                        <div className="mt-2 grid grid-cols-3 gap-2 items-center">
                          <div className="text-xs">
                            <span className="text-muted-foreground">Qtd</span>
                            <div className="font-medium">{sale.quantity}</div>
                          </div>
                          <div className="text-xs text-right">
                            <span className="text-muted-foreground">Total</span>
                            <div className="font-semibold">R$ {sale.total_price.toFixed(2)}</div>
                          </div>
                          <div className="text-xs text-right">
                            <span className="text-muted-foreground">Comissão</span>
                            <div className="font-semibold text-green-600">R$ {sale.commission_value.toFixed(2)}</div>
                          </div>
                        </div>
                      </div>
                    </div>
                    <div className="mt-3 flex items-center justify-between">
                      <div>
                        {sale.status === 'confirmed' && (
                          <Badge variant="default" className="bg-green-600 hover:bg-green-700 text-xs">Confirmado</Badge>
                        )}
                        {sale.status === 'pending' && (
                          <Badge variant="outline" className="border-yellow-500 text-yellow-600 bg-yellow-50 text-xs">Pendente</Badge>
                        )}
                        {sale.status === 'cancelled' && (
                          <Badge variant="destructive" className="text-xs">Cancelado</Badge>
                        )}
                      </div>
                      {sale.status === 'pending' && (
                        <div className="flex gap-2">
                          <Button
                            size="sm"
                            className="h-8 px-3 bg-green-600 hover:bg-green-700"
                            onClick={() => handleUpdateStatus(sale.id, 'confirmed')}
                          >
                            Confirmar
                          </Button>
                          <Button
                            size="sm"
                            variant="destructive"
                            className="h-8 px-3"
                            onClick={() => handleUpdateStatus(sale.id, 'cancelled')}
                          >
                            Cancelar
                          </Button>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}

        {/* Dialog para nova venda */}
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogContent className="max-w-md w-[95vw] overflow-hidden">
            <DialogHeader>
              <DialogTitle>Registrar Nova Venda</DialogTitle>
              <DialogDescription>
                Selecione o produto e informe a quantidade vendida
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              <div>
                <Label htmlFor="product">Produto *</Label>
                <Select value={selectedProduct} onValueChange={setSelectedProduct}>
                  <SelectTrigger id="product" className="w-full">
                    <SelectValue placeholder="Selecione um produto" />
                  </SelectTrigger>
                  <SelectContent>
                    {products.map((product) => (
                      <SelectItem key={product.id} value={product.id}>
                        {product.name} - R$ {product.price.toFixed(2)}
                        {product.stock !== null && ` (Estoque: ${product.stock})`}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label htmlFor="quantity">Quantidade *</Label>
                <Input
                  id="quantity"
                  type="number"
                  min="1"
                  value={quantity}
                  onChange={(e) => setQuantity(parseInt(e.target.value) || 1)}
                  className="w-full"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="saleDate">Data *</Label>
                  <Input
                    id="saleDate"
                    type="date"
                    value={saleDate}
                    onChange={(e) => setSaleDate(e.target.value)}
                    className="w-full"
                  />
                </div>
                <div>
                  <Label htmlFor="saleTime">Hora *</Label>
                  <Input
                    id="saleTime"
                    type="time"
                    value={saleTime}
                    onChange={(e) => setSaleTime(e.target.value)}
                    className="w-full"
                  />
                </div>
              </div>

              <div>
                <Label htmlFor="notes">Observações (opcional)</Label>
                <Input
                  id="notes"
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Ex: Cliente pagou em dinheiro"
                  className="w-full"
                />
              </div>

              {selectedProductData && (
                <div className="bg-secondary/50 p-4 rounded-lg space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>Subtotal:</span>
                    <span className="font-semibold">R$ {estimatedTotal.toFixed(2)}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span>Comissão ({estimatedCommissionPercentage.toFixed(1)}%):</span>
                    <span className="font-semibold text-green-600">R$ {estimatedCommission.toFixed(2)}</span>
                  </div>
                </div>
              )}
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setDialogOpen(false)} disabled={saving}>
                Cancelar
              </Button>
              <Button onClick={handleSaveSale} disabled={saving || !selectedProduct}>
                {saving ? (
                  <>
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                    Salvando...
                  </>
                ) : (
                  <>
                    <DollarSign className="h-4 w-4 mr-2" />
                    Registrar Venda
                  </>
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </CardContent>
    </Card>
  );
};

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { Loader2, X, ArrowLeft, Star, Scissors } from "lucide-react";
import { useOperatingHours, getDayKey } from "@/hooks/useOperatingHours";
import { useAuth } from "@/contexts/AuthContext";
import { getAvailableSlotsForBarber } from "@/utils/availability";

interface Barber {
  id: string;
  name: string;
  image_url: string | null;
  specialty: string;
  experience: string;
  rating: number | null;
}

interface Service {
  id: string;
  title: string;
  description: string;
  duration: number;
  price: number;
  image_url: string | null;
  icon: string;
}

interface QuickBookingDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  date: string;
  timeSlot?: string;
  preselectedBarberId?: string;
}

export const QuickBookingDialog = ({ open, onOpenChange, date, timeSlot = "", preselectedBarberId }: QuickBookingDialogProps) => {
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<"barber" | "time" | "client" | "service">("barber");
  const [selectedBarberId, setSelectedBarberId] = useState("");
  const [selectedTimeSlot, setSelectedTimeSlot] = useState("");
  const [selectedServiceId, setSelectedServiceId] = useState("");
  const [clientName, setClientName] = useState("");
  const [barberSlots, setBarberSlots] = useState<string[]>([]);
  const [loadingSlots, setLoadingSlots] = useState(false);
  const { operatingHours, getTimeSlotsForDate, isDateOpen } = useOperatingHours();
  const { user, role } = useAuth();
  const [currentUserBarberId, setCurrentUserBarberId] = useState<string>("");
  const [showCloseOption, setShowCloseOption] = useState(false);
  const [slotClosedInfo, setSlotClosedInfo] = useState<{ closed: boolean; breakId?: string; breakStart?: string; breakEnd?: string } | null>(null);
  const [slotState, setSlotState] = useState<Record<string, 'available' | 'break' | 'booked' | 'past'>>({});
  const [showAddPause, setShowAddPause] = useState(false);
  const [pauseStart, setPauseStart] = useState("");
  const [pauseEnd, setPauseEnd] = useState("");
  const [showReleaseMode, setShowReleaseMode] = useState(false);

  const isBarberPreselected = Boolean(preselectedBarberId);
  const effectiveTimeSlot = isBarberPreselected ? selectedTimeSlot : timeSlot;

  useEffect(() => {
    if (open) {
      loadBarbers();
      loadServices();
      setSelectedBarberId(preselectedBarberId ?? "");
      setSelectedTimeSlot("");
      setSelectedServiceId("");
      setClientName("");
      if (role === "barbeiro" && user?.id) {
        (async () => {
          const { data } = await (supabase as any)
            .from("barbers")
            .select("id")
            .eq("user_id", user.id)
            .maybeSingle();
          setCurrentUserBarberId(data?.id || "");
        })();
      } else {
        setCurrentUserBarberId("");
      }
      if (preselectedBarberId) {
        setStep("service");
      } else {
        setStep("barber");
      }
    }
  }, [open, preselectedBarberId]);

  const loadSlotsForBarber = async (barberId: string) => {
    setLoadingSlots(true);
    try {
      const dateObj = new Date(date + "T12:00:00");
      if (!isDateOpen(dateObj)) {
        setBarberSlots([]);
        setSlotState({});
        return;
      }
      // Respeitar disponibilidade diária do barbeiro (dias fechados e almoço)
      let lunchBreak: { start_time: string; end_time: string } | null = null;
      try {
        const barber = barbers.find(b => b.id === barberId) as any;
        if (barber?.availability) {
          const availability = typeof barber.availability === "string"
            ? JSON.parse(barber.availability)
            : barber.availability;
          const dayKey = getDayKey(dateObj) as any;
          const dayAvailability = availability?.[dayKey];
          if (dayAvailability?.closed) {
            setBarberSlots([]);
            setSlotState({});
            return;
          }
          if (dayAvailability?.hasLunchBreak && dayAvailability.lunchStart && dayAvailability.lunchEnd) {
            lunchBreak = {
              start_time: dayAvailability.lunchStart,
              end_time: dayAvailability.lunchEnd,
            };
          }
        }
        
        // Fallback para horário de almoço da loja se o barbeiro não tiver configurado
        if (!lunchBreak) {
          const { data: shopHours } = await supabase
            .from('site_config')
            .select('config_value')
            .eq('config_key', 'operating_hours')
            .maybeSingle();
          
          if (shopHours?.config_value) {
            const operatingHours = shopHours.config_value as any;
            const dayKey = getDayKey(dateObj) as any;
            const dayHours = operatingHours?.[dayKey];
            if (dayHours?.hasLunchBreak && dayHours.lunchStart && dayHours.lunchEnd) {
              lunchBreak = {
                start_time: dayHours.lunchStart,
                end_time: dayHours.lunchEnd,
              };
            }
          }
        }
      } catch (e) {
        console.warn("Falha ao validar disponibilidade do barbeiro no dia selecionado:", e);
      }
      const { data: appts } = await supabase
        .from("appointments")
        .select("appointment_time, services(duration)")
        .eq("barber_id", barberId)
        .eq("appointment_date", date)
        .neq("status", "cancelled");
      const barberAppointments = (appts ?? []).map((a: any) => ({
        appointment_time: a.appointment_time,
        duration: a.services?.duration,
      }));
      const { data: breaks } = await (supabase as any)
        .from("barber_breaks")
        .select("start_time, end_time")
        .eq("barber_id", barberId)
        .eq("date", date);

      const allSlots = getTimeSlotsForDate(dateObj);
      const now = new Date();
      const isToday = new Date().toISOString().split('T')[0] === date;
      const timeToMinutes = (t: string) => {
        const [h, m] = t.split(':').map(Number);
        return h * 60 + m;
      };
      const addMin = (t: string, mins: number) => {
        const h = Math.floor((timeToMinutes(t) + mins) / 60);
        const m = (timeToMinutes(t) + mins) % 60;
        return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
      };
      const apptRanges = barberAppointments.map(a => ({
        start: a.appointment_time,
        end: addMin(a.appointment_time, a.duration ?? 30)
      }));
      const combinedBreaks = [
        ...(breaks || []),
        ...(lunchBreak ? [lunchBreak] : []),
      ];
      const breakRanges = combinedBreaks.map((b: any) => ({ start: b.start_time, end: b.end_time }));
      
      const barber = barbers.find(b => b.id === barberId) as any;
      const availability = typeof barber?.availability === "string"
        ? JSON.parse(barber.availability)
        : barber?.availability;
      const dayKey = getDayKey(dateObj);
      const shopHours = operatingHours[dayKey];
      const dayAvailability = availability?.[dayKey];
      const barberOpen = dayAvailability?.open || shopHours.open;
      const barberClose = dayAvailability?.close || shopHours.close;

      const computeState = (slot: string): 'available'|'break'|'booked'|'past' => {
         // Check if slot is within barber's working hours
         if (slot < barberOpen || slot >= barberClose) return 'past';

         if (isToday) {
           const [ch, cm] = [now.getHours(), now.getMinutes()];
           const [sh, sm] = slot.split(':').map(Number);
           const slotTotalMinutes = sh * 60 + sm;
           const nowTotalMinutes = ch * 60 + cm;
           // Permitir agendar o slot atual se ainda estivermos nos primeiros 10 minutos dele
           if (slotTotalMinutes < (nowTotalMinutes - 10)) return 'past';
         }
         const slotEnd = addMin(slot, 30);
         const overlaps = (s1: string, e1: string, s2: string, e2: string) => s1 < e2 && e1 > s2;
         
         // Ensure slot doesn't end after barber's closing time
         if (slotEnd > barberClose) return 'past';

         if (breakRanges.some(r => overlaps(slot, slotEnd, r.start, r.end))) return 'break';
         if (apptRanges.some(r => overlaps(slot, slotEnd, r.start, r.end))) return 'booked';
         return 'available';
       };
      const states: Record<string,'available'|'break'|'booked'|'past'> = {};
      allSlots.forEach(s => { states[s] = computeState(s); });
      // Show only non-past slots
      let futureSlots = allSlots.filter(s => states[s] !== 'past');

      // Se um serviço foi selecionado, garantir que o bloco completo caiba sem conflito
      if (selectedServiceId) {
        const service = services.find(s => s.id === selectedServiceId);
        const duration = service?.duration ?? 30;
        const steps = Math.max(1, Math.ceil(duration / 30));
        const hasContinuousAvailability = (slot: string) => {
          let cursor = slot;
          for (let i = 0; i < steps; i++) {
            // Bloqueia se o slot não existir, se já estiver ocupado, se for pausa 
            // ou se estiver marcado como 'past' (fora do horário do barbeiro)
            if (!states[cursor] || states[cursor] !== 'available') {
              // Exceção: permite o primeiro slot se for 'available' (mesmo que os próximos sejam 'past')
              // Mas aqui queremos ser rígidos: todos os blocos do serviço devem ser 'available'
              return false;
            }
            cursor = addMin(cursor, 30);
          }
          return true;
        };
        futureSlots = futureSlots.filter(hasContinuousAvailability);
      }
      setSlotState(states);
      setBarberSlots(futureSlots);
    } catch (e) {
      console.error("Error loading barber slots:", e);
      setBarberSlots([]);
      setSlotState({});
    } finally {
      setLoadingSlots(false);
    }
  };

  const loadBarbers = async () => {
    const { data, error } = await supabase
      .from("barbers")
      .select("id, name, image_url, specialty, experience, rating, availability")
      .eq("visible", true)
      .order("order_index");

    if (error) {
      console.error("Error loading barbers:", error);
      return;
    }

    setBarbers(data || []);
  };

  const loadServices = async () => {
    // Load services
    const { data: servicesData, error: servicesError } = await supabase
      .from("services")
      .select("id, title, description, duration, price, image_url, icon")
      .eq("visible", true);

    if (servicesError) {
      console.error("Error loading services:", servicesError);
      return;
    }

    if (!servicesData || servicesData.length === 0) {
      setServices([]);
      return;
    }

    // Count appointments per service
    const { data: appointmentsData, error: appointmentsError } = await supabase
      .from("appointments")
      .select("service_id")
      .neq("status", "cancelled");

    if (appointmentsError) {
      console.error("Error loading appointments count:", appointmentsError);
      // If error, just use services with default order
      setServices(servicesData);
      return;
    }

    // Count occurrences of each service
    const serviceCounts = new Map<string, number>();
    appointmentsData?.forEach((apt: any) => {
      if (apt.service_id) {
        serviceCounts.set(apt.service_id, (serviceCounts.get(apt.service_id) || 0) + 1);
      }
    });

    // Sort services by usage count (most used first), then by order_index
    const sortedServices = servicesData.sort((a: any, b: any) => {
      const countA = serviceCounts.get(a.id) || 0;
      const countB = serviceCounts.get(b.id) || 0;
      
      // First sort by usage count (descending)
      if (countB !== countA) {
        return countB - countA;
      }
      
      // If same count, sort by order_index
      return (a.order_index || 0) - (b.order_index || 0);
    });

    setServices(sortedServices);
  };

  const handleBarberSelect = (barberId: string) => {
    setSelectedBarberId(barberId);
    setStep("service");
  };

  const handleTimeSelect = (slot: string) => {
    setSelectedTimeSlot(slot);
    if (role === "barbeiro" && selectedBarberId && selectedBarberId === currentUserBarberId) {
      setShowCloseOption(true);
      (async () => {
        try {
          const { data: breaks } = await (supabase as any)
            .from("barber_breaks")
            .select("id, start_time, end_time")
            .eq("barber_id", selectedBarberId)
            .eq("date", date);
          const timeToMinutes = (t: string) => {
            const [h, m] = t.split(":").map(Number);
            return h * 60 + m;
          };
          const slotStart = timeToMinutes(slot);
          const slotEnd = slotStart + 30;
          const found = (breaks || []).find((b: any) => {
            const bs = timeToMinutes(b.start_time);
            const be = timeToMinutes(b.end_time);
            return slotStart < be && slotEnd > bs;
          });
          if (found) {
            setSlotClosedInfo({ closed: true, breakId: found.id, breakStart: found.start_time, breakEnd: found.end_time });
          } else {
            setSlotClosedInfo({ closed: false });
          }
        } catch {
          setSlotClosedInfo({ closed: false });
        }
      })();
      return;
    }
    if (role === "gestor" || role === "admin") {
      if (selectedServiceId) {
        // Avança direto para criação do agendamento
        void (async () => {
          try {
            await handleSubmit(selectedServiceId);
          } catch (e) {
            // handleSubmit já mostra toasts
          }
        })();
      } else {
        // Se por algum motivo não houver serviço, volta para seleção
        setStep("service");
      }
      return;
    }
    setStep("client");
  };

  const handleClientNameNext = () => {
    if (role === "gestor" || role === "admin") {
      setStep("time");
    } else {
      setStep("service");
    }
  };

  const handleServiceSelect = async (serviceId: string) => {
    setSelectedServiceId(serviceId);
    if (!selectedBarberId) {
      toast.error("Selecione um barbeiro");
      setStep("barber");
      return;
    }
    await loadSlotsForBarber(selectedBarberId);
    if (role === "gestor" || role === "admin") {
      setStep("client");
    } else {
      setStep("time");
    }
  };

  const handleSubmit = async (serviceId: string) => {
    if (!selectedBarberId || !serviceId) {
      toast.error("Por favor, selecione o barbeiro e o serviço");
      return;
    }
    // Tornar a seleção do horário mais resiliente: usa o selecionado no passo atual,
    // depois o effectiveTimeSlot, e por fim o timeSlot vindo das props.
    const slotToUse = selectedTimeSlot || effectiveTimeSlot || timeSlot;
    if (!slotToUse) {
      toast.error("Por favor, selecione um horário");
      return;
    }

    setLoading(true);

    try {
      // Verificar se o dia está fechado para o barbeiro
      let lunchBreak: { start_time: string; end_time: string } | null = null;
      try {
        const barber = barbers.find(b => b.id === selectedBarberId) as any;
        const selectedDate = new Date(date + "T12:00:00");
        if (barber?.availability) {
          const availability = typeof barber.availability === "string"
            ? JSON.parse(barber.availability)
            : barber.availability;
          const dayKey = getDayKey(selectedDate) as any;
          if (availability?.[dayKey]?.closed) {
            toast.error("Barbeiro indisponível nesta data", {
              description: "Este barbeiro bloqueou a agenda para este dia.",
            });
            return;
          }
          if (availability?.[dayKey]?.hasLunchBreak && availability[dayKey].lunchStart && availability[dayKey].lunchEnd) {
            lunchBreak = {
              start_time: availability[dayKey].lunchStart,
              end_time: availability[dayKey].lunchEnd,
            };
          }
        }
        
        // Fallback para horário de almoço da loja
        if (!lunchBreak) {
          const { data: shopHours } = await supabase
            .from('site_config')
            .select('config_value')
            .eq('config_key', 'operating_hours')
            .maybeSingle();
          
          if (shopHours?.config_value) {
            const operatingHours = shopHours.config_value as any;
            const dayKey = getDayKey(selectedDate) as any;
            const dayHours = operatingHours?.[dayKey];
            if (dayHours?.hasLunchBreak && dayHours.lunchStart && dayHours.lunchEnd) {
              lunchBreak = {
                start_time: dayHours.lunchStart,
                end_time: dayHours.lunchEnd,
              };
            }
          }
        }
      } catch (e) {
        console.warn("Falha ao validar dia fechado no agendamento rápido:", e);
      }
      // Validações de conflito no momento do envio (paridade com online)
      const selectedService = services.find(s => s.id === serviceId);
      const newDuration = selectedService?.duration ?? 30;
      const timeToMinutes = (t: string) => {
        const [h, m] = t.split(':').map(Number);
        return h * 60 + m;
      };
      const newStart = timeToMinutes(slotToUse);
      const newEnd = newStart + newDuration;
      // 1) Conflito com agendamentos existentes (sobreposição de intervalos)
      const { data: appts } = await supabase
        .from('appointments')
        .select('appointment_time, services(duration)')
        .eq('barber_id', selectedBarberId)
        .eq('appointment_date', date)
        .neq('status', 'cancelled');
      const hasAppointmentOverlap = (appts || []).some((a: any) => {
        const aStart = timeToMinutes(a.appointment_time);
        const aEnd = aStart + (a.services?.duration ?? 30);
        return newStart < aEnd && newEnd > aStart;
      });
      if (hasAppointmentOverlap) {
        toast.error("Horário em conflito com outro atendimento", {
          description: "Escolha outro horário disponível.",
        });
        return;
      }
      // 2) Conflito com pausas/bloqueios
      const { data: breaks } = await (supabase as any)
        .from('barber_breaks')
        .select('start_time, end_time')
        .eq('barber_id', selectedBarberId)
        .eq('date', date);
      
      const combinedBreaks = [
        ...(breaks || []),
        ...(lunchBreak ? [lunchBreak] : []),
      ];

      const hasBreakOverlap = combinedBreaks.some((b: any) => {
        const bStart = timeToMinutes(b.start_time);
        const bEnd = timeToMinutes(b.end_time);
        return newStart < bEnd && newEnd > bStart;
      });
      if (hasBreakOverlap) {
        toast.error("Horário entra em uma pausa do barbeiro", {
          description: "Escolha outro horário ou ajuste as pausas.",
        });
        return;
      }
      // 3) Evitar horários passados (se for hoje)
      const isToday = new Date().toISOString().split('T')[0] === date;
      if (isToday) {
        const now = new Date();
        const nowMin = now.getHours() * 60 + now.getMinutes();
        if (newStart <= nowMin) {
          toast.error("Horário já passou. Selecione um horário futuro.");
          return;
        }
      }
      const localPhone = "00000000000";
      const localName = clientName.trim() || "LOCAL";


      const { data: existingProfile } = await supabase
        .from("profiles")
        .select("id")
        .eq("phone", localPhone)
        .maybeSingle();

      let clientId = existingProfile?.id;

      if (!clientId) {
        const tempEmail = `${localPhone}@local.com`;
        const { data: authData, error: authError } = await supabase.auth.signUp({
          email: tempEmail,
          password: localPhone,
          options: {
            data: {
              name: localName,
              phone: localPhone,
            },
          },
        });

        if (authError && !authError.message.includes("already registered")) {
          throw authError;
        }
        
        if (authError?.message.includes("already registered")) {
          const { data: profile } = await supabase
            .from("profiles")
            .select("id")
            .eq("phone", localPhone)
            .maybeSingle();
          clientId = profile?.id;
        } else {
          clientId = authData?.user?.id;
        }
      }

      if (!clientId) {
        throw new Error("Erro ao criar perfil");
      }

      const { data: newAppointment, error: appointmentError } = await supabase
        .from("appointments")
        .insert({
          client_id: clientId,
          barber_id: selectedBarberId,
          service_id: serviceId,
          appointment_date: date,
          appointment_time: slotToUse,
          booking_type: "local", // Mark as local booking - WILL trigger webhook
          status: "confirmed",
        })
        .select('id')
        .single();

      if (appointmentError) throw appointmentError;

      // Processamento em background para não travar a UI
      const runBackgroundNotifications = async () => {
        // Notify external webhook for UI-created appointments
        try {
          const selectedService = services.find(s => s.id === serviceId);
          const duration = selectedService?.duration || 30;
          
          // Usar formato local sem conversão para UTC para evitar discrepâncias de fuso horário no webhook
          const localStartTime = `${date}T${slotToUse}:00`;
          const startDateTime = new Date(localStartTime);
          const endDateTime = new Date(startDateTime.getTime() + duration * 60000);
          const localEndTime = `${date}T${endDateTime.getHours().toString().padStart(2, '0')}:${endDateTime.getMinutes().toString().padStart(2, '0')}:00`;

          // Get the current user (barber who created the local appointment)
          const { data: { user: currentUser } } = await supabase.auth.getUser();
          const userId = currentUser?.id || clientId; // Fallback to clientId if no user

          await supabase.functions.invoke('api', {
            body: {
              action: 'notify-webhook',
              appointmentId: newAppointment.id,
              clientName: localName === "LOCAL" ? 'LOCAL (presencial)' : localName,
              phone: '00000000000',
              service: selectedService?.title || 'Serviço',
              startTime: localStartTime,
              endTime: localEndTime,
              userId: userId,
              notes: null,
            }
          });
          console.log('External webhook notification sent for local booking');
        } catch (webhookError) {
          console.error('Error notifying external webhook:', webhookError);
        }

        // Disparar processamento da fila de WhatsApp (cliente + barbeiro)
        try {
          // Obter o token de autenticação do usuário
          const { data: { session } } = await supabase.auth.getSession();
          const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
          const supabaseAnonKey = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
          
          if (supabaseUrl) {
            // Fazer chamada direta via fetch com o token do usuário
            const response = await fetch(`${supabaseUrl}/functions/v1/whatsapp-process-queue`, {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
                'apikey': supabaseAnonKey || '',
                'Authorization': session?.access_token ? `Bearer ${session.access_token}` : `Bearer ${supabaseAnonKey}`,
              },
              body: JSON.stringify({}),
            });

            if (!response.ok) {
              const errorData = await response.json().catch(() => ({}));
              console.error('Error triggering WhatsApp queue:', response.status, errorData);
            } else {
              const data = await response.json().catch(() => ({}));
              console.log('WhatsApp queue processed after local booking', data);
            }
          } else {
            console.error('VITE_SUPABASE_URL não configurado');
          }
        } catch (queueError) {
          console.error('Error triggering WhatsApp queue after local booking:', queueError);
        }
      };

      // Inicia as notificações sem await para liberar a UI imediatamente
      runBackgroundNotifications();

      toast.success(localName === "LOCAL" 
        ? "Agendamento local realizado com sucesso!" 
        : `Agendamento para ${localName} realizado com sucesso!`);
      onOpenChange(false);
    } catch (error: any) {
      console.error("Error creating booking:", error);
      toast.error("Erro ao criar agendamento: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    onOpenChange(false);
  };

  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      handleClose();
    }
  };

  const handleBack = () => {
    if (step === "service") {
      setStep("client");
      setSelectedServiceId("");
    } else if (step === "client") {
      if (isBarberPreselected) {
        setStep("time");
      } else {
        setStep("barber");
      }
    } else if (step === "time") {
      if (isBarberPreselected) {
        handleClose();
      } else {
        setStep("barber");
      }
    }
  };

  const fetchBreakInfoForSlot = async (slot: string) => {
    try {
      const { data: breaks } = await (supabase as any)
        .from("barber_breaks")
        .select("id, start_time, end_time")
        .eq("barber_id", selectedBarberId)
        .eq("date", date);
      const timeToMinutes = (t: string) => {
        const [h, m] = t.split(":").map(Number);
        return h * 60 + m;
      };
      const slotStart = timeToMinutes(slot);
      const slotEnd = slotStart + 30;
      const found = (breaks || []).find((b: any) => {
        const bs = timeToMinutes(b.start_time);
        const be = timeToMinutes(b.end_time);
        return slotStart < be && slotEnd > bs;
      });
      if (!found) return null;
      return { breakId: found.id, breakStart: found.start_time, breakEnd: found.end_time };
    } catch {
      return null;
    }
  };

  const openSlotAt = async (slot: string) => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session || !user?.id) {
        toast.error("Faça login como barbeiro para liberar horário");
        return;
      }
      if (selectedBarberId !== currentUserBarberId) {
        toast.error("Você só pode liberar horários do seu perfil");
        return;
      }
      const info = await fetchBreakInfoForSlot(slot);
      if (!info?.breakId || !info.breakStart || !info.breakEnd) {
        toast.error("Nenhuma pausa encontrada para este horário");
        return;
      }
      const timeToMinutes = (t: string) => {
        const [h, m] = t.split(":").map(Number);
        return h * 60 + m;
      };
      const minutesToTime = (n: number) => {
        const h = String(Math.floor(n / 60)).padStart(2, "0");
        const m = String(n % 60).padStart(2, "0");
        return `${h}:${m}`;
      };
      const slotStart = timeToMinutes(slot);
      const slotEnd = slotStart + 30;
      const breakStart = timeToMinutes(info.breakStart);
      const breakEnd = timeToMinutes(info.breakEnd);
      if (breakStart === slotStart && breakEnd === slotEnd) {
        const { error } = await (supabase as any)
          .from("barber_breaks")
          .delete()
          .eq("id", info.breakId);
        if (error) throw error;
      } else if (breakStart === slotStart && breakEnd > slotEnd) {
        const { error } = await (supabase as any)
          .from("barber_breaks")
          .update({ start_time: minutesToTime(slotEnd) })
          .eq("id", info.breakId);
        if (error) throw error;
      } else if (breakStart < slotStart && breakEnd === slotEnd) {
        const { error } = await (supabase as any)
          .from("barber_breaks")
          .update({ end_time: minutesToTime(slotStart) })
          .eq("id", info.breakId);
        if (error) throw error;
      } else {
        const { error: updateErr } = await (supabase as any)
          .from("barber_breaks")
          .update({ end_time: minutesToTime(slotStart) })
          .eq("id", info.breakId);
        if (updateErr) throw updateErr;
        const { error: insertErr } = await (supabase as any)
          .from("barber_breaks")
          .insert({
            barber_id: selectedBarberId,
            date,
            start_time: minutesToTime(slotEnd),
            end_time: minutesToTime(breakEnd),
          });
        if (insertErr) throw insertErr;
      }
      toast.success(`Horário ${slot} liberado`);
      await loadSlotsForBarber(selectedBarberId);
    } catch {
      toast.error("Erro ao liberar horário");
    }
  };

  if (!open) return null;

  const selectedBarber = barbers.find(b => b.id === selectedBarberId);

  return (
    <div 
      className="fixed inset-0 z-50 flex items-center justify-center overflow-y-auto py-4"
      style={{ backgroundColor: "rgba(0, 0, 0, 0.85)" }}
      onClick={handleOverlayClick}
    >
      <div 
        className="relative w-full max-w-4xl mx-4 p-6 rounded-lg max-h-[95vh] overflow-y-auto"
        translate="no"
        style={{ 
          background: "linear-gradient(135deg, #1a1a1a 0%, #0a0a0a 100%)",
          border: "2px solid #FFD700",
          boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.5)"
        }}
      >
        {/* Close button */}
        <button
          onClick={handleClose}
