const AdminMonthlySchedule = () => {
  const { operatingHours } = useOperatingHours();

  const [mode, setMode] = useState<'barber' | 'shop'>('barber');
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [selectedBarberId, setSelectedBarberId] = useState<string>('');
  const [currentMonth, setCurrentMonth] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1));
  const [barberSchedules, setBarberSchedules] = useState<Record<string, any>>({});
  const [loadingSchedules, setLoadingSchedules] = useState(false);

  const [editingDay, setEditingDay] = useState<Date | null>(null);
  const [daySchedule, setDaySchedule] = useState<DayScheduleState>(defaultDaySchedule);
  const [saving, setSaving] = useState(false);

  const [bulkLunchOpen, setBulkLunchOpen] = useState(false);
  const [bulkLunch, setBulkLunch] = useState({ start: '12:00', end: '13:00' });
  const [applyingBulkLunch, setApplyingBulkLunch] = useState(false);

  useEffect(() => {
    loadBarbers();
  }, []);

  useEffect(() => {
    if (mode === 'barber' && selectedBarberId) {
      loadBarberSchedules();
    } else if (mode === 'shop') {
      loadShopMonthlySchedules();
    }
  }, [mode, selectedBarberId, currentMonth]);

  const loadBarbers = async () => {
    const { data } = await supabase
      .from('barbers')
      .select('id, name')
      .eq('visible', true)
      .order('name');
    if (data) {
      setBarbers(data);
      if (data.length > 0) setSelectedBarberId(data[0].id);
    }
  };

  const loadBarberSchedules = async () => {
    if (!selectedBarberId) return;
    setLoadingSchedules(true);
    try {
      const year = currentMonth.getFullYear();
      const month = currentMonth.getMonth();
      const start = new Date(year, month, 1).toISOString().split('T')[0];
      const end = new Date(year, month + 1, 0).toISOString().split('T')[0];
      const { data } = await (supabase as any)
        .from('barber_schedules')
        .select('*')
        .eq('barber_id', selectedBarberId)
        .gte('date', start)
        .lte('date', end);
      const map: Record<string, any> = {};
      (data || []).forEach((item: any) => { map[item.date] = item; });
      setBarberSchedules(map);
    } catch (e) {
      console.error('Erro ao carregar escala:', e);
    } finally {
      setLoadingSchedules(false);
    }
  };

  const loadShopMonthlySchedules = async () => {
    setLoadingSchedules(true);
    try {
      const year = currentMonth.getFullYear();
      const month = currentMonth.getMonth();
      const start = new Date(year, month, 1).toISOString().split('T')[0];
      const end = new Date(year, month + 1, 0).toISOString().split('T')[0];
      const { data } = await (supabase as any)
        .from('shop_schedules')
        .select('*')
        .gte('date', start)
        .lte('date', end);
      const map: Record<string, any> = {};
      (data || []).forEach((item: any) => { map[item.date] = item; });
      setBarberSchedules(map);
    } catch {
      setBarberSchedules({});
    } finally {
      setLoadingSchedules(false);
    }
  };

  const openDayEditor = (date: Date) => {
    const dateStr = date.toISOString().split('T')[0];
    const existing = barberSchedules[dateStr];
    const dayKey = getDayKey(date);
    const shopHours = operatingHours[dayKey];
    const openTime = existing?.open || shopHours?.open || '09:00';
    const closeTime = existing?.close || shopHours?.close || '20:00';
    setDaySchedule({
      open: openTime,
      close: closeTime,
      closed: existing ? existing.closed : (shopHours?.closed ?? false),
      observation: existing?.observation || '',
      lunch_start: existing?.lunch_start || '12:00',
      lunch_end: existing?.lunch_end || '13:00',
      has_lunch: existing ? existing.has_lunch : false,
      pause_start: existing?.pause_start || '15:00',
      pause_end: existing?.pause_end || '15:30',
      has_pause: existing?.has_pause || false,
    });
    setEditingDay(date);
  };

  const saveDaySchedule = async () => {
    if (!editingDay) return;
    setSaving(true);
    try {
      const dateStr = editingDay.toISOString().split('T')[0];
      if (mode === 'barber') {
        if (!selectedBarberId) return;
        const { error } = await (supabase as any)
          .from('barber_schedules')
          .upsert({
            barber_id: selectedBarberId,
            date: dateStr,
            ...daySchedule,
          }, { onConflict: 'barber_id,date' });
        if (error) throw error;
      } else {
        const { error } = await (supabase as any)
          .from('shop_schedules')
          .upsert({ date: dateStr, ...daySchedule }, { onConflict: 'date' });
        if (error) throw error;
      }
      toast.success('Programação do dia salva!');
      setEditingDay(null);
      mode === 'barber' ? loadBarberSchedules() : loadShopMonthlySchedules();
    } catch (e: any) {
      toast.error('Erro ao salvar: ' + e.message);
    } finally {
      setSaving(false);
    }
  };

  const applyLunchToMonth = async () => {
    const targetId = mode === 'barber' ? selectedBarberId : null;
    if (mode === 'barber' && !targetId) return;
    setApplyingBulkLunch(true);
    try {
      const year = currentMonth.getFullYear();
      const month = currentMonth.getMonth();
      const daysInMonth = new Date(year, month + 1, 0).getDate();
      for (let d = 1; d <= daysInMonth; d++) {
        const date = new Date(year, month, d);
        const dateStr = date.toISOString().split('T')[0];
        const existing = barberSchedules[dateStr];
        const dayKey = getDayKey(date);
        const shopHours = operatingHours[dayKey];
        const isOpen = existing ? !existing.closed : (shopHours ? !shopHours.closed : true);
        if (!isOpen) continue;
        if (mode === 'barber') {
          await (supabase as any).from('barber_schedules').upsert({
            barber_id: targetId,
            date: dateStr,
            open: existing?.open || shopHours?.open || '09:00',
            close: existing?.close || shopHours?.close || '20:00',
            closed: existing?.closed ?? false,
            observation: existing?.observation || '',
            lunch_start: bulkLunch.start,
            lunch_end: bulkLunch.end,
            has_lunch: true,
            pause_start: existing?.pause_start || '15:00',
            pause_end: existing?.pause_end || '15:30',
            has_pause: existing?.has_pause ?? false,
          }, { onConflict: 'barber_id,date' });
        } else {
          await (supabase as any).from('shop_schedules').upsert({
            date: dateStr,
            open: existing?.open || shopHours?.open || '09:00',
            close: existing?.close || shopHours?.close || '20:00',
            closed: existing?.closed ?? false,
            observation: existing?.observation || '',
            lunch_start: bulkLunch.start,
            lunch_end: bulkLunch.end,
            has_lunch: true,
            pause_start: existing?.pause_start || '15:00',
            pause_end: existing?.pause_end || '15:30',
            has_pause: existing?.has_pause ?? false,
          }, { onConflict: 'date' });
        }
      }
      toast.success('Horário de almoço aplicado ao mês!');
      setBulkLunchOpen(false);
      mode === 'barber' ? loadBarberSchedules() : loadShopMonthlySchedules();
    } catch (e: any) {
      toast.error('Erro: ' + e.message);
    } finally {
      setApplyingBulkLunch(false);
    }
  };

  const today = new Date().toISOString().split('T')[0];
  const year = currentMonth.getFullYear();
  const month = currentMonth.getMonth();
  const firstDayOfWeek = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  return (
    <Card className="bg-card border-border">
      <CardHeader className="pb-3 px-3 sm:px-6 sm:pb-4">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <CardTitle className="text-base sm:text-lg flex items-center gap-2">
            <Calendar className="h-4 w-4 sm:h-5 sm:w-5 text-primary shrink-0" />
            Escala Mensal — {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}
          </CardTitle>
          <div className="flex flex-wrap items-center gap-1.5 sm:gap-2">
            {/* Mode toggle */}
            <Button
              variant={mode === 'barber' ? 'default' : 'outline'}
              size="sm"
              className="h-8 px-2 sm:px-3 text-xs gap-1"
              onClick={() => setMode('barber')}
            >
              <User className="h-3.5 w-3.5" />
              <span className="hidden sm:inline">Barbeiro</span>
            </Button>
            <Button
              variant={mode === 'shop' ? 'default' : 'outline'}
              size="sm"
              className="h-8 px-2 sm:px-3 text-xs gap-1"
              onClick={() => setMode('shop')}
            >
              <Users className="h-3.5 w-3.5" />
              <span className="hidden sm:inline">Barbearia</span>
            </Button>

            {/* Barber selector */}
            {mode === 'barber' && (
              <Select value={selectedBarberId} onValueChange={setSelectedBarberId}>
                <SelectTrigger className="h-8 w-36 sm:w-44 text-xs">
                  <SelectValue placeholder="Barbeiro" />
                </SelectTrigger>
                <SelectContent>
                  {barbers.map(b => (
                    <SelectItem key={b.id} value={b.id}>{b.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            )}

            {/* Lunch bulk button */}
            <Button
              variant="outline"
              size="sm"
              className="text-orange-500 border-orange-500/40 hover:bg-orange-500/10 gap-1.5 h-8 px-2 sm:px-3"
              onClick={() => setBulkLunchOpen(true)}
            >
              <span className="text-xs">🍴</span>
              <span className="hidden sm:inline text-xs">Almoço do Mês</span>
            </Button>

            {/* Month navigation */}
            <Button
              variant="outline"
              size="icon"
              className="h-8 w-8"
              onClick={() => setCurrentMonth(new Date(year, month - 1, 1))}
            >
              <X className="h-3.5 w-3.5 rotate-45" />
            </Button>
            <Button
              variant="outline"
              size="icon"
              className="h-8 w-8"
              onClick={() => setCurrentMonth(new Date(year, month + 1, 1))}
            >
              <Plus className="h-3.5 w-3.5 rotate-45" />
            </Button>
          </div>
        </div>
      </CardHeader>

      <CardContent className="px-2 sm:px-6 pb-4">
        {loadingSchedules ? (
          <div className="flex items-center justify-center py-20">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : (
          <div className="grid grid-cols-7 gap-0.5 sm:gap-2">
            {/* Day headers */}
            {[['D','Dom'],['S','Seg'],['T','Ter'],['Q','Qua'],['Q','Qui'],['S','Sex'],['S','Sáb']].map(([short, full], i) => (
              <div key={i} className="text-center text-[10px] sm:text-xs font-bold text-muted-foreground py-1.5 sm:py-2 uppercase">
                <span className="sm:hidden">{short}</span>
                <span className="hidden sm:inline">{full}</span>
              </div>
            ))}

            {/* Empty cells */}
            {Array.from({ length: firstDayOfWeek }).map((_, i) => (
              <div key={`e-${i}`} className="h-20 sm:h-24 bg-secondary/10 rounded-lg opacity-30" />
            ))}

            {/* Day cells */}
            {Array.from({ length: daysInMonth }).map((_, idx) => {
              const d = idx + 1;
              const date = new Date(year, month, d);
              const dateStr = date.toISOString().split('T')[0];
              const schedule = barberSchedules[dateStr];
              const isToday = dateStr === today;
              const dayKey = getDayKey(date);
              const shopHours = operatingHours[dayKey];
              const isOpen = schedule ? !schedule.closed : (shopHours ? !shopHours.closed : true);
              const openTime = schedule?.open || shopHours?.open || '09:00';
              const closeTime = schedule?.close || shopHours?.close || '20:00';

              return (
                <button
                  key={d}
                  onClick={() => openDayEditor(date)}
                  className={`h-20 sm:h-24 p-1 sm:p-2 rounded-lg border text-left transition-all hover:border-primary/50 relative overflow-hidden ${
                    isToday ? 'border-primary bg-primary/5' : 'border-border bg-secondary/20'
                  } ${!isOpen ? 'opacity-60 bg-red-500/5' : ''}`}
                >
                  <span className={`text-[10px] sm:text-xs font-bold block leading-tight ${
                    isToday ? 'text-primary' : 'text-muted-foreground'
                  }`}>{d}</span>

                  <div className="mt-0.5 space-y-0.5">
                    {!isOpen ? (
                      <span className="text-[9px] sm:text-[10px] text-red-500 font-medium block">Fechado</span>
                    ) : (
                      <>
                        <span className="text-[9px] sm:text-[10px] text-foreground font-medium block leading-tight">
                          {openTime} - {closeTime}
                        </span>
                        {schedule?.has_lunch && (
                          <span className="text-[8px] sm:text-[9px] text-orange-500 font-medium block leading-tight">
                            🍴 {schedule.lunch_start} - {schedule.lunch_end}
                          </span>
                        )}
                        {schedule?.has_pause && (
                          <span className="text-[8px] sm:text-[9px] text-blue-500 font-medium block leading-tight">
                            ☕ {schedule.pause_start} - {schedule.pause_end}
                          </span>
                        )}
                        {schedule?.observation && (
                          <div className="flex items-center gap-0.5">
                            <div className="w-1 h-1 rounded-full bg-primary animate-pulse shrink-0" />
                            <span className="text-[8px] sm:text-[9px] text-primary truncate italic">
                              {schedule.observation}
                            </span>
                          </div>
                        )}
                      </>
                    )}
                  </div>

                  {schedule && (
                    <div className="absolute top-0.5 right-0.5">
                      <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        )}
      </CardContent>

      {/* Day edit dialog */}
      <Dialog open={editingDay !== null} onOpenChange={(open) => !open && setEditingDay(null)}>
        <DialogContent className="sm:max-w-md max-h-[90dvh] flex flex-col p-0">
          <DialogHeader className="px-4 pt-4 pb-2 shrink-0">
            <DialogTitle className="text-base">
              Programação: {editingDay && format(editingDay, "dd 'de' MMMM", { locale: ptBR })}
              {mode === 'barber' && selectedBarberId && (
                <span className="text-muted-foreground font-normal text-sm ml-2">
                  — {barbers.find(b => b.id === selectedBarberId)?.name}
                </span>
              )}
            </DialogTitle>
            <DialogDescription className="text-xs">
              {mode === 'barber' ? 'Horário individual do barbeiro neste dia.' : 'Horário da barbearia neste dia.'}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-3 px-4 py-2 overflow-y-auto flex-1">
            {/* Status */}
            <div className="flex items-center justify-between p-2.5 border border-border rounded-lg bg-secondary/30">
              <div className="space-y-0.5">
                <Label className="text-sm font-medium">Status do Dia</Label>
                <p className="text-xs text-muted-foreground">
                  {daySchedule.closed ? 'Fechado' : 'Aberto para agendamentos'}
                </p>
              </div>
              <Switch
                checked={!daySchedule.closed}
                onCheckedChange={(checked) => setDaySchedule({ ...daySchedule, closed: !checked })}
              />
            </div>

            {!daySchedule.closed && (
              <>
                {/* Open / Close */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1.5">
                    <Label className="text-xs">Abertura</Label>
                    <Input type="time" className="h-9 text-sm" value={daySchedule.open}
                      onChange={(e) => setDaySchedule({ ...daySchedule, open: e.target.value })} />
                  </div>
                  <div className="space-y-1.5">
                    <Label className="text-xs">Fechamento</Label>
                    <Input type="time" className="h-9 text-sm" value={daySchedule.close}
                      onChange={(e) => setDaySchedule({ ...daySchedule, close: e.target.value })} />
                  </div>
                </div>

                {/* Lunch */}
                <div className="border border-border rounded-lg bg-secondary/30 overflow-hidden">
                  <div className="flex items-center justify-between p-2.5">
                    <div className="space-y-0.5">
                      <Label className="text-sm font-medium">🍴 Horário de Almoço</Label>
                      <p className="text-xs text-muted-foreground">Habilitar intervalo de almoço</p>
                    </div>
                    <Switch checked={daySchedule.has_lunch}
                      onCheckedChange={(checked) => setDaySchedule({ ...daySchedule, has_lunch: checked })} />
                  </div>
                  {daySchedule.has_lunch && (
                    <div className="grid grid-cols-2 gap-3 px-2.5 pb-2.5 pt-0">
                      <div className="space-y-1.5">
                        <Label className="text-xs">Início</Label>
                        <Input type="time" className="h-9 text-sm" value={daySchedule.lunch_start}
                          onChange={(e) => setDaySchedule({ ...daySchedule, lunch_start: e.target.value })} />
                      </div>
                      <div className="space-y-1.5">
                        <Label className="text-xs">Fim</Label>
                        <Input type="time" className="h-9 text-sm" value={daySchedule.lunch_end}
                          onChange={(e) => setDaySchedule({ ...daySchedule, lunch_end: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>

                {/* Pause */}
                <div className="border border-border rounded-lg bg-secondary/30 overflow-hidden">
                  <div className="flex items-center justify-between p-2.5">
                    <div className="space-y-0.5">
                      <Label className="text-sm font-medium">☕ Horário de Pausa</Label>
                      <p className="text-xs text-muted-foreground">Habilitar intervalo de pausa</p>
                    </div>
                    <Switch checked={daySchedule.has_pause}
                      onCheckedChange={(checked) => setDaySchedule({ ...daySchedule, has_pause: checked })} />
                  </div>
                  {daySchedule.has_pause && (
                    <div className="grid grid-cols-2 gap-3 px-2.5 pb-2.5 pt-0">
                      <div className="space-y-1.5">
                        <Label className="text-xs">Início</Label>
                        <Input type="time" className="h-9 text-sm" value={daySchedule.pause_start}
                          onChange={(e) => setDaySchedule({ ...daySchedule, pause_start: e.target.value })} />
                      </div>
                      <div className="space-y-1.5">
                        <Label className="text-xs">Fim</Label>
                        <Input type="time" className="h-9 text-sm" value={daySchedule.pause_end}
                          onChange={(e) => setDaySchedule({ ...daySchedule, pause_end: e.target.value })} />
                      </div>
                    </div>
                  )}
                </div>

                {/* Observation */}
                <div className="space-y-1.5">
                  <Label className="text-xs">Observação Interna</Label>
                  <Input type="text" className="h-9 text-sm"
                    placeholder="Ex: Feriado local, evento..."
                    value={daySchedule.observation}
                    onChange={(e) => setDaySchedule({ ...daySchedule, observation: e.target.value })} />
                </div>
              </>
            )}
          </div>

          <div className="flex gap-2 px-4 py-3 border-t border-border shrink-0">
            <Button className="flex-1 h-9" onClick={saveDaySchedule} disabled={saving}>
              {saving ? <><Loader2 className="h-4 w-4 animate-spin mr-2" />Salvando...</> : 'Salvar'}
            </Button>
            <Button variant="outline" className="h-9" onClick={() => setEditingDay(null)} disabled={saving}>
              Cancelar
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Bulk lunch dialog */}
      <Dialog open={bulkLunchOpen} onOpenChange={(open) => !open && setBulkLunchOpen(false)}>
        <DialogContent className="sm:max-w-sm">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <span>🍴</span> Inserir Horário de Almoço
            </DialogTitle>
            <DialogDescription>
              Aplica o almoço a todos os dias abertos de{' '}
              <strong>{format(currentMonth, 'MMMM yyyy', { locale: ptBR })}</strong>
              {mode === 'barber' && selectedBarberId && (
                <> — <strong>{barbers.find(b => b.id === selectedBarberId)?.name}</strong></>
              )}.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-2">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Início</Label>
                <Input type="time" value={bulkLunch.start}
                  onChange={(e) => setBulkLunch({ ...bulkLunch, start: e.target.value })} />
              </div>
              <div className="space-y-2">
                <Label>Fim</Label>
                <Input type="time" value={bulkLunch.end}
                  onChange={(e) => setBulkLunch({ ...bulkLunch, end: e.target.value })} />
              </div>
            </div>
            <p className="text-xs text-muted-foreground">
              Dias fechados serão ignorados.
            </p>
          </div>

          <div className="flex gap-2">
            <Button className="flex-1" onClick={applyLunchToMonth} disabled={applyingBulkLunch}>
              {applyingBulkLunch
                ? <><Loader2 className="h-4 w-4 animate-spin mr-2" />Aplicando...</>
                : 'Aplicar ao Mês'
              }
            </Button>
            <Button variant="outline" onClick={() => setBulkLunchOpen(false)} disabled={applyingBulkLunch}>
              Cancelar
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </Card>
  );
};

export default AdminMonthlySchedule;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { Plus, Trash2, Key } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';

interface Barber {
  id: string;
  name: string;
  user_id?: string;
  whatsapp_phone?: string | null;
}

export const BarbeiroManager = () => {
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [showNewBarberDialog, setShowNewBarberDialog] = useState(false);
  const [newBarber, setNewBarber] = useState({
    name: '',
    email: '',
    password: '',
    phone: '',
    whatsapp_phone: '',
    specialty: '',
    experience: '',
  });

  useEffect(() => {
    loadBarbers();
  }, []);

  const loadBarbers = async () => {
    const { data } = await (supabase as any)
      .from('barbers')
      .select('*')
      .order('order_index');
    
    if (data) setBarbers(data);
  };

  const normalizePhone = (raw: string) => {
    const digits = (raw || '').replace(/\D/g, '');
    if (!digits) return '';
    if (digits.startsWith('55')) return digits;
    if (digits.length >= 10 && digits <= '12') return `55${digits}`;
    return digits;
  };

  const handleCreateBarber = async () => {
    if (!newBarber.name || !newBarber.email || !newBarber.password || !newBarber.specialty || !newBarber.experience) {
      toast.error('Preencha todos os campos obrigatórios');
      return;
    }

    try {
      const normalizedPhone = normalizePhone(newBarber.phone);
      const normalizedWhatsapp = normalizePhone(newBarber.whatsapp_phone);
      // Criar usuário
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email: newBarber.email,
        password: newBarber.password,
        options: {
          data: {
            name: newBarber.name,
            phone: normalizedPhone || '',
          }
        }
      });

      if (authError) throw authError;
      if (!authData.user) throw new Error('Falha ao criar usuário');

      // Criar profile
      const { error: profileError } = await (supabase as any)
        .from('profiles')
        .upsert({
          id: authData.user.id,
          name: newBarber.name,
          phone: normalizedPhone || '',
        });

      if (profileError) throw profileError;

      // Criar role de barbeiro
      const { error: roleError } = await (supabase as any)
        .from('user_roles')
        .insert([{
          user_id: authData.user.id,
          role: 'barbeiro'
        }]);

      if (roleError) throw roleError;

      // Criar barber com todos os dados
      const { error: barberError } = await (supabase as any)
        .from('barbers')
        .insert([{
          name: newBarber.name,
          user_id: authData.user.id,
          specialty: newBarber.specialty,
          experience: newBarber.experience,
          rating: 5.0,
          visible: true,
          whatsapp_phone: normalizedWhatsapp || null,
          order_index: barbers.length,
        }]);

      if (barberError) throw barberError;

      toast.success('Barbeiro criado com sucesso! Login, senha e WhatsApp configurados.');
      setShowNewBarberDialog(false);
      setNewBarber({ name: '', email: '', password: '', phone: '', whatsapp_phone: '', specialty: '', experience: '' });
      loadBarbers();
    } catch (error: any) {
      toast.error('Erro ao criar barbeiro: ' + error.message);
    }
  };

  const handleDeleteBarber = async (id: string) => {
    const { error } = await (supabase as any)
      .from('barbers')
      .delete()
      .eq('id', id);

    if (error) {
      toast.error('Erro ao excluir barbeiro');
    } else {
      toast.success('Barbeiro excluído!');
      loadBarbers();
    }
  };

  return (
    <div className="space-y-4">
      <Dialog open={showNewBarberDialog} onOpenChange={setShowNewBarberDialog}>
        <DialogTrigger asChild>
          <Button>
            <Plus className="mr-2 h-4 w-4" />
            Criar Novo Barbeiro
          </Button>
        </DialogTrigger>
        <DialogContent className="max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Criar Novo Barbeiro com Acesso</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div>
              <Label>Nome Completo *</Label>
              <Input
                value={newBarber.name}
                onChange={(e) => setNewBarber({ ...newBarber, name: e.target.value })}
                placeholder="João Silva"
                required
              />
            </div>
            <div>
              <Label>Email de Acesso *</Label>
              <Input
                type="email"
                value={newBarber.email}
                onChange={(e) => setNewBarber({ ...newBarber, email: e.target.value })}
                placeholder="joao@barbearia.com"
                required
              />
            </div>
            <div>
              <Label>Senha de Acesso *</Label>
              <Input
                type="password"
                value={newBarber.password}
                onChange={(e) => setNewBarber({ ...newBarber, password: e.target.value })}
                placeholder="Mínimo 6 caracteres"
                minLength={6}
                required
              />
            </div>
            <div>
              <Label>Telefone</Label>
              <Input
                type="tel"
                value={newBarber.phone}
                onChange={(e) => setNewBarber({ ...newBarber, phone: e.target.value })}
                placeholder="(00) 00000-0000"
              />
            </div>
            <div>
              <Label>WhatsApp do Barbeiro (opcional)</Label>
              <Input
                type="tel"
                value={newBarber.whatsapp_phone}
                onChange={(e) => setNewBarber({ ...newBarber, whatsapp_phone: e.target.value })}
                placeholder="Ex: 5582999999999"
              />
              <p className="mt-1 text-xs text-muted-foreground">
                Use apenas números. Exemplo: 5582982212126 (55 + DDD + número).
              </p>
            </div>
            <div>
              <Label>Especialidade *</Label>
              <Input
                value={newBarber.specialty}
                onChange={(e) => setNewBarber({ ...newBarber, specialty: e.target.value })}
                placeholder="Ex: Cortes modernos, Barbas"
                required
              />
            </div>
            <div>
              <Label>Experiência *</Label>
              <Input
                value={newBarber.experience}
                onChange={(e) => setNewBarber({ ...newBarber, experience: e.target.value })}
                placeholder="Ex: 5 anos de experiência"
                required
              />
            </div>
            <div className="flex gap-2">
              <Button onClick={handleCreateBarber} className="flex-1">
                Criar Barbeiro Completo
              </Button>
              <Button variant="outline" onClick={() => setShowNewBarberDialog(false)}>
                Cancelar
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <div className="grid gap-4">
        {barbers.map((barber) => (
          <Card key={barber.id} className="bg-card border-border">
            <CardContent className="p-4">
              <div className="flex justify-between items-start gap-4">
                <div className="flex items-center gap-3">
                  <div className="h-10 w-10 rounded-full bg-primary/20 flex items-center justify-center">
                    <Key className="h-5 w-5 text-primary" />
                  </div>
                  <div>
                    <h3 className="text-lg font-bold">{barber.name}</h3>
                    <p className="text-sm text-muted-foreground">
                      {barber.user_id ? 'Acesso configurado' : 'Sem acesso ao sistema'}
                    </p>
                    <p className="text-xs mt-1">
                      WhatsApp:{' '}
                      {barber.whatsapp_phone
                        ? <span className="text-emerald-500 font-medium">{barber.whatsapp_phone}</span>
                        : <span className="text-muted-foreground">não configurado</span>}
                    </p>
                  </div>
                </div>
                <Button 
                  size="sm" 
                  variant="destructive" 
                  onClick={() => handleDeleteBarber(barber.id)}
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
};

import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { BarberAdvance, BarberAdvanceStatus, createAdvance, listAdvancesAdmin, rejectAdvance, approveAdvance } from "@/integrations/supabase/barberAdvances";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  DropdownMenu, 
  DropdownMenuTrigger, 
  DropdownMenuContent, 
  DropdownMenuLabel, 
  DropdownMenuRadioGroup, 
  DropdownMenuRadioItem 
} from "@/components/ui/dropdown-menu";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Loader2, Plus, Trash2, Users, Filter } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";

interface Barber {
  id: string;
  name: string;
}

const BarberAdvancesManager = () => {
  const [barbers, setBarbers] = useState<Barber[]>([]);
  const [selectedBarberId, setSelectedBarberId] = useState<string>("all");
  const [statusFilter, setStatusFilter] = useState<BarberAdvanceStatus | "all">("all");
  const [loading, setLoading] = useState(false);
  const [advances, setAdvances] = useState<BarberAdvance[]>([]);

  const [creating, setCreating] = useState(false);
  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [createForm, setCreateForm] = useState({
    barber_id: "",
    amount: "",
    description: "",
    effective_date: new Date().toISOString().split("T")[0],
  });

  useEffect(() => {
    loadBarbers();
  }, []);

  useEffect(() => {
    if (barbers.length > 0) {
      loadAdvances();
    }
  }, [selectedBarberId, statusFilter, barbers]);

  const loadBarbers = async () => {
    const { data, error } = await (supabase as any)
      .from("barbers")
      .select("id, name")
      .eq("visible", true)
      .order("name");

    if (error) {
      console.error("Error loading barbers:", error);
      toast.error("Erro ao carregar barbeiros");
      return;
    }

    setBarbers(data || []);
  };

  const loadAdvances = async () => {
    console.log('📋 Carregando vales...', { selectedBarberId, statusFilter });
    setLoading(true);
    const { data, error } = await listAdvancesAdmin({
      barberId: selectedBarberId !== "all" ? selectedBarberId : undefined,
      status: statusFilter,
    });
    setLoading(false);

    if (error) {
      console.error("❌ Error loading advances:", error);
      toast.error("Erro ao carregar vales");
      return;
    }

    console.log('📊 Vales carregados:', data?.length || 0, 'vales');
    
    // Filtrar vales que foram "removidos pelo admin" para não aparecerem na lista
    const filteredData = data?.filter(advance => 
      !advance.description?.includes('[REMOVIDO PELO ADMIN]')
    ) || [];
    
    console.log('📊 Vales após filtro:', filteredData.length, 'vales (removidos os marcados como REMOVIDO PELO ADMIN)');
    
    // Carregar dados dos barbeiros para cada vale
    const advancesWithBarbers = await Promise.all(
      filteredData.map(async (advance) => {
        const barber = barbers.find(b => b.id === advance.barber_id);
        return {
          ...advance,
          barber: barber || { name: 'Barbeiro não encontrado' }
        };
      })
    );
    
    setAdvances(advancesWithBarbers);
  };

  const handleCreateAdvance = async () => {
    if (!createForm.barber_id) {
      toast.error("Selecione um barbeiro");
      return;
    }
    const amountNumber = Number(createForm.amount.replace(",", "."));
    if (!amountNumber || amountNumber <= 0) {
      toast.error("Informe um valor válido para o vale");
      return;
    }

    setCreating(true);
    const { error } = await createAdvance({
      barber_id: createForm.barber_id,
      amount: amountNumber,
      description: createForm.description || undefined,
      effective_date: createForm.effective_date,
    });
    setCreating(false);

    if (error) {
      console.error("Error creating advance:", error);
      toast.error("Erro ao criar vale");
      return;
    }

    toast.success("Vale criado com sucesso!");
    setCreateForm({
      barber_id: "",
      amount: "",
      description: "",
      effective_date: new Date().toISOString().split("T")[0],
    });
    setCreateDialogOpen(false);
    loadAdvances();
  };

  const handleDeleteAdvance = async (advanceId: string) => {
    console.log('🗑️ Tentando remover vale via RPC delete_barber_advance_admin:', advanceId);
    
    try {
      const { data: rpcResult, error: rpcError } = await supabase
        .rpc('delete_barber_advance_admin', { advance_id: advanceId });

      console.log('📊 Resultado RPC delete_barber_advance_admin:', { rpcResult, rpcError });

      if (rpcError) {
        console.error("❌ Erro na função RPC:", rpcError);
        toast.error("Erro ao remover vale: " + rpcError.message);
        return;
      }

      if (rpcResult && rpcResult.success) {
        toast.success(rpcResult.message || "Vale removido com sucesso!");
        setAdvances(prev => prev.filter(a => a.id !== advanceId));
        await loadAdvances();
      } else {
        const errorMessage = rpcResult?.error || "Erro desconhecido na remoção do vale";
        console.error("❌ RPC retornou erro lógico:", errorMessage);
        toast.error(errorMessage);
      }
    } catch (error: any) {
      console.error("❌ Exception ao chamar RPC delete_barber_advance_admin:", error);
      toast.error("Erro ao remover vale: " + (error?.message || 'desconhecido'));
    }
  };

  const formatCurrency = (value: number) =>
    value.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });

  const getStatusLabel = (status: BarberAdvanceStatus) => {
    switch (status) {
      case "pending":
        return "Pendente";
      case "approved":
        return "Aprovado";
      case "rejected":
        return "Rejeitado";
    }
  };

  const getStatusBadge = (status: BarberAdvanceStatus) => {
    switch (status) {
      case "pending":
        return <Badge variant="secondary" className="text-yellow-600 dark:text-yellow-400">Pendente</Badge>;
      case "approved":
        return <Badge variant="secondary" className="text-green-600 dark:text-green-400">Aprovado</Badge>;
      case "rejected":
        return <Badge variant="secondary" className="text-red-600 dark:text-red-400">Rejeitado</Badge>;
    }
  };

  return (
    <div className="space-y-4 sm:space-y-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
      {/* Botão para abrir modal de criação */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 sm:gap-4 w-full">
        <div></div>
        <Dialog open={createDialogOpen} onOpenChange={setCreateDialogOpen}>
          <DialogTrigger asChild>
            <Button className="flex items-center gap-2 w-full sm:w-auto">
              <Plus className="h-4 w-4" />
              <span className="hidden sm:inline">Registrar Novo Vale</span>
              <span className="sm:hidden">Novo Vale</span>
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-[95vw] sm:max-w-md overflow-hidden">
            <DialogHeader>
              <DialogTitle>Registrar Novo Vale</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Barbeiro</Label>
                <Select
                  value={createForm.barber_id}
                  onValueChange={(value) =>
                    setCreateForm((prev) => ({ ...prev, barber_id: value }))
                  }
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Selecione um barbeiro" />
                  </SelectTrigger>
                  <SelectContent>
                    {barbers.map((barber) => (
                      <SelectItem key={barber.id} value={barber.id}>
                        {barber.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2">
                  <Label>Valor do Vale (R$)</Label>
                  <Input
                    type="number"
                    step="0.01"
                    placeholder="0,00"
                    value={createForm.amount}
                    onChange={(e) =>
                      setCreateForm((prev) => ({ ...prev, amount: e.target.value }))
                    }
                  />
                </div>
                <div className="space-y-2">
                  <Label>Data de Efeito</Label>
                  <Input
                    type="date"
                    value={createForm.effective_date}
                    onChange={(e) =>
                      setCreateForm((prev) => ({ ...prev, effective_date: e.target.value }))
                    }
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label>Descrição (opcional)</Label>
                <Textarea
                  placeholder="Ex: Adiantamento de comissão, ajuda de custo, etc."
                  value={createForm.description}
                  onChange={(e) =>
                    setCreateForm((prev) => ({ ...prev, description: e.target.value }))
                  }
                />
              </div>
              <div className="flex gap-2">
                <Button
                  onClick={handleCreateAdvance}
                  disabled={creating}
                  className="flex-1"
                >
                  {creating ? (
                    <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                      Criando...
                    </>
                  ) : (
                    <>
                      <Plus className="mr-2 h-4 w-4" />
                      Criar Vale
                    </>
                  )}
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setCreateDialogOpen(false)}
                  disabled={creating}
                >
                  Cancelar
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <Card className="bg-card border-border shadow-lg w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
        <CardHeader className="p-3 sm:p-4 md:p-6">
          <CardTitle className="flex flex-col sm:flex-row items-start sm:items-center gap-2 text-lg sm:text-xl">
            Vales de Barbeiros
            {advances.filter(adv => adv.status === "pending").length > 0 && (
              <Badge variant="secondary" className="text-yellow-600 dark:text-yellow-400 text-xs">
                {advances.filter(adv => adv.status === "pending").length} pendente{advances.filter(adv => adv.status === "pending").length > 1 ? 's' : ''}
              </Badge>
            )}
          </CardTitle>
        </CardHeader>
        <CardContent className="p-2 sm:p-3 md:p-4 lg:p-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
          <div className="space-y-3 sm:space-y-4">
            <div className="grid grid-cols-2 gap-2">
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                    <Users className="h-3 w-3 mr-1" />
                    Barbeiro: {barbers.find(b => b.id === selectedBarberId)?.name || 'Todos'}
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent>
                  <DropdownMenuLabel className="text-xs">Barbeiro</DropdownMenuLabel>
                  <DropdownMenuRadioGroup value={selectedBarberId} onValueChange={setSelectedBarberId}>
                    <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                    {barbers.map((barber) => (
                      <DropdownMenuRadioItem key={barber.id} value={barber.id}>{barber.name}</DropdownMenuRadioItem>
                    ))}
                  </DropdownMenuRadioGroup>
                </DropdownMenuContent>
              </DropdownMenu>

              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                    <Filter className="h-3 w-3 mr-1" />
                    Status: {statusFilter === 'all' ? 'Todos' : statusFilter === 'pending' ? 'Pendentes' : statusFilter === 'approved' ? 'Aprovados' : 'Rejeitados'}
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent>
                  <DropdownMenuLabel className="text-xs">Status</DropdownMenuLabel>
                  <DropdownMenuRadioGroup value={statusFilter} onValueChange={(v) => setStatusFilter(v as any)}>
                    <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="pending">Pendentes</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="approved">Aprovados</DropdownMenuRadioItem>
                    <DropdownMenuRadioItem value="rejected">Rejeitados</DropdownMenuRadioItem>
                  </DropdownMenuRadioGroup>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>

          {loading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-6 w-6 animate-spin text-primary" />
            </div>
          ) : advances.length === 0 ? (
            <p className="text-sm text-muted-foreground">
              Nenhum vale encontrado com os filtros atuais.
            </p>
          ) : (
            <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
              <div className="overflow-x-auto">
                <table className="w-full text-sm" style={{ tableLayout: 'fixed', minWidth: '700px' }}>
                  <thead>
                    <tr className="border-b border-border text-left">
                      <th className="py-2 pr-2 sm:pr-4 w-[80px] sm:w-[100px]">Data</th>
                      <th className="py-2 pr-2 sm:pr-4 w-[100px] sm:w-[120px]">Barbeiro</th>
                      <th className="py-2 pr-2 sm:pr-4 w-[80px] sm:w-[100px]">Valor</th>
                      <th className="py-2 pr-2 sm:pr-4 w-[80px] sm:w-[100px]">Status</th>
                      <th className="py-2 pr-2 sm:pr-4">Descrição</th>
                      <th className="py-2 pr-2 sm:pr-4 w-[120px] sm:w-[150px]">Ações</th>
                    </tr>
                  </thead>
                  <tbody>
                  {advances.map((adv) => (
                    <tr
                      key={adv.id}
                      className="border-b border-border/60 last:border-0"
                    >
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        {new Date(adv.effective_date).toLocaleDateString(
                          "pt-BR"
                        )}
                      </td>
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        <div className="truncate max-w-[80px] sm:max-w-[100px]" title={(adv as any).barber?.name || "—"}>
                          {(adv as any).barber?.name || "—"}
                        </div>
                      </td>
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        <div className="font-medium text-xs sm:text-sm">
                          {formatCurrency(adv.amount)}
                        </div>
                      </td>
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        {getStatusBadge(adv.status)}
                      </td>
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        <div className="truncate max-w-[120px] sm:max-w-[200px]" title={adv.description || "—"}>
                          {adv.description || "—"}
                        </div>
                      </td>
                      <td className="py-2 pr-2 sm:pr-4 align-top">
                        {adv.status === "pending" ? (
                          <div className="flex gap-2">
                            <Button
                              size="sm"
                              variant="default"
                              className="bg-green-600 hover:bg-green-700"
                              onClick={async () => {
                                const { error } = await approveAdvance(adv.id, {
                                  approved_by_name: "Gestor", // Você pode pegar o nome do usuário logado
                                  approved_at: new Date().toISOString(),
                                });
                                if (error) {
                                  toast.error("Erro ao aprovar vale");
                                } else {
                                  toast.success("Vale aprovado com sucesso!");
                                  loadAdvances();
                                }
                              }}
                            >
                              Aprovar
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={async () => {
                                const { error } = await rejectAdvance(adv.id);
                                if (error) {
                                  toast.error("Erro ao cancelar vale");
                                } else {
                                  toast.success("Vale cancelado");
                                  loadAdvances();
                                }
                              }}
                            >
                              Cancelar
                            </Button>
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button
                                  size="sm"
                                  variant="destructive"
                                >
                                  <Trash2 className="h-4 w-4" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent>
                                <AlertDialogHeader>
                                  <AlertDialogTitle>Remover Vale</AlertDialogTitle>
                                  <AlertDialogDescription>
                                    Tem certeza que deseja remover este vale? Esta ação é irreversível.
                                    <br /><br />
                                    <strong>Vale:</strong> {formatCurrency(adv.amount)} para {(adv as any).barber?.name}
                                    <br />
                                    <strong>Data:</strong> {new Date(adv.effective_date).toLocaleDateString("pt-BR")}
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                  <AlertDialogAction
                                    onClick={() => handleDeleteAdvance(adv.id)}
                                    className="bg-destructive hover:bg-destructive/90"
                                  >
                                    Remover
                                  </AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </div>
                        ) : (
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button
                                size="sm"
                                variant="destructive"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                              <AlertDialogHeader>
                                <AlertDialogTitle>Remover Vale</AlertDialogTitle>
                                <AlertDialogDescription>
                                  Tem certeza que deseja remover este vale? Esta ação é irreversível.
                                  <br /><br />
                                  <strong>Vale:</strong> {formatCurrency(adv.amount)} para {(adv as any).barber?.name}
                                  <br />
                                  <strong>Status:</strong> {getStatusLabel(adv.status)}
                                  <br />
                                  <strong>Data:</strong> {new Date(adv.effective_date).toLocaleDateString("pt-BR")}
                                  {adv.status === "approved" && (
                                    <>
                                      <br /><br />
                                      <strong className="text-amber-600">⚠️ Atenção:</strong> Este vale foi aprovado e pode já ter sido descontado da comissão do barbeiro.
                                    </>
                                  )}
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                <AlertDialogAction
                                  onClick={() => handleDeleteAdvance(adv.id)}
                                  className="bg-destructive hover:bg-destructive/90"
                                >
                                  Remover
                                </AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
          )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default BarberAdvancesManager;

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { toast } from 'sonner';
import { Plus, Trash2, Edit, Clock, Calendar as CalendarIcon, AlertCircle, CheckCircle2 } from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { useBarberBreaks, BarberBreak, ConflictInfo } from '@/hooks/useBarberBreaks';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { useOperatingHours, dayNames, dayOrder, getDayKey, OperatingHours, DayHours } from '@/hooks/useOperatingHours';
import { useBarberAvailability, BarberAvailability, defaultBarberAvailability } from '@/hooks/useBarberAvailability';
import { Switch } from '@/components/ui/switch';
import { Checkbox } from '@/components/ui/checkbox';
import { useAuth } from '@/contexts/AuthContext';

interface BarberBreakManagerProps {
  barberId: string;
}

export const BarberBreakManager = ({ barberId }: BarberBreakManagerProps) => {
  const { breaks, loading, createBreak, updateBreak, deleteBreak, checkConflict } = useBarberBreaks(barberId);
  const { operatingHours, loading: hoursLoading } = useOperatingHours();
  const { availability, loading: availabilityLoading, updateDayAvailability } = useBarberAvailability(barberId);
  const { role } = useAuth();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingBreak, setEditingBreak] = useState<BarberBreak | null>(null);
  const [formData, setFormData] = useState({
    date: '',
    startTime: '',
    endTime: '',
  });
  const [checkingConflict, setCheckingConflict] = useState(false);
  const [conflictInfo, setConflictInfo] = useState<ConflictInfo | null>(null);
  const [editingAvailability, setEditingAvailability] = useState<{
    dayKey: keyof BarberAvailability;
    dayHours: DayHours;
  } | null>(null);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [bulkDeleting, setBulkDeleting] = useState(false);
  const isManager = role === 'admin' || role === 'gestor';

  useEffect(() => {
    if (selectedIds.length > 0 && breaks.length > 0) {
      const valid = new Set(breaks.map(b => b.id));
      setSelectedIds(prev => prev.filter(id => valid.has(id)));
    }
  }, [breaks]);

  const toggleSelect = (id: string, checked: boolean | string) => {
    setSelectedIds(prev => {
      const isChecked = checked === true || checked === 'indeterminate';
      return isChecked ? (prev.includes(id) ? prev : [...prev, id]) : prev.filter(x => x !== id);
    });
  };

  const selectAll = () => setSelectedIds(breaks.map(b => b.id));
  const clearSelection = () => setSelectedIds([]);

  const handleBulkDelete = async () => {
    if (selectedIds.length === 0) return;
    if (!confirm('Tem certeza que deseja excluir as pausas selecionadas?')) return;
    setBulkDeleting(true);
    try {
      const results = await Promise.allSettled(
        selectedIds.map(async (id) => {
          const { error } = await deleteBreak(id);
          return { id, error };
        })
      );
      const anyError = results.some(r => r.status === 'fulfilled' && (r as any).value.error);
      if (anyError) {
        toast.warning('Algumas pausas podem não ter sido excluídas');
      } else {
        toast.success('Pausas excluídas com sucesso');
      }
      setSelectedIds([]);
    } finally {
      setBulkDeleting(false);
    }
  };

  useEffect(() => {
    if (dialogOpen && !editingBreak) {
      const today = new Date();
      setFormData({
        date: format(today, 'yyyy-MM-dd'),
        startTime: '',
        endTime: '',
      });
      setConflictInfo(null);
    } else if (editingBreak) {
      setFormData({
        date: editingBreak.date,
        startTime: editingBreak.start_time,
        endTime: editingBreak.end_time,
      });
      setConflictInfo(null);
    }
  }, [dialogOpen, editingBreak]);

  useEffect(() => {
    if (!formData.date || editingBreak) return;
    if (formData.startTime || formData.endTime) return;
    if (!barberId) return;

    const [year, month, day] = formData.date.split('-').map(Number);
    const selectedDate = new Date(year, (month || 1) - 1, day || 1);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    const dayKey = getDayKey(selectedDate as any);
    const dayHours = operatingHours[dayKey];
    if (!dayHours || dayHours.closed) return;

    const [openH, openM] = dayHours.open.split(':').map(Number);
    const [closeH, closeM] = dayHours.close.split(':').map(Number);
    const openMinutes = openH * 60 + openM;
    const closeMinutes = closeH * 60 + closeM;

    const minutesToTime = (m: number) => {
      const h = Math.floor(m / 60);
      const mm = m % 60;
      return `${String(h).padStart(2, '0')}:${String(mm).padStart(2, '0')}`;
    };

    const suggest = async () => {
      let startMinutes: number;
      if (selectedDate.getTime() === today.getTime()) {
        const now = new Date();
        const nowMinutes = now.getHours() * 60 + now.getMinutes();
        startMinutes = Math.max(nowMinutes, openMinutes);
        startMinutes = Math.ceil(startMinutes / 30) * 30;
      } else if (selectedDate > today) {
        startMinutes = openMinutes;
      } else {
        return;
      }

      if (startMinutes >= closeMinutes) return;

      let safeStartMinutes = startMinutes;
      const maxIterations = 20;

      for (let i = 0; i < maxIterations; i++) {
        const startStr = minutesToTime(safeStartMinutes);
        const endStr = minutesToTime(closeMinutes);
        const conflict = await checkConflict(
          barberId,
          formData.date,
          startStr,
          endStr,
          editingBreak?.id
        );

        if (!conflict.hasConflict || !conflict.appointment) {
          const suggestedStart = startStr;
          const suggestedEnd = endStr;
          setFormData(prev => ({
            ...prev,
            startTime: suggestedStart,
            endTime: suggestedEnd,
          }));
          return;
        }

        const [endH, endM] = conflict.appointment.appointmentEndTime.split(':').map(Number);
        const conflictEndMinutes = endH * 60 + endM;
        safeStartMinutes = Math.max(safeStartMinutes, conflictEndMinutes);
        safeStartMinutes = Math.ceil(safeStartMinutes / 30) * 30;

        if (safeStartMinutes >= closeMinutes) {
          return;
        }
      }
    };

    suggest();
  }, [formData.date, editingBreak, operatingHours, barberId]);

  // Check for conflicts when form data changes
  useEffect(() => {
    if (formData.date && formData.startTime && formData.endTime && formData.endTime > formData.startTime) {
      const timeoutId = setTimeout(async () => {
        setCheckingConflict(true);
        const conflict = await checkConflict(
          barberId,
          formData.date,
          formData.startTime,
          formData.endTime,
          editingBreak?.id
        );
        setConflictInfo(conflict);
        setCheckingConflict(false);
      }, 500); // Debounce

      return () => clearTimeout(timeoutId);
    } else {
      setConflictInfo(null);
    }
  }, [formData.date, formData.startTime, formData.endTime, barberId, editingBreak?.id]);

  const handleSave = async () => {
    if (!formData.date || !formData.startTime || !formData.endTime) {
      toast.error('Preencha todos os campos');
      return;
    }

    if (formData.endTime <= formData.startTime) {
      toast.error('Horário de fim deve ser maior que horário de início');
      return;
    }

    // Check if date is in the past (parse como data local para evitar bug de fuso)
    const [year, month, day] = formData.date.split('-').map(Number);
    const selectedDate = new Date(year, (month || 1) - 1, day || 1);
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    selectedDate.setHours(0, 0, 0, 0);

    if (selectedDate < today) {
      toast.error('Não é possível criar pausa em datas passadas');
      return;
    }

    // Check for conflicts one more time before saving
    if (conflictInfo?.hasConflict) {
      toast.error('Não é possível salvar pausa com conflito de agendamento');
      return;
    }

    if (editingBreak) {
      const { error } = await updateBreak(
        editingBreak.id,
        formData.date,
        formData.startTime,
        formData.endTime
      );

      if (error) {
        toast.error(error.message);
      } else {
        toast.success('Pausa atualizada com sucesso!');
        setDialogOpen(false);
        setEditingBreak(null);
      }
    } else {
      const { error } = await createBreak(
        barberId,
        formData.date,
        formData.startTime,
        formData.endTime
      );

      if (error) {
        toast.error(error.message);
      } else {
        toast.success('Pausa criada com sucesso!');
        setDialogOpen(false);
      }
    }
  };

  const handleDelete = async (breakId: string) => {
    if (!confirm('Tem certeza que deseja excluir esta pausa?')) {
      return;
    }

    const { error } = await deleteBreak(breakId);
    if (error) {
      toast.error('Erro ao excluir pausa');
    } else {
      toast.success('Pausa excluída!');
    }
  };

  const handleEdit = (breakItem: BarberBreak) => {
    setEditingBreak(breakItem);
    setDialogOpen(true);
  };

  // Group breaks by date
  const breaksByDate = breaks.reduce((acc, breakItem) => {
    if (!acc[breakItem.date]) {
      acc[breakItem.date] = [];
    }
    acc[breakItem.date].push(breakItem);
    return acc;
  }, {} as Record<string, BarberBreak[]>);

  // Helper to check if a break is within barber's availability for that day
  const isBreakWithinHours = (breakItem: BarberBreak): boolean => {
    const date = new Date(breakItem.date + 'T00:00:00');
    const dayKey = getDayKey(date);
    const barberDayHours = availability[dayKey];
    
    if (barberDayHours.closed) return false;
    
    return breakItem.start_time >= barberDayHours.open && breakItem.end_time <= barberDayHours.close;
  };

  // Get breaks for a specific day of the week
  const getBreaksForDay = (dayKey: keyof OperatingHours): BarberBreak[] => {
    return breaks.filter(breakItem => {
      const date = new Date(breakItem.date + 'T00:00:00');
      return getDayKey(date) === dayKey;
    });
  };

  const handleAvailabilityChange = async (dayKey: keyof BarberAvailability, field: keyof DayHours, value: any) => {
    const currentDay = availability[dayKey];
    const newDayHours = { ...currentDay, [field]: value };
    const { error } = await updateDayAvailability(dayKey, newDayHours);
    if (error) {
      toast.error('Erro ao atualizar disponibilidade');
    } else {
      toast.success('Disponibilidade atualizada!');
    }
  };

  if (loading || hoursLoading || availabilityLoading) {
    return (
      <Card className="bg-card border-border">
        <CardContent className="p-6">
          <p className="text-muted-foreground">Carregando horários...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {/* Gerenciar Pausas */}
      <Card className="bg-card border-border">
        <CardHeader className="pb-2">
          <div className="flex justify-between items-center">
            <CardTitle className="flex items-center gap-2 text-base">
              <Clock className="h-4 w-4 text-primary" />
              Gerenciar Horários de Pausa
            </CardTitle>
            <div className="flex items-center gap-2">
              {isManager && (
                <>
                  <Button variant="outline" size="sm" onClick={selectAll} disabled={breaks.length === 0}>
                    Selecionar tudo
                  </Button>
                  <Button variant="outline" size="sm" onClick={clearSelection} disabled={selectedIds.length === 0}>
                    Limpar seleção
                  </Button>
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={handleBulkDelete}
                    disabled={selectedIds.length === 0 || bulkDeleting}
                  >
                    <Trash2 className="h-4 w-4 mr-2" />
                    Excluir selecionadas
                  </Button>
                </>
              )}
              <Dialog open={dialogOpen} onOpenChange={(open) => {
              setDialogOpen(open);
              if (!open) {
                setEditingBreak(null);
                setConflictInfo(null);
              }
            }}>
              <DialogTrigger asChild>
                <Button>
                  <Plus className="mr-2 h-4 w-4" />
                  Adicionar Pausa
                </Button>
              </DialogTrigger>
              <DialogContent className="sm:max-w-md">
                <DialogHeader>
                  <DialogTitle>
                    {editingBreak ? 'Editar Pausa' : 'Nova Pausa'}
                  </DialogTitle>
                </DialogHeader>
                <div className="space-y-4 py-4">
                  <div>
                    <Label htmlFor="date">Data</Label>
                    <Input
                      id="date"
                      type="date"
                      value={formData.date}
                      onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                      min={format(new Date(), 'yyyy-MM-dd')}
                      required
                    />
                    {formData.date && (() => {
                      const selectedDate = new Date(formData.date + 'T00:00:00');
                      const dayKey = getDayKey(selectedDate);
                      const dayHours = operatingHours[dayKey];
                      return (
                        <p className="text-xs text-muted-foreground mt-1">
                          {dayHours.closed ? (
                            <span className="text-red-400">⚠️ A barbearia está fechada neste dia</span>
                          ) : (
                            <span>Horário de funcionamento: {dayHours.open} - {dayHours.close}</span>
                          )}
                        </p>
                      );
                    })()}
                  </div>
                  <div>
                    <Label htmlFor="startTime">Horário de Início da Pausa</Label>
                    <Input
                      id="startTime"
                      type="time"
                      value={formData.startTime}
                      onChange={(e) => setFormData({ ...formData, startTime: e.target.value })}
                      required
                    />
                  </div>
                  <div>
                    <Label htmlFor="endTime">Horário de Fim da Pausa</Label>
                    <Input
                      id="endTime"
                      type="time"
                      value={formData.endTime}
                      onChange={(e) => setFormData({ ...formData, endTime: e.target.value })}
                      required
                    />
                    {formData.date && formData.startTime && formData.endTime && (() => {
                      const selectedDate = new Date(formData.date + 'T00:00:00');
                      const dayKey = getDayKey(selectedDate);
                      const dayHours = operatingHours[dayKey];
                      const withinHours = !dayHours.closed && 
                        formData.startTime >= dayHours.open && 
                        formData.endTime <= dayHours.close;
                      
                      if (!withinHours && !dayHours.closed) {
                        return (
                          <p className="text-xs text-yellow-400 mt-1">
                            ⚠️ A pausa está fora do horário de funcionamento ({dayHours.open} - {dayHours.close})
                          </p>
                        );
                      }
                      return null;
                    })()}
                  </div>

                  {checkingConflict && (
                    <p className="text-sm text-muted-foreground">Verificando conflitos...</p>
                  )}

                  {conflictInfo?.hasConflict && conflictInfo.appointment && (
                    <Alert variant="destructive">
                      <AlertCircle className="h-4 w-4" />
                      <AlertDescription>
                        <strong>Não é possível criar pausa neste horário.</strong>
                        <br />
                        Existe agendamento com:
                        <br />
                        <strong>Cliente:</strong> {conflictInfo.appointment.clientName}
                        <br />
                        <strong>Serviço:</strong> {conflictInfo.appointment.serviceTitle}
                        <br />
                        <strong>Horário:</strong> {conflictInfo.appointment.appointmentTime} às {conflictInfo.appointment.appointmentEndTime}
                      </AlertDescription>
                    </Alert>
                  )}

                  {formData.startTime && formData.endTime && formData.endTime <= formData.startTime && (
                    <Alert variant="destructive">
                      <AlertCircle className="h-4 w-4" />
                      <AlertDescription>
                        Horário de fim deve ser maior que horário de início
                      </AlertDescription>
                    </Alert>
                  )}

                  <div className="flex gap-2 pt-4">
                    <Button
                      onClick={handleSave}
                      disabled={!!conflictInfo?.hasConflict || checkingConflict || (formData.endTime && formData.endTime <= formData.startTime)}
                      className="flex-1"
                    >
                      {editingBreak ? 'Atualizar' : 'Criar'}
                    </Button>
                    <Button
                      variant="outline"
                      onClick={() => {
                        setDialogOpen(false);
                        setEditingBreak(null);
                        setConflictInfo(null);
                      }}
                    >
                      Cancelar
                    </Button>
                  </div>
                </div>
              </DialogContent>
            </Dialog>
            </div>
          </div>
        </CardHeader>
        <CardContent className="pt-2">
          {breaks.length === 0 ? (
            <p className="text-center text-muted-foreground py-8">
              Nenhuma pausa cadastrada. Clique em "Adicionar Pausa" para criar uma.
            </p>
          ) : (
            <div className="space-y-4">
              {Object.entries(breaksByDate).map(([date, dateBreaks]) => (
                <div key={date} className="space-y-2">
                  <div className="flex items-center gap-2 text-sm font-semibold text-primary mb-2">
                    <CalendarIcon className="h-4 w-4" />
                    {format(new Date(date + 'T00:00:00'), 'EEEE, dd/MM/yyyy', { locale: ptBR })}
                  </div>
                  <div className="space-y-2">
                    {dateBreaks.map((breakItem) => (
                      <div
                        key={breakItem.id}
                        className="flex items-center justify-between p-2 bg-secondary rounded-lg border border-border"
                      >
                        <div className="flex items-center gap-2">
                          {isManager && (
                            <Checkbox
                              checked={selectedIds.includes(breakItem.id)}
                              onCheckedChange={(checked) => toggleSelect(breakItem.id, checked as any)}
                              className="mr-1"
                            />
                          )}
                          <Clock className="h-3 w-3 text-muted-foreground" />
                          <span className="text-sm font-medium">
                            {breakItem.start_time} - {breakItem.end_time}
                          </span>
                        </div>
                        <div className="flex gap-2">
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleEdit(breakItem)}
                          >
                            <Edit className="h-3 w-3" />
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleDelete(breakItem.id)}
                          >
                            <Trash2 className="h-3 w-3 text-destructive" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Minha Disponibilidade Semanal */}
      <Card className="bg-card border-border">
        <CardHeader className="pb-2">
          <CardTitle className="flex items-center gap-2 text-base">
            <Clock className="h-4 w-4 text-primary" />
            Minha Disponibilidade Semanal
          </CardTitle>
          <p className="text-xs text-muted-foreground mt-1">
            Configure seus horários de disponibilidade por dia da semana.
          </p>
        </CardHeader>
        <CardContent className="pt-2">
          <div className="space-y-3">
            {dayOrder.map((dayKey) => {
              const barberDayHours = availability[dayKey];
              const shopDayHours = operatingHours[dayKey];
              
              return (
                <div key={dayKey} className="p-3 bg-secondary/30 rounded-lg border border-border">
                  <div className="flex items-center justify-between mb-3">
                    <h3 className="font-semibold text-sm">{dayNames[dayKey]}</h3>
                    <div className="flex items-center gap-2">
                      <div className="flex items-center gap-1">
                        <Label htmlFor={`closed-${dayKey}`} className="text-xs cursor-pointer">
                          {barberDayHours.closed ? 'Fechado' : 'Disponível'}
                        </Label>
                        <Switch
                          id={`closed-${dayKey}`}
                          checked={!barberDayHours.closed}
                          onCheckedChange={(checked) => 
                            handleAvailabilityChange(dayKey, 'closed', !checked)
                          }
                        />
                      </div>
                    </div>
                  </div>
                  
                  {!barberDayHours.closed && (
                    <div className="space-y-3 mt-2">
                      <div className="grid grid-cols-2 gap-3">
                        <div>
                          <Label htmlFor={`open-${dayKey}`} className="text-xs">Horário de Abertura</Label>
                          <Input
                            id={`open-${dayKey}`}
                            type="time"
                            value={barberDayHours.open}
                            onChange={(e) => handleAvailabilityChange(dayKey, 'open', e.target.value)}
                            className="mt-1 h-8 text-xs"
                          />
                        </div>
                        <div>
                          <Label htmlFor={`close-${dayKey}`} className="text-xs">Horário de Fechamento</Label>
                          <Input
                            id={`close-${dayKey}`}
                            type="time"
                            value={barberDayHours.close}
                            onChange={(e) => handleAvailabilityChange(dayKey, 'close', e.target.value)}
                            className="mt-1 h-8 text-xs"
                          />
                        </div>
                      </div>

                      <div className="pt-2 border-t border-border/40 space-y-2">
                        <div className="flex items-center gap-2">
                          <Switch
                            id={`lunch-${dayKey}`}
                            checked={barberDayHours.hasLunchBreak || false}
                            onCheckedChange={(checked) =>
                              handleAvailabilityChange(dayKey, 'hasLunchBreak', checked)
                            }
                          />
                          <Label htmlFor={`lunch-${dayKey}`} className="text-xs cursor-pointer">
                            Horário de Almoço
                          </Label>
                        </div>

                        {barberDayHours.hasLunchBreak && (
                          <div className="grid grid-cols-2 gap-3">
                            <div>
                              <Label htmlFor={`lunchStart-${dayKey}`} className="text-xs">Almoço de</Label>
                              <Input
                                id={`lunchStart-${dayKey}`}
                                type="time"
                                value={barberDayHours.lunchStart || '12:00'}
                                onChange={(e) => handleAvailabilityChange(dayKey, 'lunchStart', e.target.value)}
                                className="mt-1 h-8 text-xs"
                              />
                            </div>
                            <div>
                              <Label htmlFor={`lunchEnd-${dayKey}`} className="text-xs">até</Label>
                              <Input
                                id={`lunchEnd-${dayKey}`}
                                type="time"
                                value={barberDayHours.lunchEnd || '13:00'}
                                onChange={(e) => handleAvailabilityChange(dayKey, 'lunchEnd', e.target.value)}
                                className="mt-1 h-8 text-xs"
                              />
                            </div>
                          </div>
                        )}
                      </div>

                      <p className="text-[11px] text-muted-foreground">
                        Programação da barbearia: {shopDayHours.open} - {shopDayHours.close}
                      </p>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* Programação da Barbearia (Referência) */}
      <Card className="bg-card border-border">
        <CardHeader className="pb-2">
          <CardTitle className="flex items-center gap-2 text-base">
            <CalendarIcon className="h-4 w-4 text-primary" />
            Programação da Barbearia (Referência)
          </CardTitle>
        </CardHeader>
        <CardContent className="pt-2">
          <div className="space-y-3">
            {dayOrder.map((dayKey) => {
              const dayHours = operatingHours[dayKey];
              const barberDayHours = availability[dayKey];
              const dayBreaks = getBreaksForDay(dayKey);
              
              return (
                <div key={dayKey} className="p-3 bg-secondary/30 rounded-lg border border-border">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-semibold text-sm">{dayNames[dayKey]}</h3>
                    <div className="flex gap-2 items-center">
                      {dayHours.closed ? (
                        <span className="px-2 py-1 rounded text-xs font-medium bg-red-500/20 text-red-400">
                          Barbearia Fechada
                        </span>
                      ) : (
                        <span className="px-2 py-1 rounded text-xs font-medium bg-green-500/20 text-green-400">
                          {dayHours.open} - {dayHours.close}
                        </span>
                      )}
                      {barberDayHours.closed ? (
                        <span className="px-2 py-1 rounded text-xs font-medium bg-orange-500/20 text-orange-400">
                          Você Indisponível
                        </span>
                      ) : (
                        <span className="px-2 py-1 rounded text-xs font-medium bg-blue-500/20 text-blue-400">
                          Você: {barberDayHours.open} - {barberDayHours.close}
                        </span>
                      )}
                    </div>
                  </div>
                  
                  {!dayHours.closed && !barberDayHours.closed && dayBreaks.length > 0 && (
                    <div className="mt-3 space-y-2">
                      <p className="text-xs text-muted-foreground mb-2">Suas pausas neste dia:</p>
                      {dayBreaks.map((breakItem) => (
                        <div
                          key={breakItem.id}
                          className="flex items-center justify-between p-2 bg-secondary rounded border border-border"
                        >
                          <div className="flex items-center gap-2">
                            <Clock className="h-3 w-3 text-muted-foreground" />
                            <span className="text-xs font-medium">
                              {breakItem.start_time} - {breakItem.end_time}
                            </span>
                            {!isBreakWithinHours(breakItem) && (
                              <span className="px-2 py-0.5 rounded text-xs bg-yellow-500/20 text-yellow-400">
                                Fora do seu horário de disponibilidade
                              </span>
                            )}
                          </div>
                          <div className="flex gap-2">
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleEdit(breakItem)}
                            >
                              <Edit className="h-3 w-3" />
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => handleDelete(breakItem.id)}
                            >
                              <Trash2 className="h-3 w-3 text-destructive" />
                            </Button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      
    </div>
  );
};

import { useEffect, useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from 'sonner';
import { Pencil, Trash2, Loader2, Calendar, Clock, User, Scissors, ShoppingBag, Filter, CheckCircle2 } from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';

// Hook para detectar mobile
const useIsMobile = () => {
  const [isMobile, setIsMobile] = useState(false);
  
  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768);
    };
    
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);
  
  return isMobile;
};

interface Appointment {
  id: string;
  appointment_date: string;
  appointment_time: string;
  booking_type: string;
  status: string;
  notes?: string | null;
  client_id: string;
  client_name?: string | null;
  barber_id: string;
  service_id: string;
  service?: { title: string; price: number } | null;
  barber?: { name: string } | null;
  client?: { name: string; phone?: string } | null;
  payment_method?: string;
  appointment_payments?: { amount: number; payment_method?: string }[];
  photo_url?: string | null;
}

interface ProductSale {
  id: string;
  product_id: string;
  quantity: number;
  unit_price: number;
  total_price: number;
  sale_date: string;
  sale_time: string;
  status: 'pending' | 'confirmed' | 'cancelled';
  barber_id: string;
  notes?: string | null;
  payment_method?: string | null;
  product?: { name: string } | null;
  barber?: { name: string } | null;
}

const HISTORICO_CP_PAGE_SIZE = 30;

const HistoricoCP = () => {
  const isMobile = useIsMobile();
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(false);
  const [barbers, setBarbers] = useState<any[]>([]);
  const [services, setServices] = useState<any[]>([]);
  const [products, setProducts] = useState<any[]>([]);
  const [productSales, setProductSales] = useState<ProductSale[]>([]);
  const [loadingProductSales, setLoadingProductSales] = useState(false);
  const [editingAppointment, setEditingAppointment] = useState<Appointment | null>(null);
  const [deletingAppointment, setDeletingAppointment] = useState<Appointment | null>(null);
  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [saving, setSaving] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const [imageDialogOpen, setImageDialogOpen] = useState(false);
  const [imagePreviewUrl, setImagePreviewUrl] = useState<string | null>(null);
  const [deleteSaleDialogOpen, setDeleteSaleDialogOpen] = useState(false);
  const [deletingSale, setDeletingSale] = useState<ProductSale | null>(null);
  const [deletingSaleLoading, setDeletingSaleLoading] = useState(false);

  // Filtros
  const [filterDateFrom, setFilterDateFrom] = useState<string>('');
  const [filterDateTo, setFilterDateTo] = useState<string>('');
  const [filterBarber, setFilterBarber] = useState<string>('all');
  const [filterService, setFilterService] = useState<string>('all');
  const [filterProduct, setFilterProduct] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterType, setFilterType] = useState<'all' | 'local' | 'online' | 'manual'>('all');
  const [filterPayment, setFilterPayment] = useState<'all' | 'pix' | 'dinheiro' | 'cartao' | 'none'>('all');
  const [manualDialogOpen, setManualDialogOpen] = useState(false);
  const [manualType, setManualType] = useState<'service' | 'product'>('service');
  const [manualBarberId, setManualBarberId] = useState<string>('');
  const [manualServiceId, setManualServiceId] = useState<string>('');
  const [manualProductId, setManualProductId] = useState<string>('');
  const [manualQuantity, setManualQuantity] = useState<number>(1);
  const [manualClientName, setManualClientName] = useState<string>('');
  const [manualDate, setManualDate] = useState<string>(() => format(new Date(), 'yyyy-MM-dd'));
  const [manualTime, setManualTime] = useState<string>(() => format(new Date(), 'HH:mm'));
  const [manualSaving, setManualSaving] = useState(false);
  const [manualPaymentMethod, setManualPaymentMethod] = useState<'pix' | 'dinheiro' | 'cartao'>('pix');
  const [showFilters, setShowFilters] = useState(false);
  const [activeTab, setActiveTab] = useState<'services' | 'products'>('services');
  const [completingAppointmentId, setCompletingAppointmentId] = useState<string | null>(null);
  const [completingSaleId, setCompletingSaleId] = useState<string | null>(null);
  const [servicesPage, setServicesPage] = useState(1);
  const [productsPage, setProductsPage] = useState(1);
  const [servicesTotalCount, setServicesTotalCount] = useState(0);
  const [productsTotalCount, setProductsTotalCount] = useState(0);

  // Form de edição
  const [editForm, setEditForm] = useState({
    appointment_date: '',
    appointment_time: '',
    barber_id: '',
    service_id: '',
    status: '',
    notes: '',
  });

  useEffect(() => {
    loadBarbers();
    loadServices();
    loadProducts();
  }, []);

  useEffect(() => {
    if (activeTab === 'services') {
      loadAppointments(servicesPage);
      return;
    }

    loadProductSales(productsPage);
  }, [
    activeTab,
    servicesPage,
    productsPage,
    filterDateFrom,
    filterDateTo,
    filterBarber,
    filterService,
    filterProduct,
    filterStatus,
    filterType,
    filterPayment,
  ]);

  useEffect(() => {
    if (activeTab === 'services') {
      setServicesPage(1);
      return;
    }

    setProductsPage(1);
  }, [
    activeTab,
    filterDateFrom,
    filterDateTo,
    filterBarber,
    filterService,
    filterProduct,
    filterStatus,
    filterType,
    filterPayment,
  ]);

  const loadBarbers = async () => {
    const { data, error } = await supabase
      .from('barbers')
      .select('id, name')
      .eq('visible', true)
      .order('name');

    if (error) {
      console.error('Error loading barbers:', error);
      toast.error('Erro ao carregar barbeiros');
    } else {
      setBarbers(data || []);
    }
  };

  const loadProductSales = async (page: number = 1) => {
    setLoadingProductSales(true);
    try {
      const safePage = Math.max(1, page);
      const rangeFrom = (safePage - 1) * HISTORICO_CP_PAGE_SIZE;
      const rangeTo = rangeFrom + HISTORICO_CP_PAGE_SIZE - 1;

      let query = supabase
        .from('product_sales')
        .select(`
          id,
          product_id,
          quantity,
          unit_price,
          total_price,
          sale_date,
          sale_time,
          status,
          payment_method,
          barber_id,
          notes,
          product:products(name),
          barber:barbers(name)
        `, { count: 'exact' });

      if (filterDateFrom) {
        query = query.gte('sale_date', filterDateFrom);
      }
      if (filterDateTo) {
        query = query.lte('sale_date', filterDateTo);
      }
      if (filterBarber !== 'all') {
        query = query.eq('barber_id', filterBarber);
      }
      if (filterProduct !== 'all') {
        query = query.eq('product_id', filterProduct);
      }
      if (filterStatus !== 'all') {
        query = query.eq('status', filterStatus);
      }
      if (filterPayment !== 'all') {
        if (filterPayment === 'none') {
          query = query.is('payment_method', null);
        } else {
          query = query.eq('payment_method', filterPayment);
        }
      }

      const { data, error, count } = await query
        .order('sale_date', { ascending: false })
        .order('sale_time', { ascending: false })
        .range(rangeFrom, rangeTo);

      if (error) throw error;
      const list = (data || []) as ProductSale[];
      setProductSales(list);
      setProductsTotalCount(count ?? 0);

      let totalsQuery = supabase
        .from('product_sales')
        .select('total_price');

      if (filterDateFrom) {
        totalsQuery = totalsQuery.gte('sale_date', filterDateFrom);
      }
      if (filterDateTo) {
        totalsQuery = totalsQuery.lte('sale_date', filterDateTo);
      }
      if (filterBarber !== 'all') {
        totalsQuery = totalsQuery.eq('barber_id', filterBarber);
      }
      if (filterProduct !== 'all') {
        totalsQuery = totalsQuery.eq('product_id', filterProduct);
      }
      if (filterStatus !== 'all') {
        totalsQuery = totalsQuery.eq('status', filterStatus);
      }
      if (filterPayment !== 'all') {
        if (filterPayment === 'none') {
          totalsQuery = totalsQuery.is('payment_method', null);
        } else {
          totalsQuery = totalsQuery.eq('payment_method', filterPayment);
        }
      }

      const { data: totalsData, error: totalsError } = await totalsQuery;
      if (totalsError) throw totalsError;

      try {
        const total = (totalsData || []).reduce((sum: number, s: any) => sum + Number(s.total_price || 0), 0);
        setProductsTotal(total);
      } catch {
        setProductsTotal(0);
      }
    } catch (error: any) {
      console.error('Error loading product sales:', error);
      toast.error('Erro ao carregar vendas de produtos: ' + error.message);
      setProductSales([]);
      setProductsTotalCount(0);
      setProductsTotal(0);
    } finally {
      setLoadingProductSales(false);
    }
  };

  const loadServices = async () => {
    const { data, error } = await supabase
      .from('services')
      .select('id, title, price')
      .eq('visible', true)
      .order('order_index');

    if (error) {
      console.error('Error loading services:', error);
      toast.error('Erro ao carregar serviços');
    } else {
      setServices(data || []);
    }
  };

  const loadProducts = async () => {
    const { data, error } = await supabase
      .from('products')
      .select('id, name, price, stock')
      .eq('visible', true)
      .order('name');

    if (error) {
      console.error('Error loading products:', error);
      toast.error('Erro ao carregar produtos');
    } else {
      setProducts(data || []);
    }
  };

  const loadAppointments = async (page: number = 1) => {
    setLoading(true);
    try {
      const safePage = Math.max(1, page);
      const rangeFrom = (safePage - 1) * HISTORICO_CP_PAGE_SIZE;
      const rangeTo = rangeFrom + HISTORICO_CP_PAGE_SIZE - 1;

      let query = supabase
        .from('appointments')
        .select(`
          id,
          appointment_date,
          appointment_time,
          booking_type,
          status,
          notes,
          client_id,
          barber_id,
          service_id,
          payment_method,
          photo_url,
          service:services(title, price),
          barber:barbers(name),
          appointment_payments(amount, payment_method)
        `, { count: 'exact' });

      // Aplicar filtros
      if (filterDateFrom) {
        query = query.gte('appointment_date', filterDateFrom);
      }
      if (filterDateTo) {
        query = query.lte('appointment_date', filterDateTo);
      }
      if (filterBarber !== 'all') {
        query = query.eq('barber_id', filterBarber);
      }
      if (filterService !== 'all') {
        query = query.eq('service_id', filterService);
      }
      if (filterStatus !== 'all') {
        query = query.eq('status', filterStatus);
      }
      if (filterType !== 'all') {
        query = query.eq('booking_type', filterType);
      }

      if (filterPayment !== 'all') {
        if (filterPayment === 'none') {
          query = query.is('payment_method', null);
        } else {
          query = query.eq('payment_method', filterPayment);
        }
      }

      const { data, error, count } = await query
        .order('appointment_date', { ascending: false })
        .order('appointment_time', { ascending: false })
        .range(rangeFrom, rangeTo);

      if (error) throw error;

      setServicesTotalCount(count ?? 0);

      const raw = (data || []) as any[];
      if (raw && raw.length > 0) {
        const clientIds = [...new Set(raw.map(apt => apt.client_id))];
        const { data: clientsData } = await supabase
          .from('profiles')
          .select('id, name, phone')
          .in('id', clientIds);

        const clientsMap = new Map(clientsData?.map(c => [c.id, c]) || []);
        const appointmentsWithClients = raw.map(apt => ({
          ...apt,
          client: clientsMap.get(apt.client_id) || null,
        }));

        setAppointments(appointmentsWithClients as Appointment[]);

        let totalsQuery = supabase
          .from('appointments')
          .select(`
            status,
            payment_method,
            service:services(price)
          `);

        if (filterDateFrom) {
          totalsQuery = totalsQuery.gte('appointment_date', filterDateFrom);
        }
        if (filterDateTo) {
          totalsQuery = totalsQuery.lte('appointment_date', filterDateTo);
        }
        if (filterBarber !== 'all') {
          totalsQuery = totalsQuery.eq('barber_id', filterBarber);
        }
        if (filterService !== 'all') {
          totalsQuery = totalsQuery.eq('service_id', filterService);
        }
        if (filterStatus !== 'all') {
          totalsQuery = totalsQuery.eq('status', filterStatus);
        }
        if (filterType !== 'all') {
          totalsQuery = totalsQuery.eq('booking_type', filterType);
        }
        if (filterPayment !== 'all') {
          if (filterPayment === 'none') {
            totalsQuery = totalsQuery.is('payment_method', null);
          } else {
            totalsQuery = totalsQuery.eq('payment_method', filterPayment);
          }
        }

        const { data: totalsData, error: totalsError } = await totalsQuery;
        if (totalsError) throw totalsError;

        try {
          const servicesSum = (totalsData || []).reduce((sum: number, apt: any) => {
            const status = String(apt.status || '');
            if (status === 'confirmed' || status === 'completed') {
              const price = Number(apt.service?.price || 0);
              return sum + (price || 0);
            }
            return sum;
          }, 0);
          setServicesTotal(servicesSum);
        } catch {
          setServicesTotal(0);
        }
      } else {
        setAppointments([]);
        setServicesTotal(0);
      }
    } catch (error: any) {
      console.error('Error loading appointments:', error);
      toast.error('Erro ao carregar agendamentos: ' + error.message);
      setAppointments([]);
      setServicesTotalCount(0);
      setServicesTotal(0);
    } finally {
      setLoading(false);
    }
  };

  const [servicesTotal, setServicesTotal] = useState<number>(0);
  const [productsTotal, setProductsTotal] = useState<number>(0);

  const servicesTotalPages = Math.max(1, Math.ceil(servicesTotalCount / HISTORICO_CP_PAGE_SIZE));
  const productsTotalPages = Math.max(1, Math.ceil(productsTotalCount / HISTORICO_CP_PAGE_SIZE));

  const servicesStartIndex = servicesTotalCount === 0 ? 0 : (servicesPage - 1) * HISTORICO_CP_PAGE_SIZE + 1;
  const servicesEndIndex = Math.min(servicesPage * HISTORICO_CP_PAGE_SIZE, servicesTotalCount);
  const productsStartIndex = productsTotalCount === 0 ? 0 : (productsPage - 1) * HISTORICO_CP_PAGE_SIZE + 1;
  const productsEndIndex = Math.min(productsPage * HISTORICO_CP_PAGE_SIZE, productsTotalCount);

  useEffect(() => {
    if (servicesPage > servicesTotalPages) {
      setServicesPage(servicesTotalPages);
    }
  }, [servicesPage, servicesTotalPages]);

  useEffect(() => {
    if (productsPage > productsTotalPages) {
      setProductsPage(productsTotalPages);
    }
  }, [productsPage, productsTotalPages]);

  const handleEdit = (appointment: Appointment) => {
    setEditingAppointment(appointment);
    setEditForm({
      appointment_date: appointment.appointment_date,
      appointment_time: appointment.appointment_time,
      barber_id: appointment.barber_id,
      service_id: appointment.service_id,
      status: appointment.status,
      notes: appointment.notes || '',
    });
    setEditDialogOpen(true);
  };

  const handleSave = async () => {
    if (!editingAppointment) return;

    if (!editForm.appointment_date || !editForm.appointment_time || !editForm.barber_id || !editForm.service_id) {
      toast.error('Preencha todos os campos obrigatórios');
      return;
    }

    setSaving(true);
    try {
      const { error } = await supabase
        .from('appointments')
        .update({
          appointment_date: editForm.appointment_date,
          appointment_time: editForm.appointment_time,
          barber_id: editForm.barber_id,
          service_id: editForm.service_id,
          status: editForm.status,
          notes: editForm.notes || null,
        })
        .eq('id', editingAppointment.id);

      if (error) throw error;

      toast.success('Agendamento atualizado com sucesso!');
      setEditDialogOpen(false);
      setEditingAppointment(null);
      loadAppointments(servicesPage);
    } catch (error: any) {
      console.error('Error updating appointment:', error);
      toast.error('Erro ao atualizar agendamento: ' + error.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!deletingAppointment) return;

    setDeleting(true);
    try {
      const { error } = await supabase
        .from('appointments')
        .delete()
        .eq('id', deletingAppointment.id);

      if (error) throw error;

      // Verificar se ainda existe (política RLS pode impedir delete silenciosamente em alguns cenários)
      const { data: stillThere } = await supabase
        .from('appointments')
        .select('id')
        .eq('id', deletingAppointment.id)
        .maybeSingle();

      if (stillThere?.id) {
        // Fallback: marca como cancelado para ocultar de fluxos operacionais
        const { error: updError } = await supabase
          .from('appointments')
          .update({
            status: 'cancelled',
            notes: (deletingAppointment.notes ? deletingAppointment.notes + ' | ' : '') + 'Excluído (cancelado) pelo gestor',
          })
          .eq('id', deletingAppointment.id);
        if (updError) throw updError;
        toast.success('Agendamento cancelado (sem excluir por política)');
      } else {
        toast.success('Agendamento excluído com sucesso!');
      }

      setDeleteDialogOpen(false);
      setDeletingAppointment(null);
      await loadAppointments(servicesPage);
    } catch (error: any) {
      console.error('Error deleting appointment:', error);
      toast.error('Erro ao excluir agendamento: ' + error.message);
    } finally {
      setDeleting(false);
    }
  };

  const handleDeleteSale = async () => {
    if (!deletingSale) return;
    setDeletingSaleLoading(true);
    try {
      const { error } = await supabase
        .from('product_sales')
        .delete()
        .eq('id', deletingSale.id);
      if (error) throw error;
      toast.success('Venda de produto excluída com sucesso!');
      setDeleteSaleDialogOpen(false);
      setDeletingSale(null);
      loadProductSales(productsPage);
    } catch (error: any) {
      console.error('Error deleting product sale:', error);
      toast.error('Erro ao excluir venda: ' + error.message);
    } finally {
      setDeletingSaleLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    const variants: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
      confirmed: 'default',
      completed: 'secondary',
      cancelled: 'destructive',
      pending: 'outline',
    };
    const labels: Record<string, string> = {
      confirmed: 'Confirmado',
      completed: 'Concluído',
      cancelled: 'Cancelado',
      pending: 'Pendente',
    };
    return (
      <Badge variant={variants[status] || 'outline'}>
        {labels[status] || status}
      </Badge>
    );
  };

  const getTypeBadge = (type: string) => {
    const labels: Record<string, string> = {
      local: 'Local',
      online: 'Online',
      manual: 'Manual',
    };
    return (
      <Badge variant="outline">
        {labels[type] || type}
      </Badge>
    );
  };

  const handleCompleteAppointment = async (appointment: Appointment) => {
    if (appointment.status === 'completed') return;
    setCompletingAppointmentId(appointment.id);
    try {
      const { error } = await supabase
        .from('appointments')
        .update({ status: 'completed' })
        .eq('id', appointment.id);

      if (error) {
        throw error;
      }

      toast.success('Serviço marcado como concluído.');
      loadAppointments(servicesPage);
    } catch (error: any) {
      console.error('Error completing appointment:', error);
      toast.error(error.message || 'Erro ao concluir o serviço.');
    } finally {
      setCompletingAppointmentId(null);
    }
  };

  const handleCompleteProductSale = async (sale: ProductSale) => {
    if (sale.status === 'confirmed') return;
    setCompletingSaleId(sale.id);
    try {
      const { error } = await supabase
        .from('product_sales')
        .update({ status: 'confirmed' })
        .eq('id', sale.id);

      if (error) {
        throw error;
      }

      toast.success('Venda marcada como concluída.');
      loadProductSales(productsPage);
    } catch (error: any) {
      console.error('Error completing product sale:', error);
      toast.error(error.message || 'Erro ao concluir a venda.');
    } finally {
      setCompletingSaleId(null);
    }
  };

  // Componentes Mobile
  const MobileAppointmentCard = ({ appointment }: { appointment: Appointment }) => (
    <Card className="mb-3 border-border/50">
      <CardContent className="p-3">
        <div className="flex justify-between items-start mb-2">
          <div className="flex items-center gap-2">
            <Calendar className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium">
              {format(new Date(appointment.appointment_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}
            </span>
            <Clock className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm">{appointment.appointment_time}</span>
          </div>
          <div className="flex gap-1">
            {appointment.status !== 'completed' && (
              <Button
                size="sm"
                variant="secondary"
                onClick={() => handleCompleteAppointment(appointment)}
                disabled={completingAppointmentId === appointment.id}
                className="h-6 w-6 p-0"
              >
                {completingAppointmentId === appointment.id ? (
                  <Loader2 className="h-3 w-3 animate-spin" />
                ) : (
                  <CheckCircle2 className="h-3 w-3" />
                )}
              </Button>
            )}
            <Button
              size="sm"
              variant="outline"
              onClick={() => handleEdit(appointment)}
              className="h-6 w-6 p-0"
            >
              <Pencil className="h-3 w-3" />
            </Button>
            <Button
              size="sm"
              variant="destructive"
              onClick={() => {
                setDeletingAppointment(appointment);
                setDeleteDialogOpen(true);
              }}
              className="h-6 w-6 p-0"
            >
              <Trash2 className="h-3 w-3" />
            </Button>
          </div>
        </div>
        
        <div className="space-y-2">
          <div className="flex items-center gap-2">
            <User className="h-4 w-4 text-muted-foreground" />
            <div>
              <div className="flex flex-col gap-1">
                <div className="text-sm font-medium">{appointment.client_name || appointment.client?.name || 'N/A'}</div>
                {(() => {
                  try {
                    const n = appointment.notes ? JSON.parse(appointment.notes) : null;
                    if (n && n.fit === true) {
                      return (
                        <Badge className="bg-purple-600 text-white border-none text-[10px] h-5 w-fit px-2 font-bold uppercase shadow-sm">
                          Encaixe
                        </Badge>
                      );
                    }
                  } catch {}
                  return null;
                })()}
              </div>
              {appointment.client?.phone && (
                <div className="text-xs text-muted-foreground">{appointment.client.phone}</div>
              )}
            </div>
          </div>
          
          <div className="flex items-center gap-2">
            <Scissors className="h-4 w-4 text-muted-foreground" />
            <div>
              <div className="text-sm">{appointment.barber?.name || 'N/A'}</div>
              <div className="text-xs text-muted-foreground">{appointment.service?.title || 'N/A'}</div>
              {appointment.service?.price && (
                <div className="text-xs font-medium text-primary">R$ {appointment.service.price.toFixed(2)}</div>
              )}
            </div>
          </div>
          
          <div className="flex items-center gap-2">
            <div className="flex gap-1">
              {getStatusBadge(appointment.status)}
              {getTypeBadge(appointment.booking_type)}
            </div>
            {appointment.photo_url && (
              <button
                type="button"
                onClick={() => {
                  setImagePreviewUrl(appointment.photo_url || null);
                  setImageDialogOpen(true);
                }}
                className="ml-auto"
              >
                <img
                  src={appointment.photo_url}
                  alt="Foto do atendimento"
                  className="w-8 h-8 rounded-md object-cover border border-border"
                />
              </button>
            )}
          </div>
          
          {appointment.appointment_payments && appointment.appointment_payments.length > 0 && (
            <div className="text-xs text-muted-foreground">
              {appointment.appointment_payments.map((p, idx) => (
                <div key={idx}>
                  {p.payment_method === 'pix' ? 'Pix' : 
                   p.payment_method === 'cartao' ? 'Cartão' : 
                   p.payment_method === 'dinheiro' ? 'Dinheiro' : 'Outro'}: R$ {Number(p.amount).toFixed(2)}
                </div>
              ))}
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );

  const MobileProductCard = ({ sale }: { sale: ProductSale }) => (
    <Card className="mb-3 border-border/50">
      <CardContent className="p-3">
        <div className="flex justify-between items-start mb-2">
          <div className="flex items-center gap-2">
            <Calendar className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium">
              {format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}
            </span>
            <Clock className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm">{sale.sale_time}</span>
          </div>
          <div className="flex gap-1">
            {sale.status !== 'confirmed' && (
              <Button
                size="sm"
                variant="secondary"
                onClick={() => handleCompleteProductSale(sale)}
                disabled={completingSaleId === sale.id}
                className="h-6 w-6 p-0"
              >
                {completingSaleId === sale.id ? (
                  <Loader2 className="h-3 w-3 animate-spin" />
                ) : (
                  <CheckCircle2 className="h-3 w-3" />
                )}
              </Button>
            )}
            <Button
              size="sm"
              variant="destructive"
              onClick={() => {
                setDeletingSale(sale);
                setDeleteSaleDialogOpen(true);
              }}
              className="h-6 w-6 p-0"
            >
              <Trash2 className="h-3 w-3" />
            </Button>
          </div>
        </div>
        
        <div className="space-y-2">
          <div className="flex items-center gap-2">
            <ShoppingBag className="h-4 w-4 text-muted-foreground" />
            <div>
              <div className="text-sm font-medium">{sale.product?.name || 'Produto'}</div>
              <div className="text-xs text-muted-foreground">Qtd: {sale.quantity}</div>
              <div className="text-sm font-medium text-primary">R$ {Number(sale.total_price).toFixed(2)}</div>
            </div>
          </div>
          
          <div className="flex items-center gap-2">
            <User className="h-4 w-4 text-muted-foreground" />
            <div className="text-sm">{sale.barber?.name || barbers.find(b => b.id === sale.barber_id)?.name || 'N/A'}</div>
          </div>
          
          <div className="flex items-center gap-2">
            {sale.status === 'confirmed' && (
              <Badge className="bg-green-500/20 text-green-600 text-xs">Confirmado</Badge>
            )}
            {sale.status === 'pending' && (
              <Badge variant="outline" className="border-yellow-500 text-yellow-600 text-xs">Pendente</Badge>
            )}
            {sale.status === 'cancelled' && (
              <Badge variant="destructive" className="text-xs">Cancelado</Badge>
            )}
            {sale.payment_method === 'pix' && (
              <Badge className="bg-green-500/20 text-green-600 text-xs">Pix</Badge>
            )}
            {sale.payment_method === 'dinheiro' && (
              <Badge variant="outline" className="border-yellow-500 text-yellow-600 text-xs">Dinheiro</Badge>
            )}
            {sale.payment_method === 'cartao' && (
              <Badge className="bg-blue-500/20 text-blue-600 text-xs">Cartão</Badge>
            )}
          </div>
          
          {sale.notes && (
            <div className="text-xs text-muted-foreground truncate" title={sale.notes}>
              {sale.notes}
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );

  const handleOpenManualDialog = (type: 'service' | 'product') => {
    if (!manualBarberId) {
      toast.error('Selecione um barbeiro para lançar o registro manual');
      return;
    }
    setManualType(type);
    setManualDate(format(new Date(), 'yyyy-MM-dd'));
    setManualTime(format(new Date(), 'HH:mm'));
    setManualServiceId('');
    setManualProductId('');
    setManualQuantity(1);
    setManualClientName('');
    setManualDialogOpen(true);
  };

  const handleSaveManualAppointment = async () => {
    if (manualType === 'product') {
      if (!manualBarberId) {
        toast.error('Selecione um barbeiro');
        return;
      }
      if (!manualProductId) {
        toast.error('Selecione um produto');
        return;
      }
      if (manualQuantity <= 0) {
        toast.error('Quantidade deve ser maior que zero');
        return;
      }

      setManualSaving(true);
      try {
        const product = products.find(p => p.id === manualProductId);
        if (!product) {
          toast.error('Produto não encontrado');
          setManualSaving(false);
          return;
        }

        if (product.stock !== null && product.stock < manualQuantity) {
          toast.error(`Estoque insuficiente. Disponível: ${product.stock}`);
          setManualSaving(false);
          return;
        }

        const unitPrice = product.price;
        const totalPrice = unitPrice * manualQuantity;

        const { error } = await supabase
          .from('product_sales')
          .insert({
            barber_id: manualBarberId,
            product_id: manualProductId,
            quantity: manualQuantity,
            unit_price: unitPrice,
            total_price: totalPrice,
            sale_date: manualDate,
            sale_time: manualTime,
            status: 'confirmed',
            payment_method: manualPaymentMethod,
            notes: manualClientName.trim() ? `Histórico CP: ${manualClientName.trim()}` : 'Histórico CP: venda manual',
          });

        if (error) {
          toast.error(error.message || 'Erro ao lançar venda de produto');
          setManualSaving(false);
          return;
        }

        toast.success('Venda de produto lançada com sucesso!');
        setManualDialogOpen(false);
        setManualProductId('');
        setManualQuantity(1);
        setManualClientName('');
        setProductsPage(1);
        loadProductSales(1);
        loadProducts();
      } catch (error: any) {
        console.error('Error saving manual product sale:', error);
        toast.error(error.message || 'Erro ao lançar venda de produto');
      } finally {
        setManualSaving(false);
      }
      return;
    }

    if (!manualBarberId) {
      toast.error('Selecione um barbeiro');
      return;
    }
    if (!manualServiceId) {
      toast.error('Selecione um serviço');
      return;
    }
    setManualSaving(true);
    try {
      const service = services.find(s => s.id === manualServiceId);
      if (!service) {
        toast.error('Serviço não encontrado');
        setManualSaving(false);
        return;
      }

      const clientName = manualClientName.trim() || 'Cliente Local';
      const { data: profile, error: profileError } = await (supabase as any)
        .from('profiles')
        .insert({
          name: clientName,
          is_temp_user: true,
        })
        .select('id')
        .single();

      if (profileError || !profile?.id) {
        toast.error('Erro ao criar cliente para o lançamento');
        setManualSaving(false);
        return;
      }

      const bookingType = 'manual';
      const { error: appointmentError } = await (supabase as any)
        .from('appointments')
        .insert({
          client_id: profile.id,
          barber_id: manualBarberId,
          service_id: manualServiceId,
          appointment_date: manualDate,
          appointment_time: manualTime,
          status: 'confirmed',
          booking_type: bookingType,
          notes: 'Lançamento manual pelo gestor (Histórico CP)',
        });

      if (appointmentError) {
        toast.error(appointmentError.message || 'Erro ao lançar serviço manual');
        setManualSaving(false);
        return;
      }

      toast.success('Serviço manual lançado com sucesso!');
      setManualDialogOpen(false);
      setManualServiceId('');
      setManualClientName('');
      setServicesPage(1);
      loadAppointments(1);
    } catch (error: any) {
      console.error('Error saving manual appointment:', error);
      toast.error(error.message || 'Erro ao lançar serviço manual');
    } finally {
      setManualSaving(false);
    }
  };

  return (
    <div className="space-y-4 sm:space-y-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
      <Card className="bg-card border-border shadow-lg w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
        <CardHeader className="p-3 sm:p-4 md:p-6">
          <CardTitle className="flex items-center justify-between gap-2 text-lg sm:text-xl">
            <Calendar className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
            <span className="hidden sm:inline">Histórico CP</span>
            <span className="sm:hidden">Histórico CP</span>
            <Button
              variant="outline"
              size="sm"
              className="h-8 px-2 text-xs ml-auto"
              onClick={() => setShowFilters(v => !v)}
            >
              <Filter className="h-3 w-3 mr-1" />
              {showFilters ? 'Ocultar filtros' : 'Mostrar filtros'}
            </Button>
          </CardTitle>
        </CardHeader>
        <CardContent className="p-2 sm:p-3 md:p-4 lg:p-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
          <div className={`${showFilters ? '' : 'hidden'} mb-4 sm:mb-6 pb-3 border-b border-border`}>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-7 gap-3 sm:gap-4">
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Data Inicial</Label>
              <Input
                type="date"
                value={filterDateFrom}
                onChange={(e) => setFilterDateFrom(e.target.value)}
                className="w-full"
              />
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Data Final</Label>
              <Input
                type="date"
                value={filterDateTo}
                onChange={(e) => setFilterDateTo(e.target.value)}
                className="w-full"
              />
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Barbeiro</Label>
              <Select value={filterBarber} onValueChange={setFilterBarber}>
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  {barbers.map((barber) => (
                    <SelectItem key={barber.id} value={barber.id}>
                      {barber.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">
                {activeTab === 'services' ? 'Serviço' : 'Produto'}
              </Label>
              <Select value={activeTab === 'services' ? filterService : filterProduct} onValueChange={activeTab === 'services' ? setFilterService : setFilterProduct}>
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  {activeTab === 'services' ? (
                    services.map((service) => (
                      <SelectItem key={service.id} value={service.id}>
                        {service.title}
                      </SelectItem>
                    ))
                  ) : (
                    products.map((product) => (
                      <SelectItem key={product.id} value={product.id}>
                        {product.name}
                      </SelectItem>
                    ))
                  )}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Status</Label>
              <Select value={filterStatus} onValueChange={setFilterStatus}>
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  {activeTab === 'services' ? (
                    <>
                      <SelectItem value="confirmed">Confirmado</SelectItem>
                      <SelectItem value="completed">Concluído</SelectItem>
                      <SelectItem value="cancelled">Cancelado</SelectItem>
                      <SelectItem value="pending">Pendente</SelectItem>
                    </>
                  ) : (
                    <>
                      <SelectItem value="confirmed">Confirmado</SelectItem>
                      <SelectItem value="pending">Pendente</SelectItem>
                      <SelectItem value="cancelled">Cancelado</SelectItem>
                    </>
                  )}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Tipo</Label>
              <Select value={filterType} onValueChange={(v) => setFilterType(v as any)}>
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  {activeTab === 'services' && (
                    <>
                      <SelectItem value="local">Local</SelectItem>
                      <SelectItem value="online">Online</SelectItem>
                      <SelectItem value="manual">Manual</SelectItem>
                    </>
                  )}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm text-muted-foreground mb-1 block">Pagamento</Label>
              <Select value={filterPayment} onValueChange={(v) => setFilterPayment(v as any)}>
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Todos" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">Todos</SelectItem>
                  <SelectItem value="pix">Pix</SelectItem>
                  <SelectItem value="dinheiro">Dinheiro</SelectItem>
                  <SelectItem value="cartao">Cartão</SelectItem>
                  <SelectItem value="none">Sem pagamento</SelectItem>
                </SelectContent>
              </Select>
            </div>
            </div>
          </div>

          <div className="mb-4 sm:mb-6">
            <Card className="bg-card border-primary/40">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm sm:text-base flex items-center justify-between">
                  <span>Lançamentos manuais para barbeiros</span>
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 items-end">
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1 block">Barbeiro</Label>
                    <Select value={manualBarberId} onValueChange={setManualBarberId}>
                      <SelectTrigger className="h-9 text-xs">
                        <SelectValue placeholder="Selecione um barbeiro" />
                      </SelectTrigger>
                      <SelectContent>
                        {barbers.map((barber) => (
                          <SelectItem key={barber.id} value={barber.id}>
                            {barber.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="flex flex-col sm:flex-row gap-2 sm:justify-end">
                    <Button
                      size="sm"
                      className="flex-1 sm:flex-none"
                      onClick={() => handleOpenManualDialog('service')}
                      disabled={!manualBarberId}
                    >
                      Registrar serviço manual
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="flex-1 sm:flex-none"
                      onClick={() => handleOpenManualDialog('product')}
                      disabled={!manualBarberId}
                    >
                      Registrar venda de produto
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Abas */}
          <Tabs value={activeTab} onValueChange={(value) => setActiveTab(value as 'services' | 'products')} className="w-full">
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="services" className="flex items-center gap-2">
                <Scissors className="h-4 w-4" />
                Serviços
              </TabsTrigger>
              <TabsTrigger value="products" className="flex items-center gap-2">
                <ShoppingBag className="h-4 w-4" />
                Produtos
              </TabsTrigger>
            </TabsList>

            {/* Aba de Serviços */}
            <TabsContent value="services" className="mt-4">
              {loading ? (
                <div className="flex items-center justify-center py-8 sm:py-12">
                  <Loader2 className="h-6 w-6 animate-spin text-primary" />
                </div>
              ) : appointments.length === 0 ? (
                <p className="text-center text-muted-foreground py-8 sm:py-12 text-sm">
                  Nenhum agendamento encontrado com os filtros selecionados.
                </p>
              ) : (
                <>
                  {isMobile ? (
                    // Mobile: Cards
                    <div className="space-y-0">
                      {appointments.map((apt) => (
                        <MobileAppointmentCard key={apt.id} appointment={apt} />
                      ))}
                    </div>
                  ) : (
                    // Desktop: Tabela
                    <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                      <div className="overflow-x-auto">
                        <table className="w-full text-sm" style={{ tableLayout: 'fixed', minWidth: '860px' }}>
                          <thead>
                            <tr className="border-b border-border">
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[100px]">Data</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[60px] sm:w-[80px]">Horário</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[120px] sm:w-[150px]">Cliente</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[100px] sm:w-[120px]">Barbeiro</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[120px] sm:w-[150px]">Serviço</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[100px] sm:w-[120px]">Pagamento</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[70px] sm:w-[80px]">Tipo</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[100px]">Status</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[70px] sm:w-[80px]">Foto</th>
                              <th className="text-right py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[100px]">Ações</th>
                            </tr>
                          </thead>
                          <tbody>
                            {appointments.map((apt) => (
                              <tr key={apt.id} className="border-b border-border/50 hover:bg-muted/50">
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs sm:text-sm">
                                    {format(new Date(apt.appointment_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2 text-xs sm:text-sm">{apt.appointment_time}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div>
                                    <div className="font-medium text-xs sm:text-sm truncate" title={apt.client_name || apt.client?.name || 'N/A'}>
                                      {apt.client_name || apt.client?.name || 'N/A'}
                                    </div>
                                    {apt.client?.phone && (
                                      <div className="text-xs text-muted-foreground truncate" title={apt.client.phone}>
                                        {apt.client.phone}
                                      </div>
                                    )}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs sm:text-sm truncate" title={apt.barber?.name || 'N/A'}>
                                    {apt.barber?.name || 'N/A'}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div>
                                    <div className="flex items-center gap-2 mb-1">
                                      {(() => {
                                        try {
                                          const n = apt.notes ? JSON.parse(apt.notes) : null;
                                          if (n && n.fit === true) {
                                            return (
                                              <Badge className="bg-purple-600 text-white border-none text-[10px] h-5 px-2 font-bold uppercase shadow-sm">
                                                Encaixe
                                              </Badge>
                                            );
                                          }
                                        } catch {}
                                        return null;
                                      })()}
                                      <div className="text-xs sm:text-sm font-medium truncate max-w-[120px]" title={apt.service?.title || 'N/A'}>
                                        {apt.service?.title || 'N/A'}
                                      </div>
                                    </div>
                                    {apt.service?.price && (
                                      <div className="text-xs text-muted-foreground">
                                        R$ {apt.service.price.toFixed(2)}
                                      </div>
                                    )}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  {apt.appointment_payments && apt.appointment_payments.length > 0 ? (
                                    <div className="flex flex-col gap-1">
                                      {apt.appointment_payments.map((p, idx) => (
                                        <span key={idx} className="text-xs text-muted-foreground whitespace-nowrap">
                                          {p.payment_method === 'pix' ? 'Pix' : 
                                           p.payment_method === 'cartao' ? 'Cartão' : 
                                           p.payment_method === 'dinheiro' ? 'Dinheiro' : 'Outro'}: R$ {Number(p.amount).toFixed(2)}
                                        </span>
                                      ))}
                                    </div>
                                  ) : (
                                    <div className="text-xs text-muted-foreground">
                                      {apt.payment_method ? (
                                        <>
                                          {apt.payment_method === 'pix' ? 'Pix' : 
                                           apt.payment_method === 'cartao' ? 'Cartão' : 
                                           apt.payment_method === 'dinheiro' ? 'Dinheiro' : apt.payment_method}
                                        </>
                                      ) : '-'}
                                    </div>
                                  )}
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">{getTypeBadge(apt.booking_type)}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">{getStatusBadge(apt.status)}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  {apt.photo_url ? (
                                    <button
                                      type="button"
                                      onClick={() => {
                                        setImagePreviewUrl(apt.photo_url || null);
                                        setImageDialogOpen(true);
                                      }}
                                      className="block"
                                      title="Ver foto"
                                    >
                                      <img
                                        src={apt.photo_url}
                                        alt="Foto do atendimento"
                                        className="w-10 h-10 sm:w-12 sm:h-12 rounded-md object-cover border border-border"
                                      />
                                    </button>
                                  ) : (
                                    <span className="text-xs text-muted-foreground">-</span>
                                  )}
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="flex items-center justify-end gap-1">
                                    {apt.status !== 'completed' && (
                                      <Button
                                        size="sm"
                                        variant="secondary"
                                        onClick={() => handleCompleteAppointment(apt)}
                                        disabled={completingAppointmentId === apt.id}
                                        className="h-7 w-7 sm:h-8 sm:w-8 p-0"
                                      >
                                        {completingAppointmentId === apt.id ? (
                                          <Loader2 className="h-3 w-3 sm:h-4 sm:w-4 animate-spin" />
                                        ) : (
                                          <CheckCircle2 className="h-3 w-3 sm:h-4 sm:w-4" />
                                        )}
                                      </Button>
                                    )}
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      onClick={() => handleEdit(apt)}
                                      className="h-7 w-7 sm:h-8 sm:w-8 p-0"
                                    >
                                      <Pencil className="h-3 w-3 sm:h-4 sm:w-4" />
                                    </Button>
                                    <Button
                                      size="sm"
                                      variant="destructive"
                                      onClick={() => {
                                        setDeletingAppointment(apt);
                                        setDeleteDialogOpen(true);
                                      }}
                                      className="h-7 w-7 sm:h-8 sm:w-8 p-0"
                                    >
                                      <Trash2 className="h-3 w-3 sm:h-4 sm:w-4" />
                                    </Button>
                                  </div>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}
                  <div className="flex justify-end mt-2">
                    <div className="text-right text-sm">
                      <div className="text-muted-foreground">Total de serviços no período</div>
                      <div className="font-bold text-primary">R$ {servicesTotal.toFixed(2)}</div>
                    </div>
                  </div>
                </>
              )}
              {appointments.length > 0 && (
                <div className="flex flex-wrap items-center justify-between gap-2 mt-3 pt-3 border-t border-border/60">
                  <span className="text-xs text-muted-foreground">
                    Mostrando {servicesStartIndex}-{servicesEndIndex} de {servicesTotalCount}
                  </span>
                  <div className="flex items-center gap-2">
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-7 px-2 text-xs"
                      disabled={servicesPage <= 1}
                      onClick={() => setServicesPage((prev) => Math.max(1, prev - 1))}
                    >
                      Anterior
                    </Button>
                    <span className="text-xs text-muted-foreground min-w-[68px] text-center">
                      {servicesPage} / {servicesTotalPages}
                    </span>
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-7 px-2 text-xs"
                      disabled={servicesPage >= servicesTotalPages}
                      onClick={() => setServicesPage((prev) => Math.min(servicesTotalPages, prev + 1))}
                    >
                      Próxima
                    </Button>
                  </div>
                </div>
              )}
            </TabsContent>

            {/* Aba de Produtos */}
            <TabsContent value="products" className="mt-4">
              {loadingProductSales ? (
                <div className="flex items-center justify-center py-8 sm:py-12">
                  <Loader2 className="h-6 w-6 animate-spin text-primary" />
                </div>
              ) : productSales.length === 0 ? (
                <p className="text-center text-muted-foreground py-8 sm:py-12 text-sm">
                  Nenhuma venda encontrada com os filtros selecionados.
                </p>
              ) : (
                <>
                  {isMobile ? (
                    // Mobile: Cards
                    <div className="space-y-0">
                      {productSales.map((sale) => (
                        <MobileProductCard key={sale.id} sale={sale} />
                      ))}
                    </div>
                  ) : (
                    // Desktop: Tabela
                    <div className="w-full overflow-hidden" style={{ maxWidth: '100%' }}>
                      <div className="overflow-x-auto">
                        <table className="w-full text-sm" style={{ tableLayout: 'fixed', minWidth: '800px' }}>
                          <thead>
                            <tr className="border-b border-border">
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[100px]">Data</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[60px] sm:w-[80px]">Horário</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[160px] sm:w-[200px]">Produto</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[90px]">Qtd</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[110px] sm:w-[130px]">Total</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[120px] sm:w-[140px]">Barbeiro</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[110px] sm:w-[130px]">Pagamento</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2 w-[90px] sm:w-[110px]">Status</th>
                              <th className="text-left py-2 sm:py-3 px-1 sm:px-2">Observação</th>
                              <th className="text-right py-2 sm:py-3 px-1 sm:px-2 w-[80px] sm:w-[100px]">Ações</th>
                            </tr>
                          </thead>
                          <tbody>
                            {productSales.map((sale) => (
                              <tr key={sale.id} className="border-b border-border/50 hover:bg-muted/50">
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs sm:text-sm">
                                    {format(new Date(sale.sale_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2 text-xs sm:text-sm">{sale.sale_time}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs sm:text-sm truncate" title={sale.product?.name || 'Produto'}>
                                    {sale.product?.name || 'Produto'}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">{sale.quantity}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">R$ {Number(sale.total_price).toFixed(2)}</td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs sm:text-sm truncate" title={sale.barber?.name || barbers.find(b => b.id === sale.barber_id)?.name || 'N/A'}>
                                    {sale.barber?.name || barbers.find(b => b.id === sale.barber_id)?.name || 'N/A'}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  {sale.payment_method === 'pix' && (
                                    <Badge className="bg-green-500/20 text-green-600 text-xs">Pix</Badge>
                                  )}
                                  {sale.payment_method === 'dinheiro' && (
                                    <Badge variant="outline" className="border-yellow-500 text-yellow-600 text-xs">Dinheiro</Badge>
                                  )}
                                  {sale.payment_method === 'cartao' && (
                                    <Badge className="bg-blue-500/20 text-blue-600 text-xs">Cartão</Badge>
                                  )}
                                  {!sale.payment_method && (
                                    <span className="text-xs text-muted-foreground">-</span>
                                  )}
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  {sale.status === 'confirmed' && (
                                    <Badge className="bg-green-500/20 text-green-600 text-xs">Confirmado</Badge>
                                  )}
                                  {sale.status === 'pending' && (
                                    <Badge variant="outline" className="border-yellow-500 text-yellow-600 text-xs">Pendente</Badge>
                                  )}
                                  {sale.status === 'cancelled' && (
                                    <Badge variant="destructive" className="text-xs">Cancelado</Badge>
                                  )}
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="text-xs text-muted-foreground truncate" title={sale.notes || ''}>
                                    {sale.notes || '-'}
                                  </div>
                                </td>
                                <td className="py-2 sm:py-3 px-1 sm:px-2">
                                  <div className="flex items-center justify-end">
                                    {sale.status !== 'confirmed' && (
                                      <Button
                                        size="sm"
                                        variant="secondary"
                                        onClick={() => handleCompleteProductSale(sale)}
                                        disabled={completingSaleId === sale.id}
                                        className="h-7 w-7 sm:h-8 sm:w-8 p-0"
                                      >
                                        {completingSaleId === sale.id ? (
                                          <Loader2 className="h-3 w-3 sm:h-4 sm:w-4 animate-spin" />
                                        ) : (
                                          <CheckCircle2 className="h-3 w-3 sm:h-4 sm:w-4" />
                                        )}
                                      </Button>
                                    )}
                                    <Button
                                      size="sm"
                                      variant="destructive"
                                      onClick={() => {
                                        setDeletingSale(sale);
                                        setDeleteSaleDialogOpen(true);
                                      }}
                                      className="h-7 w-7 sm:h-8 sm:w-8 p-0"
                                    >
                                      <Trash2 className="h-3 w-3 sm:h-4 sm:w-4" />
                                    </Button>
                                  </div>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}
                  <div className="flex justify-end mt-2">
                    <div className="text-right text-sm">
                      <div className="text-muted-foreground">Total de produtos no período</div>
                      <div className="font-bold text-primary">R$ {productsTotal.toFixed(2)}</div>
                    </div>
                  </div>
                </>
              )}
              {productSales.length > 0 && (
                <div className="flex flex-wrap items-center justify-between gap-2 mt-3 pt-3 border-t border-border/60">
                  <span className="text-xs text-muted-foreground">
                    Mostrando {productsStartIndex}-{productsEndIndex} de {productsTotalCount}
                  </span>
                  <div className="flex items-center gap-2">
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-7 px-2 text-xs"
                      disabled={productsPage <= 1}
                      onClick={() => setProductsPage((prev) => Math.max(1, prev - 1))}
                    >
                      Anterior
                    </Button>
                    <span className="text-xs text-muted-foreground min-w-[68px] text-center">
                      {productsPage} / {productsTotalPages}
                    </span>
                    <Button
                      size="sm"
                      variant="outline"
                      className="h-7 px-2 text-xs"
                      disabled={productsPage >= productsTotalPages}
                      onClick={() => setProductsPage((prev) => Math.min(productsTotalPages, prev + 1))}
                    >
                      Próxima
                    </Button>
                  </div>
                </div>
              )}
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>

      {/* Dialog de Edição */}
      <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
        <DialogContent className="max-w-[95vw] sm:max-w-md overflow-hidden">
          <DialogHeader>
            <DialogTitle>Editar Agendamento</DialogTitle>
            <DialogDescription>
              Altere as informações do agendamento abaixo.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-3 sm:space-y-4 max-h-[60vh] overflow-y-auto pr-2">
            <div>
              <Label className="text-sm">Data</Label>
              <Input
                type="date"
                value={editForm.appointment_date}
                onChange={(e) => setEditForm({ ...editForm, appointment_date: e.target.value })}
                className="w-full"
              />
            </div>
            <div>
              <Label className="text-sm">Horário</Label>
              <Input
                type="time"
                value={editForm.appointment_time}
                onChange={(e) => setEditForm({ ...editForm, appointment_time: e.target.value })}
                className="w-full"
              />
            </div>
            <div>
              <Label className="text-sm">Barbeiro</Label>
              <Select
                value={editForm.barber_id}
                onValueChange={(value) => setEditForm({ ...editForm, barber_id: value })}
              >
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Selecione um barbeiro" />
                </SelectTrigger>
                <SelectContent>
                  {barbers.map((barber) => (
                    <SelectItem key={barber.id} value={barber.id}>
                      {barber.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm">Serviço</Label>
              <Select
                value={editForm.service_id}
                onValueChange={(value) => setEditForm({ ...editForm, service_id: value })}
              >
                <SelectTrigger className="w-full">
                  <SelectValue placeholder="Selecione um serviço" />
                </SelectTrigger>
                <SelectContent>
                  {services.map((service) => (
                    <SelectItem key={service.id} value={service.id}>
                      {service.title} - R$ {service.price.toFixed(2)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm">Status</Label>
              <Select
                value={editForm.status}
                onValueChange={(value) => setEditForm({ ...editForm, status: value })}
              >
                <SelectTrigger className="w-full">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="pending">Pendente</SelectItem>
                  <SelectItem value="confirmed">Confirmado</SelectItem>
                  <SelectItem value="completed">Concluído</SelectItem>
                  <SelectItem value="cancelled">Cancelado</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-sm">Observações (opcional)</Label>
              <Input
                value={editForm.notes}
                onChange={(e) => setEditForm({ ...editForm, notes: e.target.value })}
                placeholder="Observações sobre o agendamento"
                className="w-full"
              />
            </div>
          </div>
          <div className="flex flex-col sm:flex-row justify-end gap-2 mt-4 sm:mt-6">
            <Button
              variant="outline"
              onClick={() => {
                setEditDialogOpen(false);
                setEditingAppointment(null);
              }}
              className="w-full sm:w-auto"
            >
              Cancelar
            </Button>
            <Button onClick={handleSave} disabled={saving} className="w-full sm:w-auto">
              {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Salvar
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <Dialog open={imageDialogOpen} onOpenChange={setImageDialogOpen}>
        <DialogContent className="max-w-[95vw] sm:max-w-3xl p-0 overflow-hidden">
          <DialogHeader className="sr-only">
            <DialogTitle>Visualizar foto do atendimento</DialogTitle>
            <DialogDescription>Pré-visualização da foto anexada ao agendamento.</DialogDescription>
          </DialogHeader>
          <img
            src={imagePreviewUrl || ''}
            alt="Foto do atendimento"
            className="w-full h-full max-h-[85vh] object-contain bg-black"
          />
        </DialogContent>
      </Dialog>

      <Dialog open={manualDialogOpen} onOpenChange={setManualDialogOpen}>
        <DialogContent className="max-w-md w-[95vw]">
          <DialogHeader>
            <DialogTitle>
              {manualType === 'service' ? 'Lançar serviço manual' : 'Registrar venda de produto'}
            </DialogTitle>
            <DialogDescription>
              {manualType === 'service'
                ? 'Cria um agendamento manual vinculado ao barbeiro selecionado.'
                : 'Registra uma venda de produto vinculada ao barbeiro selecionado.'}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div>
              <Label className="text-xs text-muted-foreground mb-1 block">Barbeiro</Label>
              <Input
                value={barbers.find(b => b.id === manualBarberId)?.name || ''}
                readOnly
                className="h-9 text-sm"
              />
            </div>
            {manualType === 'service' ? (
              <>
                <div>
                  <Label className="text-xs text-muted-foreground mb-1 block">Serviço</Label>
                  <Select value={manualServiceId} onValueChange={setManualServiceId}>
                    <SelectTrigger className="h-9 text-sm">
                      <SelectValue placeholder="Selecione um serviço" />
                    </SelectTrigger>
                    <SelectContent>
                      {services.map((service) => (
                        <SelectItem key={service.id} value={service.id}>
                          {service.title}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground mb-1 block">Nome do cliente (opcional)</Label>
                  <Input
                    value={manualClientName}
                    onChange={(e) => setManualClientName(e.target.value)}
                    placeholder="Ex: Cliente local"
                    className="h-9 text-sm"
                  />
                </div>
              </>
            ) : (
              <>
                <div>
                  <Label className="text-xs text-muted-foreground mb-1 block">Produto</Label>
                  <Select value={manualProductId} onValueChange={setManualProductId}>
                    <SelectTrigger className="h-9 text-sm">
                      <SelectValue placeholder="Selecione um produto" />
                    </SelectTrigger>
                    <SelectContent>
                      {products.map((product) => (
                        <SelectItem key={product.id} value={product.id}>
                          {product.name} - R$ {Number(product.price).toFixed(2)}
                          {product.stock !== null && ` (Estoque: ${product.stock})`}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground mb-1 block">Quantidade</Label>
                  <Input
                    type="number"
                    min={1}
                    value={manualQuantity}
                    onChange={(e) => setManualQuantity(Number(e.target.value) || 1)}
                    className="h-9 text-sm"
                  />
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground mb-1 block">Observação (opcional)</Label>
                  <Input
                    value={manualClientName}
                    onChange={(e) => setManualClientName(e.target.value)}
                    placeholder="Ex: Cliente local ou detalhes da venda"
                    className="h-9 text-sm"
                  />
                </div>
              </>
            )}
                  <div className="grid grid-cols-2 gap-3">
              <div>
                <Label className="text-xs text-muted-foreground mb-1 block">Data</Label>
                <Input
                  type="date"
                  value={manualDate}
                  onChange={(e) => setManualDate(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>
              <div>
                <Label className="text-xs text-muted-foreground mb-1 block">Hora</Label>
                <Input
                  type="time"
                  value={manualTime}
                  onChange={(e) => setManualTime(e.target.value)}
                  className="h-9 text-sm"
                />
              </div>
            </div>
                  <div>
                    <Label className="text-xs text-muted-foreground mb-1 block">Pagamento</Label>
                    <Select value={manualPaymentMethod} onValueChange={(v) => setManualPaymentMethod(v as 'pix' | 'dinheiro' | 'cartao')}>
                      <SelectTrigger className="h-9 text-sm">
                        <SelectValue placeholder="Selecione o método" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="pix">Pix</SelectItem>
                        <SelectItem value="dinheiro">Dinheiro</SelectItem>
                        <SelectItem value="cartao">Cartão</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
          </div>
          <div className="flex justify-end gap-2 mt-2">
            <Button variant="outline" onClick={() => setManualDialogOpen(false)} disabled={manualSaving}>
              Cancelar
            </Button>
            <Button onClick={handleSaveManualAppointment} disabled={manualSaving}>
              {manualSaving && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
              Salvar lançamento
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Dialog de Confirmação de Exclusão */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent className="max-w-[95vw] sm:max-w-md overflow-hidden">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar Exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir este agendamento? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
            {deletingAppointment && (
              <div className="mt-2 p-2 bg-destructive/10 rounded text-sm text-left">
                <div><strong>Cliente:</strong> {deletingAppointment.client?.name || 'N/A'}</div>
                <div><strong>Data:</strong> {format(new Date(deletingAppointment.appointment_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}</div>
                <div><strong>Horário:</strong> {deletingAppointment.appointment_time}</div>
              </div>
            )}
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              disabled={deleting}
              className="bg-destructive hover:bg-destructive/90"
            >
              {deleting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Dialog de Confirmação de Exclusão de Venda */}
      <AlertDialog open={deleteSaleDialogOpen} onOpenChange={setDeleteSaleDialogOpen}>
        <AlertDialogContent className="max-w-[95vw] sm:max-w-md overflow-hidden">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar Exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir esta venda de produto? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
            {deletingSale && (
              <div className="mt-2 p-2 bg-destructive/10 rounded text-sm text-left">
                <div><strong>Produto:</strong> {deletingSale.product?.name || 'N/A'}</div>
                <div><strong>Data:</strong> {format(new Date(deletingSale.sale_date + 'T00:00:00'), 'dd/MM/yyyy', { locale: ptBR })}</div>
                <div><strong>Horário:</strong> {deletingSale.sale_time}</div>
                <div><strong>Qtd:</strong> {deletingSale.quantity}</div>
                <div><strong>Total:</strong> R$ {Number(deletingSale.total_price).toFixed(2)}</div>
              </div>
            )}
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deletingSaleLoading}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteSale}
              disabled={deletingSaleLoading}
              className="bg-destructive hover:bg-destructive/90"
            >
              {deletingSaleLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

