    // Load theme colors
    const { data: themeData } = await (supabase as any)
      .from('site_config')
      .select('config_value')
      .eq('config_key', 'theme_colors')
      .single();

    if (themeData) {
      setThemeColors({
        ...defaultThemeColors,
        ...(themeData.config_value || {}),
      });
    }

    // Load hero section
    const { data: heroData } = await (supabase as any)
      .from('site_config')
      .select('config_value')
      .eq('config_key', 'hero_section')
      .single();

    if (heroData) {
      const { image_url, ...heroContent } = heroData.config_value || {};
      setHeroSection({
        ...defaultHeroSection,
        ...(heroContent || {}),
      });
    }

    // Load footer info
    const { data: footerData } = await (supabase as any)
      .from('site_config')
      .select('config_value')
      .eq('config_key', 'footer_info')
      .single();

    if (footerData) {
      const config = footerData.config_value || {};
      setFooterInfo({
        ...defaultFooterInfo,
        ...config,
        social: {
          ...defaultFooterInfo.social,
          ...(config.social || {}),
