        </CardHeader>
        <CardContent className="p-2 sm:p-3 md:p-4 lg:p-6 w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
          <div className="space-y-3 sm:space-y-4">
            <div>
              <Label className="text-sm">Título Principal</Label>
