                  <img
                    src={selectedUser.image_url}
                    alt={selectedUser.name || 'User'}
                    className="w-16 h-16 rounded-full object-cover border-2 border-primary/50 shadow-md flex-shrink-0"
                    onError={(e) => {
                      (e.target as HTMLImageElement).style.display = 'none';
