import { createContext, useContext, useEffect, useState } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '@/integrations/supabase/client';
import { useNavigate } from 'react-router-dom';
import { cleanCPF } from '@/utils/cpfValidation';
import { toast } from 'sonner';

type UserRole = 'admin' | 'gestor' | 'cliente' | 'barbeiro';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  role: UserRole | null;
  blocked: boolean;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<{ error: any }>;
  signUp: (email: string, password: string, name: string) => Promise<{ error: any }>;
  signInOrSignUp: (name: string, phone: string) => Promise<{ error: any }>;
  signUpWithCPF: (cpf: string, name: string, whatsapp: string, birthDate: string) => Promise<{ error: any }>;
  signInWithCPF: (cpf: string) => Promise<{ error: any }>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [role, setRole] = useState<UserRole | null>(null);
  const [blocked, setBlocked] = useState<boolean>(false);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const fetchUserRole = async (userId: string) => {
    // Buscar todas as roles do usuário
    const { data, error } = await (supabase as any)
      .from('user_roles')
      .select('role')
      .eq('user_id', userId);

    if (error || !data || data.length === 0) {
      console.error('Error fetching user role:', error);
      return null;
    }

    // Priorizar role admin > gestor > barbeiro > cliente
    const roles = data.map((r: any) => r.role);
    const finalRole = roles.includes('admin') ? 'admin' : roles.includes('gestor') ? 'gestor' : roles.includes('barbeiro') ? 'barbeiro' : 'cliente';
    
    return finalRole;
  };

  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (event === 'TOKEN_REFRESH_FAILED') {
          toast.error('Sua sessão expirou. Faça login novamente.');
          await supabase.auth.signOut();
          setSession(null);
          setUser(null);
          setRole(null);
          navigate('/auth');
          setLoading(false);
          return;
        }

        setSession(session);
        setUser(session?.user ?? null);
        
        if (session?.user) {
          setTimeout(async () => {
            const userRole = await fetchUserRole(session.user.id);
            setRole(userRole);
            try {
              const { data: prof } = await (supabase as any)
                .from('profiles')
                .select('blocked')
                .eq('id', session.user.id)
                .maybeSingle();
              setBlocked(Boolean(prof?.blocked));
            } catch {
              setBlocked(false);
            }
          }, 0);
        } else {
          setRole(null);
          setBlocked(false);
        }
        
        setLoading(false);
      }
    );

    supabase.auth.getSession().then(async ({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      
      if (session?.user) {
        const userRole = await fetchUserRole(session.user.id);
        setRole(userRole);
        try {
          const { data: prof } = await (supabase as any)
            .from('profiles')
            .select('blocked')
            .eq('id', session.user.id)
            .maybeSingle();
          setBlocked(Boolean(prof?.blocked));
        } catch {
          setBlocked(false);
        }
      }
      
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string) => {
    try {
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });
      
      // Salvar email no localStorage para preenchimento automático futuro (apenas se login bem-sucedido)
      if (!error && typeof window !== 'undefined') {
        try {
          localStorage.setItem('lastBarberEmail', email);
        } catch (e) {
          console.warn('Não foi possível salvar email no localStorage:', e);
        }
      }
      
      return { error };
    } catch (error: any) {
      return { error };
    }
  };

  const signUp = async (email: string, password: string, name: string) => {
    try {
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: `${window.location.origin}/`,
          data: {
            name,
          }
        }
      });

      if (authError) return { error: authError };

      return { error: null };
    } catch (error: any) {
      return { error };
    }
  };

  const signInOrSignUp = async (name: string, phone: string) => {
    try {
      const tempEmail = `${phone.replace(/\D/g, '')}@cliente.com`;
      const tempPassword = phone.replace(/\D/g, '');

      // Try to sign in first
      let { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
        email: tempEmail,
        password: tempPassword,
      });

      if (signInError) {
        // If sign in fails, try to sign up
        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email: tempEmail,
          password: tempPassword,
          options: {
            data: {
              name,
              phone,
            },
          },
        });

        if (signUpError) {
          return { error: signUpError };
        }

        // O trigger handle_new_user cria profile e role automaticamente
        // Após signup, fazer signIn para criar a sessão (se não houver sessão)
        if (signUpData.user && !signUpData.session) {
          // Aguardar um pouco para o trigger executar
          await new Promise(resolve => setTimeout(resolve, 500));
          
          // Fazer signIn para criar a sessão
          const { data: signInAfterSignUp, error: signInAfterSignUpError } = await supabase.auth.signInWithPassword({
            email: tempEmail,
            password: tempPassword,
          });
          
          if (signInAfterSignUpError) {
            // Se falhar, ainda retorna sucesso pois o usuário foi criado
            // O usuário pode precisar confirmar email ou fazer login manualmente
            console.warn('SignIn after signup failed:', signInAfterSignUpError);
          }
        }

        return { error: null };
      }

      // Update profile on sign in
      if (signInData.user) {
        await (supabase as any)
          .from('profiles')
          .upsert({
            id: signInData.user.id,
            name,
            phone,
          }, {
            onConflict: 'id'
          });
      }

      return { error: null };
    } catch (error: any) {
      return { error };
    }
  };

  const signUpWithCPF = async (cpf: string, name: string, whatsapp: string, birthDate: string) => {
    try {
      const cleanedCPF = cleanCPF(cpf);
      const tempEmail = `${cleanedCPF}@cliente.com`;
      const tempPassword = cleanedCPF;

      // Criar usuário no Supabase Auth
      const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
        email: tempEmail,
        password: tempPassword,
        options: {
          data: {
            name,
            cpf: cleanedCPF,
            whatsapp,
            birth_date: birthDate,
          },
        },
      });

      if (signUpError) {
        return { error: signUpError };
      }

      // O trigger handle_new_user cria profile e role automaticamente
      // Após signup, fazer signIn para criar a sessão (se não houver sessão)
      if (signUpData.user && !signUpData.session) {
        // Aguardar um pouco para o trigger executar
        await new Promise(resolve => setTimeout(resolve, 500));
        
        // Fazer signIn para criar a sessão
        const { data: signInAfterSignUp, error: signInAfterSignUpError } = await supabase.auth.signInWithPassword({
          email: tempEmail,
          password: tempPassword,
        });
        
        if (signInAfterSignUpError) {
          console.warn('SignIn after signup failed:', signInAfterSignUpError);
          // Ainda retorna sucesso pois o usuário foi criado
        } else {
          // Salvar CPF no localStorage após cadastro bem-sucedido
          if (typeof window !== 'undefined') {
            try {
              localStorage.setItem('lastClientCPF', cleanedCPF);
            } catch (e) {
              console.warn('Não foi possível salvar CPF no localStorage:', e);
            }
          }
        }
        
        // Garantir vinculação do WhatsApp ao perfil
        try {
          const { data: currentUserRes } = await supabase.auth.getUser();
          const currentUser = currentUserRes?.user || signUpData.user;
          const phoneDigits = (whatsapp || '').replace(/\D/g, '');
          if (currentUser) {
            await (supabase as any)
              .from('profiles')
              .upsert(
                {
                  id: currentUser.id,
                  name: name?.trim() || 'Usuário',
                  phone: phoneDigits || null,
                },
                { onConflict: 'id' }
              );
          }
        } catch (e) {
          console.warn('Falha ao atualizar telefone no perfil após cadastro:', e);
        }
      } else if (signUpData.user && signUpData.session) {
        // Se já tiver sessão, salvar CPF também
        if (typeof window !== 'undefined') {
          try {
            localStorage.setItem('lastClientCPF', cleanedCPF);
          } catch (e) {
            console.warn('Não foi possível salvar CPF no localStorage:', e);
          }
        }

        // Garantir vinculação do WhatsApp ao perfil
        try {
          const currentUser = signUpData.user;
          const phoneDigits = (whatsapp || '').replace(/\D/g, '');
          if (currentUser) {
            await (supabase as any)
              .from('profiles')
              .upsert(
                {
                  id: currentUser.id,
                  name: name?.trim() || 'Usuário',
                  phone: phoneDigits || null,
                },
                { onConflict: 'id' }
              );
          }
        } catch (e) {
          console.warn('Falha ao atualizar telefone no perfil após cadastro (sessão existente):', e);
        }
      }

      return { error: null };
    } catch (error: any) {
      return { error };
    }
  };

  const signInWithCPF = async (cpf: string) => {
    try {
      const cleanedCPF = cleanCPF(cpf);
      
      // Buscar usuário pelo CPF na tabela profiles
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('id, cpf')
        .eq('cpf', cleanedCPF)
        .maybeSingle();

      if (profileError) {
        return { error: new Error('Erro ao buscar CPF: ' + profileError.message) };
      }

      if (!profile) {
        return { error: new Error('CPF não cadastrado. Faça seu cadastro primeiro.') };
      }

      // Gerar email e senha baseados no CPF
      const tempEmail = `${cleanedCPF}@cliente.com`;
      const tempPassword = cleanedCPF;

      // Fazer login
      const { data: signInData, error: signInError } = await supabase.auth.signInWithPassword({
        email: tempEmail,
        password: tempPassword,
      });

      if (signInError) {
        return { error: signInError };
      }

      // Sincronizar telefone do metadata para o perfil, caso ainda não exista
      try {
        const { data: userRes } = await supabase.auth.getUser();
        const u = userRes?.user;
        const metaPhone = (u as any)?.user_metadata?.whatsapp || (u as any)?.user_metadata?.phone || '';
        if (u && metaPhone) {
          const phoneDigits = String(metaPhone).replace(/\D/g, '');
          await (supabase as any)
            .from('profiles')
            .upsert(
              {
                id: u.id,
                name: (u as any)?.user_metadata?.name || u.email?.split('@')[0] || 'Usuário',
                phone: phoneDigits || null,
              },
              { onConflict: 'id' }
            );
        }
      } catch (e) {
        console.warn('Falha ao sincronizar telefone do metadata para perfil no login:', e);
      }

      // Salvar CPF no localStorage para preenchimento automático futuro
      if (typeof window !== 'undefined') {
        try {
          localStorage.setItem('lastClientCPF', cleanedCPF);
        } catch (e) {
          console.warn('Não foi possível salvar CPF no localStorage:', e);
        }
      }
      try {
        const { data: prof } = await (supabase as any)
          .from('profiles')
          .select('blocked')
          .eq('id', signInData.user?.id)
          .maybeSingle();
        setBlocked(Boolean(prof?.blocked));
        if (prof?.blocked) {
          toast.error('Usuário bloqueado', { description: 'Entre em contato com a barbearia para desbloqueio.' });
        }
      } catch {}

      return { error: null };
    } catch (error: any) {
      return { error };
    }
  };

  const signOut = async () => {
    await supabase.auth.signOut();
    setRole(null);
    setBlocked(false);
    navigate('/');
  };

  return (
    <AuthContext.Provider value={{ user, session, role, blocked, loading, signIn, signUp, signInOrSignUp, signUpWithCPF, signInWithCPF, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { OperatingHours, DayHours } from '@/hooks/useOperatingHours';

export interface BarberAvailability extends OperatingHours {}

export const defaultBarberAvailability: BarberAvailability = {
  monday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  tuesday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  wednesday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  thursday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  friday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  saturday: { open: '09:00', close: '18:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  sunday: { open: '09:00', close: '18:00', closed: true, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
};

export const useBarberAvailability = (barberId: string | null) => {
  const [availability, setAvailability] = useState<BarberAvailability>(defaultBarberAvailability);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (barberId) {
      loadAvailability();
    } else {
      setAvailability(defaultBarberAvailability);
      setLoading(false);
    }
  }, [barberId]);

  const loadAvailability = async () => {
    if (!barberId) return;

    setLoading(true);
    const { data, error } = await supabase
      .from('barbers')
      .select('availability')
      .eq('id', barberId)
      .maybeSingle();

    if (error) {
      console.error('Error loading barber availability:', error);
      setAvailability(defaultBarberAvailability);
    } else if (data?.availability) {
      const raw = data.availability;
      const parsed =
        typeof raw === 'string'
          ? (() => {
              try {
                return JSON.parse(raw);
              } catch {
                return null;
              }
            })()
          : raw;
      const next = parsed && typeof parsed === 'object'
        ? { ...defaultBarberAvailability, ...parsed }
        : defaultBarberAvailability;
      setAvailability(next);
    } else {
      setAvailability(defaultBarberAvailability);
    }
    setLoading(false);
  };

  const updateAvailability = async (newAvailability: BarberAvailability): Promise<{ error: Error | null }> => {
    if (!barberId) {
      return { error: new Error('Barber ID is required') };
    }

    const { error } = await supabase
      .from('barbers')
      .update({ availability: newAvailability as any })
      .eq('id', barberId);

    if (!error) {
      setAvailability(newAvailability);
    }

    return { error };
  };

  const updateDayAvailability = async (dayKey: keyof BarberAvailability, dayHours: DayHours): Promise<{ error: Error | null }> => {
    const newAvailability = { ...availability, [dayKey]: dayHours };
    return updateAvailability(newAvailability);
  };

  return {
    availability,
    loading,
    loadAvailability,
    updateAvailability,
    updateDayAvailability,
  };
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';

export interface BarberBreak {
  id: string;
  barber_id: string;
  date: string;
  start_time: string;
  end_time: string;
  created_at?: string;
  updated_at?: string;
}

export interface ConflictInfo {
  hasConflict: boolean;
  appointment?: {
    clientName: string;
    serviceTitle: string;
    appointmentTime: string;
    appointmentEndTime: string;
  };
}

export const useBarberBreaks = (barberId: string | null) => {
  const [breaks, setBreaks] = useState<BarberBreak[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (barberId) {
      loadBreaks();
    } else {
      setBreaks([]);
      setLoading(false);
    }
  }, [barberId]);

  const loadBreaks = async () => {
    if (!barberId) return;

    setLoading(true);
    const { data, error } = await supabase
      .from('barber_breaks')
      .select('*')
      .eq('barber_id', barberId)
      .gte('date', new Date().toISOString().split('T')[0]) // Only future breaks
      .order('date', { ascending: true })
      .order('start_time', { ascending: true });

    if (error) {
      // Ignore 404/table not found errors (table might not exist) - this is expected if table doesn't exist yet
      if (error.code === 'PGRST116' || error.code === 'PGRST205' || error.code === '42P01') {
        // Silently ignore - table doesn't exist yet
        setBreaks([]);
      } else {
        console.error('Error loading breaks:', error);
        setBreaks([]);
      }
    } else {
      setBreaks(data || []);
    }
    setLoading(false);
  };

  const checkConflict = async (
    barberId: string,
    date: string,
    startTime: string,
    endTime: string,
    excludeBreakId?: string
  ): Promise<ConflictInfo> => {
    // Convert times to minutes for comparison
    const timeToMinutes = (time: string): number => {
      const [hours, minutes] = time.split(':').map(Number);
      return hours * 60 + minutes;
    };

    const pauseStartMinutes = timeToMinutes(startTime);
    const pauseEndMinutes = timeToMinutes(endTime);

    // Query appointments for the date
    const { data: appointments, error } = await supabase
      .from('appointments')
      .select(`
        appointment_time,
        client_name,
        service:services(duration, title)
      `)
      .eq('barber_id', barberId)
      .eq('appointment_date', date)
      .in('status', ['confirmed', 'pending']); // Only check active appointments

    if (error) {
      console.error('Error checking conflicts:', error);
      return { hasConflict: false };
    }

    // Check each appointment for overlap
    for (const apt of appointments || []) {
      if (!apt.service || !apt.appointment_time) continue;

      const aptStartMinutes = timeToMinutes(apt.appointment_time);
      const aptDuration = apt.service.duration || 30;
      const aptEndMinutes = aptStartMinutes + aptDuration;

      // Check if pause overlaps with appointment
      // Overlap occurs if: pause_start < apt_end AND pause_end > apt_start
      if (pauseStartMinutes < aptEndMinutes && pauseEndMinutes > aptStartMinutes) {
        const minutesToTime = (minutes: number): string => {
          const hours = Math.floor(minutes / 60);
          const mins = minutes % 60;
          return `${String(hours).padStart(2, '0')}:${String(mins).padStart(2, '0')}`;
        };

        return {
          hasConflict: true,
          appointment: {
            clientName: apt.client_name || 'Cliente',
            serviceTitle: apt.service.title || 'Serviço',
            appointmentTime: apt.appointment_time,
            appointmentEndTime: minutesToTime(aptEndMinutes),
          },
        };
      }
    }

    return { hasConflict: false };
  };

  const createBreak = async (
    barberId: string,
    date: string,
    startTime: string,
    endTime: string
  ): Promise<{ error: Error | null }> => {
    // Validate times
    if (endTime <= startTime) {
      return { error: new Error('Horário de fim deve ser maior que horário de início') };
    }

    // Check for conflicts before creating
    const conflict = await checkConflict(barberId, date, startTime, endTime);
    if (conflict.hasConflict && conflict.appointment) {
      return {
        error: new Error(
          `Não é possível criar pausa. Cliente ${conflict.appointment.clientName} tem agendamento de ${conflict.appointment.serviceTitle} das ${conflict.appointment.appointmentTime} às ${conflict.appointment.appointmentEndTime}`
        ),
      };
    }

    const { error } = await supabase
      .from('barber_breaks')
      .insert([{
        barber_id: barberId,
        date,
        start_time: startTime,
        end_time: endTime,
      }])
      .select()
      .single();

    if (!error) {
      await loadBreaks();
    }

    return { error };
  };

  const updateBreak = async (
    breakId: string,
    date: string,
    startTime: string,
    endTime: string
  ): Promise<{ error: Error | null }> => {
    // Get the break to find barber_id
    const breakData = breaks.find(b => b.id === breakId);
    if (!breakData) {
      return { error: new Error('Pausa não encontrada') };
    }

    // Validate times
    if (endTime <= startTime) {
      return { error: new Error('Horário de fim deve ser maior que horário de início') };
    }

    // Check for conflicts before updating (exclude current break)
    const conflict = await checkConflict(breakData.barber_id, date, startTime, endTime, breakId);
    if (conflict.hasConflict && conflict.appointment) {
      return {
        error: new Error(
          `Não é possível atualizar pausa. Cliente ${conflict.appointment.clientName} tem agendamento de ${conflict.appointment.serviceTitle} das ${conflict.appointment.appointmentTime} às ${conflict.appointment.appointmentEndTime}`
        ),
      };
    }

    const { error } = await supabase
      .from('barber_breaks')
      .update({
        date,
        start_time: startTime,
        end_time: endTime,
      })
      .eq('id', breakId);

    if (!error) {
      await loadBreaks();
    }

    return { error };
  };

  const deleteBreak = async (breakId: string): Promise<{ error: Error | null }> => {
    const { error } = await supabase
      .from('barber_breaks')
      .delete()
      .eq('id', breakId);

    if (!error) {
      await loadBreaks();
    }

    return { error };
  };

  const getBreaksForDate = (date: string): BarberBreak[] => {
    return breaks.filter(b => b.date === date);
  };

  return {
    breaks,
    loading,
    loadBreaks,
    createBreak,
    updateBreak,
    deleteBreak,
    checkConflict,
    getBreaksForDate,
  };
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { getDayKey, OperatingHours, DayHours } from './useOperatingHours';

export interface BarberDaySchedule {
  open: string;
  close: string;
  closed: boolean;
  observation?: string;
}

export const useBarberSchedule = (barberId: string | null, date: Date | null) => {
  const [schedule, setSchedule] = useState<BarberDaySchedule | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (barberId && date) {
      loadSchedule();
    }
  }, [barberId, date?.toISOString().split('T')[0]]);

  const loadSchedule = async () => {
    if (!barberId || !date) return;
    setLoading(true);

    try {
      const dateStr = date.toISOString().split('T')[0];
      const dayKey = getDayKey(date);

      // 1. Try to get specific day schedule from barber_schedules
      const { data: monthlyData, error: monthlyError } = await supabase
        .from('barber_schedules' as any)
        .select('*')
        .eq('barber_id', barberId)
        .eq('date', dateStr)
        .maybeSingle();

      if (!monthlyError && monthlyData) {
        setSchedule({
          open: monthlyData.open,
          close: monthlyData.close,
          closed: monthlyData.closed,
          observation: monthlyData.observation
        });
        setLoading(false);
        return;
      }

      // 2. Try to get weekly availability from barbers table
      const { data: barberData, error: barberError } = await supabase
        .from('barbers')
        .select('availability')
        .eq('id', barberId)
        .maybeSingle();

      if (!barberError && barberData?.availability) {
        const availability = (typeof barberData.availability === 'string' 
          ? JSON.parse(barberData.availability) 
          : barberData.availability) as OperatingHours;

        const dayAvailability = availability[dayKey];
        if (dayAvailability) {
          setSchedule({
            open: dayAvailability.open,
            close: dayAvailability.close,
            closed: dayAvailability.closed,
          });
          setLoading(false);
          return;
        }
      }

      // 3. Fallback to site configuration
      const { data: shopData, error: shopError } = await supabase
        .from('site_config')
        .select('config_value')
        .eq('config_key', 'operating_hours')
        .maybeSingle();

      if (!shopError && shopData?.config_value) {
        const shopHours = shopData.config_value as unknown as OperatingHours;
        const dayHours = shopHours[dayKey];
        if (dayHours) {
          setSchedule({
            open: dayHours.open,
            close: dayHours.close,
            closed: dayHours.closed,
          });
          setLoading(false);
          return;
        }
      }

      // 4. Ultimate default
      setSchedule({
        open: '09:00',
        close: '20:00',
        closed: dayKey === 'sunday',
      });

    } catch (e) {
      console.error('Error loading barber schedule:', e);
    } finally {
      setLoading(false);
    }
  };

  return { schedule, loading, reload: loadSchedule };
};

import { useState, useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { getSiteConfig, invalidateSiteConfig } from '@/lib/siteConfigCache';

export interface DayHours {
  open: string;
  close: string;
  closed: boolean;
  lunchStart?: string;
  lunchEnd?: string;
  hasLunchBreak?: boolean;
}

export interface OperatingHours {
  monday: DayHours;
  tuesday: DayHours;
  wednesday: DayHours;
  thursday: DayHours;
  friday: DayHours;
  saturday: DayHours;
  sunday: DayHours;
}

export const defaultOperatingHours: OperatingHours = {
  monday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  tuesday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  wednesday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  thursday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  friday: { open: '09:00', close: '20:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  saturday: { open: '09:00', close: '18:00', closed: false, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
  sunday: { open: '09:00', close: '18:00', closed: true, lunchStart: '12:00', lunchEnd: '13:00', hasLunchBreak: false },
};

export const dayNames: Record<keyof OperatingHours, string> = {
  sunday: 'Domingo',
  monday: 'Segunda-feira',
  tuesday: 'Terça-feira',
  wednesday: 'Quarta-feira',
  thursday: 'Quinta-feira',
  friday: 'Sexta-feira',
  saturday: 'Sábado',
};

export const dayOrder: (keyof OperatingHours)[] = [
  'sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'
];

// Maps JS Date.getDay() (0-6, Sunday=0) to our day keys
export const getDayKey = (date: Date): keyof OperatingHours => {
  const dayIndex = date.getDay();
  return dayOrder[dayIndex];
};

export const useOperatingHours = () => {
  const [operatingHours, setOperatingHours] = useState<OperatingHours>(defaultOperatingHours);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadOperatingHours();
  }, []);

  const loadOperatingHours = async () => {
    const value = await getSiteConfig('operating_hours');
    if (value) {
      setOperatingHours(value as unknown as OperatingHours);
    }
    setLoading(false);
  };

  const saveOperatingHours = async (hours: OperatingHours) => {
    const { error } = await supabase
      .from('site_config')
      .upsert({
        config_key: 'operating_hours',
        config_value: hours as any,
      }, { onConflict: 'config_key' });

    if (!error) {
      setOperatingHours(hours);
      invalidateSiteConfig('operating_hours');
    }
    return { error };
  };

  // Generate time slots based on operating hours for a specific date
  const getTimeSlotsForDate = (date: Date): string[] => {
    const dayKey = getDayKey(date);
    const dayHours = operatingHours[dayKey];

    if (dayHours.closed) return [];

    const slots: string[] = [];
    const [openHour, openMin] = dayHours.open.split(':').map(Number);
    const [closeHour, closeMin] = dayHours.close.split(':').map(Number);
    
    // Parse lunch break times if enabled
    let lunchStartTime = 0;
    let lunchEndTime = 0;
    if (dayHours.hasLunchBreak && dayHours.lunchStart && dayHours.lunchEnd) {
      const [lunchStartHour, lunchStartMin] = dayHours.lunchStart.split(':').map(Number);
      const [lunchEndHour, lunchEndMin] = dayHours.lunchEnd.split(':').map(Number);
      lunchStartTime = lunchStartHour * 60 + lunchStartMin;
      lunchEndTime = lunchEndHour * 60 + lunchEndMin;
    }
    
    let currentHour = openHour;
    let currentMin = openMin;
    
    const closeTime = closeHour * 60 + closeMin;
    
    // O loop deve ser estritamente MENOR que o horário de fechamento.
    // Se fecha às 20:00, o último slot de início deve ser 19:30 (ou anterior dependendo do intervalo).
    while (currentHour * 60 + currentMin < closeTime) {
      const currentTime = currentHour * 60 + currentMin;
      const timeStr = `${String(currentHour).padStart(2, '0')}:${String(currentMin).padStart(2, '0')}`;
      
      // Skip lunch break slots
      const isDuringLunch = dayHours.hasLunchBreak && 
        currentTime >= lunchStartTime && 
        currentTime < lunchEndTime;
      
      if (!isDuringLunch) {
        slots.push(timeStr);
      }
      
      currentMin += 30;
      if (currentMin >= 60) {
        currentMin = 0;
        currentHour += 1;
      }
    }
    
    return slots;
  };

  // Generate all slots without filtering shop lunch break.
  // Use this when generating slots for a specific barber — the barber's own
  // breaks (from barber_schedules) are applied separately in combinedBreaks,
  // so the shop lunch must NOT pre-filter the base list or the slot at the
  // exact end of the lunch (e.g. 13:00 when lunch ends at 13:00) gets lost.
  const getTimeSlotsForDateRaw = (date: Date): string[] => {
    const dayKey = getDayKey(date);
    const dayHours = operatingHours[dayKey];

    if (dayHours.closed) return [];

    const slots: string[] = [];
    const [openHour, openMin] = dayHours.open.split(':').map(Number);
    const [closeHour, closeMin] = dayHours.close.split(':').map(Number);
    const closeTime = closeHour * 60 + closeMin;

    let currentHour = openHour;
    let currentMin = openMin;

    while (currentHour * 60 + currentMin < closeTime) {
      slots.push(`${String(currentHour).padStart(2, '0')}:${String(currentMin).padStart(2, '0')}`);
      currentMin += 30;
      if (currentMin >= 60) {
        currentMin = 0;
        currentHour += 1;
      }
    }

    return slots;
  };

  const isDateOpen = (date: Date): boolean => {
    const dayKey = getDayKey(date);
    return !operatingHours[dayKey].closed;
  };

  return {
    operatingHours,
    setOperatingHours,
    saveOperatingHours,
    getTimeSlotsForDate,
    getTimeSlotsForDateRaw,
    isDateOpen,
    loading,
  };
};

// Minimal Google Drive upload helper using Google Identity Services
// Requires env vars:
// - VITE_GOOGLE_DRIVE_CLIENT_ID
// - VITE_GOOGLE_DRIVE_FOLDER_ID (target folder where files will be created)
//
// Exposes: uploadToDrivePublic(file, filename, folderId?) -> returns public view URL

let gisLoaded = false;
let gapiLoaded = false;
let tokenClient: any = null;
let accessToken: string | null = null;
let tokenExpiry: number | null = null; // epoch ms

const GIS_SRC = 'https://accounts.google.com/gsi/client';

const loadScript = (src: string) =>
  new Promise<void>((resolve, reject) => {
    const existing = document.querySelector(`script[src="${src}"]`) as HTMLScriptElement | null;
    if (existing) {
      existing.onload = () => resolve();
      existing.onerror = () => reject(new Error(`Failed to load ${src}`));
      if ((existing as any).dataset.loaded === 'true') {
        resolve();
      }
      return;
    }
    const s = document.createElement('script');
    s.src = src;
    s.async = true;
    s.defer = true;
    s.onload = () => {
      (s as any).dataset.loaded = 'true';
      resolve();
    };
    s.onerror = () => reject(new Error(`Failed to load ${src}`));
    document.head.appendChild(s);
  });

async function ensureGISLoaded() {
  if (gisLoaded) return;
  await loadScript(GIS_SRC);
  gisLoaded = true;
}

function isTokenValid() {
  return accessToken && tokenExpiry && Date.now() < tokenExpiry - 30_000; // 30s margem
}

async function getAccessTokenInteractive(scopes: string, forceConsent = false): Promise<string> {
  await ensureGISLoaded();
  const clientId = (import.meta as any).env.VITE_GOOGLE_DRIVE_CLIENT_ID as string | undefined;
  if (!clientId) {
    throw new Error('VITE_GOOGLE_DRIVE_CLIENT_ID não configurado');
  }
  const google: any = (window as any).google;
  if (!tokenClient) {
    tokenClient = google.accounts.oauth2.initTokenClient({
      client_id: clientId,
      scope: scopes,
      callback: (_resp: any) => {},
    });
  }

  accessToken = await new Promise<string>((resolve, reject) => {
    tokenClient.callback = (resp: any) => {
      if (resp && resp.access_token) {
        accessToken = resp.access_token;
        const expSec = Number((resp as any).expires_in) || 3600;
        tokenExpiry = Date.now() + expSec * 1000;
        try { localStorage.setItem('gd_has_consent', '1'); } catch {}
        resolve(accessToken!);
      } else if (resp && resp.error) {
        reject(new Error(resp.error));
      } else {
        reject(new Error('Falha ao obter token de acesso'));
      }
    };
    try {
      const hasConsent = (() => { try { return localStorage.getItem('gd_has_consent') === '1'; } catch { return false; } })();
      const prompt = forceConsent ? 'consent' : (hasConsent ? '' : 'consent');
      tokenClient.requestAccessToken({ prompt });
    } catch (e) {
      reject(e);
    }
  });
  return accessToken!;
}

async function ensureToken(scopes: string) {
  if (isTokenValid()) return accessToken!;
  try {
    return await getAccessTokenInteractive(scopes, false);
  } catch (e: any) {
    // Se falhar sem consentimento (ex.: consent_required), tentar com 'consent'
    return await getAccessTokenInteractive(scopes, true);
  }
}

export async function uploadToDrivePublic(
  file: File,
  filename: string,
  folderId?: string
): Promise<string> {
  const token = await ensureToken('https://www.googleapis.com/auth/drive.file');
  const meta: Record<string, any> = { name: filename };
  if (folderId) meta.parents = [folderId];

  const boundary = '-------314159265358979323846';
  const delimiter = `\r\n--${boundary}\r\n`;
  const closeDelim = `\r\n--${boundary}--`;

  const metadataPart = [
    'Content-Type: application/json; charset=UTF-8\r\n\r\n',
    JSON.stringify(meta),
  ].join('');

  const fileContent = await file.arrayBuffer();
  const fileBlob = new Blob([new Uint8Array(fileContent)], { type: file.type || 'application/octet-stream' });
  const fileHeader = `Content-Type: ${fileBlob.type}\r\n\r\n`;

  const multipartBody = new Blob(
    [
      delimiter,
      metadataPart,
      delimiter,
      fileHeader,
      fileBlob,
      closeDelim,
    ],
    { type: `multipart/related; boundary=${boundary}` }
  );

  const uploadResp = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
    },
    body: multipartBody as any,
  });
  if (!uploadResp.ok) {
    const text = await uploadResp.text();
    throw new Error(`Falha ao enviar para o Google Drive: ${text}`);
  }
  const uploaded = await uploadResp.json();
  const fileId = uploaded.id as string;

  // Make it public
  const permResp = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}/permissions`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ role: 'reader', type: 'anyone' }),
  });
  if (!permResp.ok) {
    // If permission change fails, still return a link requiring auth
    // But attempt to proceed.
    console.warn('Não foi possível tornar o arquivo público no Drive.');
  }

  // Public view URL
  return `https://drive.google.com/uc?export=view&id=${fileId}`;
}

import { supabase } from "./client";

export type BarberAdvanceStatus = "pending" | "approved" | "rejected";

export interface BarberAdvance {
  id: string;
  barber_id: string;
  amount: number;
  description: string | null;
  requested_by: string;
  status: BarberAdvanceStatus;
  effective_date: string;
  approved_at: string | null;
  approved_by: string | null;
  digital_signature: any | null;
  created_at: string;
  updated_at: string;
}

export interface CreateBarberAdvanceInput {
  barber_id: string;
  amount: number;
  description?: string;
  effective_date?: string; // yyyy-mm-dd
}

export const createAdvance = async (input: CreateBarberAdvanceInput) => {
  const user = (await supabase.auth.getUser()).data.user;
  if (!user) {
    return { data: null, error: new Error("Usuário não autenticado") };
  }

  const { data, error } = await (supabase as any)
    .from("barber_advances")
    .insert({
      barber_id: input.barber_id,
      amount: input.amount,
      description: input.description || null,
      effective_date: input.effective_date || new Date().toISOString().split("T")[0],
      requested_by: user.id,
      status: "pending",
    })
    .select("*")
    .single();

  return { data: data as BarberAdvance | null, error };
};

export const listAdvancesAdmin = async (options?: {
  barberId?: string;
  status?: BarberAdvanceStatus | "all";
  startDate?: string;
  endDate?: string;
}) => {
  let query = (supabase as any)
    .from("barber_advances")
    // Selecionar apenas os campos da própria tabela; 
    // dados adicionais (nome do barbeiro, etc.) são carregados separadamente se necessário.
    .select("*")
    .order("created_at", { ascending: false });

  if (options?.barberId) {
    query = query.eq("barber_id", options.barberId);
  }
  if (options?.status && options.status !== "all") {
    query = query.eq("status", options.status);
  }
  if (options?.startDate && options?.endDate) {
    query = query
      .gte("effective_date", options.startDate)
      .lte("effective_date", options.endDate);
  }

  const { data, error } = await query;
  return { data: (data as BarberAdvance[]) || [], error };
};

export const listAdvancesByBarber = async (barberId: string) => {
  const { data, error } = await (supabase as any)
    .from("barber_advances")
    .select("*")
    .eq("barber_id", barberId)
    .order("created_at", { ascending: false });

  return { data: (data as BarberAdvance[]) || [], error };
};

export const approveAdvance = async (
  advanceId: string,
  signatureMeta: Record<string, any>
) => {
  const user = (await supabase.auth.getUser()).data.user;
  if (!user) {
    return { error: new Error("Usuário não autenticado") };
  }

  const digital_signature = {
    ...signatureMeta,
    approved_at: new Date().toISOString(),
    approved_by: user.id,
  };

  const { error } = await (supabase as any)
    .from("barber_advances")
    .update({
      status: "approved",
      approved_at: new Date().toISOString(),
      approved_by: user.id,
      digital_signature,
    })
    .eq("id", advanceId);

  return { error };
};

export const rejectAdvance = async (advanceId: string) => {
  const { error } = await (supabase as any)
    .from("barber_advances")
    .update({
      status: "rejected",
    })
    .eq("id", advanceId);

  return { error };
};

/**
 * Cache em memória para site_config.
 * Evita múltiplas queries ao Supabase para a mesma chave na mesma sessão.
 * TTL padrão: 5 minutos.
 */
import { supabase } from '@/integrations/supabase/client';

const TTL_MS = 5 * 60 * 1000;

interface CacheEntry {
  value: any;
  expiresAt: number;
}

const cache: Record<string, CacheEntry> = {};

export async function getSiteConfig(key: string): Promise<any | null> {
  const now = Date.now();
  const entry = cache[key];
  if (entry && entry.expiresAt > now) {
    return entry.value;
  }

  const { data, error } = await supabase
    .from('site_config')
    .select('config_value')
    .eq('config_key', key)
    .maybeSingle();

  if (error || !data) return null;

  cache[key] = { value: data.config_value, expiresAt: now + TTL_MS };
  return data.config_value;
}

export function invalidateSiteConfig(key: string) {
  delete cache[key];
}

export function invalidateAllSiteConfig() {
  Object.keys(cache).forEach(k => delete cache[k]);
}

