            {/* Card de Manutenção de Dados */}
            <Card className="bg-card border-destructive/50 shadow-lg w-full" style={{ maxWidth: '100%', overflowX: 'hidden' }}>
              <CardHeader className="p-3 sm:p-4 md:p-6">
