    const schedulesChannelName = `barber-schedules-${barberId}`;
    const appointmentsChannelName = `appointments-barber-${barberId}`;

    let breaksRemoved = false;
    const breaksChannel = supabase
      .channel(breaksChannelName)
      .on(
