  // Função para abrir o modal de edição
  const handleEditClick = (appointment: AppointmentWithRelations) => {
    setAppointmentToEdit(appointment);
    setEditAppointment({
      date: appointment.appointment_date,
      time: appointment.appointment_time,
    });
    setActionDialogOpen(false);
    setEditDialogOpen(true);
  };

  // Função para salvar as alterações do agendamento
  const handleSaveEdit = async () => {
    if (!appointmentToEdit || !editAppointment.date || !editAppointment.time) {
      toast.error('Preencha todos os campos obrigatórios');
      return;
    }

    // Verificar se é um agendamento futuro para validar conflitos
    const appointmentDateTime = new Date(`${editAppointment.date}T${editAppointment.time}:00`);
    const now = new Date();
    const isPastAppointment = appointmentDateTime < now;

    // Se não for retroativo, verificar conflitos de horário
    if (!isPastAppointment) {
      const selectedService = services.find(s => s.id === appointmentToEdit.service_id);
      const serviceDuration = selectedService?.duration || 30;

      const { data: existingAppointments } = await supabase
        .from('appointments')
        .select('id, appointment_time, service:services(duration)')
        .eq('barber_id', appointmentToEdit.barber_id)
        .eq('appointment_date', editAppointment.date)
        .neq('status', 'cancelled')
        .neq('id', appointmentToEdit.id); // Excluir o próprio agendamento

      // Check for time conflicts
      const hasConflict = (existingAppointments || []).some((appointment) => {
        const aptDuration = appointment.service?.duration || 30;
        const newEndTime = addMinutesToTime(editAppointment.time, serviceDuration);
        const aptEndTime = addMinutesToTime(appointment.appointment_time, aptDuration);
        return (editAppointment.time < aptEndTime && newEndTime > appointment.appointment_time);
      });

      if (hasConflict) {
        toast.error('Horário indisponível! Já existe um agendamento neste horário.');
        return;
      }
    }

    try {
      const { error } = await supabase
        .from('appointments')
        .update({
          appointment_date: editAppointment.date,
          appointment_time: editAppointment.time,
          notes: appointmentToEdit.notes 
            ? `${appointmentToEdit.notes} [Editado pelo barbeiro]`
            : '[Editado pelo barbeiro]'
        })
        .eq('id', appointmentToEdit.id);

      if (error) {
        console.error('Error updating appointment:', error);
        toast.error('Erro ao atualizar agendamento: ' + error.message);
      } else {
        toast.success('Agendamento atualizado com sucesso!', {
          duration: 2000, // 2 segundos
        });
        setEditDialogOpen(false);
        setAppointmentToEdit(null);
        setEditAppointment({ date: '', time: '' });
        loadAppointments();
      }
    } catch (error: unknown) {
      const updateAppointmentError = error as Error;
      console.error('Error updating appointment:', error);
      toast.error('Erro ao atualizar agendamento: ' + updateAppointmentError.message);
    }
  };

  // Sempre que o barbeiro logado for carregado/alterado, recarregar os vales
  useEffect(() => {
    if (currentUserBarber?.id) {
      loadAdvances();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentUserBarber?.id]);

  // Quando o dialog de conclusão for aberto, sugerir o valor do serviço
  useEffect(() => {
    if (completeDialogOpen && appointmentToComplete && payments.length === 0) {
      const appointment = appointments.find(a => a.id === appointmentToComplete);
      if (appointment?.service?.price) {
        setCurrentPaymentAmount(appointment.service.price.toString());
      }
    }
  }, [completeDialogOpen, appointmentToComplete, appointments]);

  const handleCreateAppointment = async () => {
    // Prevenir múltiplas submissões simultâneas
    if (creatingAppointment) {
      toast.warning('Aguarde, processando agendamento...');
      return;
    }

    // Usar barberId do formulário ou o selectedBarber como fallback
    const barberId = newAppointment.barberId || selectedBarber;
    
    // Validações básicas
    if (!newAppointment.serviceId) {
      toast.error('Selecione um serviço');
      return;
    }
    
    if (!barberId) {
      toast.error('Selecione um barbeiro');
      return;
    }
    
    if (!newAppointment.date) {
      toast.error('Selecione uma data');
      return;
    }
    
    if (!newAppointment.time) {
      toast.error('Selecione um horário');
      return;
    }

    // Verificar se o serviço existe
    const selectedService = services.find(s => s.id === newAppointment.serviceId);
    if (!selectedService) {
      toast.error('Serviço selecionado não encontrado');
      return;
    }

    // Ativar estado de loading
    setCreatingAppointment(true);

    try {
      // Verificar se é um agendamento retroativo (passado)
      const appointmentDateTime = new Date(`${newAppointment.date}T${newAppointment.time}:00`);
      const now = new Date();
      const isPastAppointment = appointmentDateTime < now;

      // 1. VALIDAÇÕES EM PARALELO (otimizado como no cliente)
      const [existingAppointmentResult, breaksResult] = await Promise.allSettled([
        // Verificar conflitos de horário (apenas se não for retroativo)
        (!isPastAppointment && !newAppointment.isRetroactive) ? 
          (supabase as any)
            .from('appointments')
            .select('appointment_time, service:services(duration)')
            .eq('barber_id', barberId)
            .eq('appointment_date', newAppointment.date)
            .neq('status', 'cancelled') :
          Promise.resolve({ data: [] }),
        
        // Verificar pausas do barbeiro (apenas se não for retroativo)
        (!isPastAppointment && !newAppointment.isRetroactive && hasBarberBreaks) ?
          (supabase as any)
            .from('barber_breaks')
            .select('*')
            .eq('barber_id', barberId)
            .eq('date', newAppointment.date) :
          Promise.resolve({ data: [] })
      ]);

      // Verificar conflitos apenas se não for retroativo
      if (!isPastAppointment && !newAppointment.isRetroactive) {
        if (existingAppointmentResult.status === 'fulfilled' && existingAppointmentResult.value.data) {
          const serviceDuration = selectedService.duration || 30;

          const hasConflict = existingAppointmentResult.value.data.some((apt: any) => {
            const aptDuration = apt.service?.duration || 30;
            const newEndTime = addMinutesToTime(newAppointment.time, serviceDuration);
            const aptEndTime = addMinutesToTime(apt.appointment_time, aptDuration);
            return (newAppointment.time < aptEndTime && newEndTime > apt.appointment_time);
          });

          if (hasConflict) {
            toast.error('Horário indisponível! Já existe um agendamento neste horário.');
            return;
          }
        }

        // Verificar pausas
        let dbBreaks: any[] = [];
        if (breaksResult.status === 'fulfilled' && breaksResult.value.data) {
          dbBreaks = breaksResult.value.data;
        }

        let lunchBreak: { start_time: string; end_time: string } | null = null;
        let monthlySchedule: any = null;
        let workingHours: { open: string; close: string } = { open: '09:00', close: '20:00' };
        try {
          const selectedDateStr = newAppointment.date;
          const selectedDate = new Date(`${selectedDateStr}T00:00:00`);
          const { data: mSchedule } = await supabase
            .from('barber_schedules' as any)
            .select('*')
            .eq('barber_id', barberId)
            .eq('date', selectedDateStr)
            .maybeSingle();
          monthlySchedule = mSchedule;

          const trimTime = (t: unknown, fallback: string) => {
            const normalized = String(t || fallback);
            return normalized.slice(0, 5) || fallback;
          };

          if (monthlySchedule?.closed) {
            toast.error('Barbeiro indisponível nesta data', {
              description: 'Este barbeiro marcou o dia como fechado.',
            });
            return;
          }

          if (monthlySchedule) {
            workingHours = {
              open: trimTime(monthlySchedule.open, '09:00'),
              close: trimTime(monthlySchedule.close, '20:00'),
            };
          }

          if (monthlySchedule && monthlySchedule.has_lunch && monthlySchedule.lunch_start && monthlySchedule.lunch_end) {
            lunchBreak = {
              start_time: monthlySchedule.lunch_start,
              end_time: monthlySchedule.lunch_end,
            };
          } else {
            const barber = barbers.find(b => b.id === barberId) as any;
            const availabilityHours = getWorkingHoursForDate(barber?.availability, selectedDate);
            if (availabilityHours) {
              workingHours = availabilityHours;
            } else {
              const dayKey = getDayKey(selectedDate);
              const shopHours = operatingHours[dayKey];
              workingHours = {
                open: shopHours?.open || '09:00',
                close: shopHours?.close || '20:00',
              };
            }
            if (barber?.availability) {
              const availability = typeof barber.availability === 'string'
                ? JSON.parse(barber.availability)
                : barber.availability;
              const dayKey = getDayKey(selectedDate);
              const dayAvailability = availability?.[dayKey];
              if (dayAvailability?.hasLunchBreak && dayAvailability.lunchStart && dayAvailability.lunchEnd) {
                lunchBreak = {
                  start_time: dayAvailability.lunchStart,
                  end_time: dayAvailability.lunchEnd,
                };
              }
            }

            // Fallback para horário de almoço da loja se o barbeiro não tiver configurado
            if (!lunchBreak) {
              const { data: shopHours } = await supabase
                .from('site_config')
                .select('config_value')
                .eq('config_key', 'operating_hours')
                .maybeSingle();
              
              if (shopHours?.config_value) {
                const operatingHours = shopHours.config_value as any;
                const dayKey = getDayKey(selectedDate);
                const dayHours = operatingHours?.[dayKey];
                if (dayHours?.hasLunchBreak && dayHours.lunchStart && dayHours.lunchEnd) {
                  lunchBreak = {
                    start_time: dayHours.lunchStart,
                    end_time: dayHours.lunchEnd,
                  };
                }
              }
            }
          }
        } catch (err) {
          debugWarn('Erro ao ler horário de almoço do barbeiro:', err);
        }

        const combinedBreaks = [
          ...dbBreaks,
          ...(lunchBreak ? [lunchBreak] : []),
        ];

        const serviceDuration = selectedService.duration || 30;
        const appointmentEnd = addMinutesToTime(newAppointment.time, serviceDuration);
        if (newAppointment.time < workingHours.open || appointmentEnd > workingHours.close) {
          toast.error('Horário fora da programação do barbeiro', {
            description: `Atendimento permitido: ${workingHours.open} até ${workingHours.close}.`,
          });
          return;
        }

        // Adicionar pausa da observação da escala mensal
        if (monthlySchedule && monthlySchedule.observation) {
          const timeMatch = monthlySchedule.observation.match(/(\d{2}:\d{2})\s*-\s*(\d{2}:\d{2})/);
          if (timeMatch) {
            combinedBreaks.push({
              start_time: timeMatch[1],
              end_time: timeMatch[2]
            });
          }
        }

        if (combinedBreaks.length > 0) {
          const timeToMinutes = (time: string) => {
            const [hours, minutes] = time.split(':').map(Number);
            return hours * 60 + minutes;
          };

          const slotStartMinutes = timeToMinutes(newAppointment.time);
          const slotEndMinutes = slotStartMinutes + serviceDuration;

          const isInBreak = combinedBreaks.some((breakItem: any) => {
            const breakStartMinutes = timeToMinutes(breakItem.start_time);
            const breakEndMinutes = timeToMinutes(breakItem.end_time);
            return slotStartMinutes < breakEndMinutes && slotEndMinutes > breakStartMinutes;
          });

          if (isInBreak) {
            toast.error("Horário indisponível", {
              description: "Este horário está em uma pausa do barbeiro.",
            });
            return;
          }
        }
      }

      // 2. CRIAR PERFIL TEMPORÁRIO (nome opcional; se vazio, usar 'Local')
      const profileId = generateUUID();
      const clientNameFinal = (newAppointment.clientName?.trim() || 'Local');
      const { data: newProfile, error: profileError } = await (supabase as any)
        .from('profiles')
        .insert([{
          id: profileId,
          name: clientNameFinal,
          is_temp_user: true,
        }])
        .select('id')
        .single();
      if (profileError || !newProfile?.id) {
        console.error('Error creating profile:', profileError);
        toast.error('Erro ao criar perfil do cliente: ' + (profileError?.message || 'Erro desconhecido'));
        return;
      }
      const finalProfileId = newProfile.id;

      // 3. CRIAR AGENDAMENTO IMEDIATAMENTE
      const bookingType = 'manual';
      const { data: appointmentData, error } = await (supabase as any)
        .from('appointments')
        .insert([{
          client_id: finalProfileId,
          barber_id: barberId,
          service_id: newAppointment.serviceId,
          appointment_date: newAppointment.date,
          appointment_time: newAppointment.time,
          status: 'confirmed',
          booking_type: bookingType,
          notes: (isPastAppointment || newAppointment.isRetroactive) 
            ? 'Agendamento criado manualmente pelo barbeiro (retroativo)' 
            : 'Agendamento criado manualmente pelo barbeiro',
        }])
        .select('id')
        .single();

      if (error) {
        console.error('Error creating appointment:', error);
        
        if (error.code === '23503' && error.message?.includes('appointments_client_id_fkey')) {
          toast.error('❌ Erro de configuração do banco!', {
            description: 'Execute o SQL de verificação no Supabase Dashboard.',
            duration: 8000,
          });
        } else if (error.code === '23503') {
          toast.error('❌ Erro de constraint no banco!', {
            description: 'Verifique se todas as migrations foram aplicadas: ' + error.message,
            duration: 6000,
          });
        } else {
          toast.error('Erro ao criar agendamento: ' + (error.message || 'Erro desconhecido'));
        }
        return;
      }

      // 4. SUCESSO IMEDIATO (como no cliente)
      const message = (isPastAppointment || newAppointment.isRetroactive)
        ? 'Agendamento retroativo criado com sucesso!'
        : 'Agendamento criado com sucesso!';
      
      toast.success(message, {
        duration: 2000,
      });

      // 5. LIMPAR FORMULÁRIO E RECARREGAR
      setShowNewAppointment(false);
      setNewAppointment({
        clientName: '',
        clientPhone: '',
        serviceId: '',
        barberId: selectedBarber || '',
        date: '',
        time: '',
        isRetroactive: false,
      });
      setNewAppointmentStep('service');
      loadAppointments();

      // 6. PROCESSAR NOTIFICAÇÕES EM BACKGROUND (não bloquear UI)
      processNotificationsAsync(appointmentData.id, newAppointment, barberId).catch(console.error);

    } catch (error: any) {
      console.error('Unexpected error in handleCreateAppointment:', error);
      toast.error('Erro inesperado: ' + (error.message || 'Erro desconhecido'));
    } finally {
      setCreatingAppointment(false);
    }
  };

  // Função assíncrona para processar notificações (como no cliente)
  const processNotificationsAsync = async (appointmentId: string, appointmentData: any, barberId: string) => {
    try {
      const selectedService = services.find(s => s.id === appointmentData.serviceId);
      const duration = selectedService?.duration || 30;
      
      // Usar formato local sem conversão para UTC para evitar discrepâncias de fuso horário no webhook
      const localStartTime = `${appointmentData.date}T${appointmentData.time}:00`;
      const startDateTime = new Date(localStartTime);
      const endDateTime = new Date(startDateTime.getTime() + duration * 60000);
      const localEndTime = `${appointmentData.date}T${endDateTime.getHours().toString().padStart(2, '0')}:${endDateTime.getMinutes().toString().padStart(2, '0')}:00`;

      // Processar webhook e WhatsApp em paralelo com timeouts
      const [webhookResult, whatsappResult] = await Promise.allSettled([
        // Webhook externo (com timeout)
        Promise.race([
          supabase.functions.invoke('api', {
            body: {
              action: 'notify-webhook',
              appointmentId,
              clientName: appointmentData.clientName,
              phone: appointmentData.clientPhone || '00000000000',
              service: selectedService?.title || 'Serviço',
              startTime: localStartTime,
              endTime: localEndTime,
              userId: barberId,
              notes: null,
            }
          }),
          new Promise((_, reject) => 
            setTimeout(() => reject(new Error('Webhook timeout')), 8000)
          )
        ]),

        // WhatsApp queue (com timeout)
        Promise.race([
          (async () => {
            const { data: { session } } = await supabase.auth.getSession();
            const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
            const supabaseAnonKey = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
            
            if (!supabaseUrl) return;

            const response = await fetch(`${supabaseUrl}/functions/v1/whatsapp-process-queue`, {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
                'apikey': supabaseAnonKey || '',
                'Authorization': session?.access_token ? `Bearer ${session.access_token}` : `Bearer ${supabaseAnonKey}`,
              },
              body: JSON.stringify({}),
            });

            if (response.ok) {
              debugLog('✅ WhatsApp queue processed');
            }
          })(),
          new Promise((_, reject) => 
            setTimeout(() => reject(new Error('WhatsApp timeout')), 6000)
          )
        ])
      ]);

      // Log dos resultados (não bloquear se falhar)
      if (webhookResult.status === 'fulfilled') {
        debugLog('✅ Webhook notification sent');
      } else {
        debugWarn('⚠️ Webhook failed:', webhookResult.reason);
      }

      if (whatsappResult.status === 'fulfilled') {
        debugLog('✅ WhatsApp notification processed');
      } else {
        debugWarn('⚠️ WhatsApp failed:', whatsappResult.reason);
      }

    } catch (error) {
      console.error('Error in processNotificationsAsync:', error);
    }
  };

 

  const handleCancelAppointment = async () => {
    if (!appointmentToCancel) return;

    if (!cancellationReason.trim()) {
      toast.error('Por favor, informe o motivo do cancelamento');
      return;
    }

    const { error } = await (supabase as any)
      .from('appointments')
      .update({ 
        status: 'cancelled',
        notes: `[Cancelado pelo barbeiro] ${cancellationReason.trim()}`
      })
      .eq('id', appointmentToCancel);

    if (error) {
      toast.error('Erro ao cancelar agendamento');
      return;
    }

    // Mostrar sucesso imediatamente
    toast.success('Agendamento cancelado com sucesso', {
      duration: 2000,
    });
    setCancelDialogOpen(false);
    setAppointmentToCancel(null);
    setCancellationReason('');
    loadAppointments();

    // Processar fila de WhatsApp de forma assíncrona (não bloqueia a UI)
    setTimeout(async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
        const supabaseAnonKey = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
        
        if (supabaseUrl) {
          // Timeout de 3 segundos para não travar
          const controller = new AbortController();
          const timeoutId = setTimeout(() => controller.abort(), 3000);

          const response = await fetch(`${supabaseUrl}/functions/v1/whatsapp-process-queue`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'apikey': supabaseAnonKey || '',
              'Authorization': session?.access_token ? `Bearer ${session.access_token}` : `Bearer ${supabaseAnonKey}`,
            },
            body: JSON.stringify({}),
            signal: controller.signal,
          });

          clearTimeout(timeoutId);

          if (response.ok) {
            debugLog('✅ WhatsApp queue processed after cancellation');
          }
        }
      } catch (queueError: any) {
        // Silenciosamente falhar - não impacta o usuário
        if (queueError.name !== 'AbortError') {
          console.error('Error triggering WhatsApp queue:', queueError);
        }
      }
    }, 100); // Pequeno delay para não bloquear a UI
  };

  const handleAddPayment = () => {
    if (!currentPaymentAmount || isNaN(parseFloat(currentPaymentAmount)) || parseFloat(currentPaymentAmount) <= 0) {
      toast.error('Informe um valor válido');
      return;
    }

    const amount = parseFloat(currentPaymentAmount);
    const newPayments = [...payments, { method: currentPaymentMethod, amount }];
    setPayments(newPayments);
    
    // Sugerir saldo restante para o próximo pagamento
    if (appointmentToComplete) {
      const appointment = appointments.find(a => a.id === appointmentToComplete);
      const servicePrice = appointment?.service?.price || 0;
      const totalPaid = newPayments.reduce((acc, curr) => acc + curr.amount, 0);
      const remaining = Math.max(0, servicePrice - totalPaid);
      setCurrentPaymentAmount(remaining > 0 ? remaining.toFixed(2) : '');
    } else {
      setCurrentPaymentAmount('');
    }
  };

  const handleRemovePayment = (index: number) => {
    const newPayments = [...payments];
    newPayments.splice(index, 1);
    setPayments(newPayments);
    
    // Recalcular saldo restante sugerido
    if (appointmentToComplete) {
      const appointment = appointments.find(a => a.id === appointmentToComplete);
      const servicePrice = appointment?.service?.price || 0;
      const totalPaid = newPayments.reduce((acc, curr) => acc + curr.amount, 0);
      const remaining = Math.max(0, servicePrice - totalPaid);
      setCurrentPaymentAmount(remaining > 0 ? remaining.toFixed(2) : '');
    }
  };

  const getTotalPaid = () => {
    return payments.reduce((acc, curr) => acc + curr.amount, 0);
  };

  const buildFinalPaymentsForAppointment = (appointmentId: string | null) => {
    if (!appointmentId) return null;
    let finalPayments = [...payments];
    const appointment = appointments.find(a => a.id === appointmentId);
    const servicePrice = appointment?.service?.price || 0;

    if (finalPayments.length === 0) {
      const fromInput = parseFloat(currentPaymentAmount || '');
      if (!isNaN(fromInput) && fromInput > 0) {
        finalPayments.push({ method: currentPaymentMethod, amount: fromInput });
      } else if (servicePrice > 0) {
        finalPayments.push({ method: currentPaymentMethod, amount: servicePrice });
      } else {
        toast.error('Adicione os pagamentos recebidos');
        return null;
      }
    }

    if (servicePrice > 0) {
      const totalPaid = finalPayments.reduce((acc, curr) => acc + curr.amount, 0);
      const diff = Math.abs(totalPaid - servicePrice);
      if (diff > 0.05) {
        toast.error(`Valor incorreto! O total pago (R$ ${totalPaid.toFixed(2)}) deve ser igual ao valor do serviço (R$ ${servicePrice.toFixed(2)})`);
        return null;
      }
    }

    return finalPayments;
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files && e.target.files[0];
    if (!file) return;

    const image = new Image();
    const objectUrl = URL.createObjectURL(file);
    image.onload = () => {
      URL.revokeObjectURL(objectUrl);
      let width = image.width;
      let height = image.height;
      const maxSize = 1600;
      const scale = Math.min(maxSize / width, maxSize / height, 1);
      width = width * scale;
      height = height * scale;

      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      ctx.drawImage(image, 0, 0, width, height);

      let text = '';
      if (appointmentToComplete) {
        const apt = appointments.find(a => a.id === appointmentToComplete);
        if (apt?.appointment_date && apt?.appointment_time) {
          const timeStr = (apt.appointment_time || '').slice(0, 5);
          const dt = new Date(`${apt.appointment_date}T${timeStr || '00:00'}:00`);
          text = dt.toLocaleString('pt-BR');
        }
      }
      if (!text) {
        text = new Date().toLocaleString('pt-BR');
      }

      const padding = 12;
      const margin = 16;
      const fontSize = Math.max(Math.round(width * 0.025), 18);
      ctx.font = `${fontSize}px sans-serif`;
      ctx.textBaseline = 'bottom';
      const textWidth = ctx.measureText(text).width;
      const rectHeight = fontSize + padding;
      const rectWidth = textWidth + padding * 2;
      const rectX = margin - 8;
      const rectY = height - rectHeight - margin / 2;

      ctx.fillStyle = 'rgba(0, 0, 0, 0.6)';
      ctx.fillRect(rectX, rectY, rectWidth, rectHeight);
      ctx.fillStyle = '#ffffff';
      ctx.fillText(text, rectX + padding, height - margin);

      canvas.toBlob((blob) => {
        if (!blob) return;
        const finalFile = new File([blob], 'captured.jpg', { type: 'image/jpeg' });
        setPhotoFile(finalFile);
        const preview = URL.createObjectURL(blob);
        setPhotoPreview(preview);
      }, 'image/jpeg', 0.9);
    };
    image.onerror = () => {
      URL.revokeObjectURL(objectUrl);
      toast.error('Não foi possível ler a foto');
    };
    image.src = objectUrl;
  };

  const handleCompleteWithPhoto = async () => {
    if (!appointmentToComplete) return;

    if (!photoFile) {
      toast.error('Tire uma foto do cliente para concluir o atendimento');
      return;
    }

    const finalPayments = buildFinalPaymentsForAppointment(appointmentToComplete);
    if (!finalPayments) return;

    setUploadingPhoto(true);
    let photoUrl: string | null = null;

    try {
      try {
        const { uploadPublicImage } = await import('@/utils/storage');
        const url = await uploadPublicImage(photoFile, {
          bucket: 'appointment-photos',
          category: 'appointment-photos',
          prefix: appointmentToComplete || undefined,
        });
        photoUrl = url;
      } catch (e) {
        console.error('Erro ao fazer upload da foto:', e);
        toast.error('Erro ao fazer upload da foto. Tente novamente.');
        throw e;
      }

      // 1. Atualizar status do agendamento
      // Para o campo payment_method no appointments, se houver múltiplos, usar 'misto' ou o primeiro.
      // Vamos usar o de maior valor ou 'misto' se houver > 1.
      let mainMethod = finalPayments[0].method;
      if (finalPayments.length > 1) {
          // Check if all are same
          const allSame = finalPayments.every(p => p.method === finalPayments[0].method);
          mainMethod = allSame ? finalPayments[0].method : 'misto'; // 'misto' não é um enum válido provavelmente? Checar check constraint.
          // O check é IN ('pix', 'dinheiro', 'cartao'). Então não posso usar 'misto'.
          // Vou usar o de maior valor.
          const maxPayment = finalPayments.reduce((prev, current) => (prev.amount > current.amount) ? prev : current);
          mainMethod = maxPayment.method;
      }

      const { error: updateError } = await (supabase as any)
        .from('appointments')
        .update({ 
          status: 'completed',
          photo_url: photoUrl,
          payment_method: mainMethod
        })
        .eq('id', appointmentToComplete);

      if (updateError) throw updateError;

      const { error: deletePaymentsError } = await supabase
        .from('appointment_payments')
        .delete()
        .eq('appointment_id', appointmentToComplete);

      if (deletePaymentsError) {
        console.error('Error deleting existing payments:', deletePaymentsError);
      }

      const paymentInserts = finalPayments.map(p => ({
          appointment_id: appointmentToComplete,
          payment_method: p.method,
          amount: p.amount
      }));

      const { error: paymentsError } = await supabase
          .from('appointment_payments')
          .insert(paymentInserts);

      if (paymentsError) {
          console.error('Error inserting payments:', paymentsError);
          toast.error('Erro ao salvar detalhes do pagamento, mas o agendamento foi concluído.');
      }

      toast.success(photoUrl ? 'Agendamento concluído com foto!' : 'Agendamento concluído!', {
        duration: 2000,
      });

      // Enviar mensagem WhatsApp de atendimento concluído ao cliente
      try {
        const completedApt = appointments.find(a => a.id === appointmentToComplete);
        const clientPhone = completedApt?.client?.phone || '';
        if (clientPhone) {
          await supabase.functions.invoke('whatsapp-notify', {
            body: {
              appointmentId: appointmentToComplete,
              clientName: completedApt?.client?.name || 'Cliente',
              phone: clientPhone,
              action: 'completed',
              appointmentDate: completedApt?.appointment_date,
              appointmentTime: completedApt?.appointment_time,
              serviceName: completedApt?.service?.title,
              barberName: completedApt?.barber?.name || currentUserBarber?.name,
              targetType: 'client',
            },
          });
        }
      } catch (waErr) {
        console.error('Erro ao enviar WhatsApp de conclusão:', waErr);
      }

      setCompleteDialogOpen(false);
      setAppointmentToComplete(null);
      setPhotoFile(null);
      setPhotoPreview(null);
      setCurrentPaymentMethod('pix');
      setPayments([]);
      setCurrentPaymentAmount('');
      loadAppointments();
      await sendBarberPendingWhatsApp(selectedAppointmentForAction?.barber_id || currentUserBarber?.id || selectedBarber);

    } catch (error: any) {
      console.error('Erro ao completar agendamento:', error);
      toast.error('Erro ao processar: ' + error.message);
    } finally {
      setUploadingPhoto(false);
    }
  };


  const loadBarberSchedules = async () => {
    try {
      const barberId = selectedBarber || currentUserBarber?.id;
      if (!barberId) return;
      
      setLoadingSchedules(true);
      const startOfMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1);
      const endOfMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0);
      
      const { data, error } = await (supabase as any)
        .from('barber_schedules')
        .select('*')
        .eq('barber_id', barberId)
        .gte('date', startOfMonth.toISOString().split('T')[0])
        .lte('date', endOfMonth.toISOString().split('T')[0]);
        
      if (error) {
        // Se a tabela não existir ainda, vamos lidar graciosamente
        if (error.code === '42P01') {
          debugWarn('Tabela barber_schedules ainda não existe.');
          return;
        }
        throw error;
      }
      
      const scheduleMap: Record<string, any> = {};
      (data as any[])?.forEach(item => {
        scheduleMap[item.date] = item;
      });
      setBarberSchedules(scheduleMap);
    } catch (e) {
      console.error('Erro ao carregar escala mensal:', e);
    } finally {
      setLoadingSchedules(false);
    }
  };

  useEffect(() => {
    if (viewMode === 'monthly') {
      loadBarberSchedules();
    }
  }, [viewMode, currentMonth, selectedBarber, currentUserBarber?.id]);

  const saveDaySchedule = async () => {
    try {
      const barberId = selectedBarber || currentUserBarber?.id;
      if (!barberId || !editingDay) return;
      
      const dateStr = editingDay.toISOString().split('T')[0];

      const conflicts = await getScheduleConflicts(barberId, dateStr, daySchedule);
      if (conflicts.length > 0) {
        setScheduleConflicts(conflicts);
        toast.error(
          `Não foi possível salvar. ${conflicts.length} agendamento(s) seriam impactados pela nova programação.`
        );
        return;
      }

      setScheduleConflicts([]);
      
      const { error } = await (supabase as any)
        .from('barber_schedules')
        .upsert({
          barber_id: barberId,
          date: dateStr,
          open: daySchedule.open,
          close: daySchedule.close,
          closed: daySchedule.closed,
          observation: daySchedule.observation,
          lunch_start: daySchedule.lunch_start,
          lunch_end: daySchedule.lunch_end,
          has_lunch: daySchedule.has_lunch,
          pause_start: daySchedule.pause_start,
          pause_end: daySchedule.pause_end,
          has_pause: daySchedule.has_pause
        }, { onConflict: 'barber_id,date' });
        
      if (error) throw error;
      
      toast.success('Programação do dia atualizada!');
      setScheduleConflicts([]);
      setEditingDay(null);
      await Promise.all([loadBarberSchedules(), loadTodayBreaks()]);
    } catch (e: any) {
      console.error('Erro ao salvar escala:', e);
      if (barberId && editingDay) {
        try {
          const dateStr = editingDay.toISOString().split('T')[0];
          const conflicts = await getScheduleConflicts(barberId, dateStr, daySchedule);
          setScheduleConflicts(conflicts);
        } catch (validationError) {
          debugWarn('Erro ao recarregar conflitos após falha de salvamento:', validationError);
        }
      }
      toast.error('Erro ao salvar: ' + e.message);
    }
  };

  const applyLunchToMonth = async () => {
    try {
      const barberId = selectedBarber || currentUserBarber?.id;
      if (!barberId) return;

      setApplyingBulkLunch(true);

      const year = currentMonth.getFullYear();
      const month = currentMonth.getMonth();
      const daysInMonth = new Date(year, month + 1, 0).getDate();
      const failedDates: { date: string; reason: string }[] = [];
      let appliedCount = 0;

      for (let d = 1; d <= daysInMonth; d++) {
        const date = new Date(year, month, d);
        const dateStr = date.toISOString().split('T')[0];
        const existing = barberSchedules[dateStr];

        const dayKey = getDayKey(date);
        const shopHours = operatingHours[dayKey];
        const isOpen = existing ? !existing.closed : (shopHours ? !shopHours.closed : true);

        if (!isOpen) continue;

        const { error } = await (supabase as any)
          .from('barber_schedules')
          .upsert({
            barber_id: barberId,
            date: dateStr,
            open: existing?.open || shopHours?.open || '09:00',
            close: existing?.close || shopHours?.close || '20:00',
            closed: existing?.closed ?? false,
            observation: existing?.observation || '',
            lunch_start: bulkLunch.start,
            lunch_end: bulkLunch.end,
            has_lunch: true,
            pause_start: existing?.pause_start || '15:00',
            pause_end: existing?.pause_end || '15:30',
            has_pause: existing?.has_pause ?? false,
          }, { onConflict: 'barber_id,date' });

        if (error) {
          failedDates.push({
            date: dateStr,
            reason: error.message || 'Conflito de agendamento',
          });
          continue;
        }

        appliedCount += 1;
      }

      if (failedDates.length > 0) {
        const failedPreview = failedDates
          .slice(0, 3)
          .map((item) => `${new Date(item.date + 'T00:00:00').toLocaleDateString('pt-BR')}: ${item.reason}`)
          .join(' | ');

        toast.error(
          `Almoço aplicado em ${appliedCount} dia(s), com ${failedDates.length} bloqueio(s) por conflito. ${failedPreview}`
        );
      } else {
        toast.success('Horário de almoço aplicado a todos os dias do mês!');
      }
      setBulkLunchDialogOpen(false);
      loadBarberSchedules();
    } catch (e: any) {
      console.error('Erro ao aplicar almoço em massa:', e);
      toast.error('Erro: ' + e.message);
    } finally {
      setApplyingBulkLunch(false);
    }
  };

  const currentBarber = userRole === 'admin' ? barbers.find(b => b.id === selectedBarber) : currentUserBarber;

  // Agrupar agendamentos por barbeiro
  const appointmentsByBarber = useMemo(() => {
    const todayLocal = new Date();
    const today = `${todayLocal.getFullYear()}-${String(todayLocal.getMonth() + 1).padStart(2, '0')}-${String(todayLocal.getDate()).padStart(2, '0')}`;

    const relevantAppointments = appointments
      .filter(a => {
        const isToday = a.appointment_date === today;
        const isFuture = a.appointment_date > today;
        const isActiveStatus = a.status === 'pending' || a.status === 'confirmed';
        return (isToday || isFuture) && isActiveStatus;
      })
      .sort((a, b) => {
        if (a.appointment_date !== b.appointment_date) {
          return a.appointment_date.localeCompare(b.appointment_date);
        }
        return a.appointment_time.localeCompare(b.appointment_time);
      });

    let appointmentsWithBreaks = [...relevantAppointments];
    const currentBarberId = selectedBarber || currentUserBarber?.id;
    debugLog('[DEBUG] appointmentsByBarber - currentBarberId:', currentBarberId, 'todayBreaks:', todayBreaks.length, 'today:', today);
    if (currentBarberId && todayBreaks.length > 0) {
      const breakAppointments = todayBreaks.map((brk) => {
        const startTime = String(brk.start_time || '').slice(0, 5);
        const isLunch = brk.isLunch === true || brk.notes === 'Almoço';
        const breakType = brk.breakType || (isLunch ? 'lunch' : 'pause');
        const title = isLunch ? 'Almoço' : 'Pausa';
        return {
          id: `break-${brk.id}`,
          barber_id: currentBarberId,
          appointment_date: today, // Usar mesma data local 'today' do useMemo
          appointment_time: startTime,
          client_name: title,
          status: 'break',
          service: { title, price: 0, duration: 30 },
          notes: brk.notes || title,
          isBreak: true,
          break_type: breakType,
          break_start_time: brk.start_time,
          break_end_time: brk.end_time,
        };
      });
      appointmentsWithBreaks = [...appointmentsWithBreaks, ...breakAppointments].sort((a, b) => {
        if (a.appointment_date !== b.appointment_date) {
          return a.appointment_date.localeCompare(b.appointment_date);
        }
        return a.appointment_time.localeCompare(b.appointment_time);
      });
    }

    const result = barbers.map(barber => {
      const barberAppointments = appointmentsWithBreaks.filter(a => a.barber_id === barber.id);
      return {
        barber,
        appointments: barberAppointments,
        todayCount: barberAppointments.filter(a => a.appointment_date === today).length,
        upcomingCount: barberAppointments.filter(a => a.appointment_date > today).length
      };
    });

    // Ordenar barbeiros: primeiro os que têm agendamentos hoje, depois por nome
    return result.sort((a, b) => {
      if (a.todayCount > 0 && b.todayCount === 0) return -1;
      if (a.todayCount === 0 && b.todayCount > 0) return 1;
      return a.barber.name.localeCompare(b.barber.name);
    });
  }, [appointments, barbers, todayBreaks, selectedBarber, currentUserBarber?.id]);

  const historyTotalPages = useMemo(() => {
    return Math.max(1, Math.ceil(historyTotalCount / HISTORY_PAGE_SIZE));
  }, [historyTotalCount]);

  const currentHistoryPage = useMemo(() => {
    return Math.min(historyPage, historyTotalPages);
  }, [historyPage, historyTotalPages]);

  const historyStartIndex = historyTotalCount === 0
    ? 0
    : (currentHistoryPage - 1) * HISTORY_PAGE_SIZE + 1;

  const historyEndIndex = Math.min(
    currentHistoryPage * HISTORY_PAGE_SIZE,
    historyTotalCount
  );

  useEffect(() => {
    if (historyPage > historyTotalPages) {
      setHistoryPage(historyTotalPages);
    }
  }, [historyPage, historyTotalPages]);

  useEffect(() => {
    setHistoryPage(1);
  }, [
    historyFilterPeriod,
    historyFilterStatus,
    historyFilterService,
    historyFilterPayment,
    selectedBarber,
    currentUserBarber?.id,
  ]);

  useEffect(() => {
    if (productHistoryPage > productHistoryTotalPages) {
      setProductHistoryPage(productHistoryTotalPages);
    }
  }, [productHistoryPage, productHistoryTotalPages]);

  useEffect(() => {
    setProductHistoryPage(1);
  }, [
    productHistoryFilterPeriod,
    productHistoryFilterStatus,
    productHistoryFilterProductId,
    selectedBarber,
    currentUserBarber?.id,
  ]);

  const upsertOperationalAppointment = async (appointmentId: string) => {
    const startedAt = performance.now();
    const targetBarber = selectedBarber || currentUserBarber?.id;
    if (!targetBarber) return;

    const lookbackDate = new Date();
    lookbackDate.setDate(lookbackDate.getDate() - OPERATIONS_LOOKBACK_DAYS);
    const lookbackDateStr = format(lookbackDate, 'yyyy-MM-dd');

    const { data, error } = await supabase
      .from('appointments')
      .select(`
        *,
        service:services(title, price, duration)
      `)
      .eq('id', appointmentId)
      .eq('barber_id', targetBarber)
      .maybeSingle();

    if (error || !data) {
      if (error) {
        logDashboardQueryMetric({
          query: 'appointments_incremental_upsert',
          durationMs: performance.now() - startedAt,
          rowCount: 0,
          filters: { barberId: targetBarber, appointmentId },
          error: error.message,
        });
      }
      return;
    }

    if (data.appointment_date < lookbackDateStr) {
      return;
    }

    const hydrated = await hydrateAppointmentsClients([data as AppointmentWithRelations]);
    const incoming = hydrated[0];
    if (!incoming) return;

    setAppointments((prev) => {
      const withoutSame = prev.filter((item) => item.id !== incoming.id);
      const merged = [...withoutSame, incoming];
      merged.sort((a, b) => {
        if (a.appointment_date !== b.appointment_date) {
          return a.appointment_date.localeCompare(b.appointment_date);
        }
        return a.appointment_time.localeCompare(b.appointment_time);
      });
      return merged;
    });

    logDashboardQueryMetric({
      query: 'appointments_incremental_upsert',
      durationMs: performance.now() - startedAt,
      rowCount: 1,
      filters: { barberId: targetBarber, appointmentId },
    });
  };

  const getSupabaseImagePreviewUrl = (
    photoUrl?: string | null,
    options?: { width?: number; height?: number; quality?: number; resize?: 'cover' | 'contain' }
  ) => {
    if (!photoUrl) return '';
    try {
      const parsed = new URL(photoUrl);
      const objectPathMarker = '/storage/v1/object/public/';
      const markerIndex = parsed.pathname.indexOf(objectPathMarker);

      if (markerIndex === -1) {
        return photoUrl;
      }

      const objectPath = parsed.pathname.slice(markerIndex + objectPathMarker.length);
      const prefix = parsed.pathname.slice(0, markerIndex);
      parsed.pathname = `${prefix}/storage/v1/render/image/public/${objectPath}`;

      const width = options?.width ?? 256;
      const quality = options?.quality ?? 55;
      const resize = options?.resize ?? 'cover';

      parsed.searchParams.set('width', String(width));
      if (options?.height) {
        parsed.searchParams.set('height', String(options.height));
      } else {
        parsed.searchParams.delete('height');
      }
      parsed.searchParams.set('resize', resize);
      parsed.searchParams.set('quality', String(quality));
      return parsed.toString();
    } catch {
      return photoUrl;
    }
  };

  const completedAppointments = useMemo(() => {
    return appointments
      .filter(a => a.status === 'completed')
      .sort((a, b) => {
        // Sort by date descending, then by time descending
        if (a.appointment_date !== b.appointment_date) {
          return b.appointment_date.localeCompare(a.appointment_date);
        }
        return b.appointment_time.localeCompare(a.appointment_time);
      });
  }, [appointments]);

  // Calcular agendamentos concluídos para diferentes períodos (Apenas do mês atual)
  const todayCompleted = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    return completedAppointments.filter(a => a.appointment_date === todayStr);
  }, [completedAppointments]);

  const weekCompleted = useMemo(() => {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    startOfMonth.setHours(0, 0, 0, 0);

    const startOfWeek = new Date(now);
    const day = now.getDay();
    const diffToMonday = now.getDate() - day + (day === 0 ? -6 : 1);
    startOfWeek.setDate(diffToMonday);
    startOfWeek.setHours(0, 0, 0, 0);
    
    const finalWeekStart = startOfWeek < startOfMonth ? startOfMonth : startOfWeek;
    return completedAppointments.filter(a => new Date(a.appointment_date + 'T00:00:00') >= finalWeekStart);
  }, [completedAppointments]);

  const monthCompleted = useMemo(() => {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    startOfMonth.setHours(0, 0, 0, 0);
    return completedAppointments.filter(a => new Date(a.appointment_date + 'T00:00:00') >= startOfMonth);
  }, [completedAppointments]);

  return (
    <div className="min-h-screen bg-background py-6 px-4 overflow-x-hidden">
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col gap-2 md:flex-row md:justify-between md:items-center mb-4">
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold">
                Painel do <span className="bg-gradient-gold bg-clip-text text-transparent">Barbeiro</span>
              </h1>
            </div>
            {userRole === 'admin' && (
              <div className="mt-4">
                <Label>Selecione o barbeiro:</Label>
                <Select value={selectedBarber} onValueChange={setSelectedBarber}>
                  <SelectTrigger className="w-64">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {barbers.map((barber) => (
                      <SelectItem key={barber.id} value={barber.id}>
                        {barber.name} - {barber.specialty}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}
          </div>
          <div className="flex flex-col gap-2 md:items-end">
            {user && (
              <div className="flex items-center gap-2 px-2 py-1 rounded-lg bg-secondary/30">
                <Avatar className="h-8 w-8">
                  <AvatarImage src={currentUserBarber?.image_url || ''} alt={displayName || 'Usuário'} />
                  <AvatarFallback className="bg-primary/20 text-primary text-sm font-bold">
                    {(displayName || user.email || 'U').charAt(0).toUpperCase()}
                  </AvatarFallback>
                </Avatar>
                <div className="text-sm font-medium text-foreground">
                  {displayName || 'Usuário'}
                </div>
                <div className="flex items-center gap-1 ml-2">
                  <Button
                    onClick={() => navigate('/configuracoes')}
                    variant="ghost"
                    className="h-8 w-8 p-0"
                    aria-label="Configurações"
                    title="Configurações"
                  >
                    <Settings className="h-4 w-4" />
                  </Button>
                {pastPendingCount > 0 && (
                  <span
                    title="Pendências vencidas"
                    className="ml-1 inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-semibold bg-yellow-500/20 text-yellow-400 border border-yellow-500/30"
                  >
                    <Clock className="h-3 w-3" />
                    {pastPendingCount}
                  </span>
                )}
                  <Button
                    onClick={async () => {
                      await signOut();
                      navigate('/');
                    }}
                    variant="ghost"
                    className="h-8 w-8 p-0 text-destructive hover:text-destructive hover:bg-destructive/10"
                    aria-label="Sair"
                    title="Sair"
                  >
                    <LogOut className="h-4 w-4" />
                  </Button>
                </div>
              </div>
            )}
          </div>
        </div>

        {(currentUserBarber || selectedBarber) && (
          <>
            <Tabs value={activeTab} onValueChange={setActiveTab as any} className="w-full">
              <TabsList className="grid w-full grid-cols-4 mb-6">
                <TabsTrigger value="agendamentos">Agendamentos</TabsTrigger>
                <TabsTrigger value="horarios">Horários</TabsTrigger>
                <TabsTrigger value="financeiro">Financeiro</TabsTrigger>
                <TabsTrigger value="historico">Histórico</TabsTrigger>
              </TabsList>

              <TabsContent value="agendamentos" className="space-y-6">
              <div className="mb-8">
                <Card className="bg-card border-border" translate="no">
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2 text-lg">
                      <Calendar className="h-5 w-5 text-primary" />
                      Resumo de Agendamentos
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-2">
                      <div className="grid grid-cols-3 text-center text-xs uppercase tracking-wide text-muted-foreground">
                        <div>Hoje</div>
                        <div>Semana</div>
                        <div>Mês</div>
                      </div>
                      <div className="grid grid-cols-3 text-center">
                        <div className="text-3xl font-bold text-primary">
                          {todayCompleted.length}
                        </div>
                        <div className="text-3xl font-bold text-green-500">
                          {weekCompleted.length}
                        </div>
                        <div className="text-3xl font-bold text-green-500">
                          {monthCompleted.length}
                        </div>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>

            

            <div className="mb-6 flex flex-row gap-2 items-stretch">
              <Dialog open={showNewAppointment} onOpenChange={setShowNewAppointment}>
                <DialogTrigger asChild>
                  <Button 
                    size="sm" 
                    className="flex-1 min-w-0 h-8 px-1 text-xs gap-1"
                    title="Novo Agendamento"
                  >
                    <Plus className="mr-1 h-3 w-3" />
                    <span className="truncate">Novo</span>
                  </Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-md">
                  <DialogHeader>
                    <DialogTitle>
                      {newAppointmentStep === 'service' ? 'Selecionar Serviço' : newAppointmentStep === 'datetime' ? 'Data e Hora' : 'Cliente (opcional)'}
                    </DialogTitle>
                    <DialogDescription>
                      {newAppointmentStep === 'service' ? 'Escolha o serviço.' : newAppointmentStep === 'datetime' ? 'Informe data (hoje por padrão) e horário.' : 'Se não informar, será marcado como Local.'}
                    </DialogDescription>
                  </DialogHeader>
                  
                  {newAppointmentStep === 'service' && (
                    <div className="space-y-4">
                      <div>
                        <Label>Serviço</Label>
                        <select
                          className="flex h-10 w-full items-center justify-between rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
                          value={newAppointment.serviceId}
                          onChange={(e) => setNewAppointment({ ...newAppointment, serviceId: e.target.value })}
                        >
                          <option value="" disabled>Selecione um serviço</option>
                          {services.map((service) => (
                            <option key={service.id} value={service.id}>
                              {service.title} - R$ {service.price}
                            </option>
                          ))}
                        </select>
                      </div>
                      <div className="flex gap-2">
                        <Button 
                          className="flex-1"
                          onClick={() => setNewAppointmentStep('datetime')}
                          disabled={!newAppointment.serviceId}
                        >
                          Continuar
                        </Button>
                        <Button variant="outline" onClick={() => setShowNewAppointment(false)}>
                          Cancelar
                        </Button>
                      </div>
                    </div>
                  )}

                  {newAppointmentStep === 'datetime' && (
                    <div className="space-y-4">
                      <div>
                        <Label>Data</Label>
                        <Input
                          type="date"
                          value={newAppointment.date}
                          onChange={(e) => setNewAppointment({ ...newAppointment, date: e.target.value })}
                        />
                      </div>
                      <div className="space-y-2">
                        <Label>Horários Disponíveis</Label>
                        {loadingNewSlots ? (
                          <div className="text-center py-6 text-muted-foreground">Carregando horários...</div>
                        ) : availableNewSlots.length === 0 ? (
                          <div className="text-center py-6 text-muted-foreground">Nenhum horário disponível</div>
                        ) : (
                          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                            {availableNewSlots.map((slot) => (
                              <Button
                                key={slot}
                                type="button"
                                onClick={() => setNewAppointment({ ...newAppointment, time: slot })}
                                className={newAppointment.time === slot ? "bg-primary text-primary-foreground border border-primary" : ""}
                                variant={newAppointment.time === slot ? "default" : "outline"}
                              >
                                {slot}
                              </Button>
                            ))}
                          </div>
                        )}
                      </div>
                      <div className="flex items-center justify-between p-3 border border-border rounded-lg bg-secondary/30">
                        <div className="flex-1">
                          <Label htmlFor="retroactive" className="text-sm font-medium cursor-pointer">
                            Agendamento Retroativo (Passado)
                          </Label>
                        </div>
                        <Switch
                          id="retroactive"
                          checked={newAppointment.isRetroactive}
                          onCheckedChange={(checked) => setNewAppointment({ ...newAppointment, isRetroactive: checked })}
                        />
                      </div>
                      <div className="flex gap-2">
                        <Button 
                          className="flex-1"
                          onClick={() => setNewAppointmentStep('client')}
                          disabled={!newAppointment.time}
                        >
                          Continuar
                        </Button>
                        <Button variant="outline" onClick={() => setNewAppointmentStep('service')}>
                          Voltar
                        </Button>
                      </div>
                    </div>
                  )}

                  {newAppointmentStep === 'client' && (
                    <div className="space-y-4">
                      <div>
                        <Label>Nome do Cliente (opcional)</Label>
                        <Input
                          value={newAppointment.clientName}
                          onChange={(e) => setNewAppointment({ ...newAppointment, clientName: e.target.value })}
                          placeholder="Local"
                        />
                        <p className="text-xs text-muted-foreground mt-1">
                          Se vazio, será registrado como Local.
                        </p>
                      </div>
                      <div className="flex gap-2">
                        <Button 
                          onClick={handleCreateAppointment} 
                          className="flex-1"
                          disabled={creatingAppointment}
                        >
                          {creatingAppointment ? (
                            <>
                              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                              Criando...
                            </>
                          ) : (
                            'Criar Agendamento'
                          )}
                        </Button>
                        <Button 
                          variant="outline" 
                          onClick={() => setNewAppointmentStep('datetime')}
                          disabled={creatingAppointment}
                        >
                          Voltar
                        </Button>
                      </div>
                    </div>
                  )}
                </DialogContent>
              </Dialog>

              <Dialog 
                open={productSaleDialogOpen} 
                onOpenChange={(open) => {
                  setProductSaleDialogOpen(open);
                  if (open) {
                    loadProductsForSale();
                  } else {
                    setSelectedProductId('');
                    setProductQuantity(1);
                  }
                }}
              >
                <DialogTrigger asChild>
                  <Button 
                    variant="outline" 
                    size="sm" 
                    className="flex-1 min-w-0 h-8 px-1 text-xs"
                    title="Vender Produto"
                  >
                    <span className="truncate">Vender</span>
                  </Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-md">
                  <DialogHeader>
                    <DialogTitle>Registrar Venda de Produto</DialogTitle>
                    <DialogDescription>
                      Registre a venda de um produto. A comissão será calculada automaticamente.
                    </DialogDescription>
                  </DialogHeader>
                  <div className="space-y-4">
                    <div>
                      <Label>Produto</Label>
                      <Select value={selectedProductId} onValueChange={setSelectedProductId}>
                        <SelectTrigger>
                          <SelectValue placeholder="Selecione um produto" />
                        </SelectTrigger>
                        <SelectContent>
                          {availableProducts.map((product) => (
                            <SelectItem 
                              key={product.id} 
                              value={product.id}
                              disabled={product.stock !== null && product.stock === 0}
                            >
                              {product.name} - R$ {product.price.toFixed(2)}
                              {product.stock !== null && ` (Estoque: ${product.stock})`}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>

                    {selectedProductId && (
                      <>
                        <div>
                          <Label>Quantidade</Label>
                          <Input
                            type="number"
                            min="1"
                            value={productQuantity}
                            onChange={(e) => {
                              const qty = parseInt(e.target.value) || 1;
                              setProductQuantity(Math.max(1, qty));
                            }}
                          />
                          {availableProducts.find(p => p.id === selectedProductId)?.stock !== null && (
                            <p className="text-xs text-muted-foreground mt-1">
                              Estoque disponível: {availableProducts.find(p => p.id === selectedProductId)?.stock || 0}
                            </p>
                          )}
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                          <div>
                            <Label className="text-sm font-medium">Forma de Pagamento</Label>
                            <Select value={productPaymentMethod} onValueChange={(v) => setProductPaymentMethod(v as any)}>
                              <SelectTrigger>
                                <SelectValue placeholder="Selecione" />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="pix">Pix</SelectItem>
                                <SelectItem value="dinheiro">Dinheiro</SelectItem>
                                <SelectItem value="cartao">Cartão</SelectItem>
                              </SelectContent>
                            </Select>
                          </div>
                          <div>
                            <Label className="text-sm font-medium">Foto (opcional)</Label>
                            <Input
                              type="file"
                              accept="image/*"
                              onChange={(e) => setProductPhotoFile(e.target.files?.[0] || null)}
                            />
                            {productPhotoFile && (
                              <p className="text-xs text-muted-foreground mt-1">
                                {productPhotoFile.name}
                              </p>
                            )}
                          </div>
                        </div>

                        <div className="p-3 bg-secondary/50 rounded-lg space-y-2">
                          <div className="flex justify-between text-sm">
                            <span className="text-muted-foreground">Valor Unitário:</span>
                            <span className="font-medium">
                              R$ {availableProducts.find(p => p.id === selectedProductId)?.price.toFixed(2) || '0.00'}
                            </span>
                          </div>
                          <div className="flex justify-between text-sm">
                            <span className="text-muted-foreground">Total:</span>
                            <span className="font-bold text-primary">
                              R$ {((availableProducts.find(p => p.id === selectedProductId)?.price || 0) * productQuantity).toFixed(2)}
                            </span>
                          </div>
                          {barberIdForCommissions && (
                            <>
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">Comissão ({(() => {
                                  const individual = getIndividualProductCommissionPercentage(barberIdForCommissions, selectedProductId);
                                  const fixed = getFixedProductCommissionPercentage(barberIdForCommissions);
                                  return individual > 0 ? individual : fixed;
                                })()}%):</span>
                                <span className="font-bold text-green-400">
                                  R$ {((() => {
                                    const product = availableProducts.find(p => p.id === selectedProductId);
                                    if (!product) return 0;
                                    const totalPrice = product.price * productQuantity;
                                    const individual = getIndividualProductCommissionPercentage(barberIdForCommissions, selectedProductId);
                                    const fixed = getFixedProductCommissionPercentage(barberIdForCommissions);
                                    const commissionPercentage = individual > 0 ? individual : fixed;
                                    return (totalPrice * commissionPercentage) / 100;
                                  })()).toFixed(2)}
                                </span>
                              </div>
                            </>
                          )}
                        </div>
                      </>
                    )}

                    <div className="flex gap-2">
                      <Button 
                        onClick={handleProductSale} 
                        className="flex-1"
                        disabled={!selectedProductId || savingProductSale}
                      >
                        {savingProductSale ? (
                          <>
                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            Registrando...
                          </>
                        ) : (
                          <>
                            <ShoppingBag className="mr-2 h-4 w-4" />
                            Registrar Venda
                          </>
                        )}
                      </Button>
                      <Button 
                        variant="outline" 
                        onClick={() => {
                          setProductSaleDialogOpen(false);
                          setSelectedProductId('');
                          setProductQuantity(1);
                        }}
                      >
                        Cancelar
                      </Button>
                    </div>
                  </div>
                </DialogContent>
              </Dialog>

              <Dialog
                open={fitDialogOpen}
                onOpenChange={(open) => {
                  setFitDialogOpen(open);
                  if (open) {
                    const now = new Date();
                    const hh = String(now.getHours()).padStart(2, '0');
                    const mm = String(now.getMinutes()).padStart(2, '0');
                    setFitStartTime(`${hh}:${mm}`);
                    setFitServiceId('');
                  } else {
                    setFitClientName('');
                    setFitServiceId('');
                  }
                }}
              >
                <DialogTrigger asChild>
                  <Button 
                    variant="outline"
                    size="sm"
                    className="flex-1 min-w-0 h-8 px-1 text-xs"
                    title="Iniciar Encaixe"
                  >
                    <Clock className="mr-1 h-3 w-3" />
                    <span className="truncate">Encaixe</span>
                  </Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-md">
                  <DialogHeader>
                    <DialogTitle>Iniciar Encaixe</DialogTitle>
                    <DialogDescription>Cria um atendimento rápido entre horários.</DialogDescription>
                  </DialogHeader>
                  <div className="space-y-4">
                    <div>
                      <Label>Serviço</Label>
                      <select
                        className="flex h-10 w-full items-center justify-between rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
                        value={fitServiceId}
                        onChange={(e) => setFitServiceId(e.target.value)}
                      >
                        <option value="" disabled>Selecione um serviço</option>
                        {services.map((service) => (
                          <option key={service.id} value={service.id}>
                            {service.title} - R$ {service.price}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <Label>Hora de início</Label>
                      <Input
                        type="time"
                        value={fitStartTime}
                        onChange={(e) => setFitStartTime(e.target.value)}
                      />
                    </div>
                    <div>
                      <Label>Nome do Cliente (opcional)</Label>
                      <Input
                        value={fitClientName}
                        onChange={(e) => setFitClientName(e.target.value)}
                        placeholder="Local"
                      />
                    </div>
                    <div className="flex gap-2">
                      <Button
                        className="flex-1"
                        onClick={async () => {
                          if (savingFit) return;
                          const barberId = selectedBarber || currentUserBarber?.id;
                          if (!barberId || !fitStartTime || !fitServiceId) return;
                          setSavingFit(true);
                          try {
                            const profileId = generateUUID();
                            const name = fitClientName?.trim() || 'Local';
                            const { data: newProfile, error: profileError } = await (supabase as any)
                              .from('profiles')
                              .insert([{ id: profileId, name, is_temp_user: true }])
                              .select('id')
                              .single();
                            if (profileError || !newProfile?.id) throw profileError || new Error('profile');
                            const todayStr = new Date().toISOString().split('T')[0];
                            
                            const notes = JSON.stringify({ fit: true, start_time: fitStartTime });
                            const { error: insertError } = await (supabase as any)
                              .from('appointments')
                              .insert([{
                                client_id: newProfile.id,
                                barber_id: barberId,
                                service_id: fitServiceId,
                                appointment_date: todayStr,
                                appointment_time: fitStartTime,
                                status: 'confirmed',
                                booking_type: 'local',
                                client_name: name,
                                notes
                              }]);
                            if (insertError) throw insertError;
                            toast.success('Encaixe iniciado');
                            setFitDialogOpen(false);
                            await loadAppointments();
                          } catch (e: any) {
                            console.error(e);
                            toast.error('Erro ao iniciar encaixe: ' + (e?.message || 'desconhecido'));
                          } finally {
                            setSavingFit(false);
                          }
                        }}
                        disabled={!fitStartTime || !fitServiceId || savingFit}
                      >
                        {savingFit ? (
                          <>
                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                            Criando...
                          </>
                        ) : 'Iniciar'}
                      </Button>
                      <Button variant="outline" onClick={() => setFitDialogOpen(false)}>
                        Fechar
                      </Button>
                    </div>
                  </div>
                </DialogContent>
              </Dialog>

              <Button
                size="sm"
                variant="outline"
                onClick={() => navigate('/fila')}
                className="flex-1 min-w-0 h-8 px-1 text-xs"
                title="Fila da Barbearia"
              >
                <span className="truncate">Fila</span>
              </Button>
            </div>
            

            <Card className="bg-card border-border" translate="no">
              <CardHeader className="pb-2">
                <CardTitle className="flex items-center gap-2 text-base">
                  <Users className="h-4 w-4" />
                  Agendamentos por Barbeiro
                </CardTitle>
              </CardHeader>
              <CardContent className="p-3 sm:p-4">
                <Tabs defaultValue="hoje" className="w-full">
                  <TabsList className="grid w-full grid-cols-2 mb-3">
                    <TabsTrigger value="hoje">Agendamentos de Hoje</TabsTrigger>
                    <TabsTrigger value="futuros">Agendamentos Futuros</TabsTrigger>
                  </TabsList>

                  <TabsContent value="hoje">
                    {appointmentsByBarber.length > 0 ? (
                      <div className="space-y-4">
                        {appointmentsByBarber.map(({ barber, appointments, todayCount, upcomingCount }) => {
                          const todayLocal2 = new Date();
                          const today = `${todayLocal2.getFullYear()}-${String(todayLocal2.getMonth() + 1).padStart(2, '0')}-${String(todayLocal2.getDate()).padStart(2, '0')}`;
                          const list = appointments.filter(a => a.appointment_date === today);
                          debugLog('[DEBUG] Rendering barber:', barber.name, 'today:', today, 'appointments:', appointments.length, 'list:', list.length, list.map(a => ({ date: a.appointment_date, time: a.appointment_time, status: a.status })));
                          return (
                            <div key={barber.id} className="border border-border rounded-lg p-3 bg-secondary/30">
                              <div className="flex items-center gap-3 mb-3 pb-2 border-b border-border">
                                <Avatar className="h-10 w-10 border-2 border-primary/20">
                                  <AvatarImage src={barber.image_url || ''} alt={barber.name} />
                                  <AvatarFallback className="bg-primary/20 text-primary font-bold text-base">
                                    <span>{barber.name.charAt(0).toUpperCase()}</span>
                                  </AvatarFallback>
                                </Avatar>
                                <div className="flex-1">
                                  <h3 className="font-bold text-base"><span>{barber.name}</span></h3>
                                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                    <span className="flex items-center gap-1">
                                      <Calendar className="h-3 w-3" />
                                      Hoje: {todayCount}
                                    </span>
                                    <span className="flex items-center gap-1">
                                      <Clock className="h-3 w-3" />
                                      Próximos: {upcomingCount}
                                    </span>
                                    <span className="flex items-center gap-1">
                                      <User className="h-3 w-3" />
                                      Total: {appointments.length}
                                    </span>
                                  </div>
                                </div>
                              </div>

                              {list.length > 0 ? (
                                <div className="space-y-3">
                                  {list.map((appointment) => {
                                    const isFit = (() => {
                                      try {
                                        if (!appointment.notes) return false;
                                        const n = JSON.parse(appointment.notes);
                                        return n && n.fit === true;
                                      } catch { return false; }
                                    })();
                                    const isBreak = appointment.isBreak || appointment.status === 'break';
                                    const clientName = isBreak
                                      ? (appointment.service?.title || 'Pausa')
                                      : (appointment.client_name || appointment.client?.name || 'Local');
                                    const clientInitial = clientName.charAt(0).toUpperCase();
                                    const appointmentTime = appointment.appointment_time.slice(0, 5);
                                    const breakStart = (appointment.break_start_time || appointment.appointment_time || '').slice(0, 5);
                                    const breakEnd = (appointment.break_end_time || '').slice(0, 5);
                                    const bookingTypeLabel = isFit ? 'Encaixe' : (appointment.booking_type === 'local' ? 'Local' : 
                                                           appointment.booking_type === 'manual' ? 'Manual' : 'Online');
                                    const bookingTypeColor = isFit ? 'bg-purple-500/20 text-purple-400 border-purple-500/30'
                                                           : appointment.booking_type === 'local' ? 'bg-blue-500/20 text-blue-400 border-blue-500/30'
                                                           : appointment.booking_type === 'manual' ? 'bg-orange-500/20 text-orange-400 border-orange-500/30'
                                                           : 'bg-green-500/20 text-green-400 border-green-500/30';

                                    const cardClasses = isBreak
                                      ? 'p-3 rounded-lg border cursor-default bg-red-500/10 border-red-400'
                                      : 'p-3 rounded-lg border cursor-pointer transition-all hover:shadow-md bg-primary/5 border-primary/30';

                                    const isLunchBreak = isBreak && (appointment.break_type === 'lunch' || appointment.client_name === 'Almoço' || appointment.service?.title === 'Almoço');

                                    const statusLabel = isBreak
                                      ? (isLunchBreak ? 'Almoço' : 'Pausa')
                                      : (appointment.status === 'confirmed' ? 'Confirmado' : 'Pendente');

                                    const statusClasses = isBreak
                                      ? 'px-2 py-0.5 rounded text-xs font-medium bg-red-500/20 text-red-500'
                                      : `px-2 py-0.5 rounded text-xs font-medium ${
                                          appointment.status === 'confirmed'
                                            ? 'bg-green-500/20 text-green-400'
                                            : 'bg-yellow-500/20 text-yellow-400'
                                        }`;

                                    return (
                                      <div 
                                        key={appointment.id} 
                                        className={cardClasses}
                                        onClick={() => {
                                          if (!isBreak) {
                                            handleAppointmentClick(appointment);
                                          }
                                        }}
                                      >
                                        <div className="flex items-center gap-3">
                                          <Avatar className={`h-10 w-10 border ${isBreak ? 'border-red-400 bg-red-500/10' : 'border-border'}`}>
                                            <AvatarImage src={isBreak ? '' : (appointment.client?.photo_url || '')} alt={clientName} />
                                            <AvatarFallback className={isBreak ? 'bg-red-500/20 text-red-500 font-semibold' : 'bg-secondary text-foreground font-semibold'}>
                                              {clientInitial}
                                            </AvatarFallback>
                                          </Avatar>
                                          <div className="flex-1 space-y-1">
                                            <div className="flex items-center justify-between">
                                              <div className="flex items-center gap-2">
                                                {isFit && (
                                                  <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-purple-600 text-white shadow-sm uppercase tracking-wider">
                                                    Encaixe
                                                  </span>
                                                )}
                                                <p className={`font-semibold text-sm ${isBreak ? 'text-red-600' : ''}`}>
                                                  {appointment.service?.title || 'Serviço'}
                                                </p>
                                              </div>
                                              <div className="flex items-center gap-2">
                                                <span className={`px-2 py-1 rounded text-xs font-medium ${
                                                  isBreak ? 'bg-red-500/20 text-red-600' : 'bg-primary/20 text-primary'
                                                }`}>
                                                  {isBreak
                                                    ? `HOJE ${breakStart}${breakEnd ? ` - ${breakEnd}` : ''}`
                                                    : `HOJE às ${appointmentTime}`
                                                  }
                                                </span>
                                              </div>
                                            </div>
                                            <div className="flex items-center justify-between">
                                              <p className={`text-xs ${isBreak ? 'text-red-600' : 'text-muted-foreground'}`}>
                                                {isBreak
                                                  ? `${isLunchBreak ? 'Horário de almoço' : 'Horário de pausa'}: ${breakStart}${breakEnd ? ` - ${breakEnd}` : ''}`
                                                  : `Cliente: ${clientName}`
                                                }
                                              </p>
                                              <div className="flex items-center gap-2">
                                                {!isBreak && (
                                                  <span className={`px-2 py-0.5 rounded text-xs font-medium border ${bookingTypeColor}`}>
                                                    {bookingTypeLabel}
                                                  </span>
                                                )}
                                                <span className={statusClasses}>
                                                  {statusLabel}
                                                </span>
                                              </div>
                                            </div>
                                          </div>
                                        </div>
                                      </div>
                                    );
                                  })}
                                </div>
                              ) : (
                                <p className="text-center text-muted-foreground py-4">
                                  Nenhum agendamento hoje para {barber.name}
                                </p>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    ) : (
                      <p className="text-center text-muted-foreground py-8">
                        Nenhum agendamento encontrado
                      </p>
                    )}
                  </TabsContent>

                  <TabsContent value="futuros">
                    {appointmentsByBarber.length > 0 ? (
                      <div className="space-y-4">
                        {appointmentsByBarber.map(({ barber, appointments, todayCount, upcomingCount }) => {
                          const today = new Date().toISOString().split('T')[0];
                          const list = appointments.filter(a => a.appointment_date > today);
                          return (
                            <div key={barber.id} className="border border-border rounded-lg p-3 bg-secondary/30">
                              <div className="flex items-center gap-3 mb-3 pb-2 border-b border-border">
                                <Avatar className="h-10 w-10 border-2 border-primary/20">
                                  <AvatarImage src={barber.image_url || ''} alt={barber.name} />
                                  <AvatarFallback className="bg-primary/20 text-primary font-bold text-base">
                                    {barber.name.charAt(0).toUpperCase()}
                                  </AvatarFallback>
                                </Avatar>
                                <div className="flex-1">
                                  <h3 className="font-bold text-base"><span>{barber.name}</span></h3>
                                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                    <span className="flex items-center gap-1">
                                      <Calendar className="h-3 w-3" />
                                      Hoje: {todayCount}
                                    </span>
                                    <span className="flex items-center gap-1">
                                      <Clock className="h-3 w-3" />
                                      Próximos: {upcomingCount}
                                    </span>
                                    <span className="flex items-center gap-1">
                                      <User className="h-3 w-3" />
                                      Total: {appointments.length}
                                    </span>
                                  </div>
                                </div>
                              </div>

                              {list.length > 0 ? (
                                <div className="space-y-3">
                                  {list.map((appointment) => {
                                    const isFit = (() => {
                                      try {
                                        if (!appointment.notes) return false;
                                        const n = JSON.parse(appointment.notes);
                                        return n && n.fit === true;
                                      } catch { return false; }
                                    })();
                                    const isBreak = appointment.isBreak || appointment.status === 'break';
                                    const clientName = isBreak
                                      ? (appointment.service?.title || 'Pausa')
                                      : (appointment.client_name || appointment.client?.name || 'Local');
                                    const clientInitial = clientName.charAt(0).toUpperCase();
                                    const appointmentTime = appointment.appointment_time.slice(0, 5);
                                    const breakStart = (appointment.break_start_time || appointment.appointment_time || '').slice(0, 5);
                                    const breakEnd = (appointment.break_end_time || '').slice(0, 5);
                                    const appointmentDate = new Date(appointment.appointment_date + 'T00:00:00');
                                    const bookingTypeLabel = isFit ? 'Encaixe' : (appointment.booking_type === 'local' ? 'Local' : 
                                                           appointment.booking_type === 'manual' ? 'Manual' : 'Online');
                                    const bookingTypeColor = isFit ? 'bg-purple-500/20 text-purple-400 border-purple-500/30'
                                                           : appointment.booking_type === 'local' ? 'bg-blue-500/20 text-blue-400 border-blue-500/30'
                                                           : appointment.booking_type === 'manual' ? 'bg-orange-500/20 text-orange-400 border-orange-500/30'
                                                           : 'bg-green-500/20 text-green-400 border-green-500/30';

                                    const cardClasses = isBreak
                                      ? 'p-3 rounded-lg border cursor-default bg-red-500/10 border-red-400'
                                      : 'p-3 rounded-lg border cursor-pointer transition-all hover:shadow-md bg-card border-border';

                                    const isLunchBreak = isBreak && (appointment.break_type === 'lunch' || appointment.client_name === 'Almoço' || appointment.service?.title === 'Almoço');

                                    const statusLabel = isBreak
                                      ? (isLunchBreak ? 'Almoço' : 'Pausa')
                                      : (appointment.status === 'confirmed' ? 'Confirmado' : 'Pendente');

                                    const statusClasses = isBreak
                                      ? 'px-2 py-0.5 rounded text-xs font-medium bg-red-500/20 text-red-500'
                                      : `px-2 py-0.5 rounded text-xs font-medium ${
                                          appointment.status === 'confirmed'
                                            ? 'bg-green-500/20 text-green-400'
                                            : 'bg-yellow-500/20 text-yellow-400'
                                        }`;

                                    return (
                                      <div 
                                        key={appointment.id} 
                                        className={cardClasses}
                                        onClick={() => {
                                          if (!isBreak) {
                                            handleAppointmentClick(appointment);
                                          }
                                        }}
                                      >
                                        <div className="flex items-center gap-3">
                                          <Avatar className={`h-10 w-10 border ${isBreak ? 'border-red-400 bg-red-500/10' : 'border-border'}`}>
                                            <AvatarImage src={isBreak ? '' : (appointment.client?.photo_url || '')} alt={clientName} />
                                            <AvatarFallback className={isBreak ? 'bg-red-500/20 text-red-500 font-semibold' : 'bg-secondary text-foreground font-semibold'}>
                                              {clientInitial}
                                            </AvatarFallback>
                                          </Avatar>
                                          <div className="flex-1 space-y-1">
                                            <div className="flex items-center justify-between">
                                              <div className="flex items-center gap-2">
                                                {isFit && (
                                                  <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-purple-600 text-white shadow-sm uppercase tracking-wider">
                                                    Encaixe
                                                  </span>
                                                )}
                                                <p className={`font-semibold text-sm ${isBreak ? 'text-red-600' : ''}`}>
                                                  {appointment.service?.title || 'Serviço'}
                                                </p>
                                              </div>
                                              <div className="flex items-center gap-2">
                                                <span className={`px-2 py-1 rounded text-xs font-medium ${
                                                  isBreak ? 'bg-red-500/20 text-red-600' : 'bg-secondary text-muted-foreground'
                                                }`}>
                                                  {isBreak
                                                    ? `${format(appointmentDate, 'dd/MM', { locale: ptBR })} ${breakStart}${breakEnd ? ` - ${breakEnd}` : ''}`
                                                    : `${format(appointmentDate, 'dd/MM', { locale: ptBR })} às ${appointmentTime}`
                                                  }
                                                </span>
                                              </div>
                                            </div>
                                            <div className="flex items-center justify-between">
                                              <p className={`text-xs ${isBreak ? 'text-red-600' : 'text-muted-foreground'}`}>
                                                {isBreak
                                                  ? `${isLunchBreak ? 'Horário de almoço' : 'Horário de pausa'}: ${breakStart}${breakEnd ? ` - ${breakEnd}` : ''}`
                                                  : `Cliente: ${clientName}`
                                                }
                                              </p>
                                              <div className="flex items-center gap-2">
                                                {!isBreak && (
                                                  <span className={`px-2 py-0.5 rounded text-xs font-medium border ${bookingTypeColor}`}>
                                                    {bookingTypeLabel}
                                                  </span>
                                                )}
                                                <span className={statusClasses}>
                                                  {statusLabel}
                                                </span>
                                              </div>
                                            </div>
                                          </div>
                                        </div>
                                      </div>
                                    );
                                  })}
                                </div>
                              ) : (
                                <p className="text-center text-muted-foreground py-4">
                                  Nenhum agendamento futuro para {barber.name}
                                </p>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    ) : (
                      <p className="text-center text-muted-foreground py-8">
                        Nenhum agendamento encontrado
                      </p>
                    )}
                  </TabsContent>
                </Tabs>
              </CardContent>
            </Card>
          </TabsContent>

          

          <TabsContent value="horarios" className="space-y-6">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-bold">Programação de Atendimento</h2>
            </div>

            <Card className="bg-card border-border">
                <CardHeader className="pb-3 px-3 sm:px-6 sm:pb-4">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <CardTitle className="text-base sm:text-lg flex items-center gap-2">
                      <Calendar className="h-4 w-4 sm:h-5 sm:w-5 text-primary shrink-0" />
                      <span>Escala Mensal - {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}</span>
                    </CardTitle>
                    <div className="flex items-center gap-1.5 sm:gap-2">
                      <Button
                        variant="outline"
                        size="sm"
                        className="text-orange-500 border-orange-500/40 hover:bg-orange-500/10 gap-1.5 h-8 px-2 sm:px-3"
                        onClick={() => setBulkLunchDialogOpen(true)}
                      >
                        <span className="text-xs">🍴</span>
                        <span className="hidden sm:inline text-xs">Horário de Almoço</span>
                      </Button>
                      <Button 
                        variant="outline" 
                        size="icon"
                        className="h-8 w-8 sm:h-9 sm:w-9"
                        onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1, 1))}
                      >
                        <X className="h-3.5 w-3.5 rotate-45" />
                      </Button>
                      <Button 
                        variant="outline" 
                        size="icon"
                        className="h-8 w-8 sm:h-9 sm:w-9"
                        onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 1))}
                      >
                        <Plus className="h-3.5 w-3.5 rotate-45" />
                      </Button>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="px-2 sm:px-6 pb-4">
                  {loadingSchedules ? (
                    <div className="flex items-center justify-center py-20">
                      <Loader2 className="h-8 w-8 animate-spin text-primary" />
                    </div>
                  ) : (
                    <div className="grid grid-cols-7 gap-0.5 sm:gap-2">
                      {[['D','Dom'], ['S','Seg'], ['T','Ter'], ['Q','Qua'], ['Q','Qui'], ['S','Sex'], ['S','Sáb']].map(([short, full], i) => (
                        <div key={i} className="text-center text-[10px] sm:text-xs font-bold text-muted-foreground py-1.5 sm:py-2 uppercase">
                          <span className="sm:hidden">{short}</span>
                          <span className="hidden sm:inline">{full}</span>
                        </div>
                      ))}
                      
                      {(() => {
                        const start = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1);
                        const daysInMonth = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0).getDate();
                        const firstDayOfWeek = start.getDay();
                        
                        const cells = [];
                        
                        // Empty cells before start of month
                        for (let i = 0; i < firstDayOfWeek; i++) {
                          cells.push(<div key={`empty-${i}`} className="h-12 sm:h-24 bg-secondary/10 rounded-lg opacity-30" />);
                        }
                        
                        // Day cells
                        for (let d = 1; d <= daysInMonth; d++) {
                          const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), d);
                          const dateStr = date.toISOString().split('T')[0];
                          const schedule = barberSchedules[dateStr];
                          const isToday = dateStr === new Date().toISOString().split('T')[0];
                          
                          // Lógica de fallback para exibir no calendário
                          const dayKey = getDayKey(date);
                          const shopHours = operatingHours[dayKey];
                          const isOpen = schedule ? !schedule.closed : (shopHours ? !shopHours.closed : true);
                          const openTime = schedule?.open || shopHours?.open || '09:00';
                          const closeTime = schedule?.close || shopHours?.close || '20:00';
                          
                          cells.push(
                            <button
                              key={d}
                              onClick={() => {
                                setScheduleConflicts([]);
                                setEditingDay(date);
                                setDaySchedule({
                                  open: openTime,
                                  close: closeTime,
                                  closed: !isOpen,
                                  observation: schedule?.observation || '',
                                  lunch_start: schedule?.lunch_start || '12:00',
                                  lunch_end: schedule?.lunch_end || '13:00',
                                  has_lunch: schedule ? schedule.has_lunch : true,
                                  pause_start: schedule?.pause_start || '15:00',
                                  pause_end: schedule?.pause_end || '15:30',
                                  has_pause: schedule?.has_pause || false
                                });
                              }}
                              className={`h-20 sm:h-24 p-1 sm:p-2 rounded-lg border text-left transition-all hover:border-primary/50 relative overflow-hidden ${
                                isToday ? 'border-primary bg-primary/5' : 'border-border bg-secondary/20'
                              } ${!isOpen ? 'opacity-60 bg-red-500/5' : ''}`}
                            >
                              <span className={`text-[10px] sm:text-xs font-bold block leading-tight ${
                                isToday ? 'text-primary' : 'text-muted-foreground'
                              }`}>
                                {d}
                              </span>

                              <div className="mt-0.5 space-y-0.5">
                                {!isOpen ? (
                                  <span className="text-[9px] sm:text-[10px] text-red-500 font-medium block">Fechado</span>
                                ) : (
                                  <>
                                    <span className="text-[9px] sm:text-[10px] text-foreground font-medium block leading-tight">
                                      {openTime} - {closeTime}
                                    </span>
                                    {schedule?.has_lunch && (
                                      <span className="text-[8px] sm:text-[9px] text-orange-500 font-medium block leading-tight">
                                        🍴 {schedule.lunch_start} - {schedule.lunch_end}
                                      </span>
                                    )}
                                    {schedule?.has_pause && (
                                      <span className="text-[8px] sm:text-[9px] text-blue-500 font-medium block leading-tight">
                                        ☕ {schedule.pause_start} - {schedule.pause_end}
                                      </span>
                                    )}
                                    {schedule?.observation && (
                                      <div className="flex items-center gap-0.5">
                                        <div className="w-1 h-1 rounded-full bg-primary animate-pulse shrink-0" />
                                        <span className="text-[8px] sm:text-[9px] text-primary truncate italic">
                                          {schedule.observation}
                                        </span>
                                      </div>
                                    )}
                                  </>
                                )}
                              </div>

                              {schedule && (
                                <div className="absolute top-0.5 right-0.5 sm:top-1 sm:right-1">
                                  <div className="w-1.5 h-1.5 rounded-full bg-primary" />
                                </div>
                              )}
                            </button>
                          );
                        }
                        
                        return cells;
                      })()}
                    </div>
                  )}
                </CardContent>
              </Card>

            <Dialog open={editingDay !== null} onOpenChange={(open) => {
              if (!open) {
                setScheduleConflicts([]);
                setEditingDay(null);
              }
            }}>
              <DialogContent className="sm:max-w-md max-h-[90dvh] flex flex-col p-0">
                <DialogHeader className="px-4 pt-4 pb-2 shrink-0">
                  <DialogTitle className="text-base">
                    Programação: {editingDay && format(editingDay, "dd 'de' MMMM", { locale: ptBR })}
                  </DialogTitle>
                  <DialogDescription className="text-xs">
                    Ajuste o horário específico para este dia ou marque como fechado.
                  </DialogDescription>
                </DialogHeader>
                
                <div className="space-y-3 px-4 py-2 overflow-y-auto flex-1">
                  <div className="flex items-center justify-between p-2.5 border border-border rounded-lg bg-secondary/30">
                    <div className="space-y-0.5">
                      <Label className="text-sm font-medium">Status do Dia</Label>
                      <p className="text-xs text-muted-foreground">
                        {daySchedule.closed ? 'Fechado para agendamentos' : 'Aberto para agendamentos'}
                      </p>
                    </div>
                    <Switch 
                      checked={!daySchedule.closed} 
                      onCheckedChange={(checked) => setDaySchedule({...daySchedule, closed: !checked})}
                    />
                  </div>

                  {!daySchedule.closed && (
                    <>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1.5">
                          <Label className="text-xs">Abertura</Label>
                          <Input 
                            type="time" 
                            className="h-9 text-sm"
                            value={daySchedule.open} 
                            onChange={(e) => setDaySchedule({...daySchedule, open: e.target.value})}
                          />
                        </div>
                        <div className="space-y-1.5">
                          <Label className="text-xs">Fechamento</Label>
                          <Input 
                            type="time" 
                            className="h-9 text-sm"
                            value={daySchedule.close} 
                            onChange={(e) => setDaySchedule({...daySchedule, close: e.target.value})}
                          />
                        </div>
                      </div>

                      <div className="border border-border rounded-lg bg-secondary/30 overflow-hidden">
                        <div className="flex items-center justify-between p-2.5">
                          <div className="space-y-0.5">
                            <Label className="text-sm font-medium">🍴 Horário de Almoço</Label>
                            <p className="text-xs text-muted-foreground">Habilitar intervalo de almoço</p>
                          </div>
                          <Switch 
                            checked={daySchedule.has_lunch} 
                            onCheckedChange={(checked) => setDaySchedule({...daySchedule, has_lunch: checked})}
                          />
                        </div>
                        {daySchedule.has_lunch && (
                          <div className="grid grid-cols-2 gap-3 px-2.5 pb-2.5 pt-0">
                            <div className="space-y-1.5">
                              <Label className="text-xs">Início</Label>
                              <Input 
                                type="time" 
                                className="h-9 text-sm"
                                value={daySchedule.lunch_start} 
                                onChange={(e) => setDaySchedule({...daySchedule, lunch_start: e.target.value})}
                              />
                            </div>
                            <div className="space-y-1.5">
                              <Label className="text-xs">Fim</Label>
                              <Input 
                                type="time" 
                                className="h-9 text-sm"
                                value={daySchedule.lunch_end} 
                                onChange={(e) => setDaySchedule({...daySchedule, lunch_end: e.target.value})}
                              />
                            </div>
                          </div>
                        )}
                      </div>

                      <div className="border border-border rounded-lg bg-secondary/30 overflow-hidden">
                        <div className="flex items-center justify-between p-2.5">
                          <div className="space-y-0.5">
                            <Label className="text-sm font-medium">☕ Horário de Pausa</Label>
                            <p className="text-xs text-muted-foreground">Habilitar intervalo de pausa</p>
                          </div>
                          <Switch 
                            checked={daySchedule.has_pause} 
                            onCheckedChange={(checked) => setDaySchedule({...daySchedule, has_pause: checked})}
                          />
                        </div>
                        {daySchedule.has_pause && (
                          <div className="grid grid-cols-2 gap-3 px-2.5 pb-2.5 pt-0">
                            <div className="space-y-1.5">
                              <Label className="text-xs">Início</Label>
                              <Input 
                                type="time" 
                                className="h-9 text-sm"
                                value={daySchedule.pause_start} 
                                onChange={(e) => setDaySchedule({...daySchedule, pause_start: e.target.value})}
                              />
                            </div>
                            <div className="space-y-1.5">
                              <Label className="text-xs">Fim</Label>
                              <Input 
                                type="time" 
                                className="h-9 text-sm"
                                value={daySchedule.pause_end} 
                                onChange={(e) => setDaySchedule({...daySchedule, pause_end: e.target.value})}
                              />
                            </div>
                          </div>
                        )}
                      </div>

                      <div className="space-y-1.5">
                        <Label className="text-xs">Observação Interna</Label>
                        <Input 
                          type="text" 
                          placeholder="Ex: Feriado local, evento..."
                          value={daySchedule.observation}
                          onChange={(e) => setDaySchedule({...daySchedule, observation: e.target.value})}
                        />
                      </div>
                    </>
                  )}

                  {scheduleConflicts.length > 0 && (
                    <div className="rounded-lg border border-destructive/40 bg-destructive/10 p-3 space-y-2">
                      <p className="text-sm font-semibold text-destructive">
                        Não foi possível salvar a programação
                      </p>
                      <p className="text-xs text-destructive/90">
                        Ajuste os horários e tente novamente. Agendamentos impactados:
                      </p>
                      <div className="space-y-2 max-h-52 overflow-y-auto pr-1">
                        {scheduleConflicts.map((conflict) => (
                          <div
                            key={conflict.appointmentId}
                            className="rounded-md border border-destructive/30 bg-background/70 p-2"
                          >
                            <div className="flex items-center justify-between gap-2 text-xs">
                              <span className="font-semibold text-foreground truncate">{conflict.clientName}</span>
                              <span className="font-semibold text-destructive">{conflict.appointmentTime}</span>
                            </div>
                            <p className="text-xs text-muted-foreground truncate">{conflict.serviceTitle}</p>
                            <p className="text-[11px] text-destructive mt-1">
                              {conflict.reasons.join(' • ')}
                            </p>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex gap-2 px-4 py-3 border-t border-border shrink-0">
                  <Button className="flex-1 h-9" onClick={saveDaySchedule}>
                    Salvar Programação
                  </Button>
                  <Button variant="outline" className="h-9" onClick={() => setEditingDay(null)}>
                    Cancelar
                  </Button>
                </div>
              </DialogContent>
            </Dialog>

            <Dialog open={bulkLunchDialogOpen} onOpenChange={(open) => !open && setBulkLunchDialogOpen(false)}>
              <DialogContent className="sm:max-w-sm">
                <DialogHeader>
                  <DialogTitle className="flex items-center gap-2">
                    <span>🍴</span>
                    Inserir Horário de Almoço
                  </DialogTitle>
                  <DialogDescription>
                    Define o horário de almoço para todos os dias abertos de{' '}
                    <strong>{format(currentMonth, 'MMMM yyyy', { locale: ptBR })}</strong>.
                  </DialogDescription>
                </DialogHeader>

                <div className="space-y-4 py-2">
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>Início do Almoço</Label>
                      <Input
                        type="time"
                        value={bulkLunch.start}
                        onChange={(e) => setBulkLunch({ ...bulkLunch, start: e.target.value })}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>Fim do Almoço</Label>
                      <Input
                        type="time"
                        value={bulkLunch.end}
                        onChange={(e) => setBulkLunch({ ...bulkLunch, end: e.target.value })}
                      />
                    </div>
                  </div>

                  <p className="text-xs text-muted-foreground">
                    O horário será aplicado a todos os dias abertos do mês selecionado. Dias marcados como fechados serão ignorados.
                  </p>
                </div>

                <div className="flex gap-2">
                  <Button
                    className="flex-1"
                    onClick={applyLunchToMonth}
                    disabled={applyingBulkLunch}
                  >
                    {applyingBulkLunch ? (
                      <>
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                        Aplicando...
                      </>
                    ) : (
                      'Aplicar ao Mês'
                    )}
                  </Button>
                  <Button variant="outline" onClick={() => setBulkLunchDialogOpen(false)} disabled={applyingBulkLunch}>
                    Cancelar
                  </Button>
                </div>
              </DialogContent>
            </Dialog>
          </TabsContent>

          {/* Duplicate Financeiro Tab Removed */}

      <TabsContent value="financeiro" className="space-y-6">
        <BarberFinancialDashboard barberId={selectedBarber} isActive={activeTab === 'financeiro'} />
        <Card className="bg-card border-border">
          <CardHeader className="pb-2">
            <CardTitle className="text-base flex items-center justify-between">
                      <span>Meus Vales</span>
                      {loadingAdvances ? (
                        <Loader2 className="h-4 w-4 animate-spin text-primary" />
                      ) : null}
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-1">
                    {advances.length === 0 ? (
                      <p className="text-sm text-muted-foreground">
                        Nenhum vale registrado.
                      </p>
                    ) : (
                      <>
                        <p className="text-sm text-muted-foreground">
                          Pendentes:{" "}
                          <span className="font-semibold">
                            {advances.filter((a) => a.status === "pending").length}
                          </span>{" "}
                          • Aprovados:{" "}
                          <span className="font-semibold">
                            {advances.filter((a) => a.status === "approved").length}
                          </span>
                        </p>
                        <div className="max-h-40 overflow-y-auto space-y-2 text-sm">
                          {advances.slice(0, 5).map((adv) => (
                            <div
                              key={adv.id}
                              className="flex items-center justify-between border border-border/60 rounded-md px-2 py-1 text-xs"
                            >
                              <div className="space-y-1">
                                <p className="font-medium">
                                  R${" "}
                                  {Number(adv.amount).toLocaleString("pt-BR", {
                                    minimumFractionDigits: 2,
                                  })}
                                </p>
                                <p className="text-xs text-muted-foreground">
                                  {new Date(
                                    adv.effective_date
                                  ).toLocaleDateString("pt-BR")}
                                  {adv.description
                                    ? ` • ${adv.description.slice(0, 40)}${
                                        adv.description.length > 40 ? "..." : ""
                                      }`
                                    : ""}
                                </p>
                              </div>
                              {adv.status === "pending" && currentBarber && (
                                <div className="flex flex-col gap-1 items-end">
                                  <Button
                                    size="sm"
                                    onClick={async () => {
                                      const signatureMeta = {
                                        barber_id: currentBarber.id,
                                        barber_name: currentBarber.name,
                                      };
                                      const { error } = await approveAdvance(
                                        adv.id,
                                        signatureMeta
                                      );
                                      if (error) {
                                        toast.error(
                                          "Erro ao aprovar vale: " + error.message
                                        );
                                      } else {
                                        toast.success(
                                          "Vale aprovado. O valor será descontado da sua comissão."
                                        );
                                        loadAdvances();
                                      }
                                    }}
                                  >
                                    Aprovar
                                  </Button>
                                  <Button
                                    size="sm"
                                    variant="outline"
                                    className="text-xs h-7 px-2"
                                    onClick={async () => {
                                      const { error } = await rejectAdvance(adv.id);
                                      if (error) {
                                        toast.error(
                                          "Erro ao rejeitar/cancelar vale: " +
                                            error.message
                                        );
                                      } else {
                                        toast.success("Vale rejeitado/cancelado.");
                                        loadAdvances();
                                      }
                                    }}
                                  >
                                    Rejeitar
                                  </Button>
                                </div>
                              )}
                              {adv.status === "approved" && (
                                <span className="text-xs text-green-500 font-medium">
                                  Aprovado
                                </span>
                              )}
                              {adv.status === "rejected" && (
                                <span className="text-xs text-red-500 font-medium">
                                  Rejeitado
                                </span>
                              )}
                            </div>
                          ))}
                        </div>
                      </>
                    )}
                  </CardContent>
                </Card>
              </TabsContent>

              <TabsContent value="historico" className="space-y-6">
                <Tabs value={historySectionTab} onValueChange={setHistorySectionTab as any} className="w-full">
                  <TabsList className="grid w-full grid-cols-2 mb-4">
                    <TabsTrigger value="servicos">Histórico de Serviços</TabsTrigger>
                    <TabsTrigger value="produtos">Histórico de Produtos</TabsTrigger>
                  </TabsList>
                  <TabsContent value="servicos" className="space-y-6">
                <Card className="bg-card border-border">
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-base">Histórico de Serviços</CardTitle>
                      <div className="flex items-center gap-2">
                        <Dialog open={pendingDialogOpen} onOpenChange={setPendingDialogOpen}>
                          <DialogTrigger asChild>
                            <Button
                              size="sm"
                              variant="outline"
                              className="h-8 px-2 text-xs gap-1"
                              title="Pendências vencidas"
                            >
                              <Clock className="h-3 w-3" />
                              Pendências{pastPendingCount > 0 ? ` (${pastPendingCount})` : ''}
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="sm:max-w-lg">
                            <DialogHeader>
                              <DialogTitle>Pendências vencidas</DialogTitle>
                              <DialogDescription>Agendamentos passados que ainda precisam ser concluídos.</DialogDescription>
                            </DialogHeader>
                            <div className="space-y-3 max-h-[60vh] overflow-y-auto">
                              {pastPendingList.length === 0 ? (
                                <p className="text-sm text-muted-foreground">Nenhuma pendência vencida encontrada.</p>
                              ) : (
                                pastPendingList.map((appointment) => {
                                  const clientName = appointment.client_name || appointment.client?.name || 'Local';
                                  const appointmentTime = (appointment.appointment_time || '').slice(0, 5);
                                  const appointmentDate = new Date(appointment.appointment_date + 'T00:00:00');
                                  const bookingTypeLabel =
                                    appointment.booking_type === 'local'
                                      ? 'Local'
                                      : appointment.booking_type === 'manual'
                                      ? 'Manual'
                                      : 'Online';
                                  const bookingTypeColor =
                                    appointment.booking_type === 'local'
                                      ? 'bg-blue-500/20 text-blue-400 border-blue-500/30'
                                      : appointment.booking_type === 'manual'
                                      ? 'bg-orange-500/20 text-orange-400 border-orange-500/30'
                                      : 'bg-green-500/20 text-green-400 border-green-500/30';
                                  return (
                                    <div
                                      key={appointment.id}
                                      className="p-3 rounded-lg border cursor-pointer transition-all hover:shadow-md bg-red-500/5 border-red-500/30"
                                      onClick={() => {
                                        setPendingDialogOpen(false);
                                        handleAppointmentClick(appointment);
                                      }}
                                    >
                                      <div className="flex items-center justify-between gap-3">
                                        <div className="flex items-center gap-3">
                                          <Avatar className="h-9 w-9 border border-border">
                                            <AvatarImage src={appointment.client?.photo_url || ''} alt={clientName} />
                                            <AvatarFallback className="bg-secondary text-foreground font-semibold text-xs">
                                              {(clientName || 'C').charAt(0).toUpperCase()}
                                            </AvatarFallback>
                                          </Avatar>
                                          <div className="flex-1">
                                            <p className="font-semibold text-sm">{appointment.service?.title || 'Serviço'}</p>
                                            <p className="text-xs text-muted-foreground">Cliente: {clientName}</p>
                                          </div>
                                        </div>
                                        <div className="flex items-center gap-2">
                                          <span className="px-2 py-1 rounded text-xs font-medium bg-red-500/20 text-red-400 border border-red-500/30">
                                            {format(appointmentDate, 'dd/MM', { locale: ptBR })} às {appointmentTime}
                                          </span>
                                          <span className={`px-2 py-0.5 rounded text-xs font-medium border ${bookingTypeColor}`}>
                                            {bookingTypeLabel}
                                          </span>
                                          <span
                                            className={`px-2 py-0.5 rounded text-xs font-medium ${
                                              appointment.status === 'confirmed'
                                                ? 'bg-green-500/20 text-green-400'
                                                : 'bg-yellow-500/20 text-yellow-400'
                                            }`}
                                          >
                                            {appointment.status === 'confirmed' ? 'Confirmado' : 'Pendente'}
                                          </span>
                                        </div>
                                      </div>
                                    </div>
                                  );
                                })
                              )}
                            </div>
                          </DialogContent>
                        </Dialog>
                        <Button
                          size="sm"
                          variant="outline"
                          className="h-8 px-2 text-xs"
                          onClick={() => setShowHistoryFilters((v) => !v)}
                        >
                          {showHistoryFilters ? 'Ocultar filtros' : 'Mostrar filtros'}
                        </Button>
                      </div>
                    </div>
                  </CardHeader>
                  <CardContent>
                    {/* Filtros */}
                    <div className={`mb-4 pb-3 border-b border-border ${showHistoryFilters ? '' : 'hidden'}`}>
                        <div className="grid grid-cols-2 gap-2">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <Calendar className="h-3 w-3 mr-1" />
                              Período: {
                                historyFilterPeriod === 'all' ? 'Todos' :
                                historyFilterPeriod === 'today' ? 'Hoje' :
                                historyFilterPeriod === 'week' ? 'Última Semana' :
                                historyFilterPeriod === 'month' ? 'Último Mês' : 'Último Ano'
                              }
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Período</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={historyFilterPeriod} onValueChange={(v) => setHistoryFilterPeriod(v as any)}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="today">Hoje</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="week">Última Semana</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="month">Último Mês</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="year">Último Ano</DropdownMenuRadioItem>
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>

                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <Filter className="h-3 w-3 mr-1" />
                              Status: {
                                historyFilterStatus === 'all' ? 'Todos' :
                                historyFilterStatus === 'completed' ? 'Concluído' :
                                historyFilterStatus === 'confirmed' ? 'Confirmado' : 'Cancelado'
                              }
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Status</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={historyFilterStatus} onValueChange={(v) => setHistoryFilterStatus(v as any)}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="completed">Concluído</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="confirmed">Confirmado</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="cancelled">Cancelado</DropdownMenuRadioItem>
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>

                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <Scissors className="h-3 w-3 mr-1" />
                              Serviço: {services.find(s => s.id === historyFilterService)?.title || 'Todos'}
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Serviço</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={historyFilterService} onValueChange={setHistoryFilterService}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              {services.map((service) => (
                                <DropdownMenuRadioItem key={service.id} value={service.id}>{service.title}</DropdownMenuRadioItem>
                              ))}
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>

                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <CreditCard className="h-3 w-3 mr-1" />
                              Pagamento: {historyFilterPayment === 'all' ? 'Todos' : historyFilterPayment === 'pix' ? 'Pix' : 'Dinheiro'}
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Pagamento</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={historyFilterPayment} onValueChange={(v) => setHistoryFilterPayment(v as any)}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="pix">Pix</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="dinheiro">Dinheiro</DropdownMenuRadioItem>
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </div>
                    </div>

                    {loadingHistoryAppointments ? (
                      <div className="flex items-center justify-center py-8">
                        <Loader2 className="h-6 w-6 animate-spin text-primary" />
                      </div>
                    ) : (() => {
                      const visibleAppointments = historyAppointments;
                      return historyTotalCount > 0 ? (
                        <div className="space-y-3">
                          {visibleAppointments.map((appointment) => (
                          <div key={appointment.id} className={`p-3 rounded-lg border ${
                            appointment.status === 'completed' ? 'bg-green-500/10 border-green-500/30' :
                            appointment.status === 'confirmed' ? 'bg-blue-500/10 border-blue-500/30' :
                            appointment.status === 'cancelled' ? 'bg-red-500/10 border-red-500/30' :
                            'bg-yellow-500/10 border-yellow-500/30'
                          }`}>
                            <div className="flex justify-between items-start">
                              <div className="space-y-1">
                                <div className="flex items-center gap-2 flex-wrap">
                                  {(() => {
                                    try {
                                      const n = appointment.notes ? JSON.parse(appointment.notes) : null;
                                      if (n && n.fit === true) {
                                        return <span className="px-2 py-0.5 rounded text-[10px] font-bold bg-purple-600 text-white shadow-sm uppercase tracking-wider">Encaixe</span>;
                                      }
                                    } catch {}
                                    return null;
                                  })()}
                                  <p className="font-bold text-base">
                                    {appointment.service?.title || 'Serviço'}
                                  </p>
                                  <span className={`px-2 py-1 rounded text-xs font-medium ${
                                    appointment.status === 'completed' ? 'bg-green-500/20 text-green-400' :
                                    appointment.status === 'confirmed' ? 'bg-blue-500/20 text-blue-400' :
                                    appointment.status === 'cancelled' ? 'bg-red-500/20 text-red-400' :
                                    'bg-yellow-500/20 text-yellow-400'
                                  }`}>
                                    {appointment.status === 'completed' ? 'Concluído' :
                                     appointment.status === 'confirmed' ? 'Confirmado' :
                                     appointment.status === 'cancelled' ? 'Cancelado' :
                                     'Pendente'}
                                  </span>
                                  {/* Badge para agendamentos manuais/retroativos */}
                                  {appointment.booking_type === 'manual' && (
                                    <span className="px-2 py-1 rounded text-xs font-medium bg-orange-500/20 text-orange-400 border border-orange-500/30" title="Agendamento criado manualmente pelo barbeiro">
                                      📝 Manual
                                    </span>
                                  )}
                                  {/* Badge para forma de pagamento (apenas concluídos) */}
                                  {appointment.status === 'completed' && (
                                    <>
                                      {/* Verifica se tem pagamentos parciais */}
                                      {appointment.appointment_payments && appointment.appointment_payments.length > 0 ? (
                                        <div className="flex flex-wrap gap-1">
                                          {appointment.appointment_payments.map((payment, idx) => (
                                            <span key={idx} className="px-2 py-1 rounded text-xs font-medium bg-primary/20 text-primary border border-primary/30">
                                              {payment.payment_method === 'pix' ? '💳 Pix' : 
                                               payment.payment_method === 'cartao' ? '💳 Cartão' : '💵 Dinheiro'}: R$ {Number(payment.amount).toFixed(2)}
                                            </span>
                                          ))}
                                        </div>
                                      ) : appointment.payment_method ? (
                                        // Fallback para método único antigo
                                        <span className="px-2 py-1 rounded text-xs font-medium bg-primary/20 text-primary">
                                          {appointment.payment_method === 'pix' ? '💳 Pix' : 
                                           appointment.payment_method === 'cartao' ? '💳 Cartão' : '💵 Dinheiro'}
                                        </span>
                                      ) : null}
                                    </>
                                  )}
                                </div>
                                <p className="text-xs font-medium">Cliente: {appointment.client?.name ?? 'Cliente'}</p>
                                <div className="flex items-center gap-2">
                                  {appointment.client?.phone ? (
                                    <a 
                                      href={`https://wa.me/${formatWhatsappNumber(appointment.client.phone)}`}
                                      target="_blank"
                                      rel="noopener noreferrer"
                                      className="text-xs text-primary hover:underline"
                                    >
                                      Tel: {appointment.client.phone}
                                    </a>
                                  ) : (
                                    <span className="text-xs text-muted-foreground">Sem telefone</span>
                                  )}
                                  <Button 
                                    size="sm" 
                                    className="bg-green-600 hover:bg-green-700 text-white h-7 px-2 text-xs"
                                    onClick={() => handleWhatsAppClick(appointment)}
                                    title="Falar no WhatsApp"
                                  >
                                    <Smartphone className="h-3 w-3" />
                                    WhatsApp
                                  </Button>
                                </div>
                                <div className="flex items-center gap-3 text-xs text-muted-foreground mt-2">
                                  <div className="flex items-center gap-2">
                                    <Calendar className="h-3 w-3" />
                                    <span>{new Date(appointment.appointment_date + 'T00:00:00').toLocaleDateString('pt-BR')}</span>
                                  </div>
                                  <div className="flex items-center gap-2">
                                    <Clock className="h-3 w-3" />
                                    <span className="font-bold text-primary">{appointment.appointment_time.slice(0, 5)}</span>
                                  </div>
                                  {appointment.service?.price && (
                                    <div className="text-primary font-bold">
                                      R$ {appointment.service.price.toFixed(2)}
                                    </div>
                                  )}
                                </div>
                                {appointment.photo_url && (
                                  <div className="mt-3">
                                    <Button
                                      type="button"
                                      variant="outline"
                                      size="sm"
                                      className="h-7 px-2 text-xs"
                                      onClick={() => {
                                        setPhotoModalUrl(
                                          getSupabaseImagePreviewUrl(appointment.photo_url as string, {
                                            width: 960,
                                            quality: 70,
                                            resize: 'contain',
                                          })
                                        );
                                        setPhotoModalOpen(true);
                                      }}
                                    >
                                      Ver foto
                                    </Button>
                                  </div>
                                )}
                              </div>
                            </div>
                          </div>
                        ))}

                          <div className="flex flex-wrap items-center justify-between gap-2 pt-2 border-t border-border/60">
                            <span className="text-xs text-muted-foreground">
                              Mostrando {historyStartIndex}-{historyEndIndex} de {historyTotalCount}
                            </span>
                            <div className="flex items-center gap-2">
                              <Button
                                size="sm"
                                variant="outline"
                                className="h-7 px-2 text-xs"
                                disabled={currentHistoryPage <= 1}
                                onClick={() => setHistoryPage((prev) => Math.max(1, prev - 1))}
                              >
                                Anterior
                              </Button>
                              <span className="text-xs text-muted-foreground min-w-[68px] text-center">
                                {currentHistoryPage} / {historyTotalPages}
                              </span>
                              <Button
                                size="sm"
                                variant="outline"
                                className="h-7 px-2 text-xs"
                                disabled={currentHistoryPage >= historyTotalPages}
                                onClick={() => setHistoryPage((prev) => Math.min(historyTotalPages, prev + 1))}
                              >
                                Próxima
                              </Button>
                            </div>
                          </div>
                      </div>
                    ) : (
                      <p className="text-center text-muted-foreground py-8">
                        {historyTotalCount === 0 
                          ? 'Nenhum serviço registrado ainda'
                          : 'Nenhum agendamento encontrado com os filtros selecionados'}
                      </p>
                    );
                    })()}
                  </CardContent>
              </Card>
            </TabsContent>
                  <TabsContent value="produtos" className="space-y-6">
                <Card className="bg-card border-border">
                  <CardHeader className="pb-2">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-base">Histórico de Produtos</CardTitle>
                      <Button
                        size="sm"
                        variant="outline"
                        className="h-8 px-2 text-xs"
                        onClick={() => setShowProductHistoryFilters((v) => !v)}
                      >
                        {showProductHistoryFilters ? 'Ocultar filtros' : 'Mostrar filtros'}
                      </Button>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className={`mb-4 pb-3 border-b border-border ${showProductHistoryFilters ? '' : 'hidden'}`}>
                      <div className="grid grid-cols-3 gap-2">
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <Calendar className="h-3 w-3 mr-1" />
                              Período: {
                                productHistoryFilterPeriod === 'all' ? 'Todos' :
                                productHistoryFilterPeriod === 'today' ? 'Hoje' :
                                productHistoryFilterPeriod === 'week' ? 'Última Semana' :
                                productHistoryFilterPeriod === 'month' ? 'Último Mês' : 'Último Ano'
                              }
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Período</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={productHistoryFilterPeriod} onValueChange={(v) => setProductHistoryFilterPeriod(v as any)}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="today">Hoje</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="week">Última Semana</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="month">Último Mês</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="year">Último Ano</DropdownMenuRadioItem>
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>
                        
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <Filter className="h-3 w-3 mr-1" />
                              Status: {
                                productHistoryFilterStatus === 'all' ? 'Todos' :
                                productHistoryFilterStatus === 'confirmed' ? 'Confirmado' :
                                productHistoryFilterStatus === 'pending' ? 'Pendente' : 'Cancelado'
                              }
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Status</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={productHistoryFilterStatus} onValueChange={(v) => setProductHistoryFilterStatus(v as any)}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="confirmed">Confirmado</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="pending">Pendente</DropdownMenuRadioItem>
                              <DropdownMenuRadioItem value="cancelled">Cancelado</DropdownMenuRadioItem>
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>
                        
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="outline" size="sm" className="h-8 px-2 text-xs w-full truncate justify-center">
                              <ShoppingBag className="h-3 w-3 mr-1" />
                              Produto: {
                                productHistoryFilterProductId === 'all' 
                                  ? 'Todos' 
                                  : (productFilterList.find(p => p.id === productHistoryFilterProductId)?.name || 'Selecionado')
                              }
                            </Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent>
                            <DropdownMenuLabel className="text-xs">Produto</DropdownMenuLabel>
                            <DropdownMenuRadioGroup value={productHistoryFilterProductId} onValueChange={setProductHistoryFilterProductId}>
                              <DropdownMenuRadioItem value="all">Todos</DropdownMenuRadioItem>
                              {productFilterList.map((p) => (
                                <DropdownMenuRadioItem key={p.id} value={p.id}>{p.name}</DropdownMenuRadioItem>
                              ))}
                            </DropdownMenuRadioGroup>
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </div>
                    </div>
                    {loadingProductHistory ? (
                      <div className="flex items-center justify-center py-8">
                        <Loader2 className="h-6 w-6 animate-spin text-primary" />
                      </div>
                    ) : (() => {
                      const sales = productHistory;
                      return sales.length > 0 ? (
                        <div className="space-y-3">
                          {sales.map((sale) => (
                            <div key={sale.id} className="p-3 rounded-lg border bg-secondary/20 border-border">
                              <div className="flex justify-between items-start gap-3">
                                <div className="space-y-1">
                                  <div className="flex items-center gap-2">
                                    <p className="font-bold text-sm">{sale.product?.name || 'Produto'}</p>
                                    <span className={`px-2 py-1 rounded text-xs font-medium ${
                                      sale.status === 'confirmed' ? 'bg-green-500/20 text-green-500' :
                                      sale.status === 'pending' ? 'bg-yellow-500/20 text-yellow-600' :
                                      'bg-red-500/20 text-red-500'
                                    }`}>
                                      {sale.status === 'confirmed' ? 'Confirmado' : sale.status === 'pending' ? 'Pendente' : 'Cancelado'}
                                    </span>
                                  </div>
                                  {sale.notes && (
                                    <p className="text-xs text-muted-foreground">{sale.notes}</p>
                                  )}
                                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                    <div className="flex items-center gap-2">
                                      <span>Pagamento:</span>
                                      <span className="font-semibold text-primary">
                                        {sale.payment_method ? (sale.payment_method === 'pix' ? 'Pix' : sale.payment_method === 'cartao' ? 'Cartão' : 'Dinheiro') : '-'}
                                      </span>
                                    </div>
                                    {sale.photo_url && (
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-6 px-2 text-xs"
                                        onClick={() => {
                                          setPhotoModalUrl(
                                            getSupabaseImagePreviewUrl(sale.photo_url, {
                                              width: 960,
                                              quality: 70,
                                              resize: 'contain',
                                            })
                                          );
                                          setPhotoModalOpen(true);
                                        }}
                                      >
                                        Ver foto
                                      </Button>
                                    )}
                                  </div>
                                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                                    <div className="flex items-center gap-2">
                                      <Calendar className="h-3 w-3" />
                                      <span>{new Date(sale.sale_date + 'T00:00:00').toLocaleDateString('pt-BR')}</span>
                                    </div>
                                    <div className="flex items-center gap-2">
                                      <Clock className="h-3 w-3" />
                                      <span className="font-bold text-primary">{String(sale.sale_time).slice(0,5)}</span>
                                    </div>
                                    <div className="text-primary font-bold">
                                      R$ {Number(sale.total_price).toFixed(2)}
                                    </div>
                                  </div>
                                </div>
                                <div className="text-xs text-right min-w-[80px]">
                                  <div className="text-muted-foreground">Qtd</div>
                                  <div className="font-semibold">{sale.quantity}</div>
                                </div>
                              </div>
                            </div>
                          ))}

                          <div className="flex flex-wrap items-center justify-between gap-2 pt-2 border-t border-border/60">
                            <span className="text-xs text-muted-foreground">
                              Mostrando {productHistoryStartIndex}-{productHistoryEndIndex} de {productHistoryTotalCount}
                            </span>
                            <div className="flex items-center gap-2">
                              <Button
                                size="sm"
                                variant="outline"
                                className="h-7 px-2 text-xs"
                                disabled={currentProductHistoryPage <= 1}
                                onClick={() => setProductHistoryPage((prev) => Math.max(1, prev - 1))}
                              >
                                Anterior
                              </Button>
                              <span className="text-xs text-muted-foreground min-w-[68px] text-center">
                                {currentProductHistoryPage} / {productHistoryTotalPages}
                              </span>
                              <Button
                                size="sm"
                                variant="outline"
                                className="h-7 px-2 text-xs"
                                disabled={currentProductHistoryPage >= productHistoryTotalPages}
                                onClick={() => setProductHistoryPage((prev) => Math.min(productHistoryTotalPages, prev + 1))}
                              >
                                Próxima
                              </Button>
                            </div>
                          </div>
                        </div>
                      ) : (
                        <p className="text-center text-muted-foreground py-8">
                          Nenhuma venda de produto encontrada no período selecionado
                        </p>
                      );
                    })()}
                  </CardContent>
                </Card>
                  </TabsContent>
                </Tabs>
              </TabsContent>
            </Tabs>
          </>
        )}


        <Dialog 
          open={photoModalOpen} 
          onOpenChange={(open) => {
            setPhotoModalOpen(open);
            if (!open) {
              setPhotoModalUrl(null);
            }
          }}
        >
          <DialogContent className="max-w-3xl">
            {photoModalUrl && (
              <img 
                src={photoModalUrl} 
                alt="Foto do corte" 
                className="w-full max-h-[80vh] object-contain rounded-lg"
              />
            )}
          </DialogContent>
        </Dialog>

        {/* Dialog de ação ao clicar no agendamento (Concluir ou Cancelar) */}
        <Dialog 
          open={actionDialogOpen} 
          onOpenChange={(open) => {
            setActionDialogOpen(open);
            if (!open) {
              setSelectedAppointmentForAction(null);
            }
          }}
        >
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>O que deseja fazer?</DialogTitle>
              {selectedAppointmentForAction && (
                <DialogDescription>
                  Serviço: <span className="font-semibold">{selectedAppointmentForAction.service?.title || 'Serviço'}</span><br />
                  Cliente: <span className="font-semibold">{selectedAppointmentForAction.client?.name || selectedAppointmentForAction.client_name || 'Local'}</span><br />
                  Data: {new Date(selectedAppointmentForAction.appointment_date + 'T00:00:00').toLocaleDateString('pt-BR')} às {selectedAppointmentForAction.appointment_time.slice(0, 5)}
                </DialogDescription>
              )}
            </DialogHeader>
            <div className="space-y-3 pt-2">
              <Button
                className="w-full bg-green-600 hover:bg-green-700"
                onClick={() => {
                  if (!selectedAppointmentForAction) return;
                  handleWhatsAppClick(selectedAppointmentForAction);
                }}
              >
                Falar com o Cliente (WhatsApp)
              </Button>
              <Button
                className="w-full bg-green-600 hover:bg-green-700"
                onClick={() => {
                  if (!selectedAppointmentForAction) return;
                  setAppointmentToComplete(selectedAppointmentForAction.id);
                  setActionDialogOpen(false);
                  setCompleteDialogOpen(true);
                }}
              >
                Concluir atendimento
              </Button>
              <Button
                className="w-full bg-blue-600 hover:bg-blue-700"
                onClick={() => {
                  if (!selectedAppointmentForAction) return;
                  handleEditClick(selectedAppointmentForAction);
                }}
              >
                Alterar Data/Hora
              </Button>
              <Button
                className="w-full"
                variant="destructive"
                onClick={() => {
                  if (!selectedAppointmentForAction) return;
                  setAppointmentToCancel(selectedAppointmentForAction.id);
                  setCancellationReason('');
                  setActionDialogOpen(false);
                  setCancelDialogOpen(true);
                }}
              >
                Cancelar agendamento
              </Button>
              <Button
                className="w-full"
                variant="outline"
                onClick={() => setActionDialogOpen(false)}
              >
                Fechar
              </Button>
            </div>
          </DialogContent>
        </Dialog>

        {/* Dialog para adicionar foto ao concluir */}
        <Dialog 
          open={completeDialogOpen} 
          onOpenChange={(open) => {
            setCompleteDialogOpen(open);
            if (!open) {
              setCurrentPaymentMethod('pix');
              setPhotoFile(null);
              setPhotoPreview(null);
              setPayments([]);
              setCurrentPaymentAmount('');
            }
          }}
        >
          <DialogContent className="max-w-md">
            <DialogHeader>
              <DialogTitle>Concluir Atendimento</DialogTitle>
              {appointmentToComplete && selectedAppointmentForAction && (
                <DialogDescription>
                  Cliente: <span className="font-semibold">{selectedAppointmentForAction.client?.name || selectedAppointmentForAction.client_name || 'Local'}</span><br />
                  Serviço: <span className="font-semibold">{selectedAppointmentForAction.service?.title || 'Serviço'}</span><br />
                  Data: {new Date(selectedAppointmentForAction.appointment_date + 'T00:00:00').toLocaleDateString('pt-BR')} às {selectedAppointmentForAction.appointment_time.slice(0, 5)}
                </DialogDescription>
              )}
            </DialogHeader>
            <div className="space-y-4 py-4">
              <p className="text-sm text-muted-foreground">
                Tire uma foto do corte realizado para concluir o atendimento.
              </p>
              
              <div className="w-full h-64 border-2 border-dashed border-border rounded-lg overflow-hidden flex items-center justify-center bg-black relative">
                {photoPreview ? (
                  <>
                    <img 
                      src={photoPreview} 
                      alt="Preview" 
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute bottom-3 left-0 right-0 flex justify-center">
                      <Button
                        type="button"
                        variant="secondary"
                        className="gap-2"
                        onClick={() => {
                          setPhotoFile(null);
                          setPhotoPreview(null);
                          fileInputRef.current?.click();
                        }}
                      >
                        <Camera className="w-4 h-4" />
                        Tirar outra foto
                      </Button>
                    </div>
                  </>
                ) : (
                  <button
                    type="button"
                    className="flex flex-col items-center justify-center text-center p-4 text-muted-foreground gap-3"
                    onClick={() => fileInputRef.current?.click()}
                  >
                    <Camera className="w-12 h-12 text-muted-foreground mb-2" />
                    <span className="font-semibold text-sm text-foreground">Tirar foto</span>
                    <span className="text-xs text-muted-foreground">A câmera do aparelho será aberta</span>
                  </button>
                )}
                <input 
                  ref={fileInputRef}
                  type="file" 
                  className="hidden" 
                  accept="image/*"
                  capture="environment"
                  onChange={handlePhotoChange}
                />
              </div>

              {/* Campo de forma de pagamento */}
              <div className="space-y-4">
