                          {p.method === 'pix' && <Smartphone className="h-4 w-4 text-primary" />}
                          {p.method === 'dinheiro' && <Banknote className="h-4 w-4 text-green-500" />}
                          {p.method === 'cartao' && <CreditCard className="h-4 w-4 text-blue-500" />}
