                                {(role === "admin" || role === "gestor") && (
                                  <div className="flex items-center gap-1">
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      className="h-6 px-2 text-[10px]"
                                      onClick={(e) => {
                                        e.stopPropagation();
                                        setCancelTarget(apt as any);
                                        setCancelReason('');
