                      </div>
                    )}
                  </div>
                </button>
                );
              })}
            </div>
          </TabsContent>

          {/* Removida aba de agendamentos futuros */}
        </Tabs>

        {!isReadOnly && !quickBookingOpen && (
          <QuickBookingDialog
            open={dialogOpen}
            onOpenChange={setDialogOpen}
