        {!isReadOnly && quickBookingOpen && (
          <QuickBookingDialog
            open={quickBookingOpen}
            onOpenChange={handleQuickBookingClose}
            date={today}
            timeSlot={quickBookingPreselectedBarberId ? "" : availableSlots[0] ?? ""}
