                </div>
                {breakMode === "block" && (
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <Label className="text-xs">Início</Label>
                      <Input type="time" value={breakStart} onChange={(e) => setBreakStart(e.target.value)} className="h-9 text-sm" />
                    </div>
                    <div>
                      <Label className="text-xs">Fim</Label>
                      <Input type="time" value={breakEnd} onChange={(e) => setBreakEnd(e.target.value)} className="h-9 text-sm" />
                    </div>
                  </div>
                )}
                {breakMode === "release" && (
                  <div className="p-2 bg-secondary/20 rounded border border-border/50">
                    <div className="text-xs font-semibold text-muted-foreground mb-2">Pausas nessa data</div>
                    <div className="space-y-2 max-h-48 overflow-y-auto">
                      {breaksForDialog.length > 0 ? (
                        breaksForDialog.map((br) => (
                          <div key={br.id || `${br.start_time}-${br.end_time}`} className="flex items-center justify-between p-2 bg-secondary/40 rounded border border-border/40">
                            <span className="text-sm font-semibold">{String(br.start_time).slice(0,5)} - {String(br.end_time).slice(0,5)}</span>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={async () => {
                                if (!br.id) return;
                                const { error } = await supabase
                                  .from("barber_breaks")
                                  .delete()
                                  .eq("id", br.id);
                                if (error) {
                                  toast.error(error.message || "Erro ao excluir pausa");
                                } else {
                                  toast.success("Pausa excluída");
                                  const { data } = await (supabase as any)
                                    .from("barber_breaks")
                                    .select("id, start_time, end_time")
                                    .eq("barber_id", breakBarberId)
                                    .eq("date", breakDate)
                                    .order("start_time");
                                  setBreaksForDialog(data || []);
                                  await loadBreaksForToday();
                                  await calculateAvailableSlots();
                                }
                              }}
                            >
                              <Trash2 className="h-3 w-3 mr-1" /> Excluir
                            </Button>
                          </div>
                        ))
                      ) : (
                        <div className="text-xs text-muted-foreground">Sem pausas nessa data</div>
                      )}
                    </div>
                  </div>
                )}
              </div>
              <div className="flex justify-end gap-2 mt-3">
                <Button variant="outline" onClick={() => setBreakDialogOpen(false)} disabled={breakSubmitting}>Cancelar</Button>
                {breakMode === "block" && (
                  <Button onClick={handleSubmitBreak} disabled={breakSubmitting}>
                    Bloquear
                  </Button>
                )}
              </div>
            </DialogContent>
          </Dialog>
        )}

        {(role === "admin" || role === "gestor") && (
          <Dialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
            <DialogContent className="max-w-md w-[95vw]">
              <DialogHeader>
                <DialogTitle>Cancelar agendamento</DialogTitle>
                <DialogDescription>Informe um motivo (opcional) e confirme o cancelamento.</DialogDescription>
              </DialogHeader>
              <div className="space-y-3">
                {cancelTarget && (
                  <div className="p-2 bg-secondary/30 rounded border border-border/40 text-sm">
                    <div><strong>Cliente:</strong> {cancelTarget.client_name || (cancelTarget as any).profiles?.name || 'Local'}</div>
                    <div><strong>Serviço:</strong> {cancelTarget.services?.title}</div>
                    <div><strong>Data:</strong> {format(new Date(cancelTarget.appointment_date + 'T00:00:00'), 'dd/MM/yyyy')}</div>
                    <div><strong>Hora:</strong> {cancelTarget.appointment_time}</div>
                  </div>
                )}
                <div>
                  <Label className="text-xs">Motivo (opcional)</Label>
                  <Input
                    value={cancelReason}
                    onChange={(e) => setCancelReason(e.target.value)}
                    placeholder="Ex.: cliente não compareceu"
                    className="h-9 text-sm"
                  />
                </div>
                <div className="flex justify-end gap-2">
                  <Button variant="outline" onClick={() => setCancelDialogOpen(false)} disabled={cancelling}>Fechar</Button>
                  <Button
                    onClick={async () => {
                      if (!cancelTarget) return;
                      setCancelling(true);
                      try {
                        const notes = cancelReason?.trim()
                          ? `${cancelTarget.notes ? cancelTarget.notes + ' | ' : ''}Cancelado pelo gestor: ${cancelReason.trim()}`
                          : cancelTarget.notes || null;
                        const { error } = await supabase
                          .from('appointments')
                          .update({ status: 'cancelled', notes })
                          .eq('id', cancelTarget.id);
                        if (error) throw error;
                        toast.success('Agendamento cancelado');
                        setCancelDialogOpen(false);
                        setCancelTarget(null);
                        setCancelReason('');
                        await loadAppointments();
                        await calculateAvailableSlots();
                      } catch (e: any) {
                        toast.error('Erro ao cancelar', { description: e.message });
                      } finally {
                        setCancelling(false);
                      }
                    }}
                    className="bg-destructive hover:bg-destructive/90"
                    disabled={cancelling}
                  >
                    {cancelling ? 'Cancelando...' : 'Confirmar cancelamento'}
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        )}
        {(role === "admin" || role === "gestor") && (
          <Dialog open={openDayDialogOpen} onOpenChange={setOpenDayDialogOpen}>
            <DialogContent className="max-w-md w-[95vw]">
              <DialogHeader>
                <DialogTitle>Abrir hoje</DialogTitle>
                <DialogDescription>Defina o período de atendimento de hoje</DialogDescription>
              </DialogHeader>
              <div className="grid grid-cols-2 gap-3 mt-2">
                <div>
                  <Label className="text-xs">Início</Label>
                  <Input type="time" value={openDayStart} onChange={(e) => setOpenDayStart(e.target.value)} className="h-9 text-sm" />
                </div>
                <div>
                  <Label className="text-xs">Fim</Label>
                  <Input type="time" value={openDayEnd} onChange={(e) => setOpenDayEnd(e.target.value)} className="h-9 text-sm" />
                </div>
              </div>
              <div className="flex justify-end gap-2 mt-3">
                <Button variant="outline" onClick={() => setOpenDayDialogOpen(false)}>Cancelar</Button>
                <Button
                  onClick={async () => {
                    if (!openDayBarberId || !openDayStart || !openDayEnd || openDayEnd <= openDayStart) {
                      toast.error("Defina horários válidos");
                      return;
                    }
                    try {
                      const { data, error } = await supabase
                        .from("barbers")
                        .select("availability")
                        .eq("id", openDayBarberId)
                        .maybeSingle();
                      if (error) throw error;
                      const base = (data?.availability as any) || {};
                      const dayKeyMap = ["sunday","monday","tuesday","wednesday","thursday","friday","saturday"] as const;
                      const dayKey = dayKeyMap[todayDate.getDay()];
                      const currentDay = (base?.[dayKey] as any) || defaultBarberAvailability[dayKey];
                      const newAvailability = { ...defaultBarberAvailability, ...base, [dayKey]: { ...currentDay, closed: false, open: openDayStart, close: openDayEnd } };
                      const { error: updError } = await supabase
                        .from("barbers")
                        .update({ availability: newAvailability as any })
                        .eq("id", openDayBarberId);
                      if (updError) throw updError;
                      toast.success("Dia aberto com período definido");
                      setOpenDayDialogOpen(false);
                      setOpenDayBarberId(null);
                      await loadBarbers();
                      await calculateAvailableSlots();
                    } catch (e: any) {
                      toast.error(e.message || "Erro ao abrir hoje");
                    }
                  }}
                >
                  Abrir
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        )}

        {(role === "admin" || role === "gestor") && (
          <Dialog open={viewSlotsOpen} onOpenChange={setViewSlotsOpen}>
            <DialogContent className="max-w-md w-[95vw]">
              <DialogHeader>
                <DialogTitle>Horários disponíveis</DialogTitle>
                <DialogDescription>Visualização dos horários — sem ações</DialogDescription>
              </DialogHeader>
              <div className="space-y-3">
                <div className="p-2 bg-secondary/20 rounded border border-border/50">
                  <div className="text-xs font-semibold text-muted-foreground mb-2">Hoje</div>
                  <div className="flex flex-wrap gap-2">
                    {(viewSlotsBarberId && (availableSlotsByBarber[viewSlotsBarberId] || []).length > 0) ? (
                      (availableSlotsByBarber[viewSlotsBarberId] || []).map((s) => (
                        <span
                          key={`${viewSlotsBarberId}-${s}`}
                          className="px-3 py-1 rounded-full text-sm font-semibold border border-border bg-secondary text-secondary-foreground"
                        >
                          {s}
                        </span>
                      ))
                    ) : (
                      <span className="text-xs text-muted-foreground">Nenhum horário disponível hoje para este barbeiro.</span>
                    )}
                  </div>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        )}

      </main>
    </div>
  );
};

export default FilaDaBarbearia;

import { supabase } from '@/integrations/supabase/client';

export type ConnectionStatus = 'disconnected' | 'connecting' | 'connected' | 'error';

export interface WhatsAppConnectionState {
  status: ConnectionStatus;
  message?: string;
  lastUpdate: Date;
  instanceId?: string;
  number?: string;
}

export interface WhatsAppInstance {
  instanceName: string;
  status: 'open' | 'close' | 'connecting';
  number?: string;
  qrcode?: {
    base64?: string;
    code?: string;
  };
}

type StatusChangeCallback = (state: WhatsAppConnectionState) => void;

class WhatsAppConnectionService {
  private currentState: WhatsAppConnectionState = {
    status: 'disconnected',
    lastUpdate: new Date(),
  };
  
  private callbacks: Set<StatusChangeCallback> = new Set();
  private isManualMode = true; // Por padrão, modo manual (sem polling automático)

  constructor() {
    // Carregar estado do localStorage se disponível
    this.loadStateFromStorage();
  }

  private loadStateFromStorage() {
    try {
      const stored = localStorage.getItem('whatsapp_connection_state');
      if (stored) {
        const parsed = JSON.parse(stored);
        // Verificar se não é muito antigo (mais de 5 minutos)
        const lastUpdate = new Date(parsed.lastUpdate);
        const now = new Date();
        const fiveMinutes = 5 * 60 * 1000;
        
        if ((now.getTime() - lastUpdate.getTime()) < fiveMinutes) {
          this.currentState = {
            ...parsed,
            lastUpdate: new Date(parsed.lastUpdate),
          };
        }
      }
    } catch (error) {
      console.warn('Erro ao carregar estado do localStorage:', error);
    }
  }

  private saveStateToStorage() {
    try {
      localStorage.setItem('whatsapp_connection_state', JSON.stringify(this.currentState));
    } catch (error) {
      console.warn('Erro ao salvar estado no localStorage:', error);
    }
  }

  private updateState(newState: Partial<WhatsAppConnectionState>) {
    this.currentState = {
      ...this.currentState,
      ...newState,
      lastUpdate: new Date(),
    };
    
    this.saveStateToStorage();
    
    // Notificar todos os callbacks
    this.callbacks.forEach(callback => {
      try {
        callback(this.currentState);
      } catch (error) {
        console.error('Erro ao executar callback de mudança de estado:', error);
      }
    });
  }
  
  private sanitizeMessage(msg?: string): string | undefined {
    if (!msg) return msg;
    if (msg.includes('Railway')) {
      return 'Erro na Evolution API (servidor local). Reinicie o serviço local, verifique a URL pública do Cloudflare Tunnel/Workers e gere um novo QR.';
    }
    return msg;
  }

  async getStatus(): Promise<WhatsAppConnectionState> {
    if (this.isManualMode) {
      return this.currentState;
    }

    try {
      const { data, error } = await supabase.functions.invoke('whatsapp-manager', {
        body: { action: 'list' }
      });

      if (error) throw error;

      if (data?.success && data?.instances) {
        const instances: WhatsAppInstance[] = data.instances;
        const connectedInstance = instances.find(i => i.status === 'open');
        
        if (connectedInstance) {
          this.updateState({
            status: 'connected',
            instanceId: connectedInstance.instanceName,
            number: connectedInstance.number,
            message: `Conectado como ${connectedInstance.number || connectedInstance.instanceName}`,
          });
        } else {
          const connectingInstance = instances.find(i => i.status === 'connecting');
          if (connectingInstance) {
            this.updateState({
              status: 'connecting',
              instanceId: connectingInstance.instanceName,
              message: 'Conectando...',
            });
          } else {
            this.updateState({
              status: 'disconnected',
              message: 'Nenhuma instância conectada',
            });
          }
        }
      } else {
        this.updateState({
          status: 'error',
          message: this.sanitizeMessage(data?.error) || 'Erro ao verificar status',
        });
      }
    } catch (error: any) {
      this.updateState({
        status: 'error',
        message: this.sanitizeMessage(error.message) || 'Erro de conexão',
      });
    }

    return this.currentState;
  }

  async connect(instanceName?: string): Promise<any> {
    const targetInstance = instanceName || 'default';
    
    this.updateState({
      status: 'connecting',
      instanceId: targetInstance,
      message: 'Iniciando conexão...',
    });

    try {
      // Primeiro, criar a instância se não existir
      const { data: createData, error: createError } = await supabase.functions.invoke('whatsapp-manager', {
        body: { 
          action: 'create',
          instanceName: targetInstance
        }
      });

      if (createError) throw createError;

      // Aguardar um pouco para a instância ser criada
      await new Promise(resolve => setTimeout(resolve, 2000));

      // Gerar QR code
      const { data: qrData, error: qrError } = await supabase.functions.invoke('whatsapp-manager', {
        body: { 
          action: 'get-qrcode',
          instanceName: targetInstance
        }
      });

      if (qrError) throw qrError;

      if (qrData?.success && qrData?.qrcode) {
        this.updateState({
          status: 'connecting',
          message: 'QR Code gerado. Escaneie com seu WhatsApp.',
        });
        
        // Retornar o QR code para o componente exibir
        return qrData.qrcode;
      } else {
        throw new Error(qrData?.error || 'Erro ao gerar QR code');
      }
    } catch (error: any) {
      this.updateState({
        status: 'error',
        message: this.sanitizeMessage(error.message) || 'Erro ao conectar',
      });
      throw error;
    }
  }

  async disconnect(instanceName?: string): Promise<void> {
    const targetInstance = instanceName || this.currentState.instanceId || 'default';
    
    try {
      const { data, error } = await supabase.functions.invoke('whatsapp-manager', {
        body: { 
          action: 'disconnect',
          instanceName: targetInstance
        }
      });

      if (error) throw error;

      if (data?.success) {
        this.updateState({
          status: 'disconnected',
          instanceId: undefined,
          number: undefined,
          message: 'Desconectado com sucesso',
        });
      } else {
        throw new Error(data?.error || 'Erro ao desconectar');
      }
    } catch (error: any) {
      this.updateState({
        status: 'error',
        message: this.sanitizeMessage(error.message) || 'Erro ao desconectar',
      });
      throw error;
    }
  }

  onStatusChange(callback: StatusChangeCallback): () => void {
    this.callbacks.add(callback);
    
    // Retornar função para remover o callback
    return () => {
      this.callbacks.delete(callback);
    };
  }

  // Método para verificar status uma única vez (sem polling)
  async checkStatusOnce(): Promise<WhatsAppConnectionState> {
    const wasManualMode = this.isManualMode;
    this.isManualMode = false; // Temporariamente permitir verificação
    
    try {
      const status = await this.getStatus();
      return status;
    } finally {
      this.isManualMode = wasManualMode; // Restaurar modo anterior
    }
  }

  // Controle do modo manual
  setManualMode(manual: boolean) {
    this.isManualMode = manual;
  }

  isInManualMode(): boolean {
    return this.isManualMode;
  }

  // Limpar todos os callbacks (útil para cleanup)
  clearCallbacks() {
    this.callbacks.clear();
  }
}

