// Get caller's role from JWT or user_roles table
const getCallerRole = async (authHeader: string | null): Promise<{ userId: string | null; role: 'admin' | 'gestor' | 'barbeiro' | 'cliente' | null }> => {
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return { userId: null, role: null };
  }

  const token = authHeader.replace('Bearer ', '');
  
  // Skip if it's the anon key or service role key
  const anonKey = Deno.env.get('SUPABASE_ANON_KEY');
  if (token === anonKey) {
    return { userId: null, role: null };
  }

  try {
    // Get user from token
    const { data: { user }, error } = await supabase.auth.getUser(token);
    if (error || !user) {
      return { userId: null, role: null };
    }

    // Get user's role from user_roles table
    const { data: roles } = await supabase
      .from('user_roles')
      .select('role')
      .eq('user_id', user.id);

    if (!roles || roles.length === 0) {
      return { userId: user.id, role: 'cliente' };
    }

    const roleList = roles.map((r: any) => r.role);
    if (roleList.includes('admin')) return { userId: user.id, role: 'admin' };
    if (roleList.includes('gestor')) return { userId: user.id, role: 'gestor' };
    if (roleList.includes('barbeiro')) return { userId: user.id, role: 'barbeiro' };
    return { userId: user.id, role: 'cliente' };
  } catch (e) {
    console.error('Error getting caller role:', e);
    return { userId: null, role: null };
  }
};

// List all users with their roles (based primarily on profiles)
const listAllUsers = async () => {
  const authUsers: any[] = [];
  let page = 1;
  const perPage = 1000;

  while (true) {
    const { data, error } = await supabase.auth.admin.listUsers({ page, perPage });

    if (error) {
      throw new Error('Erro ao listar usuários: ' + error.message);
    }

    const users = data?.users || [];
    authUsers.push(...users);

    if (!data || users.length < perPage) {
      break;
    }

    page += 1;
  }

  // Get all profiles
  const { data: profiles } = await supabase
    .from('profiles')
    .select('*');

  // Get all roles
  const { data: userRoles } = await supabase
    .from('user_roles')
    .select('user_id, role');

  // Get all barbers (to get their photos)
  const { data: barbers } = await supabase
    .from('barbers')
    .select('user_id, image_url');

  const authUserMap = new Map<string, any>();
  authUsers.forEach((u: any) => {
    authUserMap.set(u.id, u);
  });

  const users: any[] = [];

  // 1) Base: todos os perfis (inclui clientes com e sem usuário Auth)
  (profiles || []).forEach((profile: any) => {
    const user = authUserMap.get(profile.id);
    const isTempUser = profile.is_temp_user === true;
    const roles = userRoles
      ?.filter((r: any) => r.user_id === profile.id)
      .map((r: any) => r.role) || [];

    let primaryRole = 'cliente';
    if (roles.includes('admin')) primaryRole = 'admin';
    else if (roles.includes('gestor')) primaryRole = 'gestor';
    else if (roles.includes('barbeiro')) primaryRole = 'barbeiro';

    const barber = barbers?.find((b: any) => b.user_id === profile.id);
    const imageUrl = barber?.image_url || null;

    const metaPhone = user?.user_metadata?.whatsapp || user?.user_metadata?.phone || null;
    const phone = profile.phone || profile.whatsapp || metaPhone || '';

    const metaCpf = user?.user_metadata?.cpf || null;
    const cpf = profile.cpf || metaCpf || null;
    const emailFromAuth = user?.email || null;
    const emailFromCpf = cpf ? `${cpf}@cliente.com` : null;
    const fallbackEmail = `${profile.id}@cliente.local`;
    const email = emailFromAuth || emailFromCpf || fallbackEmail;

    // Ignorar usuários locais/temporários sem CPF (clientes criados só como "Cliente Local")
    if (!cpf && isTempUser && !user) {
      return;
    }

    users.push({
      id: profile.id,
      email,
      name: profile.name || user?.user_metadata?.name || (emailFromAuth || '').split('@')[0] || 'Cliente',
      phone,
      cpf,
      role: primaryRole,
      roles,
      image_url: imageUrl,
      createdAt: user?.created_at || profile.created_at || null,
      lastSignIn: user?.last_sign_in_at || null,
    });
  });

  // 2) Auth users que não têm profile (admins/gestores antigos, etc.)
  const profileIds = new Set((profiles || []).map((p: any) => p.id));
  authUsers
    .filter((u: any) => !profileIds.has(u.id))
    .forEach((user: any) => {
      const roles = userRoles
        ?.filter((r: any) => r.user_id === user.id)
        .map((r: any) => r.role) || [];

      let primaryRole = 'cliente';
      if (roles.includes('admin')) primaryRole = 'admin';
      else if (roles.includes('gestor')) primaryRole = 'gestor';
      else if (roles.includes('barbeiro')) primaryRole = 'barbeiro';

      const barber = barbers?.find((b: any) => b.user_id === user.id);
      const imageUrl = barber?.image_url || null;

      const metaPhone = user.user_metadata?.whatsapp || user.user_metadata?.phone || null;
      const metaCpf = user.user_metadata?.cpf || null;

      users.push({
        id: user.id,
        email: user.email,
        name: user.user_metadata?.name || (user.email || '').split('@')[0] || 'Usuário',
        phone: metaPhone || '',
        cpf: metaCpf || null,
        role: primaryRole,
        roles,
        image_url: imageUrl,
        createdAt: user.created_at,
        lastSignIn: user.last_sign_in_at,
      });
    });

  return users;
};

// Create a new user
const createUser = async (data: {
  email: string;
  password: string;
  name: string;
  phone?: string;
  role: 'barbeiro' | 'gestor' | 'admin';
}) => {
  // Create auth user
  const { data: authData, error: authError } = await supabase.auth.admin.createUser({
    email: data.email,
    password: data.password,
    email_confirm: true,
    user_metadata: {
      name: data.name,
    },
  });

  if (authError) {
    throw new Error('Erro ao criar usuário: ' + authError.message);
  }

  const userId = authData.user.id;

  // Create profile
  await supabase
    .from('profiles')
    .upsert({
      id: userId,
      name: data.name,
      phone: data.phone || null,
    }, { onConflict: 'id' });

  // Create user role
  await supabase
    .from('user_roles')
    .insert({
      user_id: userId,
      role: data.role,
    });

  // If barber, create barber entry
  if (data.role === 'barbeiro') {
    await supabase
      .from('barbers')
      .insert({
        name: data.name,
        user_id: userId,
        specialty: 'Cortes em geral',
        experience: 'Novo',
        rating: 5.0,
        visible: true,
        order_index: 999,
      });
  }

  return {
    id: userId,
    email: data.email,
    name: data.name,
    phone: data.phone || '',
    role: data.role,
  };
};

// Update user password
const updateUserPassword = async (userId: string, newPassword: string) => {
  const { error } = await supabase.auth.admin.updateUserById(userId, {
    password: newPassword,
  });

  if (error) {
    throw new Error('Erro ao atualizar senha: ' + error.message);
  }

