          success: false,
          error: 'UPDATE_ERROR',
          message: error.message
        }), { 
          status: 400, 
          headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
        });
      }
    }

    // PUT/POST /admin/users/:id/role - Update user role
    if ((req.method === 'PUT' || req.method === 'POST') && path.startsWith('admin/users/') && path.endsWith('/role')) {
